/* boater-data.js — Boater Safety practice (NASBLA-style boating safety course basics). 6 topics, all 6 languages.
   window.BOAT = { cats:[{id,name,blurb}], q:[{cat,a,q,o,e}] }
   132 questions: rules(22), operation(22), equipment(22), emergencies(22), law(22), sports(22) */
window.BOAT = {"cats":[{"id":"rules","name":{"en":"Navigation Rules","es":"Reglas de navegación","ru":"Правила судоходства","tr":"Seyir Kuralları","hi":"नौवहन नियम","ar":"قواعد الملاحة"},"blurb":{"en":"Right-of-way, stand-on and give-way, meeting, crossing, overtaking, sound signals and navigation lights.","es":"Derecho de paso, buque que sigue a rumbo y que cede, encuentro, cruce, adelantamiento, señales sonoras y luces de navegación.","ru":"Право прохода, привилегированное и уступающее судно, встречный курс, пересечение, обгон, звуковые сигналы и навигационные огни.","tr":"Geçiş hakkı, yol veren ve yol alan tekne, karşılaşma, kesişme, geçme, ses işaretleri ve seyir fenerleri.","hi":"रास्ते का अधिकार, स्टैंड-ऑन और गिव-वे, आमना-सामना, क्रॉसिंग, ओवरटेकिंग, ध्वनि संकेत और नौवहन बत्तियाँ।","ar":"حق المرور، السفينة الملتزمة والمتنازلة، التلاقي، التقاطع، التجاوز، الإشارات الصوتية وأضواء الملاحة."}},{"id":"operation","name":{"en":"Safe Operation","es":"Operación segura","ru":"Безопасное управление","tr":"Güvenli Kullanım","hi":"सुरक्षित संचालन","ar":"التشغيل الآمن"},"blurb":{"en":"Safe speed, proper lookout, capacity plate, weather, anchoring, fueling and cold-water risks.","es":"Velocidad segura, vigía adecuado, placa de capacidad, clima, fondeo, carga de combustible y riesgos de agua fría.","ru":"Безопасная скорость, надлежащее наблюдение, табличка вместимости, погода, постановка на якорь, заправка и риски холодной воды.","tr":"Güvenli hız, uygun gözcü, kapasite plakası, hava durumu, demirleme, yakıt ikmali ve soğuk su riskleri.","hi":"सुरक्षित गति, उचित लुकआउट, क्षमता प्लेट, मौसम, लंगर डालना, ईंधन भरना और ठंडे पानी के जोखिम।","ar":"السرعة الآمنة، المراقبة السليمة، لوحة السعة، الطقس، الرسو، التزود بالوقود ومخاطر المياه الباردة."}},{"id":"equipment","name":{"en":"Required Equipment","es":"Equipo obligatorio","ru":"Обязательное снаряжение","tr":"Zorunlu Ekipman","hi":"आवश्यक उपकरण","ar":"المعدات المطلوبة"},"blurb":{"en":"Life jackets, fire extinguishers, visual distress signals, ventilation, backfire arrestors and sound devices.","es":"Chalecos salvavidas, extintores, señales visuales de socorro, ventilación, antirretorno de llama y dispositivos sonoros.","ru":"Спасательные жилеты, огнетушители, визуальные сигналы бедствия, вентиляция, пламегасители и звуковые устройства.","tr":"Can yelekleri, yangın söndürücüler, görsel tehlike işaretleri, havalandırma, geri tepme önleyiciler ve ses cihazları.","hi":"लाइफ जैकेट, अग्निशामक, दृश्य संकट संकेत, वेंटिलेशन, बैकफायर अरेस्टर और ध्वनि उपकरण।","ar":"سترات النجاة، طفايات الحريق، إشارات الاستغاثة المرئية، التهوية، مانعات الارتداد اللهبي وأجهزة الصوت."}},{"id":"emergencies","name":{"en":"Emergencies","es":"Emergencias","ru":"Аварийные ситуации","tr":"Acil Durumlar","hi":"आपात स्थितियाँ","ar":"حالات الطوارئ"},"blurb":{"en":"Capsizing, falls overboard, fire, collisions, carbon monoxide and rendering assistance.","es":"Volcaduras, caídas al agua, incendio, colisiones, monóxido de carbono y prestar auxilio.","ru":"Опрокидывание, падение за борт, пожар, столкновения, угарный газ и оказание помощи.","tr":"Alabora olma, denize düşme, yangın, çarpışma, karbon monoksit ve yardım etme.","hi":"नाव पलटना, पानी में गिरना, आग, टक्कर, कार्बन मोनोऑक्साइड और सहायता प्रदान करना।","ar":"الانقلاب، السقوط في الماء، الحريق، التصادم، أول أكسيد الكربون وتقديم المساعدة."}},{"id":"law","name":{"en":"Laws & Regulations","es":"Leyes y regulaciones","ru":"Законы и правила","tr":"Yasalar ve Düzenlemeler","hi":"कानून और विनियम","ar":"القوانين واللوائح"},"blurb":{"en":"Registration and numbering, boating under the influence, accident reporting and age/education rules.","es":"Registro y numeración, navegar bajo los efectos del alcohol, reporte de accidentes y reglas de edad/educación.","ru":"Регистрация и нумерация, управление в состоянии опьянения, отчётность о происшествиях и правила возраста/обучения.","tr":"Kayıt ve numaralandırma, alkol/uyuşturucu etkisinde tekne kullanma, kaza bildirimi ve yaş/eğitim kuralları.","hi":"पंजीकरण और नंबरिंग, नशे में नाव चलाना, दुर्घटना रिपोर्टिंग और आयु/शिक्षा नियम।","ar":"التسجيل والترقيم، قيادة القارب تحت التأثير، الإبلاغ عن الحوادث وقواعد العمر/التعليم."}},{"id":"sports","name":{"en":"Water Activities & Sports","es":"Actividades y deportes acuáticos","ru":"Водные развлечения и спорт","tr":"Su Etkinlikleri ve Sporları","hi":"जल गतिविधियाँ और खेल","ar":"الأنشطة والرياضات المائية"},"blurb":{"en":"Towing skiers, observer rules, personal watercraft, diver-down flags and hunting or fishing from boats.","es":"Remolque de esquiadores, reglas del observador, motos acuáticas, banderas de buzo y caza o pesca desde embarcaciones.","ru":"Буксировка лыжников, правила наблюдателя, гидроциклы, флаги «водолаз под водой» и охота или рыбалка с лодок.","tr":"Kayakçı çekme, gözlemci kuralları, jet ski, dalgıç bayrakları ve teknelerden avlanma veya balıkçılık.","hi":"स्कीयर खींचना, ऑब्ज़र्वर नियम, पर्सनल वॉटरक्राफ्ट, डाइवर-डाउन झंडे और नावों से शिकार या मछली पकड़ना।","ar":"سحب المتزلجين، قواعد المراقب، المركبات المائية الشخصية، أعلام الغطس والصيد البري أو صيد الأسماك من القوارب."}}],"q":[{"cat":"rules","a":1,"q":{"en":"Two power-driven vessels are approaching each other head-on. What should each vessel do?","es":"Dos embarcaciones a motor se aproximan de frente. ¿Qué debe hacer cada una?","ru":"Два моторных судна сближаются встречными курсами. Что должно сделать каждое судно?","tr":"İki motorlu tekne birbirine baş baba yaklaşıyor. Her tekne ne yapmalı?","hi":"दो इंजन-चालित नावें आमने-सामने आ रही हैं। प्रत्येक नाव को क्या करना चाहिए?","ar":"قاربان بمحرك يقتربان من بعضهما وجهاً لوجه. ماذا يجب أن يفعل كل قارب؟"},"o":[{"en":"Both should hold course and speed","es":"Ambas deben mantener rumbo y velocidad","ru":"Оба должны сохранять курс и скорость","tr":"İkisi de rota ve hızını korumalı","hi":"दोनों को अपना मार्ग और गति बनाए रखनी चाहिए","ar":"على كليهما الحفاظ على المسار والسرعة"},{"en":"Each should alter course to starboard so they pass port-to-port","es":"Cada una debe virar a estribor para pasar babor con babor","ru":"Каждое должно повернуть вправо (на правый борт), чтобы разойтись левыми бортами","tr":"Her biri sancağa dönerek iskele-iskele geçmeli","hi":"प्रत्येक को स्टारबोर्ड (दाईं ओर) मुड़ना चाहिए ताकि वे बाईं-से-बाईं ओर से गुज़रें","ar":"على كل منهما الانعطاف يميناً ليتجاوزا يساراً بيسار"},{"en":"Each should alter course to port","es":"Cada una debe virar a babor","ru":"Каждое должно повернуть влево (на левый борт)","tr":"Her biri iskeleye dönmeli","hi":"प्रत्येक को पोर्ट (बाईं ओर) मुड़ना चाहिए","ar":"على كل منهما الانعطاف يساراً"},{"en":"The larger vessel has the right-of-way and holds course","es":"La embarcación más grande tiene derecho de paso y mantiene rumbo","ru":"Более крупное судно имеет право прохода и сохраняет курс","tr":"Büyük tekne geçiş hakkına sahiptir ve rotasını korur","hi":"बड़ी नाव को रास्ते का अधिकार है और वह मार्ग बनाए रखती है","ar":"القارب الأكبر له حق المرور ويحافظ على مساره"}],"e":{"en":"In a head-on meeting, both power-driven vessels turn to starboard (right) and pass port-to-port (left side to left side).","es":"En un encuentro de frente, ambas embarcaciones a motor viran a estribor (derecha) y pasan babor con babor (lado izquierdo con lado izquierdo).","ru":"При встрече лоб в лоб оба моторных судна поворачивают вправо (на правый борт) и расходятся левыми бортами.","tr":"Baş baba karşılaşmada her iki motorlu tekne de sancağa (sağa) döner ve iskele-iskele (sol taraf sol tarafa) geçer.","hi":"आमने-सामने की मुलाक़ात में, दोनों इंजन-चालित नावें स्टारबोर्ड (दाईं ओर) मुड़ती हैं और बाईं-से-बाईं ओर से गुज़रती हैं।","ar":"في التلاقي وجهاً لوجه، ينعطف كلا القاربين ذوي المحرك يميناً (نحو الميمنة) ويتجاوزان يساراً بيسار."}},{"cat":"rules","a":0,"q":{"en":"When two power-driven vessels are crossing, which one is the give-way vessel?","es":"Cuando dos embarcaciones a motor se cruzan, ¿cuál es la embarcación que cede el paso?","ru":"Когда два моторных судна пересекаются, какое из них уступает дорогу?","tr":"İki motorlu tekne kesişirken hangisi yol veren teknedir?","hi":"जब दो इंजन-चालित नावें क्रॉस करती हैं, तो कौन सी नाव रास्ता देने वाली (गिव-वे) होती है?","ar":"عندما يتقاطع قاربان بمحرك، أيهما هو القارب المتنازل عن حق المرور؟"},"o":[{"en":"The vessel that has the other on its own starboard (right) side","es":"La embarcación que tiene a la otra por su lado de estribor (derecho)","ru":"Судно, у которого другое находится справа (по правому борту)","tr":"Diğerini sancak (sağ) tarafında gören tekne","hi":"वह नाव जिसके अपने स्टारबोर्ड (दाईं) ओर दूसरी नाव है","ar":"القارب الذي يرى الآخر على جانبه الأيمن (الميمنة)"},{"en":"The vessel that has the other on its port (left) side","es":"La embarcación que tiene a la otra por su lado de babor (izquierdo)","ru":"Судно, у которого другое находится слева (по левому борту)","tr":"Diğerini iskele (sol) tarafında gören tekne","hi":"वह नाव जिसके अपने पोर्ट (बाईं) ओर दूसरी नाव है","ar":"القارب الذي يرى الآخر على جانبه الأيسر (اليسار)"},{"en":"The faster vessel","es":"La embarcación más rápida","ru":"Более быстрое судно","tr":"Daha hızlı tekne","hi":"तेज़ चलने वाली नाव","ar":"القارب الأسرع"},{"en":"The vessel flying a flag","es":"La embarcación que enarbola una bandera","ru":"Судно с поднятым флагом","tr":"Bayrak taşıyan tekne","hi":"झंडा फहराने वाली नाव","ar":"القارب الذي يرفع علماً"}],"e":{"en":"In a crossing situation the vessel that has the other on its starboard (right) side must give way and keep clear; the other is the stand-on vessel.","es":"En un cruce, la embarcación que tiene a la otra por su estribor (derecha) debe ceder y mantenerse alejada; la otra es la que sigue a rumbo.","ru":"При пересечении курсов судно, у которого другое находится справа, обязано уступить дорогу и держаться в стороне; другое — привилегированное.","tr":"Kesişme durumunda diğerini sancak (sağ) tarafında gören tekne yol vermeli ve uzak durmalı; diğeri yol alan (stand-on) teknedir.","hi":"क्रॉसिंग की स्थिति में जिस नाव के दाईं (स्टारबोर्ड) ओर दूसरी नाव है उसे रास्ता देना और दूर रहना चाहिए; दूसरी नाव स्टैंड-ऑन होती है।","ar":"في حالة التقاطع، على القارب الذي يرى الآخر على ميمنته (يمينه) أن يتنازل ويبتعد؛ والآخر هو القارب الملتزم بمساره."}},{"cat":"rules","a":2,"q":{"en":"You are overtaking another boat. Which statement is correct?","es":"Está adelantando a otra embarcación. ¿Qué afirmación es correcta?","ru":"Вы обгоняете другое судно. Какое утверждение верно?","tr":"Başka bir tekneyi geçiyorsunuz. Hangi ifade doğrudur?","hi":"आप किसी अन्य नाव से आगे निकल रहे हैं। कौन सा कथन सही है?","ar":"أنت تتجاوز قارباً آخر. أي عبارة صحيحة؟"},"o":[{"en":"The boat being overtaken must speed up","es":"La embarcación adelantada debe acelerar","ru":"Обгоняемое судно должно ускориться","tr":"Geçilen tekne hızlanmalı","hi":"जिस नाव को ओवरटेक किया जा रहा है उसे गति बढ़ानी चाहिए","ar":"على القارب الذي يُتجاوَز أن يسرع"},{"en":"The overtaken boat must turn to starboard","es":"La embarcación adelantada debe virar a estribor","ru":"Обгоняемое судно должно повернуть вправо","tr":"Geçilen tekne sancağa dönmeli","hi":"जिस नाव को ओवरटेक किया जा रहा है उसे स्टारबोर्ड मुड़ना चाहिए","ar":"على القارب الذي يُتجاوَز أن ينعطف يميناً"},{"en":"The overtaking vessel is the give-way vessel and must keep clear of the boat ahead","es":"La embarcación que adelanta cede el paso y debe mantenerse alejada de la de adelante","ru":"Обгоняющее судно уступает дорогу и должно держаться в стороне от судна впереди","tr":"Geçen tekne yol veren teknedir ve öndeki tekneden uzak durmalı","hi":"आगे निकलने वाली नाव गिव-वे नाव है और उसे आगे वाली नाव से दूर रहना चाहिए","ar":"القارب المتجاوِز هو المتنازل ويجب أن يبتعد عن القارب الأمامي"},{"en":"Neither vessel has any duty","es":"Ninguna embarcación tiene obligación alguna","ru":"Ни одно из судов не имеет обязанностей","tr":"Hiçbir teknenin yükümlülüğü yoktur","hi":"किसी भी नाव का कोई कर्तव्य नहीं है","ar":"لا واجب على أي من القاربين"}],"e":{"en":"The overtaking vessel is always the give-way vessel and must keep well clear of the vessel it is passing, which is the stand-on vessel.","es":"La embarcación que adelanta siempre cede el paso y debe mantenerse bien alejada de la que adelanta, que sigue a rumbo.","ru":"Обгоняющее судно всегда уступает дорогу и должно держаться в стороне от обгоняемого судна, которое является привилегированным.","tr":"Geçen tekne her zaman yol veren teknedir ve geçtiği (yol alan) tekneden iyice uzak durmalıdır.","hi":"आगे निकलने वाली नाव हमेशा गिव-वे नाव होती है और उसे उस नाव से अच्छी तरह दूर रहना चाहिए जिसे वह पार कर रही है, जो स्टैंड-ऑन नाव है।","ar":"القارب المتجاوِز هو دائماً المتنازل ويجب أن يبتعد جيداً عن القارب الذي يتجاوزه، وهو القارب الملتزم بمساره."}},{"cat":"rules","a":3,"q":{"en":"What does one short blast of a horn from a power-driven vessel usually indicate in a meeting or crossing?","es":"¿Qué indica normalmente un pitido corto de bocina de una embarcación a motor en un encuentro o cruce?","ru":"Что обычно означает один короткий гудок моторного судна при встрече или пересечении?","tr":"Motorlu bir teknenin bir kısa korna sesi karşılaşma veya kesişmede genellikle neyi belirtir?","hi":"किसी इंजन-चालित नाव का एक छोटा हॉर्न मुलाक़ात या क्रॉसिंग में आमतौर पर क्या दर्शाता है?","ar":"ماذا تعني عادةً نفخة بوق قصيرة واحدة من قارب بمحرك عند التلاقي أو التقاطع؟"},"o":[{"en":"I am operating in reverse","es":"Estoy operando en reversa","ru":"Я даю задний ход","tr":"Geri gidiyorum","hi":"मैं रिवर्स में चला रहा हूँ","ar":"أنا أعمل بالعكس"},{"en":"I am in distress","es":"Estoy en peligro","ru":"Я терплю бедствие","tr":"Tehlikedeyim","hi":"मैं संकट में हूँ","ar":"أنا في خطر"},{"en":"I do not understand your intentions","es":"No entiendo sus intenciones","ru":"Я не понимаю ваших намерений","tr":"Niyetinizi anlamıyorum","hi":"मैं आपके इरादे नहीं समझता","ar":"لا أفهم نواياك"},{"en":"I intend to pass you on my port side / leave you on my port side","es":"Pretendo pasarle por mi lado de babor","ru":"Я намерен разойтись с вами левым бортом","tr":"Sizi iskele tarafımdan geçmek istiyorum","hi":"मेरा इरादा आपको अपनी बाईं (पोर्ट) ओर से पार करने का है","ar":"أنوي تجاوزك من جهة ميسرتي"}],"e":{"en":"On U.S. inland waters, one short blast means \"I intend to leave you on my port side\" (pass port-to-port). Two short blasts means starboard-to-starboard.","es":"En aguas interiores de EE. UU., un pitido corto significa \"pretendo dejarlo por mi babor\" (pasar babor con babor). Dos pitidos cortos significan estribor con estribor.","ru":"Во внутренних водах США один короткий гудок означает «намерен разойтись левыми бортами». Два коротких — правыми бортами.","tr":"ABD iç sularında bir kısa düdük \"sizi iskele tarafımda bırakmak istiyorum\" (iskele-iskele geçiş) demektir. İki kısa düdük sancak-sancak demektir.","hi":"अमेरिकी अंतर्देशीय जल में, एक छोटा हॉर्न का अर्थ है \"मैं आपको अपनी बाईं ओर से पार करना चाहता हूँ\" (पोर्ट-टू-पोर्ट)। दो छोटे हॉर्न का अर्थ स्टारबोर्ड-टू-स्टारबोर्ड है।","ar":"في المياه الداخلية الأمريكية، تعني النفخة القصيرة الواحدة \"أنوي تركك على جهة ميسرتي\" (تجاوز يسار بيسار). ونفختان قصيرتان تعنيان يمين بيمين."}},{"cat":"rules","a":1,"q":{"en":"What sound signal means \"danger\" or \"I do not understand your intentions\"?","es":"¿Qué señal sonora significa \"peligro\" o \"no entiendo sus intenciones\"?","ru":"Какой звуковой сигнал означает «опасность» или «я не понимаю ваших намерений»?","tr":"Hangi ses işareti \"tehlike\" veya \"niyetinizi anlamıyorum\" anlamına gelir?","hi":"कौन सा ध्वनि संकेत \"खतरा\" या \"मैं आपके इरादे नहीं समझता\" का अर्थ रखता है?","ar":"أي إشارة صوتية تعني \"خطر\" أو \"لا أفهم نواياك\"؟"},"o":[{"en":"One short blast","es":"Un pitido corto","ru":"Один короткий гудок","tr":"Bir kısa düdük","hi":"एक छोटा हॉर्न","ar":"نفخة قصيرة واحدة"},{"en":"Five or more short, rapid blasts","es":"Cinco o más pitidos cortos y rápidos","ru":"Пять или более коротких быстрых гудков","tr":"Beş veya daha fazla kısa, hızlı düdük","hi":"पाँच या अधिक छोटे, तेज़ हॉर्न","ar":"خمس نفخات قصيرة سريعة أو أكثر"},{"en":"One prolonged blast","es":"Un pitido prolongado","ru":"Один продолжительный гудок","tr":"Bir uzun düdük","hi":"एक लंबा हॉर्न","ar":"نفخة طويلة واحدة"},{"en":"Three short blasts","es":"Tres pitidos cortos","ru":"Три коротких гудка","tr":"Üç kısa düdük","hi":"तीन छोटे हॉर्न","ar":"ثلاث نفخات قصيرة"}],"e":{"en":"Five (or more) short, rapid blasts is the danger or doubt signal, used when you do not understand another vessel's intentions or think danger exists.","es":"Cinco (o más) pitidos cortos y rápidos son la señal de peligro o duda, usada cuando no entiende las intenciones de otra embarcación o cree que hay peligro.","ru":"Пять (или более) коротких быстрых гудков — сигнал опасности или сомнения, подаётся, когда вы не понимаете намерений другого судна или считаете, что есть опасность.","tr":"Beş (veya daha fazla) kısa, hızlı düdük tehlike veya kuşku işaretidir; başka bir teknenin niyetini anlamadığınızda ya da tehlike olduğunu düşündüğünüzde kullanılır.","hi":"पाँच (या अधिक) छोटे, तेज़ हॉर्न खतरे या संदेह का संकेत हैं, जिनका उपयोग तब होता है जब आप किसी अन्य नाव के इरादे नहीं समझते या खतरे का अनुमान लगाते हैं।","ar":"خمس (أو أكثر) نفخات قصيرة سريعة هي إشارة الخطر أو الشك، تُستخدم عندما لا تفهم نوايا قارب آخر أو تعتقد بوجود خطر."}},{"cat":"rules","a":2,"q":{"en":"What color is the light on the starboard (right) side of a boat at night?","es":"¿De qué color es la luz del lado de estribor (derecho) de una embarcación por la noche?","ru":"Какого цвета огонь на правом борту (starboard) судна ночью?","tr":"Gece bir teknenin sancak (sağ) tarafındaki fener ne renktir?","hi":"रात में नाव के स्टारबोर्ड (दाईं) ओर की बत्ती किस रंग की होती है?","ar":"ما لون الضوء على جانب الميمنة (اليمين) من القارب ليلاً؟"},"o":[{"en":"Red","es":"Rojo","ru":"Красный","tr":"Kırmızı","hi":"लाल","ar":"أحمر"},{"en":"White","es":"Blanco","ru":"Белый","tr":"Beyaz","hi":"सफ़ेद","ar":"أبيض"},{"en":"Green","es":"Verde","ru":"Зелёный","tr":"Yeşil","hi":"हरा","ar":"أخضر"},{"en":"Yellow","es":"Amarillo","ru":"Жёлтый","tr":"Sarı","hi":"पीला","ar":"أصفر"}],"e":{"en":"The starboard sidelight is green and the port sidelight is red. \"Red, right, returning\" is for buoys — not sidelights — so remember green = starboard.","es":"La luz de costado de estribor es verde y la de babor es roja. Recuerde: verde = estribor.","ru":"Бортовой огонь правого борта — зелёный, левого — красный. Запомните: зелёный = правый борт (starboard).","tr":"Sancak yan feneri yeşil, iskele yan feneri kırmızıdır. Unutmayın: yeşil = sancak.","hi":"स्टारबोर्ड साइड की बत्ती हरी और पोर्ट साइड की बत्ती लाल होती है। याद रखें: हरा = स्टारबोर्ड।","ar":"الضوء الجانبي للميمنة أخضر والضوء الجانبي للميسرة أحمر. تذكّر: أخضر = ميمنة."}},{"cat":"rules","a":0,"q":{"en":"You see only a green sidelight and a white light on another power-driven vessel at night. What is your relationship to it?","es":"Por la noche ve solo una luz verde de costado y una luz blanca en otra embarcación a motor. ¿Cuál es su situación respecto a ella?","ru":"Ночью вы видите на другом моторном судне только зелёный бортовой и белый огни. Каково ваше положение относительно него?","tr":"Gece başka bir motorlu teknede yalnızca yeşil bir yan fener ve beyaz bir fener görüyorsunuz. Ona göre durumunuz nedir?","hi":"रात में आप किसी अन्य इंजन-चालित नाव पर केवल एक हरी साइड बत्ती और एक सफ़ेद बत्ती देखते हैं। उसके संबंध में आपकी स्थिति क्या है?","ar":"ترى ليلاً على قارب آخر بمحرك ضوءاً جانبياً أخضر وضوءاً أبيض فقط. ما وضعك بالنسبة له؟"},"o":[{"en":"You are the stand-on vessel; it should keep clear","es":"Usted sigue a rumbo; la otra debe mantenerse alejada","ru":"Вы — привилегированное судно; оно должно уступить","tr":"Siz yol alan teknesiniz; o uzak durmalı","hi":"आप स्टैंड-ऑन नाव हैं; उसे दूर रहना चाहिए","ar":"أنت القارب الملتزم؛ عليه أن يبتعد"},{"en":"You are the give-way vessel and must keep clear","es":"Usted cede el paso y debe mantenerse alejado","ru":"Вы — уступающее судно и должны держаться в стороне","tr":"Siz yol veren teknesiniz ve uzak durmalısınız","hi":"आप गिव-वे नाव हैं और आपको दूर रहना चाहिए","ar":"أنت المتنازل وعليك الابتعاد"},{"en":"You are meeting head-on","es":"Se están encontrando de frente","ru":"Вы идёте встречными курсами","tr":"Baş baba karşılaşıyorsunuz","hi":"आप आमने-सामने मिल रहे हैं","ar":"أنتما تتلاقيان وجهاً لوجه"},{"en":"The other vessel is anchored","es":"La otra embarcación está fondeada","ru":"Другое судно стоит на якоре","tr":"Diğer tekne demirlemiş","hi":"दूसरी नाव लंगर डाले हुए है","ar":"القارب الآخر راسٍ"}],"e":{"en":"Seeing the other boat's green sidelight means it is on your port side crossing — you are the stand-on vessel and should hold course and speed while it keeps clear.","es":"Ver la luz verde de la otra embarcación significa que cruza por su babor: usted sigue a rumbo y debe mantener rumbo y velocidad mientras la otra se aparta.","ru":"Если вы видите зелёный бортовой огонь другого судна, оно пересекает ваш курс слева — вы привилегированное судно и сохраняете курс и скорость, пока оно уступает.","tr":"Diğer teknenin yeşil yan fenerini görmeniz, onun iskele tarafınızdan kesiştiği anlamına gelir — siz yol alan teknesiniz, o uzak dururken rota ve hızınızı koruyun.","hi":"दूसरी नाव की हरी साइड बत्ती दिखने का अर्थ है वह आपकी बाईं (पोर्ट) ओर से क्रॉस कर रही है — आप स्टैंड-ऑन नाव हैं और मार्ग व गति बनाए रखें जबकि वह दूर रहे।","ar":"رؤية الضوء الجانبي الأخضر للقارب الآخر تعني أنه يعبر من جهة ميسرتك — أنت القارب الملتزم وعليك الحفاظ على المسار والسرعة بينما يبتعد هو."}},{"cat":"rules","a":3,"q":{"en":"Between a power-driven vessel and a sailing vessel (under sail only) in most situations, which is the give-way vessel?","es":"Entre una embarcación a motor y un velero (solo a vela) en la mayoría de los casos, ¿cuál cede el paso?","ru":"Между моторным и парусным судном (только под парусом) в большинстве ситуаций какое уступает дорогу?","tr":"Motorlu bir tekne ile (yalnızca yelkenle giden) bir yelkenli arasında çoğu durumda hangisi yol verir?","hi":"अधिकांश स्थितियों में इंजन-चालित नाव और (केवल पाल पर चलने वाली) पाल-नाव के बीच कौन गिव-वे नाव होती है?","ar":"بين قارب بمحرك ومركب شراعي (يسير بالشراع فقط) في معظم الحالات، أيهما المتنازل عن حق المرور؟"},"o":[{"en":"The sailing vessel","es":"El velero","ru":"Парусное судно","tr":"Yelkenli","hi":"पाल-नाव","ar":"المركب الشراعي"},{"en":"Whichever is larger","es":"La que sea más grande","ru":"То, что крупнее","tr":"Hangisi büyükse","hi":"जो बड़ी हो","ar":"الأكبر منهما"},{"en":"Whichever is faster","es":"La que sea más rápida","ru":"То, что быстрее","tr":"Hangisi hızlıysa","hi":"जो तेज़ हो","ar":"الأسرع منهما"},{"en":"The power-driven vessel","es":"La embarcación a motor","ru":"Моторное судно","tr":"Motorlu tekne","hi":"इंजन-चालित नाव","ar":"القارب ذو المحرك"}],"e":{"en":"A power-driven vessel generally must give way to a vessel under sail. Exceptions include when the sailboat is overtaking, or the powerboat is a vessel the sailboat must avoid (e.g., restricted in ability to maneuver).","es":"Una embarcación a motor generalmente debe ceder el paso a una a vela. Hay excepciones (p. ej., cuando el velero adelanta o la de motor está restringida en su maniobra).","ru":"Моторное судно, как правило, должно уступать дорогу парусному. Есть исключения (например, когда парусник обгоняет или моторное судно ограничено в манёвре).","tr":"Motorlu tekne genellikle yelkenliye yol vermelidir. İstisnalar vardır (ör. yelkenli geçiyorsa ya da motorlu tekne manevra kabiliyeti kısıtlıysa).","hi":"इंजन-चालित नाव को आमतौर पर पाल पर चल रही नाव को रास्ता देना चाहिए। अपवाद हैं (जैसे जब पाल-नाव ओवरटेक कर रही हो या इंजन-नाव की गति सीमित हो)।","ar":"يجب على القارب ذي المحرك عموماً أن يتنازل للمركب الشراعي. هناك استثناءات (مثل تجاوز المركب الشراعي، أو كون القارب مقيّد القدرة على المناورة)."}},{"cat":"rules","a":1,"q":{"en":"As a stand-on vessel, what is your responsibility?","es":"Como embarcación que sigue a rumbo, ¿cuál es su responsabilidad?","ru":"Каковы обязанности привилегированного судна?","tr":"Yol alan (stand-on) tekne olarak sorumluluğunuz nedir?","hi":"स्टैंड-ऑन नाव के रूप में आपकी ज़िम्मेदारी क्या है?","ar":"بصفتك القارب الملتزم بمساره، ما مسؤوليتك؟"},"o":[{"en":"Turn away immediately","es":"Apartarse de inmediato","ru":"Немедленно отвернуть","tr":"Hemen uzaklaşmak","hi":"तुरंत हट जाना","ar":"الابتعاد فوراً"},{"en":"Maintain course and speed, but be ready to act if the give-way vessel fails to keep clear","es":"Mantener rumbo y velocidad, pero estar listo para actuar si la otra no se aparta","ru":"Сохранять курс и скорость, но быть готовым к действиям, если уступающее судно не расходится","tr":"Rota ve hızı korumak, ama yol veren tekne uzaklaşmazsa harekete geçmeye hazır olmak","hi":"मार्ग और गति बनाए रखना, लेकिन तैयार रहना कि यदि गिव-वे नाव दूर न हटे तो कार्रवाई करें","ar":"الحفاظ على المسار والسرعة، مع الاستعداد للتصرف إذا لم يبتعد القارب المتنازل"},{"en":"Stop the engine and drift","es":"Apagar el motor y quedarse a la deriva","ru":"Заглушить двигатель и дрейфовать","tr":"Motoru durdurup sürüklenmek","hi":"इंजन बंद करके बहना","ar":"إيقاف المحرك والانجراف"},{"en":"Sound five short blasts and speed up","es":"Tocar cinco pitidos cortos y acelerar","ru":"Дать пять коротких гудков и ускориться","tr":"Beş kısa düdük çalıp hızlanmak","hi":"पाँच छोटे हॉर्न बजाकर गति बढ़ाना","ar":"إطلاق خمس نفخات قصيرة والتسريع"}],"e":{"en":"The stand-on vessel normally holds its course and speed so it is predictable, but must take action to avoid a collision if the give-way vessel does not keep clear.","es":"La embarcación que sigue a rumbo normalmente mantiene rumbo y velocidad para ser predecible, pero debe actuar para evitar una colisión si la otra no se aparta.","ru":"Привилегированное судно обычно сохраняет курс и скорость, оставаясь предсказуемым, но обязано предпринять действия во избежание столкновения, если уступающее судно не расходится.","tr":"Yol alan tekne öngörülebilir olması için normalde rota ve hızını korur, ancak yol veren tekne uzaklaşmazsa çarpışmayı önlemek için harekete geçmelidir.","hi":"स्टैंड-ऑन नाव सामान्यतः मार्ग और गति बनाए रखती है ताकि उसका व्यवहार पूर्वानुमेय रहे, पर यदि गिव-वे नाव दूर न हटे तो टक्कर टालने के लिए कार्रवाई करनी चाहिए।","ar":"عادةً يحافظ القارب الملتزم على مساره وسرعته ليكون متوقَّعاً، لكن عليه التصرف لتجنّب التصادم إذا لم يبتعد القارب المتنازل."}},{"cat":"rules","a":2,"q":{"en":"Under the Navigation Rules, what is the main purpose of the \"give-way\" and \"stand-on\" roles?","es":"Según las Reglas de navegación, ¿cuál es el propósito principal de los roles de \"ceder\" y \"seguir a rumbo\"?","ru":"Согласно правилам судоходства, какова главная цель ролей «уступающего» и «привилегированного» судна?","tr":"Seyir Kurallarına göre \"yol veren\" ve \"yol alan\" rollerinin temel amacı nedir?","hi":"नौवहन नियमों के अनुसार, \"गिव-वे\" और \"स्टैंड-ऑन\" भूमिकाओं का मुख्य उद्देश्य क्या है?","ar":"وفقاً لقواعد الملاحة، ما الغرض الرئيسي من دوري \"المتنازل\" و\"الملتزم\"؟"},"o":[{"en":"To decide who pays for damages","es":"Para decidir quién paga los daños","ru":"Чтобы определить, кто оплачивает ущерб","tr":"Hasarları kimin ödeyeceğini belirlemek","hi":"यह तय करना कि नुकसान कौन भरेगा","ar":"لتحديد من يدفع الأضرار"},{"en":"To set speed limits","es":"Para fijar límites de velocidad","ru":"Чтобы установить ограничения скорости","tr":"Hız sınırları koymak","hi":"गति सीमा तय करना","ar":"لتحديد حدود السرعة"},{"en":"To prevent collisions by making each operator's duty clear","es":"Prevenir colisiones dejando clara la obligación de cada operador","ru":"Предотвращать столкновения, чётко определяя обязанности каждого судоводителя","tr":"Her operatörün görevini netleştirerek çarpışmaları önlemek","hi":"प्रत्येक चालक का कर्तव्य स्पष्ट करके टक्कर रोकना","ar":"منع التصادم بجعل واجب كل مشغّل واضحاً"},{"en":"To rank vessels by size","es":"Para clasificar embarcaciones por tamaño","ru":"Чтобы ранжировать суда по размеру","tr":"Tekneleri boyuta göre sıralamak","hi":"आकार के अनुसार नावों को क्रमबद्ध करना","ar":"لترتيب القوارب حسب الحجم"}],"e":{"en":"The give-way and stand-on roles exist to prevent collisions: each operator knows in advance who must yield and who should hold course, so actions are predictable.","es":"Los roles de ceder y seguir a rumbo existen para prevenir colisiones: cada operador sabe de antemano quién debe ceder y quién mantiene rumbo, haciendo las acciones predecibles.","ru":"Роли уступающего и привилегированного судна существуют для предотвращения столкновений: каждый судоводитель заранее знает, кто уступает, а кто сохраняет курс, поэтому действия предсказуемы.","tr":"Yol veren ve yol alan rolleri çarpışmaları önlemek için vardır: her operatör kimin yol vereceğini kimin rota tutacağını önceden bilir, böylece hareketler öngörülebilir olur.","hi":"गिव-वे और स्टैंड-ऑन भूमिकाएँ टक्कर रोकने के लिए हैं: प्रत्येक चालक पहले से जानता है कि किसे रास्ता देना है और किसे मार्ग बनाए रखना है, जिससे कार्रवाई पूर्वानुमेय होती है।","ar":"دورا المتنازل والملتزم موجودان لمنع التصادم: كل مشغّل يعرف مسبقاً من يتنازل ومن يحافظ على مساره، فتصبح التصرفات متوقَّعة."}},{"cat":"rules","a":0,"q":{"en":"When are you required to have a proper lookout on board?","es":"¿Cuándo se requiere mantener un vigía adecuado a bordo?","ru":"Когда требуется вести надлежащее наблюдение на борту?","tr":"Ne zaman teknede uygun bir gözcü bulundurmanız gerekir?","hi":"आपको बोर्ड पर उचित लुकआउट कब रखना आवश्यक है?","ar":"متى يُطلب منك وجود مراقب سليم على متن القارب؟"},"o":[{"en":"At all times the vessel is under way","es":"En todo momento en que la embarcación esté navegando","ru":"В любое время, когда судно находится на ходу","tr":"Tekne seyir halindeyken her zaman","hi":"हर उस समय जब नाव चल रही हो","ar":"في كل وقت يكون فيه القارب متحركاً"},{"en":"Only at night","es":"Solo por la noche","ru":"Только ночью","tr":"Yalnızca gece","hi":"केवल रात में","ar":"في الليل فقط"},{"en":"Only in fog","es":"Solo con niebla","ru":"Только в тумане","tr":"Yalnızca siste","hi":"केवल कोहरे में","ar":"في الضباب فقط"},{"en":"Only on large lakes","es":"Solo en lagos grandes","ru":"Только на больших озёрах","tr":"Yalnızca büyük göllerde","hi":"केवल बड़ी झीलों पर","ar":"في البحيرات الكبيرة فقط"}],"e":{"en":"Rule 5 requires every vessel to keep a proper lookout by sight and hearing at all times to fully appraise the situation and risk of collision.","es":"La Regla 5 exige que toda embarcación mantenga un vigía adecuado con la vista y el oído en todo momento para evaluar plenamente la situación y el riesgo de colisión.","ru":"Правило 5 требует, чтобы каждое судно постоянно вело надлежащее наблюдение зрением и слухом для полной оценки обстановки и риска столкновения.","tr":"Kural 5, her teknenin durumu ve çarpışma riskini tam değerlendirmek için her zaman görme ve işitme yoluyla uygun gözcü bulundurmasını gerektirir.","hi":"नियम 5 के अनुसार प्रत्येक नाव को स्थिति और टक्कर के जोखिम का पूरा आकलन करने के लिए हर समय दृष्टि और श्रवण द्वारा उचित लुकआउट रखना आवश्यक है।","ar":"تُلزِم القاعدة 5 كل قارب بالحفاظ على مراقبة سليمة بالبصر والسمع في كل الأوقات لتقييم الموقف وخطر التصادم بالكامل."}},{"cat":"rules","a":3,"q":{"en":"On most inland waters, which side of a channel should you keep the red buoys on when returning from open water?","es":"En la mayoría de aguas interiores, ¿de qué lado del canal debe dejar las boyas rojas al regresar de mar abierto?","ru":"На большинстве внутренних вод с какой стороны канала следует держать красные буи при возвращении с открытой воды?","tr":"Çoğu iç suda, açık sudan dönerken kanalın hangi tarafında kırmızı şamandıraları tutmalısınız?","hi":"अधिकांश अंतर्देशीय जल में, खुले पानी से लौटते समय आपको चैनल की किस ओर लाल बॉय रखनी चाहिए?","ar":"في معظم المياه الداخلية، على أي جانب من القناة يجب أن تُبقي الطوافات الحمراء عند العودة من المياه المفتوحة؟"},"o":[{"en":"On your port (left) side","es":"Por su lado de babor (izquierdo)","ru":"С левого борта (слева)","tr":"İskele (sol) tarafınızda","hi":"अपनी पोर्ट (बाईं) ओर","ar":"على جانب ميسرتك (اليسار)"},{"en":"Directly ahead","es":"Justo al frente","ru":"Прямо по курсу","tr":"Tam önünüzde","hi":"सीधे आगे","ar":"مباشرة أمامك"},{"en":"It does not matter","es":"No importa","ru":"Не имеет значения","tr":"Fark etmez","hi":"इससे कोई फ़र्क नहीं","ar":"لا يهم"},{"en":"On your starboard (right) side","es":"Por su lado de estribor (derecho)","ru":"С правого борта (справа)","tr":"Sancak (sağ) tarafınızda","hi":"अपनी स्टारबोर्ड (दाईं) ओर","ar":"على جانب ميمنتك (اليمين)"}],"e":{"en":"\"Red, Right, Returning\" — when returning from open water toward a harbor or upstream, keep red (nun) buoys on your starboard (right) side.","es":"\"Rojo, derecha, regresando\": al regresar de mar abierto hacia un puerto o río arriba, deje las boyas rojas por su estribor (derecha).","ru":"«Красный — справа — при возвращении»: возвращаясь с открытой воды к гавани или вверх по течению, держите красные буи справа (по правому борту).","tr":"\"Kırmızı, Sağ, Dönerken\" — açık sudan limana veya akıntı yukarı dönerken kırmızı şamandıraları sancak (sağ) tarafınızda tutun.","hi":"\"रेड, राइट, रिटर्निंग\" — खुले पानी से बंदरगाह की ओर या धारा के ऊपर लौटते समय, लाल बॉय को अपनी स्टारबोर्ड (दाईं) ओर रखें।","ar":"\"أحمر، يمين، عند العودة\" — عند العودة من المياه المفتوحة نحو مرفأ أو عكس التيار، أبقِ الطوافات الحمراء على جانب ميمنتك (اليمين)."}},{"cat":"rules","a":1,"q":{"en":"What does one prolonged blast of a horn signal when leaving a dock or approaching a blind bend?","es":"¿Qué señala un pitido prolongado de bocina al salir de un muelle o acercarse a una curva ciega?","ru":"Что сигнализирует один продолжительный гудок при отходе от причала или подходе к слепому повороту?","tr":"İskeleden ayrılırken veya kör bir dönemece yaklaşırken bir uzun düdük neyi işaret eder?","hi":"घाट से निकलते समय या अंधे मोड़ के पास पहुँचते समय एक लंबा हॉर्न क्या संकेत देता है?","ar":"ماذا تعني نفخة بوق طويلة واحدة عند مغادرة الرصيف أو الاقتراب من منعطف أعمى؟"},"o":[{"en":"I am anchoring","es":"Estoy fondeando","ru":"Я становлюсь на якорь","tr":"Demirliyorum","hi":"मैं लंगर डाल रहा हूँ","ar":"أنا أرسو"},{"en":"A warning that I am present / getting under way","es":"Una advertencia de que estoy presente / iniciando la marcha","ru":"Предупреждение о моём присутствии / начале движения","tr":"Burada olduğuma / harekete geçtiğime dair uyarı","hi":"चेतावनी कि मैं मौजूद हूँ / चलना शुरू कर रहा हूँ","ar":"تحذير بأنني موجود / أبدأ التحرك"},{"en":"I am in distress","es":"Estoy en peligro","ru":"Я терплю бедствие","tr":"Tehlikedeyim","hi":"मैं संकट में हूँ","ar":"أنا في خطر"},{"en":"I intend to pass on your starboard","es":"Pretendo pasar por su estribor","ru":"Я намерен разойтись вашим правым бортом","tr":"Sancağınızdan geçmek istiyorum","hi":"मेरा इरादा आपकी स्टारबोर्ड ओर से पार करने का है","ar":"أنوي التجاوز من ميمنتك"}],"e":{"en":"One prolonged blast (about 4-6 seconds) is a warning signal given when leaving a dock/berth or approaching a bend where other vessels may not be visible.","es":"Un pitido prolongado (unos 4-6 segundos) es una señal de advertencia que se da al salir de un muelle o acercarse a una curva donde otras embarcaciones podrían no verse.","ru":"Один продолжительный гудок (около 4-6 секунд) — предупредительный сигнал при отходе от причала или подходе к повороту, где другие суда могут быть не видны.","tr":"Bir uzun düdük (yaklaşık 4-6 saniye), iskeleden ayrılırken veya diğer teknelerin görünmeyebileceği bir dönemece yaklaşırken verilen uyarı işaretidir.","hi":"एक लंबा हॉर्न (लगभग 4-6 सेकंड) चेतावनी संकेत है जो घाट से निकलते समय या ऐसे मोड़ के पास दिया जाता है जहाँ अन्य नावें दिखाई न दें।","ar":"نفخة طويلة واحدة (حوالي 4-6 ثوانٍ) هي إشارة تحذير تُعطى عند مغادرة الرصيف أو الاقتراب من منعطف قد لا تُرى فيه القوارب الأخرى."}},{"cat":"rules","a":2,"q":{"en":"At night, a single all-round white light showing on an anchored vessel means what?","es":"Por la noche, una sola luz blanca todo horizonte en una embarcación fondeada significa ¿qué?","ru":"Ночью один круговой белый огонь на судне на якоре означает что?","tr":"Gece, demirlemiş bir teknede görünen tek bir seyir boyu (all-round) beyaz fener neyi ifade eder?","hi":"रात में लंगर डाले हुए नाव पर दिखने वाली एक ऑल-राउंड सफ़ेद बत्ती का क्या अर्थ है?","ar":"ليلاً، ضوء أبيض واحد يُرى من جميع الجهات على قارب راسٍ يعني ماذا؟"},"o":[{"en":"The vessel is towing","es":"La embarcación está remolcando","ru":"Судно ведёт буксировку","tr":"Tekne yedekleme yapıyor","hi":"नाव खींच रही है","ar":"القارب يقطر"},{"en":"The vessel is fishing","es":"La embarcación está pescando","ru":"Судно занимается рыбной ловлей","tr":"Tekne balık avlıyor","hi":"नाव मछली पकड़ रही है","ar":"القارب يصطاد"},{"en":"The vessel is anchored / at rest","es":"La embarcación está fondeada / detenida","ru":"Судно стоит на якоре / без движения","tr":"Tekne demirlemiş / duruyor","hi":"नाव लंगर डाले / रुकी हुई है","ar":"القارب راسٍ / متوقف"},{"en":"The vessel is aground","es":"La embarcación está encallada","ru":"Судно село на мель","tr":"Tekne karaya oturmuş","hi":"नाव फँसी हुई है","ar":"القارب جانح"}],"e":{"en":"A small anchored vessel displays a single all-round white light (often called an anchor light) so others can see it at night; power-driven boats under way also show sidelights and a masthead light.","es":"Una embarcación pequeña fondeada muestra una sola luz blanca todo horizonte (luz de fondeo) para ser vista de noche; las de motor en marcha muestran además luces de costado y de tope.","ru":"Небольшое судно на якоре несёт один круговой белый огонь (якорный), чтобы его было видно ночью; идущие моторные суда также несут бортовые и топовый огни.","tr":"Küçük demirli bir tekne, gece görülebilmesi için tek bir seyir boyu beyaz fener (demir feneri) gösterir; seyirdeki motorlu tekneler ayrıca yan fenerler ve direk feneri gösterir.","hi":"लंगर डाली छोटी नाव रात में दिखने के लिए एक ऑल-राउंड सफ़ेद बत्ती (एंकर लाइट) दिखाती है; चलती इंजन-नावें साइड बत्तियाँ और मास्टहेड बत्ती भी दिखाती हैं।","ar":"يُظهر القارب الصغير الراسي ضوءاً أبيض واحداً من جميع الجهات (يُسمى ضوء المرساة) ليُرى ليلاً؛ أما القوارب ذات المحرك المتحركة فتُظهر أيضاً أضواءً جانبية وضوء صارٍ."}},{"cat":"rules","a":0,"q":{"en":"Which vessel generally has the LEAST maneuverability and should be given extra room?","es":"¿Qué embarcación tiene generalmente la MENOR maniobrabilidad y a la que se debe dar más espacio?","ru":"Какое судно, как правило, обладает НАИМЕНЬШЕЙ манёвренностью и которому следует дать больше места?","tr":"Genellikle EN AZ manevra kabiliyetine sahip olan ve daha fazla yer verilmesi gereken tekne hangisidir?","hi":"किस नाव की गतिशीलता आमतौर पर सबसे कम होती है और जिसे अतिरिक्त जगह दी जानी चाहिए?","ar":"أي قارب يمتلك عادةً أقل قدرة على المناورة ويجب إعطاؤه مساحة إضافية؟"},"o":[{"en":"A large ship or vessel restricted in its ability to maneuver in a channel","es":"Un buque grande o embarcación restringida en su maniobra dentro de un canal","ru":"Крупное судно или судно, ограниченное в манёвре в канале","tr":"Kanalda manevra kabiliyeti kısıtlı büyük bir gemi veya tekne","hi":"किसी चैनल में चल रहा बड़ा जहाज या मैन्युवर में सीमित नाव","ar":"سفينة كبيرة أو قارب مقيّد القدرة على المناورة في قناة"},{"en":"A personal watercraft (PWC)","es":"Una moto acuática (PWC)","ru":"Гидроцикл (PWC)","tr":"Jet ski (PWC)","hi":"पर्सनल वॉटरक्राफ्ट (PWC)","ar":"مركبة مائية شخصية (PWC)"},{"en":"A small runabout","es":"Una lancha pequeña","ru":"Небольшой катер","tr":"Küçük bir motorbot","hi":"एक छोटी रनअबाउट नाव","ar":"زورق صغير"},{"en":"A canoe","es":"Una canoa","ru":"Каноэ","tr":"Bir kano","hi":"एक डोंगी (कैनो)","ar":"قارب كانو"}],"e":{"en":"Large ships and vessels constrained by draft or restricted in maneuverability need lots of room and distance to stop. Small, agile boats should stay well clear and never assume a big ship can avoid them.","es":"Los buques grandes y las embarcaciones limitadas por su calado o maniobra necesitan mucho espacio y distancia para detenerse. Las embarcaciones pequeñas deben mantenerse bien alejadas.","ru":"Крупным судам и судам, стеснённым осадкой или ограниченным в манёвре, нужно много места и расстояния для остановки. Малые манёвренные лодки должны держаться в стороне.","tr":"Büyük gemiler ve su çekimiyle kısıtlı veya manevrası sınırlı tekneler durmak için çok yer ve mesafeye ihtiyaç duyar. Küçük, çevik tekneler iyice uzak durmalıdır.","hi":"बड़े जहाज़ और ड्राफ्ट या मैन्युवर में सीमित नावों को रुकने के लिए बहुत जगह और दूरी चाहिए। छोटी, फुर्तीली नावों को अच्छी तरह दूर रहना चाहिए।","ar":"تحتاج السفن الكبيرة والقوارب المقيّدة بغاطسها أو المحدودة المناورة إلى مساحة ومسافة كبيرة للتوقف. على القوارب الصغيرة الرشيقة الابتعاد جيداً."}},{"cat":"rules","a":3,"q":{"en":"Two power-driven vessels are meeting head-on. Which vessel is the give-way vessel?","es":"Dos embarcaciones a motor se encuentran de frente. ¿Cuál es la que cede el paso?","ru":"Два моторных судна встречаются лоб в лоб. Какое из них уступает дорогу?","tr":"İki motorlu tekne baş baba karşılaşıyor. Hangisi yol veren teknedir?","hi":"दो इंजन-चालित नावें आमने-सामने मिल रही हैं। कौन सी नाव गिव-वे नाव है?","ar":"قاربان بمحرك يتلاقيان وجهاً لوجه. أيهما القارب المتنازل؟"},"o":[{"en":"The vessel on the right","es":"La embarcación de la derecha","ru":"Судно справа","tr":"Sağdaki tekne","hi":"दाईं ओर की नाव","ar":"القارب على اليمين"},{"en":"The vessel on the left","es":"La embarcación de la izquierda","ru":"Судно слева","tr":"Soldaki tekne","hi":"बाईं ओर की नाव","ar":"القارب على اليسار"},{"en":"The smaller vessel","es":"La embarcación más pequeña","ru":"Меньшее судно","tr":"Küçük tekne","hi":"छोटी नाव","ar":"القارب الأصغر"},{"en":"Neither — both are give-way vessels and both alter course to starboard","es":"Ninguna: ambas ceden el paso y viran a estribor","ru":"Ни одно — оба уступают и поворачивают вправо","tr":"Hiçbiri — ikisi de yol verir ve sancağa döner","hi":"कोई नहीं — दोनों गिव-वे नावें हैं और दोनों स्टारबोर्ड मुड़ती हैं","ar":"لا أحد — كلاهما متنازل وكلاهما ينعطف يميناً"}],"e":{"en":"A true head-on meeting has no single stand-on vessel: both are considered give-way vessels and each alters course to starboard to pass port-to-port.","es":"En un verdadero encuentro de frente no hay una sola embarcación que siga a rumbo: ambas ceden el paso y cada una vira a estribor para pasar babor con babor.","ru":"При настоящей встрече лоб в лоб нет единственного привилегированного судна: оба считаются уступающими и каждое поворачивает вправо, чтобы разойтись левыми бортами.","tr":"Gerçek bir baş baba karşılaşmada tek bir yol alan tekne yoktur: ikisi de yol veren sayılır ve her biri iskele-iskele geçmek için sancağa döner.","hi":"वास्तविक आमने-सामने मुलाक़ात में कोई एक स्टैंड-ऑन नाव नहीं होती: दोनों को गिव-वे नाव माना जाता है और प्रत्येक पोर्ट-टू-पोर्ट पार करने के लिए स्टारबोर्ड मुड़ती है।","ar":"في التلاقي الحقيقي وجهاً لوجه لا يوجد قارب ملتزم واحد: كلاهما يُعتبر متنازلاً وكل منهما ينعطف يميناً للتجاوز يساراً بيسار."}},{"cat":"rules","a":1,"q":{"en":"You hear two short blasts from an oncoming power-driven vessel on inland waters. What is it proposing?","es":"Escucha dos pitidos cortos de una embarcación a motor que se aproxima en aguas interiores. ¿Qué propone?","ru":"Вы слышите два коротких гудка от встречного моторного судна во внутренних водах. Что оно предлагает?","tr":"İç sularda yaklaşan motorlu bir tekneden iki kısa düdük duyuyorsunuz. Ne öneriyor?","hi":"अंतर्देशीय जल में आती हुई इंजन-चालित नाव से आप दो छोटे हॉर्न सुनते हैं। वह क्या प्रस्ताव कर रही है?","ar":"تسمع نفختين قصيرتين من قارب بمحرك قادم في المياه الداخلية. ماذا يقترح؟"},"o":[{"en":"It is backing down","es":"Está dando marcha atrás","ru":"Оно даёт задний ход","tr":"Geri geliyor","hi":"वह पीछे जा रही है","ar":"إنه يتراجع للخلف"},{"en":"To pass starboard-to-starboard (leave you on its starboard side)","es":"Pasar estribor con estribor (dejarlo por su estribor)","ru":"Разойтись правыми бортами (оставить вас со своего правого борта)","tr":"Sancak-sancak geçmek (sizi kendi sancağında bırakmak)","hi":"स्टारबोर्ड-टू-स्टारबोर्ड पार करना (आपको अपनी स्टारबोर्ड ओर छोड़ना)","ar":"التجاوز يمين بيمين (تركك على ميمنته)"},{"en":"It is in distress","es":"Está en peligro","ru":"Оно терпит бедствие","tr":"Tehlikede","hi":"वह संकट में है","ar":"إنه في خطر"},{"en":"It does not understand you","es":"No lo entiende","ru":"Оно вас не понимает","tr":"Sizi anlamıyor","hi":"वह आपको नहीं समझती","ar":"إنه لا يفهمك"}],"e":{"en":"On inland waters, two short blasts proposes a starboard-to-starboard passing. If you agree, answer with the same signal; if not, sound the danger signal (five short blasts).","es":"En aguas interiores, dos pitidos cortos proponen un cruce estribor con estribor. Si está de acuerdo, responda con la misma señal; si no, dé la señal de peligro (cinco pitidos cortos).","ru":"Во внутренних водах два коротких гудка предлагают расхождение правыми бортами. Если согласны — ответьте тем же сигналом; если нет — подайте сигнал опасности (пять коротких гудков).","tr":"İç sularda iki kısa düdük sancak-sancak geçiş önerir. Kabul ediyorsanız aynı işaretle yanıt verin; etmiyorsanız tehlike işaretini (beş kısa düdük) verin.","hi":"अंतर्देशीय जल में दो छोटे हॉर्न स्टारबोर्ड-टू-स्टारबोर्ड पार करने का प्रस्ताव देते हैं। सहमत हों तो वही संकेत लौटाएँ; न हों तो खतरे का संकेत (पाँच छोटे हॉर्न) दें।","ar":"في المياه الداخلية، تقترح نفختان قصيرتان التجاوز يمين بيمين. إذا وافقت فأجب بالإشارة نفسها؛ وإلا فأطلق إشارة الخطر (خمس نفخات قصيرة)."}},{"cat":"rules","a":2,"q":{"en":"In restricted visibility (fog), how often should a power-driven vessel under way sound its fog signal?","es":"Con visibilidad reducida (niebla), ¿con qué frecuencia debe una embarcación a motor en marcha dar su señal de niebla?","ru":"При ограниченной видимости (тумане) как часто идущее моторное судно должно подавать туманный сигнал?","tr":"Kısıtlı görüşte (sis), seyir halindeki motorlu bir tekne sis işaretini ne sıklıkla vermelidir?","hi":"सीमित दृश्यता (कोहरे) में, चलती इंजन-चालित नाव को कितनी बार अपना फॉग सिग्नल बजाना चाहिए?","ar":"في الرؤية المحدودة (الضباب)، كم مرة يجب على قارب بمحرك متحرك أن يُطلق إشارة الضباب؟"},"o":[{"en":"Once every 30 seconds","es":"Una vez cada 30 segundos","ru":"Один раз каждые 30 секунд","tr":"Her 30 saniyede bir","hi":"हर 30 सेकंड में एक बार","ar":"مرة كل 30 ثانية"},{"en":"Only when another boat is seen","es":"Solo cuando se ve otra embarcación","ru":"Только когда видно другое судно","tr":"Yalnızca başka bir tekne görülünce","hi":"केवल जब कोई अन्य नाव दिखे","ar":"فقط عند رؤية قارب آخر"},{"en":"At least every 2 minutes (one prolonged blast)","es":"Al menos cada 2 minutos (un pitido prolongado)","ru":"Не реже чем каждые 2 минуты (один продолжительный гудок)","tr":"En az her 2 dakikada bir (bir uzun düdük)","hi":"कम से कम हर 2 मिनट में (एक लंबा हॉर्न)","ar":"على الأقل كل دقيقتين (نفخة طويلة واحدة)"},{"en":"Continuously","es":"De forma continua","ru":"Непрерывно","tr":"Sürekli","hi":"लगातार","ar":"بشكل مستمر"}],"e":{"en":"In or near an area of restricted visibility, a power-driven vessel making way sounds one prolonged blast at intervals of not more than 2 minutes.","es":"En o cerca de una zona de visibilidad reducida, una embarcación a motor que avanza da un pitido prolongado a intervalos no mayores de 2 minutos.","ru":"В зоне ограниченной видимости или вблизи неё идущее моторное судно подаёт один продолжительный гудок с интервалами не более 2 минут.","tr":"Kısıtlı görüş bölgesinde veya yakınında, ilerleyen motorlu bir tekne en fazla 2 dakika aralıkla bir uzun düdük verir.","hi":"सीमित दृश्यता वाले क्षेत्र में या उसके पास, आगे बढ़ रही इंजन-चालित नाव 2 मिनट से अधिक के अंतराल पर एक लंबा हॉर्न बजाती है।","ar":"في منطقة الرؤية المحدودة أو قربها، يُطلق القارب ذو المحرك المتحرك نفخة طويلة واحدة على فترات لا تزيد عن دقيقتين."}},{"cat":"rules","a":0,"q":{"en":"When must you slow to a no-wake or idle speed?","es":"¿Cuándo debe reducir a velocidad sin estela o de ralentí?","ru":"Когда нужно снизить скорость до «без волны» или самого малого хода?","tr":"Ne zaman iz bırakmayan (no-wake) veya rölanti hızına düşmelisiniz?","hi":"आपको नो-वेक या आइडल गति तक कब धीमा करना चाहिए?","ar":"متى يجب أن تبطئ إلى سرعة بلا موجة (no-wake) أو سرعة الخمول؟"},"o":[{"en":"Near marinas, docks, moored boats, swimmers and in marked no-wake zones","es":"Cerca de marinas, muelles, embarcaciones amarradas, nadadores y en zonas marcadas sin estela","ru":"Вблизи марин, причалов, пришвартованных лодок, пловцов и в обозначенных зонах «без волны»","tr":"Marina, iskele, bağlı tekneler, yüzücüler yakınında ve işaretli no-wake bölgelerinde","hi":"मरीना, घाट, बंधी नावों, तैराकों के पास और चिह्नित नो-वेक ज़ोन में","ar":"بالقرب من المراسي والأرصفة والقوارب المربوطة والسباحين وفي مناطق بلا موجة المعلّمة"},{"en":"Only when the police are watching","es":"Solo cuando la policía está mirando","ru":"Только когда наблюдает полиция","tr":"Yalnızca polis izlerken","hi":"केवल जब पुलिस देख रही हो","ar":"فقط عندما تراقب الشرطة"},{"en":"Only at night","es":"Solo por la noche","ru":"Только ночью","tr":"Yalnızca gece","hi":"केवल रात में","ar":"في الليل فقط"},{"en":"Never — wake is not your responsibility","es":"Nunca: la estela no es su responsabilidad","ru":"Никогда — волна не ваша ответственность","tr":"Asla — iz sizin sorumluluğunuz değil","hi":"कभी नहीं — वेक आपकी ज़िम्मेदारी नहीं","ar":"أبداً — الموجة ليست مسؤوليتك"}],"e":{"en":"Operate at no-wake/idle speed near marinas, docks, launch ramps, moored or anchored boats, swimmers, and wherever no-wake zones are marked. You are responsible for damage or injury your wake causes.","es":"Navegue a velocidad sin estela cerca de marinas, muelles, rampas, embarcaciones amarradas o fondeadas, nadadores y donde haya zonas marcadas sin estela. Usted es responsable de los daños que cause su estela.","ru":"Двигайтесь со скоростью «без волны» вблизи марин, причалов, спусков, пришвартованных или стоящих на якоре лодок, пловцов и в обозначенных зонах. Вы отвечаете за ущерб от вашей волны.","tr":"Marina, iskele, kızak, bağlı veya demirli tekneler, yüzücüler yakınında ve no-wake bölgeleri işaretli her yerde iz bırakmayan/rölanti hızıyla seyredin. İzinizin verdiği hasardan siz sorumlusunuz.","hi":"मरीना, घाट, लॉन्च रैम्प, बंधी या लंगर डाली नावों, तैराकों के पास और जहाँ भी नो-वेक ज़ोन चिह्नित हों वहाँ नो-वेक/आइडल गति से चलाएँ। आपकी वेक से हुए नुकसान के लिए आप ज़िम्मेदार हैं।","ar":"سِر بسرعة بلا موجة/الخمول قرب المراسي والأرصفة ومنحدرات الإنزال والقوارب المربوطة أو الراسية والسباحين وحيثما تُعلَّم مناطق بلا موجة. أنت مسؤول عن الأضرار التي تسبّبها موجتك."}},{"cat":"rules","a":3,"q":{"en":"Who is ultimately responsible for avoiding a collision under the Navigation Rules?","es":"¿Quién es en última instancia responsable de evitar una colisión según las Reglas de navegación?","ru":"Кто в конечном счёте отвечает за предотвращение столкновения согласно правилам судоходства?","tr":"Seyir Kurallarına göre çarpışmayı önlemekten nihai olarak kim sorumludur?","hi":"नौवहन नियमों के अनुसार टक्कर से बचने के लिए अंततः कौन ज़िम्मेदार है?","ar":"من المسؤول في نهاية المطاف عن تجنّب التصادم وفقاً لقواعد الملاحة؟"},"o":[{"en":"Only the give-way vessel","es":"Solo la embarcación que cede el paso","ru":"Только уступающее судно","tr":"Yalnızca yol veren tekne","hi":"केवल गिव-वे नाव","ar":"القارب المتنازل فقط"},{"en":"Only the stand-on vessel","es":"Solo la embarcación que sigue a rumbo","ru":"Только привилегированное судно","tr":"Yalnızca yol alan tekne","hi":"केवल स्टैंड-ऑन नाव","ar":"القارب الملتزم فقط"},{"en":"The larger vessel only","es":"Solo la embarcación más grande","ru":"Только более крупное судно","tr":"Yalnızca büyük tekne","hi":"केवल बड़ी नाव","ar":"القارب الأكبر فقط"},{"en":"Both operators — each must do whatever is needed to avoid a collision","es":"Ambos operadores: cada uno debe hacer lo necesario para evitar la colisión","ru":"Оба судоводителя — каждый обязан сделать всё необходимое, чтобы избежать столкновения","tr":"Her iki operatör de — her biri çarpışmayı önlemek için gerekeni yapmalı","hi":"दोनों चालक — प्रत्येक को टक्कर टालने के लिए जो आवश्यक हो वह करना चाहिए","ar":"كلا المشغّلين — على كل منهما فعل ما يلزم لتجنّب التصادم"}],"e":{"en":"The Rules make both operators responsible for avoiding collisions. Even the stand-on vessel must act if a collision looks likely, and no rule relieves anyone of the duty to take action.","es":"Las Reglas hacen responsables a ambos operadores de evitar colisiones. Incluso la que sigue a rumbo debe actuar si parece probable una colisión; ninguna regla exime del deber de actuar.","ru":"Правила возлагают ответственность за предотвращение столкновений на обоих судоводителей. Даже привилегированное судно обязано действовать при угрозе столкновения; ни одно правило не освобождает от обязанности действовать.","tr":"Kurallar çarpışmayı önlemekten her iki operatörü de sorumlu tutar. Çarpışma olası görünüyorsa yol alan tekne bile harekete geçmelidir; hiçbir kural harekete geçme görevinden muaf tutmaz.","hi":"नियम टक्कर से बचने के लिए दोनों चालकों को ज़िम्मेदार बनाते हैं। यदि टक्कर की संभावना हो तो स्टैंड-ऑन नाव को भी कार्रवाई करनी चाहिए; कोई नियम किसी को कार्रवाई के कर्तव्य से मुक्त नहीं करता।","ar":"تجعل القواعد كلا المشغّلين مسؤولين عن تجنّب التصادم. حتى القارب الملتزم يجب أن يتصرف إذا بدا التصادم مرجحاً، ولا تُعفي أي قاعدة أحداً من واجب التصرف."}},{"cat":"rules","a":1,"q":{"en":"What is the safest way to pass a large commercial ship in a narrow channel?","es":"¿Cuál es la forma más segura de pasar a un gran buque comercial en un canal estrecho?","ru":"Как безопаснее всего разойтись с крупным коммерческим судном в узком канале?","tr":"Dar bir kanalda büyük bir ticari gemiyi geçmenin en güvenli yolu nedir?","hi":"संकरे चैनल में किसी बड़े वाणिज्यिक जहाज को पार करने का सबसे सुरक्षित तरीका क्या है?","ar":"ما أسلم طريقة لتجاوز سفينة تجارية كبيرة في قناة ضيقة؟"},"o":[{"en":"Cut closely across its bow to save time","es":"Cruzar cerca de su proa para ahorrar tiempo","ru":"Пересечь близко перед его носом, чтобы сэкономить время","tr":"Zamandan tasarruf için baş tarafından yakından geçmek","hi":"समय बचाने के लिए उसकी नाक के पास से पार करना","ar":"العبور بالقرب من مقدمته لتوفير الوقت"},{"en":"Stay to the edge of the channel, keep well clear, and avoid crossing close ahead of it","es":"Mantenerse al borde del canal, bien alejado, y evitar cruzar cerca de su proa","ru":"Держаться у кромки канала, вдали от судна, и не пересекать близко перед его носом","tr":"Kanalın kenarında kalmak, iyice uzak durmak ve baş tarafına yakın geçmekten kaçınmak","hi":"चैनल के किनारे रहना, अच्छी तरह दूर रहना, और उसकी नाक के पास से पार करने से बचना","ar":"البقاء على حافة القناة والابتعاد جيداً وتجنّب العبور قرب مقدمته"},{"en":"Follow directly behind in its wake as close as possible","es":"Seguir justo detrás en su estela lo más cerca posible","ru":"Идти прямо за ним в кильватере как можно ближе","tr":"İzinde olabildiğince yakından hemen arkasından gitmek","hi":"उसके ठीक पीछे उसकी वेक में यथासंभव नज़दीक चलना","ar":"السير خلفه مباشرة في موجته بأقرب مسافة ممكنة"},{"en":"Stop in the middle of the channel and wait","es":"Detenerse en medio del canal y esperar","ru":"Остановиться посреди канала и ждать","tr":"Kanalın ortasında durup beklemek","hi":"चैनल के बीच रुककर इंतज़ार करना","ar":"التوقف في منتصف القناة والانتظار"}],"e":{"en":"Large ships cannot stop or turn quickly and may not see a small boat. Stay near the channel edge, keep well clear, and never cut across close in front of one.","es":"Los buques grandes no pueden detenerse ni girar rápido y quizá no vean una embarcación pequeña. Manténgase cerca del borde del canal, bien alejado, y nunca cruce cerca de su proa.","ru":"Крупные суда не могут быстро остановиться или повернуть и могут не заметить малую лодку. Держитесь у кромки канала, вдали, и никогда не пересекайте курс близко перед носом.","tr":"Büyük gemiler hızlı duramaz veya dönemez ve küçük bir tekneyi görmeyebilir. Kanal kenarına yakın kalın, iyice uzak durun ve asla baş tarafından yakından kesmeyin.","hi":"बड़े जहाज़ जल्दी रुक या मुड़ नहीं सकते और छोटी नाव को न देख पाएँ। चैनल के किनारे रहें, अच्छी तरह दूर रहें, और कभी उसकी नाक के पास से पार न करें।","ar":"لا تستطيع السفن الكبيرة التوقف أو الانعطاف بسرعة وقد لا ترى قارباً صغيراً. ابقَ قرب حافة القناة وابتعد جيداً ولا تعبر أبداً قرب مقدمتها."}},{"cat":"rules","a":2,"q":{"en":"On a boat under way at night, which light should be visible from ahead and around the stern (all-round) on many small power-driven vessels?","es":"En una embarcación navegando de noche, ¿qué luz debe verse de frente y alrededor de la popa (todo horizonte) en muchas embarcaciones a motor pequeñas?","ru":"На идущем ночью небольшом моторном судне какой огонь должен быть виден спереди и вокруг кормы (круговой)?","tr":"Gece seyir halindeki birçok küçük motorlu teknede önden ve kıç etrafından (all-round) görünmesi gereken fener hangisidir?","hi":"रात में चल रही कई छोटी इंजन-चालित नावों पर कौन सी बत्ती आगे से और स्टर्न के चारों ओर (ऑल-राउंड) दिखनी चाहिए?","ar":"في قارب متحرك ليلاً، أي ضوء يجب أن يُرى من الأمام وحول المؤخرة (من جميع الجهات) في كثير من القوارب الصغيرة ذات المحرك؟"},"o":[{"en":"A red all-round light","es":"Una luz roja todo horizonte","ru":"Красный круговой огонь","tr":"Kırmızı bir seyir boyu fener","hi":"एक लाल ऑल-राउंड बत्ती","ar":"ضوء أحمر من جميع الجهات"},{"en":"A green all-round light","es":"Una luz verde todo horizonte","ru":"Зелёный круговой огонь","tr":"Yeşil bir seyir boyu fener","hi":"एक हरी ऑल-राउंड बत्ती","ar":"ضوء أخضر من جميع الجهات"},{"en":"A white light (masthead/stern) visible so others can see you","es":"Una luz blanca (tope/popa) visible para que otros lo vean","ru":"Белый огонь (топовый/кормовой), видимый другим","tr":"Beyaz bir fener (direk/kıç) — başkaları sizi görsün diye","hi":"एक सफ़ेद बत्ती (मास्टहेड/स्टर्न) जो दूसरों को दिखाई दे","ar":"ضوء أبيض (صارٍ/مؤخرة) يراه الآخرون"},{"en":"A blue flashing light","es":"Una luz azul intermitente","ru":"Синий проблесковый огонь","tr":"Mavi yanıp sönen bir fener","hi":"एक नीली चमकती बत्ती","ar":"ضوء أزرق وامض"}],"e":{"en":"White lights (masthead and stern light, or an all-round white light on small boats) let others see you from behind and ahead at night. Blue flashing lights are reserved for law-enforcement vessels.","es":"Las luces blancas (tope y popa, o una luz blanca todo horizonte en embarcaciones pequeñas) permiten que otros lo vean de noche por detrás y de frente. Las luces azules intermitentes son de embarcaciones policiales.","ru":"Белые огни (топовый и кормовой либо круговой белый на малых лодках) позволяют другим видеть вас ночью сзади и спереди. Синие проблесковые огни — только у судов правоохранительных органов.","tr":"Beyaz fenerler (direk ve kıç feneri veya küçük teknelerde seyir boyu beyaz fener) başkalarının sizi gece önden ve arkadan görmesini sağlar. Mavi yanıp sönen fenerler kolluk teknelerine özeldir.","hi":"सफ़ेद बत्तियाँ (मास्टहेड और स्टर्न बत्ती, या छोटी नावों पर ऑल-राउंड सफ़ेद बत्ती) रात में दूसरों को आपको आगे-पीछे से देखने देती हैं। नीली चमकती बत्तियाँ कानून-प्रवर्तन नावों के लिए आरक्षित हैं।","ar":"تتيح الأضواء البيضاء (ضوء الصاري والمؤخرة، أو ضوء أبيض من جميع الجهات على القوارب الصغيرة) للآخرين رؤيتك ليلاً من الخلف والأمام. الأضواء الزرقاء الوامضة مخصّصة لقوارب إنفاذ القانون."}},{"cat":"operation","a":2,"q":{"en":"What factors must you consider when choosing a \"safe speed\"?","es":"¿Qué factores debe considerar al elegir una \"velocidad segura\"?","ru":"Какие факторы нужно учитывать при выборе «безопасной скорости»?","tr":"\"Güvenli hız\" seçerken hangi faktörleri dikkate almalısınız?","hi":"\"सुरक्षित गति\" चुनते समय आपको किन कारकों पर विचार करना चाहिए?","ar":"ما العوامل التي يجب مراعاتها عند اختيار \"السرعة الآمنة\"؟"},"o":[{"en":"Only the posted speed limit","es":"Solo el límite de velocidad indicado","ru":"Только установленное ограничение скорости","tr":"Yalnızca yazılı hız sınırı","hi":"केवल निर्धारित गति सीमा","ar":"حد السرعة المعلن فقط"},{"en":"Only how fast your boat can go","es":"Solo la velocidad máxima de su embarcación","ru":"Только максимальная скорость вашей лодки","tr":"Yalnızca teknenizin gidebileceği hız","hi":"केवल आपकी नाव कितनी तेज़ जा सकती है","ar":"سرعة قاربك القصوى فقط"},{"en":"Visibility, traffic, maneuverability, wind, water conditions and hazards","es":"Visibilidad, tráfico, maniobrabilidad, viento, condiciones del agua y peligros","ru":"Видимость, интенсивность движения, манёвренность, ветер, состояние воды и опасности","tr":"Görüş, trafik, manevra kabiliyeti, rüzgar, su koşulları ve tehlikeler","hi":"दृश्यता, ट्रैफ़िक, गतिशीलता, हवा, पानी की स्थिति और खतरे","ar":"الرؤية والحركة والقدرة على المناورة والرياح وحالة الماء والمخاطر"},{"en":"Only the time of day","es":"Solo la hora del día","ru":"Только время суток","tr":"Yalnızca günün saati","hi":"केवल दिन का समय","ar":"وقت النهار فقط"}],"e":{"en":"Safe speed lets you stop within a safe distance and avoid collision. Consider visibility, traffic density, your boat's maneuverability, wind, sea state, and nearby hazards.","es":"La velocidad segura le permite detenerse a una distancia segura y evitar colisiones. Considere la visibilidad, la densidad del tráfico, la maniobrabilidad, el viento, el estado del mar y los peligros cercanos.","ru":"Безопасная скорость позволяет остановиться на безопасном расстоянии и избежать столкновения. Учитывайте видимость, плотность движения, манёвренность лодки, ветер, состояние воды и близкие опасности.","tr":"Güvenli hız, güvenli mesafede durmanızı ve çarpışmayı önlemenizi sağlar. Görüş, trafik yoğunluğu, teknenizin manevrası, rüzgar, deniz durumu ve yakın tehlikeleri göz önünde bulundurun.","hi":"सुरक्षित गति आपको सुरक्षित दूरी में रुकने और टक्कर टालने देती है। दृश्यता, ट्रैफ़िक घनत्व, नाव की गतिशीलता, हवा, पानी की स्थिति और आसपास के खतरों पर विचार करें।","ar":"تتيح لك السرعة الآمنة التوقف ضمن مسافة آمنة وتجنّب التصادم. راعِ الرؤية وكثافة الحركة وقدرة قاربك على المناورة والرياح وحالة البحر والمخاطر القريبة."}},{"cat":"operation","a":0,"q":{"en":"The capacity plate on a boat tells you what?","es":"¿Qué le indica la placa de capacidad de una embarcación?","ru":"О чём сообщает табличка вместимости на судне?","tr":"Teknedeki kapasite plakası size neyi söyler?","hi":"नाव पर लगी क्षमता प्लेट आपको क्या बताती है?","ar":"ماذا تخبرك لوحة السعة الموجودة على القارب؟"},"o":[{"en":"The maximum number of people and/or total weight the boat can safely carry","es":"El número máximo de personas y/o el peso total que la embarcación puede llevar con seguridad","ru":"Максимальное число людей и/или общий вес, который лодка может безопасно нести","tr":"Teknenin güvenle taşıyabileceği azami kişi sayısı ve/veya toplam ağırlık","hi":"अधिकतम व्यक्तियों की संख्या और/या कुल वज़न जिसे नाव सुरक्षित रूप से ढो सकती है","ar":"الحد الأقصى لعدد الأشخاص و/أو الوزن الكلي الذي يمكن للقارب حمله بأمان"},{"en":"The top speed of the boat","es":"La velocidad máxima de la embarcación","ru":"Максимальную скорость лодки","tr":"Teknenin azami hızı","hi":"नाव की अधिकतम गति","ar":"السرعة القصوى للقارب"},{"en":"The year the boat was built","es":"El año de fabricación","ru":"Год постройки лодки","tr":"Teknenin yapıldığı yıl","hi":"नाव के निर्माण का वर्ष","ar":"سنة صنع القارب"},{"en":"The required insurance amount","es":"El monto de seguro requerido","ru":"Требуемую сумму страховки","tr":"Gereken sigorta tutarı","hi":"आवश्यक बीमा राशि","ar":"مبلغ التأمين المطلوب"}],"e":{"en":"The capacity plate lists the maximum number of persons, the maximum weight of persons plus gear, and often the maximum engine horsepower. Never exceed these limits.","es":"La placa de capacidad indica el número máximo de personas, el peso máximo de personas más equipo y, a menudo, la potencia máxima del motor. Nunca supere estos límites.","ru":"Табличка вместимости указывает максимальное число людей, максимальный вес людей и снаряжения, а часто и максимальную мощность двигателя. Никогда не превышайте эти пределы.","tr":"Kapasite plakası azami kişi sayısını, kişiler artı teçhizatın azami ağırlığını ve genellikle azami motor gücünü belirtir. Bu sınırları asla aşmayın.","hi":"क्षमता प्लेट अधिकतम व्यक्तियों की संख्या, व्यक्तियों तथा सामान का अधिकतम वज़न, और अक्सर अधिकतम इंजन हॉर्सपावर बताती है। इन सीमाओं को कभी न लांघें।","ar":"تُبيّن لوحة السعة الحد الأقصى لعدد الأشخاص، والوزن الأقصى للأشخاص مع العتاد، وغالباً القوة الحصانية القصوى للمحرك. لا تتجاوز هذه الحدود أبداً."}},{"cat":"operation","a":3,"q":{"en":"What is the FIRST thing you should do if the weather turns bad and a storm approaches while boating?","es":"¿Qué es lo PRIMERO que debe hacer si el clima empeora y se acerca una tormenta mientras navega?","ru":"Что нужно сделать ПЕРВЫМ делом, если во время плавания погода ухудшается и приближается шторм?","tr":"Tekne kullanırken hava bozar ve fırtına yaklaşırsa yapmanız gereken İLK şey nedir?","hi":"नौकायन के दौरान यदि मौसम बिगड़े और तूफ़ान आए तो आपको सबसे पहले क्या करना चाहिए?","ar":"ما أول ما يجب فعله إذا ساء الطقس واقتربت عاصفة أثناء الإبحار؟"},"o":[{"en":"Speed up to outrun the storm","es":"Acelerar para escapar de la tormenta","ru":"Ускориться, чтобы обогнать шторм","tr":"Fırtınadan kaçmak için hızlanmak","hi":"तूफ़ान से आगे निकलने के लिए गति बढ़ाना","ar":"التسريع للهروب من العاصفة"},{"en":"Stand up for a better view","es":"Ponerse de pie para ver mejor","ru":"Встать, чтобы лучше видеть","tr":"Daha iyi görmek için ayağa kalkmak","hi":"बेहतर दृश्य के लिए खड़े हो जाना","ar":"الوقوف لرؤية أفضل"},{"en":"Remove life jackets to move freely","es":"Quitarse los chalecos para moverse libremente","ru":"Снять спасательные жилеты для свободы движений","tr":"Rahat hareket için can yeleklerini çıkarmak","hi":"आज़ादी से चलने के लिए लाइफ जैकेट उतारना","ar":"خلع سترات النجاة للتحرك بحرية"},{"en":"Have everyone put on life jackets, slow down, and head for the nearest safe shore","es":"Que todos se pongan el chaleco, reducir la velocidad y dirigirse a la costa segura más cercana","ru":"Чтобы все надели жилеты, снизить скорость и идти к ближайшему безопасному берегу","tr":"Herkese can yeleği giydirin, yavaşlayın ve en yakın güvenli kıyıya yönelin","hi":"सभी को लाइफ जैकेट पहनाएँ, गति धीमी करें और निकटतम सुरक्षित तट की ओर बढ़ें","ar":"اطلب من الجميع ارتداء سترات النجاة، وخفّف السرعة، وتوجّه إلى أقرب شاطئ آمن"}],"e":{"en":"When a storm threatens, have everyone put on a life jacket, reduce speed, secure loose gear, and head for the nearest safe shore or shelter. Keep passengers low and centered.","es":"Cuando amenaza una tormenta, que todos se pongan el chaleco, reduzca la velocidad, asegure el equipo suelto y diríjase a la costa o refugio seguro más cercano. Mantenga a los pasajeros bajos y centrados.","ru":"При угрозе шторма пусть все наденут жилеты, снизьте скорость, закрепите незакреплённые вещи и идите к ближайшему безопасному берегу или укрытию. Пассажиры должны сидеть низко и по центру.","tr":"Fırtına tehdidi varsa herkese can yeleği giydirin, hızı azaltın, gevşek eşyaları sabitleyin ve en yakın güvenli kıyıya veya sığınağa yönelin. Yolcuları alçak ve ortada tutun.","hi":"तूफ़ान के खतरे पर सभी को लाइफ जैकेट पहनाएँ, गति कम करें, ढीले सामान को सुरक्षित करें और निकटतम सुरक्षित तट या आश्रय की ओर बढ़ें। यात्रियों को नीचे और बीच में रखें।","ar":"عند تهديد العاصفة، اطلب من الجميع ارتداء سترة النجاة، وخفّف السرعة، وثبّت العتاد المتحرك، وتوجّه إلى أقرب شاطئ أو ملجأ آمن. أبقِ الركاب منخفضين وفي المنتصف."}},{"cat":"operation","a":1,"q":{"en":"What is the greatest danger of falling into cold water (below about 70°F / 21°C)?","es":"¿Cuál es el mayor peligro de caer en agua fría (por debajo de unos 21 °C / 70 °F)?","ru":"В чём главная опасность падения в холодную воду (ниже примерно 21 °C / 70 °F)?","tr":"Soğuk suya (yaklaşık 21°C / 70°F altı) düşmenin en büyük tehlikesi nedir?","hi":"ठंडे पानी (लगभग 21°C / 70°F से नीचे) में गिरने का सबसे बड़ा खतरा क्या है?","ar":"ما أكبر خطر للسقوط في الماء البارد (أقل من حوالي 21°م / 70°ف)؟"},"o":[{"en":"Sunburn","es":"Quemaduras de sol","ru":"Солнечный ожог","tr":"Güneş yanığı","hi":"सनबर्न","ar":"حروق الشمس"},{"en":"Cold-water shock and then hypothermia, which can cause drowning","es":"El choque por agua fría y luego la hipotermia, que puede provocar ahogamiento","ru":"Холодовой шок и последующая гипотермия, которые могут привести к утоплению","tr":"Soğuk su şoku ve ardından boğulmaya yol açabilen hipotermi","hi":"ठंडे पानी का शॉक और फिर हाइपोथर्मिया, जो डूबने का कारण बन सकता है","ar":"صدمة الماء البارد ثم انخفاض حرارة الجسم، مما قد يسبّب الغرق"},{"en":"Dehydration","es":"Deshidratación","ru":"Обезвоживание","tr":"Susuz kalma","hi":"निर्जलीकरण","ar":"الجفاف"},{"en":"Motion sickness","es":"Mareo","ru":"Морская болезнь","tr":"Deniz tutması","hi":"मोशन सिकनेस","ar":"دوار الحركة"}],"e":{"en":"Sudden immersion in cold water causes an involuntary gasp and rapid breathing (cold-water shock), then loss of muscle control and hypothermia. A life jacket keeps you afloat while your body cools.","es":"La inmersión súbita en agua fría provoca un jadeo involuntario y respiración rápida (choque por agua fría), luego pérdida de control muscular e hipotermia. El chaleco lo mantiene a flote mientras el cuerpo se enfría.","ru":"Внезапное погружение в холодную воду вызывает непроизвольный вдох и учащённое дыхание (холодовой шок), затем потерю контроля над мышцами и гипотермию. Жилет удерживает вас на плаву, пока тело остывает.","tr":"Ani soğuk suya girmek istemsiz nefes alma ve hızlı solunuma (soğuk su şoku), sonra kas kontrolü kaybına ve hipotermiye yol açar. Can yeleği vücudunuz soğurken sizi yüzeyde tutar.","hi":"ठंडे पानी में अचानक डूबने से अनैच्छिक हाँफना और तेज़ साँस (कोल्ड-वॉटर शॉक), फिर मांसपेशी नियंत्रण का नुकसान और हाइपोथर्मिया होता है। शरीर ठंडा होते समय लाइफ जैकेट आपको तैरता रखता है।","ar":"يسبّب الانغماس المفاجئ في الماء البارد لهاثاً لا إرادياً وتنفساً سريعاً (صدمة الماء البارد)، ثم فقدان السيطرة على العضلات وانخفاض حرارة الجسم. تُبقيك سترة النجاة طافياً بينما يبرد جسمك."}},{"cat":"operation","a":2,"q":{"en":"To reduce the effects of hypothermia while waiting for rescue in the water, you should do what?","es":"Para reducir los efectos de la hipotermia mientras espera el rescate en el agua, ¿qué debe hacer?","ru":"Чтобы уменьшить последствия гипотермии, ожидая спасения в воде, что нужно делать?","tr":"Suda kurtarılmayı beklerken hipoterminin etkilerini azaltmak için ne yapmalısınız?","hi":"पानी में बचाव की प्रतीक्षा करते समय हाइपोथर्मिया के प्रभाव कम करने के लिए आपको क्या करना चाहिए?","ar":"لتقليل آثار انخفاض حرارة الجسم أثناء انتظار الإنقاذ في الماء، ماذا يجب أن تفعل؟"},"o":[{"en":"Swim vigorously to stay warm","es":"Nadar con fuerza para mantenerse caliente","ru":"Энергично плыть, чтобы согреться","tr":"Isınmak için güçlüce yüzmek","hi":"गर्म रहने के लिए ज़ोर से तैरना","ar":"السباحة بقوة للبقاء دافئاً"},{"en":"Remove clothing to swim faster","es":"Quitarse la ropa para nadar más rápido","ru":"Снять одежду, чтобы быстрее плыть","tr":"Daha hızlı yüzmek için giysileri çıkarmak","hi":"तेज़ तैरने के लिए कपड़े उतारना","ar":"خلع الملابس للسباحة أسرع"},{"en":"Keep clothing on, stay still, and use the H.E.L.P. or huddle position with a life jacket on","es":"Mantener la ropa puesta, quedarse quieto y usar la posición H.E.L.P. o de grupo con el chaleco puesto","ru":"Оставаться в одежде, не двигаться и принять позу H.E.L.P. или сгруппироваться с надетым жилетом","tr":"Giysileri çıkarmamak, hareketsiz kalmak ve can yeleğiyle H.E.L.P. veya küme (huddle) pozisyonunu kullanmak","hi":"कपड़े पहने रहना, स्थिर रहना, और लाइफ जैकेट पहनकर H.E.L.P. या हडल पोज़िशन का उपयोग करना","ar":"إبقاء الملابس والبقاء ساكناً واستخدام وضعية H.E.L.P. أو التجمّع مع ارتداء سترة النجاة"},{"en":"Float on your back and kick constantly","es":"Flotar boca arriba y patear constantemente","ru":"Лежать на спине и постоянно работать ногами","tr":"Sırtüstü yüzüp sürekli tekmelemek","hi":"पीठ के बल तैरना और लगातार लात मारना","ar":"الطفو على الظهر والركل باستمرار"}],"e":{"en":"Keep your clothes on, minimize movement, and use the Heat Escape Lessening Posture (H.E.L.P.) alone or the huddle with others. Swimming and thrashing speed heat loss.","es":"Mantenga la ropa puesta, minimice el movimiento y use la Posición para Disminuir la Pérdida de Calor (H.E.L.P.) solo o el grupo con otros. Nadar y agitarse aceleran la pérdida de calor.","ru":"Оставайтесь в одежде, сведите к минимуму движения и примите позу для уменьшения теплопотерь (H.E.L.P.) в одиночку или сгруппируйтесь с другими. Плавание и барахтанье ускоряют потерю тепла.","tr":"Giysilerinizi çıkarmayın, hareketi en aza indirin ve tek başınıza Isı Kaybını Azaltıcı Duruş'u (H.E.L.P.) ya da başkalarıyla küme pozisyonunu kullanın. Yüzmek ve çırpınmak ısı kaybını hızlandırır.","hi":"कपड़े पहने रहें, हलचल न्यूनतम करें, और अकेले हों तो हीट एस्केप लेसनिंग पोज़्चर (H.E.L.P.) या दूसरों के साथ हडल का उपयोग करें। तैरना और छटपटाना गर्मी का नुकसान बढ़ाता है।","ar":"أبقِ ملابسك، وقلّل الحركة، واستخدم وضعية تقليل فقدان الحرارة (H.E.L.P.) منفرداً أو التجمّع مع الآخرين. السباحة والحركة العنيفة تسرّعان فقدان الحرارة."}},{"cat":"operation","a":0,"q":{"en":"When refueling a gasoline-powered boat with a built-in tank, you should do all of the following EXCEPT:","es":"Al cargar combustible en una embarcación de gasolina con tanque incorporado, debe hacer todo lo siguiente EXCEPTO:","ru":"При заправке бензинового судна со встроенным баком следует делать всё перечисленное, КРОМЕ:","tr":"Sabit yakıt tanklı benzinli bir tekneye yakıt alırken aşağıdakilerin tümünü yapmalısınız, ŞUNUN DIŞINDA:","hi":"बिल्ट-इन टैंक वाली गैसोलीन नाव में ईंधन भरते समय आपको निम्न सभी करना चाहिए, सिवाय:","ar":"عند تزويد قارب يعمل بالبنزين وله خزان مدمج بالوقود، عليك فعل كل ما يلي باستثناء:"},"o":[{"en":"Leave the engine running to save time","es":"Dejar el motor en marcha para ahorrar tiempo","ru":"Оставить двигатель работающим, чтобы сэкономить время","tr":"Zamandan tasarruf için motoru çalışır bırakmak","hi":"समय बचाने के लिए इंजन चालू छोड़ना","ar":"ترك المحرك يعمل لتوفير الوقت"},{"en":"Stop the engine and have everyone leave the boat","es":"Apagar el motor y que todos bajen de la embarcación","ru":"Заглушить двигатель и высадить всех с лодки","tr":"Motoru durdurup herkesin tekneden inmesini sağlamak","hi":"इंजन बंद करें और सभी को नाव से उतारें","ar":"إيقاف المحرك ونزول الجميع من القارب"},{"en":"Keep the fill nozzle in contact with the tank opening","es":"Mantener la boquilla en contacto con la boca del tanque","ru":"Держать заправочный пистолет в контакте с горловиной бака","tr":"Dolum tabancasını depo ağzıyla temasta tutmak","hi":"फिल नोज़ल को टैंक के मुँह के संपर्क में रखें","ar":"إبقاء فوهة التعبئة ملامسة لفتحة الخزان"},{"en":"Ventilate the bilge and check for fuel odors before starting","es":"Ventilar la sentina y comprobar olores a combustible antes de arrancar","ru":"Провентилировать трюм и проверить запах топлива перед запуском","tr":"Çalıştırmadan önce sintineyi havalandırmak ve yakıt kokusu kontrol etmek","hi":"स्टार्ट करने से पहले बिल्ज को हवादार करें और ईंधन की गंध जाँचें","ar":"تهوية القاع والتحقّق من روائح الوقود قبل التشغيل"}],"e":{"en":"Never refuel with the engine running. Stop the engine, put everyone ashore, avoid open flames, keep the nozzle grounded to the fill pipe, and ventilate and sniff for fumes before restarting.","es":"Nunca cargue combustible con el motor en marcha. Apague el motor, baje a todos, evite llamas, mantenga la boquilla en contacto con el tubo de llenado y ventile y huela por vapores antes de arrancar.","ru":"Никогда не заправляйтесь с работающим двигателем. Заглушите двигатель, высадите всех на берег, избегайте открытого огня, держите пистолет в контакте с горловиной и проветрите, проверив запах, перед запуском.","tr":"Motor çalışırken asla yakıt almayın. Motoru durdurun, herkesi karaya çıkarın, açık alevden kaçının, tabancayı dolum borusuna temasta tutun ve çalıştırmadan önce havalandırıp koku kontrolü yapın.","hi":"इंजन चालू रखकर कभी ईंधन न भरें। इंजन बंद करें, सभी को किनारे उतारें, खुली लौ से बचें, नोज़ल को फिल पाइप के संपर्क में रखें, और स्टार्ट करने से पहले हवादार करके गंध जाँचें।","ar":"لا تُزوّد بالوقود أبداً والمحرك يعمل. أوقف المحرك، وأنزِل الجميع إلى البر، وتجنّب اللهب المكشوف، وأبقِ الفوهة ملامسة لأنبوب التعبئة، وهوِّ وتشمّم الأبخرة قبل إعادة التشغيل."}},{"cat":"operation","a":3,"q":{"en":"After refueling a boat with an inboard gasoline engine, what should you do before starting the engine?","es":"Después de cargar combustible en una embarcación con motor de gasolina interior, ¿qué debe hacer antes de arrancar?","ru":"После заправки лодки со стационарным бензиновым двигателем что нужно сделать перед запуском?","tr":"İçten takma benzinli motorlu bir tekneye yakıt aldıktan sonra motoru çalıştırmadan önce ne yapmalısınız?","hi":"इनबोर्ड गैसोलीन इंजन वाली नाव में ईंधन भरने के बाद, इंजन स्टार्ट करने से पहले आपको क्या करना चाहिए?","ar":"بعد تزويد قارب بمحرك بنزين داخلي بالوقود، ماذا يجب أن تفعل قبل تشغيل المحرك؟"},"o":[{"en":"Nothing special","es":"Nada especial","ru":"Ничего особенного","tr":"Özel bir şey yok","hi":"कुछ खास नहीं","ar":"لا شيء خاص"},{"en":"Start immediately to test it","es":"Arrancar de inmediato para probarlo","ru":"Сразу запустить, чтобы проверить","tr":"Test için hemen çalıştırmak","hi":"इसे परखने के लिए तुरंत स्टार्ट करना","ar":"تشغيله فوراً لاختباره"},{"en":"Turn on all cabin lights","es":"Encender todas las luces de cabina","ru":"Включить весь свет в каюте","tr":"Tüm kabin ışıklarını açmak","hi":"सभी केबिन लाइटें जलाना","ar":"تشغيل جميع أضواء المقصورة"},{"en":"Run the blower for about 4 minutes and check the bilge for gasoline fumes","es":"Hacer funcionar el extractor unos 4 minutos y revisar la sentina por vapores de gasolina","ru":"Включить вентилятор примерно на 4 минуты и проверить трюм на пары бензина","tr":"Yaklaşık 4 dakika aspiratörü çalıştırmak ve sintinede benzin kokusu kontrol etmek","hi":"लगभग 4 मिनट ब्लोअर चलाएँ और बिल्ज में गैसोलीन की गंध जाँचें","ar":"تشغيل المنفاخ لحوالي 4 دقائق وفحص القاع بحثاً عن أبخرة البنزين"}],"e":{"en":"Gasoline vapors are heavier than air and collect in the bilge. Run the exhaust blower for at least four minutes and check by smell for fumes before starting the engine to prevent an explosion.","es":"Los vapores de gasolina son más pesados que el aire y se acumulan en la sentina. Haga funcionar el extractor al menos cuatro minutos y compruebe por el olfato antes de arrancar para evitar una explosión.","ru":"Пары бензина тяжелее воздуха и скапливаются в трюме. Включите вытяжной вентилятор минимум на четыре минуты и проверьте по запаху перед запуском двигателя, чтобы предотвратить взрыв.","tr":"Benzin buharları havadan ağırdır ve sintinede birikir. Patlamayı önlemek için motoru çalıştırmadan önce egzoz aspiratörünü en az dört dakika çalıştırın ve koku kontrolü yapın.","hi":"गैसोलीन के वाष्प हवा से भारी होते हैं और बिल्ज में जमा होते हैं। विस्फोट रोकने के लिए इंजन स्टार्ट करने से पहले एग्ज़ॉस्ट ब्लोअर कम से कम चार मिनट चलाएँ और गंध से जाँचें।","ar":"أبخرة البنزين أثقل من الهواء وتتجمّع في القاع. شغّل منفاخ العادم أربع دقائق على الأقل وافحص بالشمّ قبل تشغيل المحرك لمنع الانفجار."}},{"cat":"operation","a":1,"q":{"en":"Where is the safest place for passengers to ride in a small boat under way?","es":"¿Cuál es el lugar más seguro para que viajen los pasajeros en una embarcación pequeña en marcha?","ru":"Где безопаснее всего находиться пассажирам в идущей небольшой лодке?","tr":"Seyir halindeki küçük bir teknede yolcuların oturması için en güvenli yer neresidir?","hi":"चल रही छोटी नाव में यात्रियों के बैठने के लिए सबसे सुरक्षित जगह कौन सी है?","ar":"ما أسلم مكان لركوب الركاب في قارب صغير أثناء سيره؟"},"o":[{"en":"On the bow, gunwales, seat backs, or motor cover","es":"En la proa, las bordas, los respaldos o la tapa del motor","ru":"На носу, планширях, спинках сидений или крышке мотора","tr":"Baş tarafta, küpeştede, koltuk arkalıklarında veya motor kapağında","hi":"नाव की नाक, गनवेल, सीट की पीठ या मोटर कवर पर","ar":"على المقدمة أو حواف القارب أو ظهور المقاعد أو غطاء المحرك"},{"en":"Seated low and toward the center of the boat","es":"Sentados abajo y hacia el centro de la embarcación","ru":"Сидя низко и ближе к центру лодки","tr":"Alçakta ve teknenin ortasına doğru oturarak","hi":"नीचे और नाव के केंद्र की ओर बैठे हुए","ar":"جالسين منخفضين ونحو مركز القارب"},{"en":"Standing to see over the windshield","es":"De pie para ver por encima del parabrisas","ru":"Стоя, чтобы видеть поверх ветрового стекла","tr":"Ön camdan görmek için ayakta","hi":"विंडशील्ड के ऊपर देखने के लिए खड़े","ar":"واقفين للرؤية فوق الزجاج الأمامي"},{"en":"Anywhere they like","es":"Donde quieran","ru":"Где угодно","tr":"İstedikleri her yerde","hi":"जहाँ चाहें","ar":"في أي مكان يريدونه"}],"e":{"en":"Passengers should sit low and near the center of the boat. Riding on the bow, gunwales, seat backs, or transom is dangerous — a fall overboard or into the propeller can be fatal.","es":"Los pasajeros deben sentarse abajo y cerca del centro. Viajar en la proa, las bordas, los respaldos o el espejo de popa es peligroso: una caída al agua o hacia la hélice puede ser mortal.","ru":"Пассажиры должны сидеть низко и ближе к центру лодки. Сидеть на носу, планширях, спинках сидений или транце опасно — падение за борт или на винт может быть смертельным.","tr":"Yolcular alçakta ve teknenin ortasına yakın oturmalıdır. Baş tarafta, küpeştede, koltuk arkalıklarında veya kıç aynalıkta oturmak tehlikelidir — denize veya pervaneye düşmek ölümcül olabilir.","hi":"यात्रियों को नीचे और नाव के केंद्र के पास बैठना चाहिए। नाव की नाक, गनवेल, सीट की पीठ या ट्रांसम पर बैठना खतरनाक है — पानी में या प्रोपेलर में गिरना घातक हो सकता है।","ar":"يجب أن يجلس الركاب منخفضين وقرب مركز القارب. الجلوس على المقدمة أو الحواف أو ظهور المقاعد أو المؤخرة خطر — فالسقوط في الماء أو نحو المروحة قد يكون قاتلاً."}},{"cat":"operation","a":2,"q":{"en":"Before heading out on the water, checking the marine weather forecast is:","es":"Antes de salir al agua, consultar el pronóstico meteorológico marino es:","ru":"Перед выходом на воду проверка морского прогноза погоды является:","tr":"Suya açılmadan önce deniz hava durumu tahminini kontrol etmek:","hi":"पानी पर निकलने से पहले समुद्री मौसम पूर्वानुमान की जाँच करना:","ar":"قبل الخروج إلى الماء، التحقّق من توقعات الطقس البحري يُعدّ:"},"o":[{"en":"A waste of time","es":"Una pérdida de tiempo","ru":"Пустой тратой времени","tr":"Zaman kaybı","hi":"समय की बर्बादी","ar":"مضيعة للوقت"},{"en":"Only needed on the ocean","es":"Solo necesario en el océano","ru":"Нужным только в океане","tr":"Yalnızca okyanusta gerekli","hi":"केवल समुद्र में आवश्यक","ar":"لازماً في المحيط فقط"},{"en":"An important safety step you should do every trip","es":"Un paso de seguridad importante que debe hacer en cada salida","ru":"Важным шагом безопасности, который следует делать перед каждым выходом","tr":"Her seferde yapmanız gereken önemli bir güvenlik adımı","hi":"एक महत्वपूर्ण सुरक्षा कदम जिसे हर यात्रा में करना चाहिए","ar":"خطوة أمان مهمة يجب فعلها كل رحلة"},{"en":"Only necessary for sailboats","es":"Solo necesario para veleros","ru":"Нужным только для парусных судов","tr":"Yalnızca yelkenliler için gerekli","hi":"केवल पाल-नावों के लिए आवश्यक","ar":"لازماً للمراكب الشراعية فقط"}],"e":{"en":"Always check the marine forecast before every trip and watch the sky while out. Sudden storms, wind shifts, and rough water are leading causes of boating accidents.","es":"Consulte siempre el pronóstico marino antes de cada salida y vigile el cielo mientras navega. Las tormentas repentinas, los cambios de viento y el agua agitada son causas principales de accidentes.","ru":"Всегда проверяйте морской прогноз перед каждым выходом и следите за небом на воде. Внезапные штормы, смена ветра и волнение — ведущие причины аварий на воде.","tr":"Her seferden önce deniz tahminini kontrol edin ve dışarıdayken gökyüzünü izleyin. Ani fırtınalar, rüzgar değişimleri ve dalgalı su, tekne kazalarının başlıca nedenleridir.","hi":"हर यात्रा से पहले समुद्री पूर्वानुमान जाँचें और बाहर रहते समय आसमान पर नज़र रखें। अचानक तूफ़ान, हवा में बदलाव और उथल-पुथल भरा पानी नौका दुर्घटनाओं के प्रमुख कारण हैं।","ar":"تحقّق دائماً من التوقعات البحرية قبل كل رحلة وراقب السماء أثناء وجودك في الماء. العواصف المفاجئة وتغيّرات الرياح والماء المضطرب من أبرز أسباب حوادث القوارب."}},{"cat":"operation","a":0,"q":{"en":"What is the recommended amount of anchor line (scope) to let out relative to water depth?","es":"¿Cuál es la cantidad recomendada de línea de ancla (escantillón/scope) a soltar respecto a la profundidad del agua?","ru":"Какое рекомендуемое соотношение длины якорного каната (запаса) к глубине воды?","tr":"Su derinliğine göre salınması önerilen çapa halatı miktarı (scope) nedir?","hi":"पानी की गहराई के सापेक्ष एंकर लाइन (स्कोप) की अनुशंसित मात्रा क्या है?","ar":"ما مقدار حبل المرساة (scope) الموصى به الذي يجب إرخاؤه مقارنة بعمق الماء؟"},"o":[{"en":"About 7 to 10 times the depth of the water","es":"Aproximadamente 7 a 10 veces la profundidad del agua","ru":"Примерно в 7-10 раз больше глубины воды","tr":"Su derinliğinin yaklaşık 7 ila 10 katı","hi":"पानी की गहराई का लगभग 7 से 10 गुना","ar":"حوالي 7 إلى 10 أضعاف عمق الماء"},{"en":"Exactly the same as the depth","es":"Exactamente igual a la profundidad","ru":"Ровно столько же, сколько глубина","tr":"Derinlikle tam olarak aynı","hi":"गहराई के बिल्कुल बराबर","ar":"بالضبط مثل العمق"},{"en":"Half the depth","es":"La mitad de la profundidad","ru":"Половину глубины","tr":"Derinliğin yarısı","hi":"गहराई का आधा","ar":"نصف العمق"},{"en":"As little as possible","es":"Lo menos posible","ru":"Как можно меньше","tr":"Mümkün olduğunca az","hi":"जितना कम हो सके","ar":"أقل ما يمكن"}],"e":{"en":"A common rule is a scope of about 7:1 (up to 10:1 in rough conditions) — let out 7 to 10 feet of line for each foot of water depth so the anchor holds.","es":"Una regla común es un scope de unos 7:1 (hasta 10:1 con mal tiempo): suelte de 7 a 10 pies de línea por cada pie de profundidad para que el ancla agarre.","ru":"Обычное правило — запас около 7:1 (до 10:1 при непогоде): выпускайте 7-10 футов каната на каждый фут глубины, чтобы якорь держал.","tr":"Yaygın kural yaklaşık 7:1 scope'tur (kötü koşullarda 10:1'e kadar): çapanın tutması için her ayak su derinliği başına 7 ila 10 ayak halat salın.","hi":"एक सामान्य नियम लगभग 7:1 स्कोप है (कठिन परिस्थितियों में 10:1 तक) — पानी की प्रत्येक फुट गहराई के लिए 7 से 10 फुट लाइन छोड़ें ताकि एंकर पकड़े।","ar":"القاعدة الشائعة هي مقدار حوالي 7:1 (حتى 10:1 في الظروف الصعبة): أرخِ من 7 إلى 10 أقدام من الحبل لكل قدم من عمق الماء لكي تثبت المرساة."}},{"cat":"operation","a":3,"q":{"en":"From which part of the boat should you normally lower and raise the anchor?","es":"¿Desde qué parte de la embarcación debe normalmente arriar y levar el ancla?","ru":"С какой части лодки обычно следует опускать и поднимать якорь?","tr":"Çapayı normalde teknenin hangi kısmından indirip kaldırmalısınız?","hi":"नाव के किस हिस्से से आपको सामान्यतः एंकर उतारना और उठाना चाहिए?","ar":"من أي جزء من القارب يجب عادةً إنزال المرساة ورفعها؟"},"o":[{"en":"The stern (back)","es":"La popa (parte trasera)","ru":"С кормы (сзади)","tr":"Kıç (arka)","hi":"स्टर्न (पीछे)","ar":"المؤخرة (الخلف)"},{"en":"The side (beam)","es":"El costado","ru":"С борта","tr":"Yandan (kemere)","hi":"किनारा (बीम)","ar":"الجانب"},{"en":"It does not matter","es":"No importa","ru":"Не имеет значения","tr":"Fark etmez","hi":"इससे कोई फ़र्क नहीं","ar":"لا يهم"},{"en":"The bow (front)","es":"La proa (parte delantera)","ru":"С носа (спереди)","tr":"Baş (ön)","hi":"नाव की नाक (सामने)","ar":"المقدمة (الأمام)"}],"e":{"en":"Always anchor from the bow. Anchoring from the stern can pull the low transom under, swamp the boat, and cause it to capsize, especially in current or waves.","es":"Fondee siempre por la proa. Fondear por la popa puede hundir el espejo bajo, inundar la embarcación y volcarla, sobre todo con corriente u olas.","ru":"Всегда становитесь на якорь с носа. Постановка с кормы может затянуть низкий транец под воду, залить лодку и опрокинуть её, особенно на течении или волне.","tr":"Her zaman baştan demirleyin. Kıçtan demirlemek alçak aynalığı suya çekebilir, tekneyi su basabilir ve özellikle akıntı veya dalgada alabora olmasına yol açabilir.","hi":"हमेशा नाव की नाक (बो) से लंगर डालें। स्टर्न से लंगर डालने पर नीचा ट्रांसम पानी में खिंच सकता है, नाव में पानी भर सकता है और वह पलट सकती है, विशेषकर धारा या लहरों में।","ar":"ارسِ دائماً من المقدمة. الرسو من المؤخرة قد يجرّ المؤخرة المنخفضة تحت الماء ويُغرق القارب ويقلبه، خصوصاً في التيار أو الأمواج."}},{"cat":"operation","a":1,"q":{"en":"What should the operator do to reduce the risk of the boat capsizing or swamping?","es":"¿Qué debe hacer el operador para reducir el riesgo de volcadura o inundación de la embarcación?","ru":"Что должен делать судоводитель, чтобы снизить риск опрокидывания или заливания лодки?","tr":"Teknenin alabora olma veya su basma riskini azaltmak için operatör ne yapmalıdır?","hi":"नाव के पलटने या पानी भरने का जोखिम कम करने के लिए चालक को क्या करना चाहिए?","ar":"ماذا يجب أن يفعل المشغّل لتقليل خطر انقلاب القارب أو غمره بالماء؟"},"o":[{"en":"Overload the boat to sit lower and be more stable","es":"Sobrecargar la embarcación para que se asiente más baja y estable","ru":"Перегрузить лодку, чтобы она сидела ниже и была устойчивее","tr":"Daha alçak ve dengeli olması için tekneyi aşırı yüklemek","hi":"अधिक स्थिर होने के लिए नाव को ओवरलोड करना","ar":"تحميل القارب زيادةً ليجلس أخفض ويكون أثبت"},{"en":"Distribute weight evenly, don't overload, and slow down in rough water","es":"Distribuir el peso uniformemente, no sobrecargar y reducir la velocidad en agua agitada","ru":"Равномерно распределять вес, не перегружать и снижать скорость на волнении","tr":"Ağırlığı eşit dağıtmak, aşırı yüklememek ve dalgalı suda yavaşlamak","hi":"वज़न समान रूप से बाँटना, ओवरलोड न करना और उथल-पुथल भरे पानी में धीमा करना","ar":"توزيع الوزن بالتساوي وعدم التحميل الزائد وإبطاء السرعة في الماء المضطرب"},{"en":"Make sharp high-speed turns","es":"Hacer giros bruscos a alta velocidad","ru":"Делать резкие повороты на высокой скорости","tr":"Yüksek hızda keskin dönüşler yapmak","hi":"तेज़ गति पर तीखे मोड़ लेना","ar":"القيام بمنعطفات حادة بسرعة عالية"},{"en":"Let everyone stand on one side","es":"Dejar que todos se paren en un solo lado","ru":"Позволить всем встать на один борт","tr":"Herkesin bir tarafta durmasına izin vermek","hi":"सभी को एक ओर खड़ा होने देना","ar":"السماح للجميع بالوقوف على جانب واحد"}],"e":{"en":"Prevent capsizing and swamping by not overloading, distributing weight evenly and low, avoiding sharp high-speed turns, and slowing down in waves or when another boat's wake approaches.","es":"Evite volcaduras e inundaciones no sobrecargando, distribuyendo el peso de forma uniforme y baja, evitando giros bruscos a alta velocidad y reduciendo la velocidad ante olas o la estela de otra embarcación.","ru":"Предотвращайте опрокидывание и заливание: не перегружайте, распределяйте вес равномерно и низко, избегайте резких поворотов на скорости и снижайте ход на волне или при приближении чужой волны.","tr":"Aşırı yüklememek, ağırlığı eşit ve alçak dağıtmak, yüksek hızda keskin dönüşlerden kaçınmak ve dalgalarda ya da başka teknenin izi yaklaşırken yavaşlamak alabora ve su basmayı önler.","hi":"ओवरलोड न करके, वज़न समान व नीचा रखकर, तेज़ गति पर तीखे मोड़ों से बचकर, और लहरों या दूसरी नाव की वेक आने पर धीमा करके पलटने और पानी भरने से बचें।","ar":"امنع الانقلاب والغمر بعدم التحميل الزائد، وتوزيع الوزن بالتساوي ومنخفضاً، وتجنّب المنعطفات الحادة السريعة، وإبطاء السرعة في الأمواج أو عند اقتراب موجة قارب آخر."}},{"cat":"operation","a":2,"q":{"en":"Why should you not operate a boat while fatigued, dehydrated, or overexposed to sun, wind, and noise?","es":"¿Por qué no debe operar una embarcación estando fatigado, deshidratado o sobreexpuesto al sol, viento y ruido?","ru":"Почему нельзя управлять лодкой в состоянии усталости, обезвоживания или при чрезмерном воздействии солнца, ветра и шума?","tr":"Yorgun, susuz kalmış ya da güneş, rüzgar ve gürültüye aşırı maruz kalmışken neden tekne kullanmamalısınız?","hi":"थके, निर्जलित, या धूप, हवा और शोर के अत्यधिक संपर्क में होने पर आपको नाव क्यों नहीं चलानी चाहिए?","ar":"لماذا يجب ألا تُشغّل قارباً وأنت متعب أو مصاب بالجفاف أو مفرط التعرّض للشمس والرياح والضوضاء؟"},"o":[{"en":"It uses more fuel","es":"Consume más combustible","ru":"Это расходует больше топлива","tr":"Daha çok yakıt harcar","hi":"इससे अधिक ईंधन खर्च होता है","ar":"يستهلك وقوداً أكثر"},{"en":"It voids the warranty","es":"Anula la garantía","ru":"Это аннулирует гарантию","tr":"Garantiyi geçersiz kılar","hi":"इससे वारंटी रद्द हो जाती है","ar":"يُلغي الضمان"},{"en":"\"Boater's fatigue\" slows reaction time and impairs judgment, increasing accident risk","es":"La \"fatiga del navegante\" reduce el tiempo de reacción y afecta el juicio, aumentando el riesgo de accidente","ru":"«Усталость моряка» замедляет реакцию и ухудшает суждение, повышая риск аварии","tr":"\"Denizci yorgunluğu\" tepki süresini yavaşlatır ve muhakemeyi bozar, kaza riskini artırır","hi":"\"बोटर की थकान\" प्रतिक्रिया समय धीमा करती है और निर्णय बिगाड़ती है, जिससे दुर्घटना का जोखिम बढ़ता है","ar":"\"إرهاق البحّار\" يبطئ زمن رد الفعل ويضعف الحكم، مما يزيد خطر الحوادث"},{"en":"It is illegal in all states","es":"Es ilegal en todos los estados","ru":"Это незаконно во всех штатах","tr":"Tüm eyaletlerde yasa dışıdır","hi":"सभी राज्यों में यह अवैध है","ar":"غير قانوني في جميع الولايات"}],"e":{"en":"Sun, wind, noise, vibration, and motion cause \"boater's fatigue,\" which dulls reactions and judgment much like alcohol. Stay hydrated, rested, and take breaks.","es":"El sol, el viento, el ruido, la vibración y el movimiento causan \"fatiga del navegante\", que embota las reacciones y el juicio como el alcohol. Manténgase hidratado, descansado y tome descansos.","ru":"Солнце, ветер, шум, вибрация и качка вызывают «усталость моряка», притупляющую реакцию и суждение подобно алкоголю. Пейте воду, отдыхайте и делайте перерывы.","tr":"Güneş, rüzgar, gürültü, titreşim ve hareket \"denizci yorgunluğu\"na yol açar; bu, alkol gibi tepkileri ve muhakemeyi köreltir. Susuz kalmayın, dinlenin ve mola verin.","hi":"धूप, हवा, शोर, कंपन और गति \"बोटर की थकान\" पैदा करते हैं, जो शराब की तरह प्रतिक्रिया और निर्णय को कुंद कर देती है। हाइड्रेटेड और आराम में रहें तथा विराम लें।","ar":"تسبّب الشمس والرياح والضوضاء والاهتزاز والحركة \"إرهاق البحّار\"، الذي يُضعِف ردود الفعل والحكم مثل الكحول. حافظ على الترطيب والراحة وخذ فترات استراحة."}},{"cat":"operation","a":0,"q":{"en":"When docking or launching, the best general approach is to:","es":"Al atracar o botar, el mejor enfoque general es:","ru":"При швартовке или спуске лучший общий подход:","tr":"Yanaşırken veya suya indirirken en iyi genel yaklaşım nedir?","hi":"डॉकिंग या लॉन्चिंग करते समय, सबसे अच्छा सामान्य तरीका है:","ar":"عند الرسو أو الإنزال، أفضل نهج عام هو:"},"o":[{"en":"Approach slowly and account for wind and current","es":"Aproximarse despacio y tener en cuenta el viento y la corriente","ru":"Подходить медленно, учитывая ветер и течение","tr":"Yavaş yaklaşmak ve rüzgar ile akıntıyı hesaba katmak","hi":"धीरे-धीरे पहुँचना और हवा तथा धारा को ध्यान में रखना","ar":"الاقتراب ببطء ومراعاة الرياح والتيار"},{"en":"Approach at full speed to maintain control","es":"Aproximarse a toda velocidad para mantener el control","ru":"Подходить на полной скорости для сохранения управления","tr":"Kontrolü korumak için tam hızda yaklaşmak","hi":"नियंत्रण बनाए रखने के लिए पूरी गति से पहुँचना","ar":"الاقتراب بأقصى سرعة للحفاظ على السيطرة"},{"en":"Ignore wind since boats aren't affected by it","es":"Ignorar el viento porque no afecta a las embarcaciones","ru":"Игнорировать ветер, так как он не влияет на лодки","tr":"Rüzgarı yok saymak çünkü tekneler etkilenmez","hi":"हवा को अनदेखा करना क्योंकि नावें इससे प्रभावित नहीं होतीं","ar":"تجاهل الرياح لأن القوارب لا تتأثر بها"},{"en":"Have passengers jump to the dock while moving","es":"Hacer que los pasajeros salten al muelle en movimiento","ru":"Заставить пассажиров прыгать на причал на ходу","tr":"Yolcuların hareket halindeyken iskeleye atlamasını sağlamak","hi":"चलते समय यात्रियों को घाट पर कूदने के लिए कहना","ar":"جعل الركاب يقفزون إلى الرصيف أثناء الحركة"}],"e":{"en":"Dock and launch at slow, controlled (idle) speed, and always factor in wind and current, which push the boat. Never have people jump to a dock from a moving boat.","es":"Atraque y bote a velocidad lenta y controlada (ralentí), y tenga siempre en cuenta el viento y la corriente que empujan la embarcación. Nunca haga que la gente salte al muelle desde una embarcación en movimiento.","ru":"Швартуйтесь и спускайтесь на малой контролируемой скорости (холостой ход) и всегда учитывайте ветер и течение, которые сносят лодку. Никогда не позволяйте прыгать на причал с движущейся лодки.","tr":"Yavaş, kontrollü (rölanti) hızda yanaşın ve indirin; tekneyi iten rüzgar ve akıntıyı daima hesaba katın. Hareket halindeki tekneden asla insanların iskeleye atlamasına izin vermeyin.","hi":"धीमी, नियंत्रित (आइडल) गति से डॉक और लॉन्च करें, और हमेशा हवा तथा धारा का ध्यान रखें जो नाव को धकेलती हैं। चलती नाव से किसी को घाट पर कूदने न दें।","ar":"ارسُ وأنزِل بسرعة بطيئة ومسيطر عليها (خمول)، وراعِ دائماً الرياح والتيار اللذين يدفعان القارب. لا تجعل الناس يقفزون إلى الرصيف من قارب متحرك أبداً."}},{"cat":"operation","a":3,"q":{"en":"You are operating in an area with heavy boat traffic. What is the best practice?","es":"Está navegando en una zona con mucho tráfico de embarcaciones. ¿Cuál es la mejor práctica?","ru":"Вы идёте в районе с интенсивным движением судов. Как лучше поступить?","tr":"Yoğun tekne trafiği olan bir bölgede seyrediyorsunuz. En iyi uygulama nedir?","hi":"आप भारी नाव यातायात वाले क्षेत्र में चला रहे हैं। सबसे अच्छा अभ्यास क्या है?","ar":"أنت تُبحر في منطقة ذات حركة قوارب كثيفة. ما أفضل ممارسة؟"},"o":[{"en":"Weave quickly between boats","es":"Zigzaguear rápidamente entre embarcaciones","ru":"Быстро лавировать между лодками","tr":"Tekneler arasında hızlıca zikzak çizmek","hi":"नावों के बीच तेज़ी से लहराते हुए चलना","ar":"المناورة السريعة بين القوارب"},{"en":"Assume everyone will get out of your way","es":"Suponer que todos se apartarán de su camino","ru":"Считать, что все уступят вам дорогу","tr":"Herkesin size yol açacağını varsaymak","hi":"यह मान लेना कि सभी आपके रास्ते से हट जाएँगे","ar":"افتراض أن الجميع سيبتعد عن طريقك"},{"en":"Turn off your navigation lights to see better","es":"Apagar las luces de navegación para ver mejor","ru":"Выключить навигационные огни, чтобы лучше видеть","tr":"Daha iyi görmek için seyir fenerlerini kapatmak","hi":"बेहतर देखने के लिए नौवहन बत्तियाँ बंद करना","ar":"إطفاء أضواء الملاحة للرؤية أفضل"},{"en":"Reduce speed, keep a sharp lookout, and maintain a predictable course","es":"Reducir la velocidad, mantener buena vigilancia y un rumbo predecible","ru":"Снизить скорость, вести внимательное наблюдение и держать предсказуемый курс","tr":"Hızı azaltmak, keskin gözcülük yapmak ve öngörülebilir bir rota tutmak","hi":"गति कम करना, तेज़ लुकआउट रखना और पूर्वानुमेय मार्ग बनाए रखना","ar":"تقليل السرعة والمراقبة الحادة والحفاظ على مسار متوقَّع"}],"e":{"en":"In heavy traffic, slow down, keep a sharp lookout in all directions, and steer a steady, predictable course so other operators can anticipate your movements.","es":"Con mucho tráfico, reduzca la velocidad, mantenga buena vigilancia en todas direcciones y siga un rumbo estable y predecible para que otros anticipen sus movimientos.","ru":"При интенсивном движении снижайте скорость, ведите наблюдение во всех направлениях и держите ровный предсказуемый курс, чтобы другие могли предугадать ваши манёвры.","tr":"Yoğun trafikte hızı azaltın, her yönde keskin gözcülük yapın ve diğerlerinin hareketlerinizi öngörebilmesi için sabit, öngörülebilir bir rota izleyin.","hi":"भारी यातायात में गति कम करें, सभी दिशाओं में तेज़ लुकआउट रखें, और स्थिर, पूर्वानुमेय मार्ग पर चलें ताकि अन्य चालक आपकी गतिविधियों का अनुमान लगा सकें।","ar":"في الحركة الكثيفة، خفّف السرعة، وراقب بحدة في كل الاتجاهات، وسِر في مسار ثابت متوقَّع حتى يستطيع المشغّلون الآخرون توقّع حركتك."}},{"cat":"operation","a":1,"q":{"en":"How can you best tell how much fuel you should carry for a trip?","es":"¿Cómo puede saber mejor cuánto combustible debe llevar para una salida?","ru":"Как лучше всего определить, сколько топлива взять в рейс?","tr":"Bir gezi için ne kadar yakıt taşımanız gerektiğini en iyi nasıl belirlersiniz?","hi":"किसी यात्रा के लिए आपको कितना ईंधन ले जाना चाहिए, यह सबसे अच्छे तरीके से कैसे तय करें?","ar":"كيف تعرف بشكل أفضل كمية الوقود التي يجب أن تحملها للرحلة؟"},"o":[{"en":"Fill it half full to save money","es":"Llenar hasta la mitad para ahorrar dinero","ru":"Заполнить наполовину, чтобы сэкономить деньги","tr":"Para tasarrufu için yarıya kadar doldurmak","hi":"पैसे बचाने के लिए आधा भरना","ar":"ملؤه إلى النصف لتوفير المال"},{"en":"Use the one-third rule: a third out, a third back, a third in reserve","es":"Usar la regla de un tercio: un tercio de ida, un tercio de vuelta y un tercio de reserva","ru":"Правило трети: треть на путь туда, треть обратно, треть в резерв","tr":"Üçte bir kuralı: üçte biri gidiş, üçte biri dönüş, üçte biri yedek","hi":"एक-तिहाई नियम अपनाएँ: एक-तिहाई जाने में, एक-तिहाई लौटने में, एक-तिहाई रिज़र्व में","ar":"استخدم قاعدة الثلث: ثلث للذهاب وثلث للعودة وثلث احتياطي"},{"en":"Just guess","es":"Simplemente adivinar","ru":"Просто угадать","tr":"Sadece tahmin etmek","hi":"बस अंदाज़ा लगाना","ar":"مجرد التخمين"},{"en":"Carry only enough to reach your destination","es":"Llevar solo lo justo para llegar al destino","ru":"Взять топлива только до пункта назначения","tr":"Yalnızca varış noktasına yetecek kadar taşımak","hi":"केवल गंतव्य तक पहुँचने भर का ईंधन ले जाना","ar":"حمل ما يكفي فقط للوصول إلى الوجهة"}],"e":{"en":"Follow the one-third rule: use one-third of your fuel going out, one-third returning, and keep one-third in reserve for emergencies, headwinds, or currents.","es":"Siga la regla de un tercio: use un tercio del combustible a la ida, un tercio a la vuelta y guarde un tercio de reserva para emergencias, viento en contra o corrientes.","ru":"Следуйте правилу трети: треть топлива — на путь туда, треть — обратно, треть держите в резерве на случай непредвиденного, встречного ветра или течений.","tr":"Üçte bir kuralını izleyin: yakıtın üçte birini gidişte, üçte birini dönüşte kullanın ve acil durumlar, ters rüzgar veya akıntılar için üçte birini yedekte tutun.","hi":"एक-तिहाई नियम अपनाएँ: ईंधन का एक-तिहाई जाते समय, एक-तिहाई लौटते समय उपयोग करें, और आपात, प्रतिकूल हवा या धाराओं के लिए एक-तिहाई रिज़र्व रखें।","ar":"اتّبع قاعدة الثلث: استخدم ثلث الوقود للذهاب وثلثاً للعودة واحتفظ بثلث احتياطياً للطوارئ أو الرياح المعاكسة أو التيارات."}},{"cat":"operation","a":2,"q":{"en":"What does a mushroom, fluke (Danforth), or plow describe on a boat?","es":"¿Qué describen un ancla de hongo, de arado o tipo Danforth (fluke) en una embarcación?","ru":"Что описывают «грибовидный», «Данфорт» (fluke) или «плуг» применительно к лодке?","tr":"Bir teknede mantar, çırpı (Danforth) veya saban ne tür şeyi tanımlar?","hi":"नाव पर मशरूम, फ्लूक (डैनफोर्थ), या प्लाउ किसका वर्णन करते हैं?","ar":"ماذا تصف كلمات فطر (mushroom) أو danforth أو محراث في القارب؟"},"o":[{"en":"Types of propellers","es":"Tipos de hélices","ru":"Типы гребных винтов","tr":"Pervane türleri","hi":"प्रोपेलर के प्रकार","ar":"أنواع المراوح"},{"en":"Types of engines","es":"Tipos de motores","ru":"Типы двигателей","tr":"Motor türleri","hi":"इंजन के प्रकार","ar":"أنواع المحركات"},{"en":"Types of anchors","es":"Tipos de anclas","ru":"Типы якорей","tr":"Çapa türleri","hi":"एंकर के प्रकार","ar":"أنواع المراسي"},{"en":"Types of life jackets","es":"Tipos de chalecos salvavidas","ru":"Типы спасательных жилетов","tr":"Can yeleği türleri","hi":"लाइफ जैकेट के प्रकार","ar":"أنواع سترات النجاة"}],"e":{"en":"These are common anchor types. The right anchor depends on the bottom (mud, sand, rock, weeds) and your boat's size. Carry enough line and choose an anchor suited to local conditions.","es":"Son tipos comunes de anclas. El ancla adecuada depende del fondo (lodo, arena, roca, algas) y del tamaño de la embarcación. Lleve suficiente línea y elija un ancla adecuada a las condiciones locales.","ru":"Это распространённые типы якорей. Подходящий якорь зависит от грунта (ил, песок, камень, водоросли) и размера лодки. Берите достаточно каната и выбирайте якорь под местные условия.","tr":"Bunlar yaygın çapa türleridir. Doğru çapa dibe (çamur, kum, kaya, yosun) ve teknenizin boyutuna bağlıdır. Yeterli halat taşıyın ve yerel koşullara uygun çapa seçin.","hi":"ये सामान्य एंकर प्रकार हैं। सही एंकर तल (कीचड़, रेत, चट्टान, घास) और नाव के आकार पर निर्भर करता है। पर्याप्त लाइन रखें और स्थानीय परिस्थितियों के अनुकूल एंकर चुनें।","ar":"هذه أنواع شائعة من المراسي. تعتمد المرساة المناسبة على طبيعة القاع (طين، رمل، صخر، أعشاب) وحجم قاربك. احمل حبلاً كافياً واختر مرساة مناسبة للظروف المحلية."}},{"cat":"operation","a":0,"q":{"en":"Before every outing, a pre-departure checklist should include:","es":"Antes de cada salida, una lista de verificación previa debe incluir:","ru":"Перед каждым выходом контрольный список должен включать:","tr":"Her seferden önce, kalkış öncesi kontrol listesi neyi içermelidir?","hi":"हर यात्रा से पहले, रवानगी-पूर्व चेकलिस्ट में क्या शामिल होना चाहिए?","ar":"قبل كل رحلة، يجب أن تتضمّن قائمة التحقّق قبل المغادرة:"},"o":[{"en":"Checking fuel, safety gear, weather, and telling someone your float plan","es":"Revisar combustible, equipo de seguridad, clima e informar a alguien su plan de navegación","ru":"Проверку топлива, снаряжения безопасности, погоды и сообщение кому-то плана выхода","tr":"Yakıt, güvenlik ekipmanı, hava durumunu kontrol ve birine sefer planınızı bildirmek","hi":"ईंधन, सुरक्षा उपकरण, मौसम की जाँच और किसी को अपना फ्लोट प्लान बताना","ar":"فحص الوقود ومعدات السلامة والطقس وإخبار شخص بخطة إبحارك"},{"en":"Only checking the radio","es":"Solo revisar la radio","ru":"Только проверку радио","tr":"Yalnızca telsizi kontrol etmek","hi":"केवल रेडियो की जाँच","ar":"فحص الراديو فقط"},{"en":"Only checking the paint","es":"Solo revisar la pintura","ru":"Только проверку окраски","tr":"Yalnızca boyayı kontrol etmek","hi":"केवल पेंट की जाँच","ar":"فحص الطلاء فقط"},{"en":"Nothing — inspections aren't needed","es":"Nada: no se necesitan inspecciones","ru":"Ничего — проверки не нужны","tr":"Hiçbir şey — kontrole gerek yok","hi":"कुछ नहीं — जाँच की ज़रूरत नहीं","ar":"لا شيء — لا حاجة للفحوص"}],"e":{"en":"A good pre-departure check covers fuel level, engine and battery, required safety equipment, life jackets, weather forecast, and leaving a float plan with someone ashore.","es":"Una buena verificación previa cubre el nivel de combustible, el motor y la batería, el equipo de seguridad requerido, los chalecos, el pronóstico del tiempo y dejar un plan de navegación con alguien en tierra.","ru":"Хорошая предстартовая проверка охватывает уровень топлива, двигатель и аккумулятор, обязательное снаряжение, жилеты, прогноз погоды и оставленный на берегу план выхода.","tr":"İyi bir kalkış öncesi kontrol; yakıt seviyesi, motor ve akü, zorunlu güvenlik ekipmanı, can yelekleri, hava tahmini ve karadaki birine sefer planı bırakmayı kapsar.","hi":"एक अच्छी रवानगी-पूर्व जाँच में ईंधन स्तर, इंजन व बैटरी, आवश्यक सुरक्षा उपकरण, लाइफ जैकेट, मौसम पूर्वानुमान, और किनारे पर किसी के पास फ्लोट प्लान छोड़ना शामिल है।","ar":"يشمل الفحص الجيد قبل المغادرة مستوى الوقود والمحرك والبطارية ومعدات السلامة المطلوبة وسترات النجاة وتوقعات الطقس وترك خطة إبحار مع شخص على البر."}},{"cat":"operation","a":3,"q":{"en":"A \"float plan\" is:","es":"Un \"plan de navegación\" (float plan) es:","ru":"«План выхода» (float plan) — это:","tr":"\"Sefer planı\" (float plan) nedir?","hi":"\"फ्लोट प्लान\" क्या है?","ar":"\"خطة الإبحار\" (float plan) هي:"},"o":[{"en":"A map of the ocean floor","es":"Un mapa del fondo del océano","ru":"Карта морского дна","tr":"Okyanus tabanının haritası","hi":"समुद्र तल का नक्शा","ar":"خريطة لقاع المحيط"},{"en":"A list of songs to play on the boat","es":"Una lista de canciones para el barco","ru":"Список песен для проигрывания на лодке","tr":"Teknede çalınacak şarkı listesi","hi":"नाव पर बजाने के गानों की सूची","ar":"قائمة أغانٍ لتشغيلها على القارب"},{"en":"A plan for how to distribute weight","es":"Un plan de distribución de peso","ru":"План распределения веса","tr":"Ağırlık dağıtım planı","hi":"वज़न वितरण की योजना","ar":"خطة لتوزيع الوزن"},{"en":"Information you leave with someone ashore about your trip and expected return","es":"Información que deja con alguien en tierra sobre su salida y regreso previsto","ru":"Информация, которую вы оставляете кому-то на берегу о рейсе и ожидаемом возвращении","tr":"Gezinizi ve dönüş saatinizi karadaki birine bıraktığınız bilgiler","hi":"आपकी यात्रा और अपेक्षित वापसी के बारे में किनारे पर किसी को दी गई जानकारी","ar":"معلومات تتركها مع شخص على البر عن رحلتك وموعد عودتك المتوقع"}],"e":{"en":"A float plan tells a reliable person your boat description, who is aboard, where you are going, and when you expect to return, so help can be sent if you fail to come back.","es":"Un plan de navegación indica a una persona de confianza la descripción de la embarcación, quiénes van a bordo, adónde va y cuándo prevé regresar, para pedir ayuda si no vuelve.","ru":"План выхода сообщает надёжному человеку описание лодки, кто на борту, куда вы идёте и когда планируете вернуться, чтобы помощь могли выслать, если вы не вернётесь.","tr":"Sefer planı, güvenilir birine teknenizin tanımını, kimlerin olduğunu, nereye gittiğinizi ve ne zaman döneceğinizi bildirir; dönmezseniz yardım gönderilebilir.","hi":"फ्लोट प्लान किसी विश्वसनीय व्यक्ति को नाव का विवरण, बोर्ड पर कौन है, आप कहाँ जा रहे हैं और कब लौटने की अपेक्षा है बताता है, ताकि आप न लौटें तो मदद भेजी जा सके।","ar":"تُخبر خطة الإبحار شخصاً موثوقاً بوصف قاربك ومَن على متنه وإلى أين تذهب ومتى تتوقع العودة، حتى يُرسَل الإنقاذ إن لم تعُد."}},{"cat":"operation","a":1,"q":{"en":"What is the safest action if your boat runs aground?","es":"¿Cuál es la acción más segura si su embarcación encalla?","ru":"Каково самое безопасное действие, если лодка села на мель?","tr":"Tekneniz karaya oturursa en güvenli hareket nedir?","hi":"यदि आपकी नाव फँस (अग्राउंड) जाए तो सबसे सुरक्षित कार्रवाई क्या है?","ar":"ما التصرف الأسلم إذا جنح قاربك؟"},"o":[{"en":"Immediately gun the engine to power off","es":"Acelerar de inmediato a fondo para salir","ru":"Сразу дать полный газ, чтобы сойти","tr":"Hemen tam gaz verip çıkmak","hi":"तुरंत इंजन को ज़ोर से चलाकर निकलना","ar":"دفع المحرك فوراً بأقصى قوة للخروج"},{"en":"Stop the engine, check for damage and leaks, then try to ease off gently, shifting weight if needed","es":"Apagar el motor, revisar daños y filtraciones, y luego intentar salir suavemente, desplazando el peso si es necesario","ru":"Заглушить двигатель, проверить повреждения и течи, затем осторожно сходить, при необходимости смещая вес","tr":"Motoru durdurup hasar ve su sızıntısını kontrol etmek, sonra gerekirse ağırlığı kaydırarak nazikçe çıkmaya çalışmak","hi":"इंजन बंद करें, क्षति व रिसाव जाँचें, फिर आवश्यकता हो तो वज़न खिसकाते हुए धीरे से निकलने का प्रयास करें","ar":"إيقاف المحرك وفحص الأضرار والتسربات، ثم محاولة الخروج بلطف مع نقل الوزن عند الحاجة"},{"en":"Have everyone jump overboard","es":"Que todos salten al agua","ru":"Заставить всех прыгнуть за борт","tr":"Herkesin denize atlaması","hi":"सभी को पानी में कूदने के लिए कहना","ar":"جعل الجميع يقفز إلى الماء"},{"en":"Ignore it and keep going","es":"Ignorarlo y seguir adelante","ru":"Игнорировать и продолжать движение","tr":"Görmezden gelip devam etmek","hi":"इसे अनदेखा कर आगे बढ़ते रहना","ar":"تجاهله والاستمرار"}],"e":{"en":"If you run aground, stop the engine and check for hull damage and leaks first. Shift weight and try to ease off slowly; forcing the throttle can worsen damage or leave you stranded.","es":"Si encalla, apague el motor y revise primero daños en el casco y filtraciones. Desplace el peso e intente salir despacio; forzar el acelerador puede empeorar el daño o dejarlo varado.","ru":"При посадке на мель сначала заглушите двигатель и проверьте корпус на повреждения и течи. Сместите вес и осторожно сходите; резкий газ может усугубить повреждения или посадить прочнее.","tr":"Karaya oturursanız önce motoru durdurun ve teknede hasar ile su sızıntısı olup olmadığını kontrol edin. Ağırlığı kaydırın ve yavaşça çıkmaya çalışın; gazı zorlamak hasarı artırabilir ya da sizi mahsur bırakabilir.","hi":"यदि नाव फँसे, तो पहले इंजन बंद करें और पतवार की क्षति व रिसाव जाँचें। वज़न खिसकाएँ और धीरे-धीरे निकलने का प्रयास करें; थ्रॉटल को ज़ोर देने से क्षति बढ़ सकती है या नाव और फँस सकती है।","ar":"إذا جنحت، أوقف المحرك وافحص أولاً بدن القارب بحثاً عن أضرار وتسربات. انقل الوزن وحاول الخروج ببطء؛ فدفع الخانق بقوة قد يزيد الضرر أو يُبقيك عالقاً."}},{"cat":"operation","a":2,"q":{"en":"What is a key benefit of using an engine cut-off switch (ECOS) lanyard or wireless device while operating?","es":"¿Cuál es un beneficio clave de usar el cordón o dispositivo inalámbrico del interruptor de corte del motor (ECOS) al navegar?","ru":"В чём ключевая польза шнура или беспроводного устройства аварийного выключателя двигателя (ECOS) при управлении?","tr":"Kullanım sırasında motor durdurma anahtarı (ECOS) kordonu veya kablosuz cihazının temel faydası nedir?","hi":"संचालन के दौरान इंजन कट-ऑफ स्विच (ECOS) लैनयार्ड या वायरलेस डिवाइस का उपयोग करने का एक मुख्य लाभ क्या है?","ar":"ما الفائدة الرئيسية لاستخدام حبل مفتاح إيقاف المحرك (ECOS) أو الجهاز اللاسلكي أثناء القيادة؟"},"o":[{"en":"It makes the boat go faster","es":"Hace que la embarcación vaya más rápido","ru":"Он ускоряет лодку","tr":"Tekneyi daha hızlı yapar","hi":"इससे नाव तेज़ चलती है","ar":"يجعل القارب أسرع"},{"en":"It stops the engine if the operator is thrown from the helm, preventing a runaway boat","es":"Detiene el motor si el operador es arrojado del timón, evitando una embarcación descontrolada","ru":"Он глушит двигатель, если судоводителя выбросило из-за штурвала, предотвращая неуправляемый ход","tr":"Operatör dümenden savrulursa motoru durdurur, kontrolsüz tekneyi önler","hi":"चालक के पतवार से गिरने पर इंजन बंद कर देता है, जिससे बेकाबू नाव रुक जाती है","ar":"يوقف المحرك إذا قُذف المشغّل من الدفّة، مانعاً انطلاق القارب دون سيطرة"},{"en":"It saves fuel","es":"Ahorra combustible","ru":"Он экономит топливо","tr":"Yakıt tasarrufu sağlar","hi":"यह ईंधन बचाता है","ar":"يوفّر الوقود"},{"en":"It charges the battery","es":"Carga la batería","ru":"Он заряжает аккумулятор","tr":"Aküyü şarj eder","hi":"यह बैटरी चार्ज करता है","ar":"يشحن البطارية"}],"e":{"en":"An engine cut-off switch shuts down the engine if the operator falls off or away from the helm, stopping the boat from circling back or running away out of control.","es":"El interruptor de corte del motor lo apaga si el operador cae o se aleja del timón, evitando que la embarcación gire de regreso o se descontrole.","ru":"Аварийный выключатель глушит двигатель, если судоводитель упал или отдалился от штурвала, не давая лодке кружить назад или уйти без управления.","tr":"Motor durdurma anahtarı, operatör dümenden düşer veya uzaklaşırsa motoru kapatarak teknenin geri dönüp dönmesini ya da kontrolsüz kaçmasını önler.","hi":"इंजन कट-ऑफ स्विच चालक के गिरने या पतवार से दूर होने पर इंजन बंद कर देता है, जिससे नाव घूमकर वापस आने या बेकाबू भागने से रुक जाती है।","ar":"يُطفئ مفتاح إيقاف المحرك المحرك إذا سقط المشغّل أو ابتعد عن الدفّة، مانعاً القارب من الدوران عائداً أو الانطلاق دون سيطرة."}},{"cat":"operation","a":3,"q":{"en":"While operating at night, you should adjust your speed so that you can:","es":"Al navegar de noche, debe ajustar la velocidad de modo que pueda:","ru":"При движении ночью следует выбирать скорость так, чтобы вы могли:","tr":"Gece seyrederken hızınızı ayarlamalısınız ki:","hi":"रात में चलाते समय, आपको अपनी गति इस तरह समायोजित करनी चाहिए कि आप:","ar":"عند القيادة ليلاً، يجب ضبط سرعتك بحيث تستطيع:"},"o":[{"en":"Reach your destination as quickly as possible","es":"Llegar a su destino lo más rápido posible","ru":"Достичь пункта назначения как можно быстрее","tr":"Varış yerinize mümkün olan en kısa sürede ulaşmak","hi":"अपने गंतव्य तक जितनी जल्दी हो सके पहुँचना","ar":"الوصول إلى وجهتك بأسرع ما يمكن"},{"en":"Keep up with other boats","es":"Mantener el ritmo de otras embarcaciones","ru":"Не отставать от других лодок","tr":"Diğer teknelere ayak uydurmak","hi":"अन्य नावों के साथ गति बनाए रखना","ar":"مجاراة القوارب الأخرى"},{"en":"Create a large wake","es":"Crear una gran estela","ru":"Создавать большую волну","tr":"Büyük bir iz oluşturmak","hi":"बड़ी वेक बनाना","ar":"إحداث موجة كبيرة"},{"en":"Stop within the distance you can see with your lights or in available light","es":"Detenerse dentro de la distancia que puede ver con sus luces o con la luz disponible","ru":"Остановиться в пределах видимости, обеспечиваемой вашими огнями или имеющимся светом","tr":"Fenerlerinizle ya da mevcut ışıkta görebildiğiniz mesafe içinde durabilmek","hi":"अपनी बत्तियों या उपलब्ध रोशनी में जितनी दूरी तक देख सकें, उसके भीतर रुकना","ar":"التوقف ضمن المسافة التي تراها بأضوائك أو بالضوء المتاح"}],"e":{"en":"At night, run at a speed slow enough to stop within your visible range. Reduced visibility, unlit hazards, and floating debris make high speed after dark especially dangerous.","es":"De noche, navegue a una velocidad lo bastante lenta para detenerse dentro de su alcance visible. La visibilidad reducida, los peligros sin luz y los restos flotantes hacen que la alta velocidad de noche sea muy peligrosa.","ru":"Ночью держите скорость достаточно малой, чтобы остановиться в пределах видимости. Плохая видимость, неосвещённые опасности и плавающий мусор делают высокую скорость в темноте особенно опасной.","tr":"Gece, görebildiğiniz mesafe içinde durabilecek kadar yavaş seyredin. Azalan görüş, ışıksız tehlikeler ve yüzen enkaz, karanlıkta yüksek hızı özellikle tehlikeli kılar.","hi":"रात में इतनी धीमी गति से चलें कि अपनी दृश्य सीमा के भीतर रुक सकें। कम दृश्यता, बिना रोशनी वाले खतरे और तैरता मलबा अंधेरे में तेज़ गति को विशेष रूप से खतरनाक बनाते हैं।","ar":"ليلاً، سِر بسرعة بطيئة بما يكفي للتوقف ضمن مدى رؤيتك. الرؤية المحدودة والمخاطر غير المضاءة والحطام العائم تجعل السرعة العالية بعد حلول الظلام خطِرة بشكل خاص."}},{"cat":"equipment","a":1,"q":{"en":"What is the most important reason to wear a life jacket (PFD) rather than just carry one aboard?","es":"¿Cuál es la razón más importante para llevar puesto el chaleco salvavidas (PFD) en lugar de solo tenerlo a bordo?","ru":"Какова главная причина носить спасательный жилет (PFD), а не просто держать его на борту?","tr":"Can yeleğini (PFD) sadece teknede bulundurmak yerine giymenin en önemli nedeni nedir?","hi":"लाइफ जैकेट (PFD) को केवल बोर्ड पर रखने के बजाय पहनने का सबसे महत्वपूर्ण कारण क्या है?","ar":"ما أهم سبب لارتداء سترة النجاة (PFD) بدلاً من مجرد حملها على متن القارب؟"},"o":[{"en":"It keeps you warmer","es":"Lo mantiene más caliente","ru":"Он лучше согревает","tr":"Sizi daha sıcak tutar","hi":"यह आपको गर्म रखता है","ar":"يبقيك أدفأ"},{"en":"In a sudden fall overboard there is often no time to find and put one on","es":"En una caída repentina al agua muchas veces no hay tiempo para buscarlo y ponérselo","ru":"При внезапном падении за борт часто нет времени найти и надеть его","tr":"Ani bir denize düşmede genellikle bulup giymeye zaman olmaz","hi":"अचानक पानी में गिरने पर अक्सर उसे ढूँढकर पहनने का समय नहीं होता","ar":"عند السقوط المفاجئ في الماء غالباً لا يوجد وقت لإيجادها وارتدائها"},{"en":"It is required to be worn at all times by all boaters everywhere","es":"Su uso es obligatorio en todo momento para todos los navegantes en todas partes","ru":"Его обязаны носить постоянно все судоводители везде","tr":"Her yerde tüm denizciler için her zaman giyilmesi zorunludur","hi":"इसे हर जगह सभी नाविकों द्वारा हर समय पहनना आवश्यक है","ar":"ارتداؤها إلزامي طوال الوقت لكل البحّارة في كل مكان"},{"en":"It makes swimming easier","es":"Facilita nadar","ru":"Он облегчает плавание","tr":"Yüzmeyi kolaylaştırır","hi":"यह तैरना आसान बनाता है","ar":"يجعل السباحة أسهل"}],"e":{"en":"Most drowning victims had a life jacket aboard but were not wearing it. In a capsize or sudden fall there is rarely time to reach for and put one on, so wear it.","es":"La mayoría de los ahogados tenían un chaleco a bordo pero no lo llevaban puesto. En una volcadura o caída repentina rara vez hay tiempo para alcanzarlo y ponérselo; por eso, úselo.","ru":"У большинства утонувших жилет был на борту, но не надет. При опрокидывании или внезапном падении редко есть время его достать и надеть — поэтому носите его.","tr":"Boğulan kişilerin çoğunun teknede can yeleği vardı ama giymiyorlardı. Alabora ya da ani düşmede uzanıp giymeye nadiren zaman olur; bu yüzden giyin.","hi":"अधिकांश डूबने वाले लोगों के पास बोर्ड पर लाइफ जैकेट थी पर वे पहने नहीं थे। पलटने या अचानक गिरने पर उसे लेकर पहनने का समय शायद ही होता है, इसलिए इसे पहनें।","ar":"معظم ضحايا الغرق كانت لديهم سترة نجاة على متن القارب لكنهم لم يرتدوها. عند الانقلاب أو السقوط المفاجئ نادراً ما يوجد وقت للوصول إليها وارتدائها، فارتدِها."}},{"cat":"equipment","a":0,"q":{"en":"For most recreational boats, how many wearable life jackets must be on board?","es":"En la mayoría de embarcaciones recreativas, ¿cuántos chalecos salvavidas de uso personal debe haber a bordo?","ru":"На большинстве прогулочных судов сколько носимых спасательных жилетов должно быть на борту?","tr":"Çoğu tekne için, teknede kaç adet giyilebilir can yeleği bulunmalıdır?","hi":"अधिकांश मनोरंजक नावों के लिए, बोर्ड पर कितने पहनने योग्य लाइफ जैकेट होने चाहिए?","ar":"بالنسبة لمعظم القوارب الترفيهية، كم عدد سترات النجاة القابلة للارتداء التي يجب أن تكون على متن القارب؟"},"o":[{"en":"One U.S. Coast Guard-approved, properly fitting life jacket for each person aboard","es":"Un chaleco aprobado por la Guardia Costera de EE. UU., de la talla correcta, para cada persona a bordo","ru":"По одному одобренному Береговой охраной США жилету подходящего размера на каждого человека на борту","tr":"Teknedeki her kişi için ABD Sahil Güvenliği onaylı, uygun bedende bir can yeleği","hi":"बोर्ड पर प्रत्येक व्यक्ति के लिए एक अमेरिकी कोस्ट गार्ड-अनुमोदित, सही फिट होने वाला लाइफ जैकेट","ar":"سترة نجاة واحدة معتمدة من خفر السواحل الأمريكي وبمقاس مناسب لكل شخص على متن القارب"},{"en":"One for the whole boat","es":"Uno para toda la embarcación","ru":"Один на всю лодку","tr":"Tüm tekne için bir tane","hi":"पूरी नाव के लिए एक","ar":"واحدة للقارب كله"},{"en":"Two for the operator only","es":"Dos solo para el operador","ru":"Два только для судоводителя","tr":"Yalnızca operatör için iki tane","hi":"केवल चालक के लिए दो","ar":"اثنتان للمشغّل فقط"},{"en":"None if everyone can swim","es":"Ninguno si todos saben nadar","ru":"Ни одного, если все умеют плавать","tr":"Herkes yüzebiliyorsa hiç","hi":"यदि सभी तैर सकते हैं तो कोई नहीं","ar":"لا شيء إذا كان الجميع يجيد السباحة"}],"e":{"en":"Federal rules require one wearable, Coast Guard-approved life jacket of the correct size for each person aboard. Being able to swim does not remove this requirement.","es":"Las normas federales exigen un chaleco de uso personal, aprobado por la Guardia Costera y de la talla correcta, para cada persona a bordo. Saber nadar no elimina este requisito.","ru":"Федеральные правила требуют один носимый одобренный Береговой охраной жилет нужного размера на каждого на борту. Умение плавать не отменяет это требование.","tr":"Federal kurallar, teknedeki her kişi için doğru bedende, giyilebilir ve Sahil Güvenliği onaylı bir can yeleği gerektirir. Yüzme bilmek bu zorunluluğu kaldırmaz.","hi":"संघीय नियम बोर्ड पर प्रत्येक व्यक्ति के लिए एक पहनने योग्य, कोस्ट गार्ड-अनुमोदित, सही आकार का लाइफ जैकेट अनिवार्य करते हैं। तैरना आने से यह आवश्यकता समाप्त नहीं होती।","ar":"تُلزِم القواعد الفيدرالية بوجود سترة نجاة واحدة قابلة للارتداء ومعتمدة من خفر السواحل وبالمقاس الصحيح لكل شخص على متن القارب. معرفة السباحة لا تُلغي هذا الشرط."}},{"cat":"equipment","a":2,"q":{"en":"In addition to wearable life jackets, what is required on many boats 16 feet and longer (except canoes and kayaks)?","es":"Además de los chalecos de uso personal, ¿qué se requiere en muchas embarcaciones de 16 pies o más (excepto canoas y kayaks)?","ru":"Помимо носимых жилетов, что требуется на многих судах длиной 16 футов и более (кроме каноэ и каяков)?","tr":"Giyilebilir can yeleklerine ek olarak, 16 fit ve daha uzun birçok teknede (kano ve kayak hariç) ne gerekir?","hi":"पहनने योग्य लाइफ जैकेट के अलावा, 16 फुट या उससे लंबी कई नावों (कैनो और कयाक को छोड़कर) पर क्या आवश्यक है?","ar":"بالإضافة إلى سترات النجاة القابلة للارتداء، ما المطلوب في كثير من القوارب بطول 16 قدماً فأكثر (باستثناء الكانو والكاياك)؟"},"o":[{"en":"A second engine","es":"Un segundo motor","ru":"Второй двигатель","tr":"İkinci bir motor","hi":"एक दूसरा इंजन","ar":"محرك ثانٍ"},{"en":"A spare propeller","es":"Una hélice de repuesto","ru":"Запасной винт","tr":"Yedek pervane","hi":"एक अतिरिक्त प्रोपेलर","ar":"مروحة احتياطية"},{"en":"At least one Type IV throwable flotation device","es":"Al menos un dispositivo de flotación arrojable Tipo IV","ru":"Как минимум одно бросаемое спасательное средство типа IV","tr":"En az bir Tip IV atılabilir yüzdürme cihazı","hi":"कम से कम एक टाइप IV थ्रोएबल फ्लोटेशन डिवाइस","ar":"على الأقل جهاز طفو واحد قابل للرمي من النوع الرابع (Type IV)"},{"en":"A life raft","es":"Una balsa salvavidas","ru":"Спасательный плот","tr":"Bir cankurtaran salı","hi":"एक लाइफ राफ्ट","ar":"طوف نجاة"}],"e":{"en":"Boats 16 feet and over (other than canoes/kayaks) must also carry at least one Type IV throwable device, such as a ring buoy or seat cushion, ready to toss to someone in the water.","es":"Las embarcaciones de 16 pies o más (salvo canoas/kayaks) deben llevar además al menos un dispositivo arrojable Tipo IV, como un aro salvavidas o cojín, listo para lanzar a alguien en el agua.","ru":"Суда длиной 16 футов и более (кроме каноэ/каяков) должны также иметь минимум одно бросаемое средство типа IV — спасательный круг или подушку, готовое бросить упавшему в воду.","tr":"16 fit ve üzeri tekneler (kano/kayak hariç) ayrıca suya düşen birine atmaya hazır en az bir Tip IV atılabilir cihaz (can simidi veya oturma yastığı) bulundurmalıdır.","hi":"16 फुट या उससे बड़ी नावों (कैनो/कयाक को छोड़कर) को कम से कम एक टाइप IV थ्रोएबल डिवाइस भी रखनी चाहिए, जैसे रिंग बॉय या सीट कुशन, जो पानी में किसी को फेंकने के लिए तैयार हो।","ar":"يجب أن تحمل القوارب بطول 16 قدماً فأكثر (عدا الكانو/الكاياك) أيضاً جهازاً واحداً على الأقل قابلاً للرمي من النوع الرابع، مثل طوق نجاة أو وسادة، جاهزاً لرميه لمن في الماء."}},{"cat":"equipment","a":3,"q":{"en":"How should life jackets be maintained to remain effective?","es":"¿Cómo deben mantenerse los chalecos para seguir siendo eficaces?","ru":"Как следует содержать спасательные жилеты, чтобы они оставались эффективными?","tr":"Can yelekleri etkili kalması için nasıl bakılmalıdır?","hi":"लाइफ जैकेट को प्रभावी बनाए रखने के लिए उनका रखरखाव कैसे किया जाना चाहिए?","ar":"كيف يجب صيانة سترات النجاة لتبقى فعّالة؟"},"o":[{"en":"Use them as boat fenders or kneeling pads","es":"Usarlos como defensas o para arrodillarse","ru":"Использовать их как кранцы или подстилки","tr":"Usturmaça ya da diz altlığı olarak kullanmak","hi":"उन्हें फेंडर या घुटने के गद्दे के रूप में उपयोग करना","ar":"استخدامها كوسائد صد للقارب أو للركوع عليها"},{"en":"Store them permanently sealed in plastic","es":"Guardarlos siempre sellados en plástico","ru":"Хранить их постоянно запечатанными в пластик","tr":"Sürekli plastikte kapalı saklamak","hi":"उन्हें हमेशा प्लास्टिक में सील करके रखना","ar":"تخزينها مغلقة بالبلاستيك دائماً"},{"en":"Never check them once bought","es":"Nunca revisarlos después de comprarlos","ru":"Никогда не проверять после покупки","tr":"Alındıktan sonra hiç kontrol etmemek","hi":"खरीदने के बाद उन्हें कभी न जाँचना","ar":"عدم فحصها أبداً بعد الشراء"},{"en":"Keep them clean, dry, in good condition, and readily accessible — not used as cushions or fenders","es":"Mantenerlos limpios, secos, en buen estado y accesibles; no usarlos como cojines ni defensas","ru":"Держать чистыми, сухими, в хорошем состоянии и доступными; не использовать как подушки или кранцы","tr":"Temiz, kuru, iyi durumda ve kolay ulaşılır tutmak; yastık veya usturmaça olarak kullanmamak","hi":"उन्हें साफ़, सूखा, अच्छी हालत में और आसानी से पहुँच योग्य रखें — कुशन या फेंडर के रूप में उपयोग न करें","ar":"إبقاؤها نظيفة وجافة وبحالة جيدة وسهلة الوصول — وعدم استخدامها كوسائد أو صادات"}],"e":{"en":"Keep life jackets clean, dry, in good condition, and within easy reach — not stowed away or used as seat cushions or fenders. Check regularly for rips, mildew, and loss of buoyancy.","es":"Mantenga los chalecos limpios, secos, en buen estado y a mano; no guardados ni usados como cojines o defensas. Revíselos con frecuencia por roturas, moho y pérdida de flotabilidad.","ru":"Держите жилеты чистыми, сухими, в хорошем состоянии и под рукой — не убранными и не в роли подушек или кранцев. Регулярно проверяйте на разрывы, плесень и потерю плавучести.","tr":"Can yeleklerini temiz, kuru, iyi durumda ve kolay ulaşılır tutun; kaldırıp saklamayın ya da yastık/usturmaça yapmayın. Yırtık, küf ve yüzdürme kaybı için düzenli kontrol edin.","hi":"लाइफ जैकेट को साफ़, सूखा, अच्छी हालत में और आसानी से पहुँच में रखें — छिपाकर या सीट कुशन/फेंडर के रूप में उपयोग न करें। फटन, फफूँदी और उछाल की कमी के लिए नियमित जाँचें।","ar":"أبقِ سترات النجاة نظيفة وجافة وبحالة جيدة وقريبة المنال — لا مخزّنة بعيداً ولا مستخدمة كوسائد أو صادات. افحصها بانتظام بحثاً عن تمزّق أو عفن أو فقدان الطفو."}},{"cat":"equipment","a":0,"q":{"en":"Children on a moving recreational boat are generally required to:","es":"En general, se exige que los niños en una embarcación recreativa en marcha:","ru":"На движущемся прогулочном судне дети, как правило, обязаны:","tr":"Hareket halindeki bir tekneede çocukların genellikle:","hi":"चल रही मनोरंजक नाव पर बच्चों को आमतौर पर आवश्यक है कि:","ar":"يُطلب عموماً من الأطفال في قارب ترفيهي متحرك أن:"},"o":[{"en":"Wear a properly fitted, approved life jacket (specific age varies by state)","es":"Llevar puesto un chaleco aprobado y de talla adecuada (la edad exacta varía por estado)","ru":"Носить одобренный жилет подходящего размера (точный возраст зависит от штата)","tr":"Uygun bedende, onaylı bir can yeleği giymesi (yaş sınırı eyalete göre değişir)","hi":"एक सही फिट, अनुमोदित लाइफ जैकेट पहनें (सटीक आयु राज्यानुसार भिन्न)","ar":"يرتدوا سترة نجاة معتمدة وبمقاس مناسب (يختلف السن المحدد حسب الولاية)"},{"en":"Stay below deck at all times","es":"Permanecer bajo cubierta en todo momento","ru":"Постоянно находиться под палубой","tr":"Her zaman güvertenin altında kalması","hi":"हर समय डेक के नीचे रहें","ar":"يبقوا تحت سطح المركب دائماً"},{"en":"Hold onto an adult instead","es":"Sujetarse de un adulto en su lugar","ru":"Держаться за взрослого вместо этого","tr":"Bunun yerine bir yetişkine tutunması","hi":"इसके बजाय किसी वयस्क को पकड़े रहें","ar":"يتمسّكوا ببالغ بدلاً من ذلك"},{"en":"Wear any adult life jacket","es":"Llevar cualquier chaleco de adulto","ru":"Носить любой взрослый жилет","tr":"Herhangi bir yetişkin can yeleği giymesi","hi":"कोई भी वयस्क लाइफ जैकेट पहनें","ar":"يرتدوا أي سترة نجاة للكبار"}],"e":{"en":"Most states require young children to wear a properly fitting, Coast Guard-approved life jacket whenever a boat is under way. The exact age and rules vary by state, so check local law.","es":"La mayoría de los estados exige que los niños pequeños lleven un chaleco aprobado y de talla adecuada siempre que la embarcación esté en marcha. La edad y las reglas varían por estado; consulte la ley local.","ru":"Большинство штатов требуют, чтобы маленькие дети носили одобренный жилет подходящего размера, когда судно на ходу. Точный возраст и правила зависят от штата — проверяйте местный закон.","tr":"Çoğu eyalet, tekne seyir halindeyken küçük çocukların uygun bedende, Sahil Güvenliği onaylı can yeleği giymesini ister. Yaş ve kurallar eyalete göre değişir; yerel yasayı kontrol edin.","hi":"अधिकांश राज्य छोटे बच्चों को नाव के चलते समय सही फिट, कोस्ट गार्ड-अनुमोदित लाइफ जैकेट पहनना अनिवार्य करते हैं। सटीक आयु और नियम राज्यानुसार भिन्न होते हैं, इसलिए स्थानीय कानून देखें।","ar":"تُلزِم معظم الولايات الأطفال الصغار بارتداء سترة نجاة معتمدة وبمقاس مناسب كلما كان القارب متحركاً. يختلف السن والقواعد حسب الولاية، فراجع القانون المحلي."}},{"cat":"equipment","a":1,"q":{"en":"A B-I marine fire extinguisher on a boat is designed mainly to fight what kind of fire?","es":"Un extintor marino B-I en una embarcación está diseñado principalmente para combatir ¿qué tipo de incendio?","ru":"Судовой огнетушитель класса B-I предназначен главным образом для тушения какого типа пожара?","tr":"Teknede bir B-I deniz yangın söndürücüsü esas olarak hangi tür yangınla mücadele için tasarlanmıştır?","hi":"नाव पर B-I समुद्री अग्निशामक मुख्यतः किस प्रकार की आग बुझाने के लिए बनाया गया है?","ar":"طفاية حريق بحرية من فئة B-I على القارب مصمّمة أساساً لمكافحة أي نوع من الحرائق؟"},"o":[{"en":"Electrical wiring fires only","es":"Solo incendios de cableado eléctrico","ru":"Только пожары электропроводки","tr":"Yalnızca elektrik kablosu yangınları","hi":"केवल विद्युत तारों की आग","ar":"حرائق الأسلاك الكهربائية فقط"},{"en":"Flammable liquids such as gasoline, oil, and grease","es":"Líquidos inflamables como gasolina, aceite y grasa","ru":"Легковоспламеняющиеся жидкости — бензин, масло, жир","tr":"Benzin, yağ ve gres gibi yanıcı sıvılar","hi":"गैसोलीन, तेल और ग्रीस जैसे ज्वलनशील तरल","ar":"السوائل القابلة للاشتعال مثل البنزين والزيت والشحم"},{"en":"Burning wood and paper only","es":"Solo madera y papel ardiendo","ru":"Только горящее дерево и бумагу","tr":"Yalnızca yanan ahşap ve kağıt","hi":"केवल जलती लकड़ी और कागज़","ar":"الخشب والورق المشتعل فقط"},{"en":"Cooking-oil fires only","es":"Solo incendios de aceite de cocina","ru":"Только пожары кулинарного масла","tr":"Yalnızca pişirme yağı yangınları","hi":"केवल खाना पकाने के तेल की आग","ar":"حرائق زيت الطهي فقط"}],"e":{"en":"Marine extinguishers on boats are Class B, rated for flammable liquid fires (gasoline, oil, grease) common aboard. B-I is the smaller size; B-II is larger. Larger boats require more or bigger extinguishers.","es":"Los extintores marinos de las embarcaciones son Clase B, para incendios de líquidos inflamables (gasolina, aceite, grasa) comunes a bordo. B-I es el tamaño menor; B-II el mayor. Las embarcaciones grandes requieren más o mayores.","ru":"Судовые огнетушители — класса B, для пожаров легковоспламеняющихся жидкостей (бензин, масло, жир), характерных на борту. B-I меньшего размера, B-II крупнее. Более крупным судам нужно больше или крупнее.","tr":"Teknelerdeki deniz söndürücüleri B Sınıfıdır; teknede yaygın yanıcı sıvı yangınları (benzin, yağ, gres) içindir. B-I küçük, B-II büyük boydur. Büyük tekneler daha çok veya daha büyük söndürücü gerektirir.","hi":"नावों के समुद्री अग्निशामक क्लास B के होते हैं, जो बोर्ड पर सामान्य ज्वलनशील तरल आग (गैसोलीन, तेल, ग्रीस) के लिए रेटेड हैं। B-I छोटा आकार है, B-II बड़ा। बड़ी नावों को अधिक या बड़े अग्निशामक चाहिए।","ar":"طفايات القوارب البحرية من الفئة B، مخصّصة لحرائق السوائل القابلة للاشتعال (البنزين والزيت والشحم) الشائعة على متن القارب. B-I هي الحجم الأصغر وB-II الأكبر. القوارب الأكبر تتطلّب عدداً أكثر أو أحجاماً أكبر."}},{"cat":"equipment","a":2,"q":{"en":"How should you aim a fire extinguisher to put out a fire?","es":"¿Cómo debe apuntar un extintor para apagar un incendio?","ru":"Как нужно направлять огнетушитель, чтобы потушить огонь?","tr":"Yangını söndürmek için yangın söndürücüyü nasıl yöneltmelisiniz?","hi":"आग बुझाने के लिए अग्निशामक को कैसे लक्ष्य करना चाहिए?","ar":"كيف يجب توجيه طفاية الحريق لإخماد النار؟"},"o":[{"en":"At the top of the flames","es":"A la parte superior de las llamas","ru":"В верхнюю часть пламени","tr":"Alevlerin üstüne","hi":"आग की लपटों के ऊपरी हिस्से पर","ar":"إلى أعلى اللهب"},{"en":"Into the smoke","es":"Hacia el humo","ru":"В дым","tr":"Dumana doğru","hi":"धुएँ की ओर","ar":"نحو الدخان"},{"en":"At the base of the flames, using a side-to-side sweeping motion","es":"A la base de las llamas, con un movimiento de lado a lado","ru":"В основание пламени, метя из стороны в сторону","tr":"Alevlerin tabanına, yanlamasına süpürme hareketiyle","hi":"आग की लपटों के आधार पर, अगल-बगल स्वीप करते हुए","ar":"إلى قاعدة اللهب مع حركة مسح جانبية"},{"en":"Straight up into the air","es":"Directamente hacia arriba","ru":"Прямо вверх в воздух","tr":"Doğrudan havaya yukarı","hi":"सीधे हवा में ऊपर की ओर","ar":"مباشرة إلى الأعلى في الهواء"}],"e":{"en":"Use the P.A.S.S. method: Pull the pin, Aim at the base of the flames, Squeeze the handle, and Sweep from side to side. Aiming at the base attacks the fuel source.","es":"Use el método P.A.S.S.: quite el seguro (Pull), apunte a la base (Aim), apriete la manija (Squeeze) y barra de lado a lado (Sweep). Apuntar a la base ataca la fuente de combustible.","ru":"Используйте метод P.A.S.S.: выньте чеку (Pull), цельтесь в основание (Aim), нажмите рычаг (Squeeze), водите из стороны в сторону (Sweep). Основание — это источник топлива.","tr":"P.A.S.S. yöntemini kullanın: Pimi çekin (Pull), alevin tabanını hedefleyin (Aim), kolu sıkın (Squeeze), yanlamasına süpürün (Sweep). Tabana nişan almak yakıt kaynağına saldırır.","hi":"P.A.S.S. विधि अपनाएँ: पिन खींचें (Pull), आधार पर निशाना लगाएँ (Aim), हैंडल दबाएँ (Squeeze), अगल-बगल स्वीप करें (Sweep)। आधार पर निशाना ईंधन स्रोत पर वार करता है।","ar":"استخدم طريقة P.A.S.S.: اسحب المسمار (Pull)، وجّه نحو قاعدة اللهب (Aim)، اضغط المقبض (Squeeze)، وامسح جانبياً (Sweep). التوجيه نحو القاعدة يهاجم مصدر الوقود."}},{"cat":"equipment","a":3,"q":{"en":"On coastal waters and the Great Lakes, boats are generally required to carry what to signal distress?","es":"En aguas costeras y los Grandes Lagos, ¿qué se exige generalmente llevar para señalar socorro?","ru":"В прибрежных водах и на Великих озёрах суда, как правило, обязаны иметь что для подачи сигнала бедствия?","tr":"Kıyı sularında ve Büyük Göller'de tekneler tehlike işareti vermek için genellikle neyi bulundurmak zorundadır?","hi":"तटीय जल और ग्रेट लेक्स में, संकट संकेत देने के लिए नावों को आमतौर पर क्या रखना आवश्यक है?","ar":"في المياه الساحلية والبحيرات العظمى، ما المطلوب عادةً حمله على القوارب للإشارة إلى الاستغاثة؟"},"o":[{"en":"A whistle only","es":"Solo un silbato","ru":"Только свисток","tr":"Yalnızca bir düdük","hi":"केवल एक सीटी","ar":"صافرة فقط"},{"en":"A spare battery","es":"Una batería de repuesto","ru":"Запасной аккумулятор","tr":"Yedek bir akü","hi":"एक अतिरिक्त बैटरी","ar":"بطارية احتياطية"},{"en":"A boat hook","es":"Un bichero","ru":"Отпорный крюк","tr":"Bir tekne kancası","hi":"एक बोट हुक","ar":"خطاف قارب"},{"en":"U.S. Coast Guard-approved visual distress signals (VDS), such as flares or an electric distress light","es":"Señales visuales de socorro (VDS) aprobadas por la Guardia Costera, como bengalas o una luz eléctrica de socorro","ru":"Одобренные Береговой охраной США визуальные сигналы бедствия (VDS) — фальшфейеры или электрический сигнальный огонь","tr":"Sahil Güvenliği onaylı görsel tehlike işaretleri (VDS), fişek veya elektrikli tehlike ışığı gibi","hi":"कोस्ट गार्ड-अनुमोदित दृश्य संकट संकेत (VDS), जैसे फ्लेयर या विद्युत संकट प्रकाश","ar":"إشارات استغاثة مرئية معتمدة من خفر السواحل (VDS) مثل الشعلات أو ضوء استغاثة كهربائي"}],"e":{"en":"On coastal waters, the Great Lakes, and connected waters, most boats must carry Coast Guard-approved visual distress signals valid for day and night, such as flares or an electric distress light.","es":"En aguas costeras, los Grandes Lagos y aguas conectadas, la mayoría de las embarcaciones deben llevar señales visuales de socorro aprobadas, válidas de día y de noche, como bengalas o una luz eléctrica de socorro.","ru":"В прибрежных водах, на Великих озёрах и связанных с ними водах большинство судов должны иметь одобренные визуальные сигналы бедствия, действительные днём и ночью — фальшфейеры или электрический сигнальный огонь.","tr":"Kıyı sularında, Büyük Göller'de ve bağlantılı sularda çoğu tekne, gündüz ve gece geçerli, onaylı görsel tehlike işaretleri (fişek veya elektrikli tehlike ışığı) bulundurmalıdır.","hi":"तटीय जल, ग्रेट लेक्स और जुड़े जल में अधिकांश नावों को दिन-रात मान्य, अनुमोदित दृश्य संकट संकेत रखने चाहिए, जैसे फ्लेयर या विद्युत संकट प्रकाश।","ar":"في المياه الساحلية والبحيرات العظمى والمياه المتصلة، يجب أن تحمل معظم القوارب إشارات استغاثة مرئية معتمدة صالحة للنهار والليل، مثل الشعلات أو ضوء استغاثة كهربائي."}},{"cat":"equipment","a":0,"q":{"en":"A red aerial or handheld flare is used to:","es":"Una bengala aérea o de mano roja se usa para:","ru":"Красный воздушный или ручной фальшфейер применяется для того, чтобы:","tr":"Kırmızı havai veya el fişeği ne için kullanılır?","hi":"एक लाल हवाई या हाथ में पकड़ी जाने वाली फ्लेयर का उपयोग किया जाता है:","ar":"تُستخدم الشعلة الحمراء الجوية أو المحمولة باليد من أجل:"},"o":[{"en":"Signal that you are in distress and need help","es":"Señalar que está en peligro y necesita ayuda","ru":"Подать сигнал бедствия и запросить помощь","tr":"Tehlikede olduğunuzu ve yardım gerektiğini işaret etmek","hi":"संकेत देना कि आप संकट में हैं और मदद चाहिए","ar":"الإشارة إلى أنك في خطر وتحتاج مساعدة"},{"en":"Mark a good fishing spot","es":"Marcar un buen lugar de pesca","ru":"Отметить хорошее место для рыбалки","tr":"İyi bir balık tutma yerini işaretlemek","hi":"एक अच्छी मछली पकड़ने की जगह चिह्नित करना","ar":"تحديد مكان جيد لصيد الأسماك"},{"en":"Celebrate on the water","es":"Celebrar en el agua","ru":"Устроить праздник на воде","tr":"Suda kutlama yapmak","hi":"पानी पर जश्न मनाना","ar":"الاحتفال على الماء"},{"en":"Light up the campsite","es":"Iluminar el campamento","ru":"Осветить место стоянки","tr":"Kamp alanını aydınlatmak","hi":"शिविर स्थल को रोशन करना","ar":"إضاءة موقع التخييم"}],"e":{"en":"Flares are emergency distress signals. Use them only when you genuinely need rescue. Firing flares for fun is dangerous, wastes limited signals, and is illegal.","es":"Las bengalas son señales de socorro. Úselas solo cuando realmente necesite rescate. Lanzarlas por diversión es peligroso, malgasta señales limitadas y es ilegal.","ru":"Фальшфейеры — сигналы бедствия. Используйте их только при реальной необходимости спасения. Пуск ради развлечения опасен, расходует ограниченные средства и незаконен.","tr":"Fişekler acil tehlike işaretleridir. Yalnızca gerçekten kurtarılmaya ihtiyaç duyduğunuzda kullanın. Eğlence için ateşlemek tehlikelidir, sınırlı işaretleri harcar ve yasa dışıdır.","hi":"फ्लेयर आपातकालीन संकट संकेत हैं। उनका उपयोग केवल तभी करें जब आपको वास्तव में बचाव चाहिए। मज़े के लिए फ्लेयर चलाना खतरनाक है, सीमित संकेत बर्बाद करता है और अवैध है।","ar":"الشعلات إشارات استغاثة طارئة. استخدمها فقط عند حاجتك الفعلية للإنقاذ. إطلاقها للتسلية خطر ويهدر إشارات محدودة وغير قانوني."}},{"cat":"equipment","a":1,"q":{"en":"What must gasoline-powered boats built with enclosed engine or fuel-tank compartments have to prevent explosions?","es":"¿Qué deben tener las embarcaciones de gasolina con compartimentos cerrados de motor o tanque para evitar explosiones?","ru":"Что должны иметь бензиновые суда с закрытыми моторными или топливными отсеками, чтобы предотвратить взрывы?","tr":"Kapalı motor veya yakıt deposu bölmeli benzinli tekneler patlamayı önlemek için ne bulundurmalıdır?","hi":"बंद इंजन या ईंधन-टैंक कक्षों वाली गैसोलीन नावों में विस्फोट रोकने के लिए क्या होना चाहिए?","ar":"ماذا يجب أن تحتوي القوارب البنزينية ذات مقصورات المحرك أو خزان الوقود المغلقة لمنع الانفجارات؟"},"o":[{"en":"Extra seating","es":"Asientos adicionales","ru":"Дополнительные сиденья","tr":"Ek koltuklar","hi":"अतिरिक्त सीटें","ar":"مقاعد إضافية"},{"en":"A ventilation system (blowers and vents) to clear fuel vapors","es":"Un sistema de ventilación (extractores y respiraderos) para eliminar los vapores de combustible","ru":"Систему вентиляции (вентиляторы и вентотверстия) для удаления паров топлива","tr":"Yakıt buharını gidermek için havalandırma sistemi (aspiratör ve menfezler)","hi":"ईंधन वाष्प निकालने के लिए वेंटिलेशन सिस्टम (ब्लोअर और वेंट)","ar":"نظام تهوية (منافيخ وفتحات) لإزالة أبخرة الوقود"},{"en":"A louder horn","es":"Una bocina más fuerte","ru":"Более громкий гудок","tr":"Daha yüksek sesli korna","hi":"एक तेज़ हॉर्न","ar":"بوق أعلى صوتاً"},{"en":"Larger fuel tanks","es":"Tanques de combustible más grandes","ru":"Более крупные топливные баки","tr":"Daha büyük yakıt tankları","hi":"बड़े ईंधन टैंक","ar":"خزانات وقود أكبر"}],"e":{"en":"Boats with enclosed gasoline engine or tank spaces must have proper ventilation — natural vents and, in most cases, a powered blower — to remove explosive fuel vapors from the bilge.","es":"Las embarcaciones con espacios cerrados de motor o tanque de gasolina deben tener ventilación adecuada —respiraderos naturales y, en la mayoría de los casos, un extractor eléctrico— para eliminar los vapores explosivos de la sentina.","ru":"Суда с закрытыми отсеками бензинового двигателя или бака должны иметь надлежащую вентиляцию — естественные вентотверстия и, как правило, электровентилятор — для удаления взрывоопасных паров из трюма.","tr":"Kapalı benzin motoru veya tank bölmesi olan tekneler, sintineden patlayıcı yakıt buharlarını atmak için uygun havalandırmaya — doğal menfezler ve çoğu durumda elektrikli aspiratöre — sahip olmalıdır.","hi":"बंद गैसोलीन इंजन या टैंक स्थान वाली नावों में बिल्ज से विस्फोटक ईंधन वाष्प हटाने के लिए उचित वेंटिलेशन होना चाहिए — प्राकृतिक वेंट और अधिकांश मामलों में एक पावर्ड ब्लोअर।","ar":"يجب أن تحتوي القوارب ذات مقصورات محرك أو خزان بنزين مغلقة على تهوية مناسبة — فتحات طبيعية وفي معظم الحالات منفاخ كهربائي — لإزالة أبخرة الوقود المتفجّرة من القاع."}},{"cat":"equipment","a":2,"q":{"en":"A backfire flame arrestor is installed on an inboard gasoline engine to:","es":"Un antirretorno de llama se instala en un motor de gasolina interior para:","ru":"Пламегаситель устанавливают на стационарный бензиновый двигатель, чтобы:","tr":"Geri tepme alev tutucu, içten takma benzinli motora ne için takılır?","hi":"बैकफायर फ्लेम अरेस्टर इनबोर्ड गैसोलीन इंजन पर लगाया जाता है ताकि:","ar":"يُركّب مانع اللهب الارتدادي على محرك بنزين داخلي من أجل:"},"o":[{"en":"Increase horsepower","es":"Aumentar la potencia","ru":"Увеличить мощность","tr":"Beygir gücünü artırmak","hi":"हॉर्सपावर बढ़ाना","ar":"زيادة القوة الحصانية"},{"en":"Reduce noise","es":"Reducir el ruido","ru":"Снизить шум","tr":"Gürültüyü azaltmak","hi":"शोर कम करना","ar":"تقليل الضوضاء"},{"en":"Prevent an engine backfire from igniting fuel vapors and causing a fire or explosion","es":"Evitar que un petardeo del motor encienda vapores y provoque incendio o explosión","ru":"Не дать вспышке в карбюраторе воспламенить пары топлива и вызвать пожар или взрыв","tr":"Motor geri tepmesinin yakıt buharını tutuşturup yangın veya patlamaya yol açmasını önlemek","hi":"इंजन बैकफायर से ईंधन वाष्प के प्रज्वलन और आग या विस्फोट को रोकना","ar":"منع ارتداد لهب المحرك من إشعال أبخرة الوقود والتسبّب في حريق أو انفجار"},{"en":"Filter the drinking water","es":"Filtrar el agua potable","ru":"Фильтровать питьевую воду","tr":"İçme suyunu filtrelemek","hi":"पीने के पानी को फ़िल्टर करना","ar":"تصفية مياه الشرب"}],"e":{"en":"A Coast Guard-approved backfire flame arrestor on the carburetor stops flames from an engine backfire from reaching and igniting gasoline vapors, preventing a fire or explosion.","es":"Un antirretorno de llama aprobado en el carburador impide que las llamas de un petardeo lleguen a los vapores de gasolina y los enciendan, evitando incendio o explosión.","ru":"Одобренный Береговой охраной пламегаситель на карбюраторе не даёт пламени от обратной вспышки достичь и воспламенить пары бензина, предотвращая пожар или взрыв.","tr":"Karbüratördeki onaylı geri tepme alev tutucu, motor geri tepmesindeki alevlerin benzin buharına ulaşıp tutuşmasını engelleyerek yangın veya patlamayı önler.","hi":"कार्बोरेटर पर लगा अनुमोदित बैकफायर फ्लेम अरेस्टर इंजन बैकफायर की लपटों को गैसोलीन वाष्प तक पहुँचने और प्रज्वलित होने से रोकता है, जिससे आग या विस्फोट टलता है।","ar":"يمنع مانع اللهب الارتدادي المعتمد على المكربن لهب ارتداد المحرك من الوصول إلى أبخرة البنزين وإشعالها، فيقي من الحريق أو الانفجار."}},{"cat":"equipment","a":3,"q":{"en":"What sound-producing device is required so a boat can signal its intentions or warn others?","es":"¿Qué dispositivo productor de sonido se requiere para que una embarcación señale sus intenciones o advierta a otros?","ru":"Какое звукоизлучающее устройство требуется, чтобы судно могло сигнализировать о намерениях или предупреждать других?","tr":"Bir teknenin niyetini işaret edebilmesi veya başkalarını uyarabilmesi için hangi ses çıkaran cihaz gereklidir?","hi":"नाव अपने इरादे संकेतित कर सके या दूसरों को चेतावनी दे सके, इसके लिए कौन सा ध्वनि-उत्पादक उपकरण आवश्यक है?","ar":"ما جهاز إصدار الصوت المطلوب حتى يتمكّن القارب من الإشارة إلى نواياه أو تحذير الآخرين؟"},"o":[{"en":"A radio antenna","es":"Una antena de radio","ru":"Радиоантенна","tr":"Bir telsiz anteni","hi":"एक रेडियो एंटीना","ar":"هوائي راديو"},{"en":"A depth finder","es":"Un sonda de profundidad","ru":"Эхолот","tr":"Bir derinlik ölçer","hi":"एक डेप्थ फाइंडर","ar":"جهاز قياس العمق"},{"en":"A GPS unit","es":"Una unidad GPS","ru":"GPS-приёмник","tr":"Bir GPS cihazı","hi":"एक GPS यूनिट","ar":"جهاز GPS"},{"en":"An efficient sound-producing device such as a whistle, horn, or bell (as required for the boat's size)","es":"Un dispositivo sonoro eficiente como silbato, bocina o campana (según el tamaño de la embarcación)","ru":"Эффективное звуковое устройство — свисток, гудок или колокол (в зависимости от размера судна)","tr":"Teknenin boyutuna göre gerekli, verimli bir ses cihazı: düdük, korna veya çan","hi":"एक कुशल ध्वनि-उत्पादक उपकरण जैसे सीटी, हॉर्न या घंटी (नाव के आकार अनुसार आवश्यक)","ar":"جهاز صوت فعّال مثل صافرة أو بوق أو جرس (بحسب حجم القارب)"}],"e":{"en":"Every boat must have an efficient sound-producing device. Small boats need at least a whistle or horn; larger vessels also need a bell. Sound signals warn others and communicate maneuvering intentions.","es":"Toda embarcación debe tener un dispositivo sonoro eficiente. Las pequeñas necesitan al menos un silbato o bocina; las mayores también una campana. Las señales sonoras advierten y comunican maniobras.","ru":"Каждое судно должно иметь эффективное звуковое устройство. Малым лодкам нужен хотя бы свисток или гудок; крупным — ещё и колокол. Звуковые сигналы предупреждают и сообщают о манёврах.","tr":"Her tekne verimli bir ses cihazı bulundurmalıdır. Küçük tekneler en az bir düdük veya korna, büyük tekneler ayrıca çan gerektirir. Ses işaretleri uyarır ve manevra niyetini iletir.","hi":"हर नाव में एक कुशल ध्वनि-उत्पादक उपकरण होना चाहिए। छोटी नावों को कम से कम सीटी या हॉर्न चाहिए; बड़ी नावों को घंटी भी। ध्वनि संकेत दूसरों को चेतावनी देते और मैन्युवर के इरादे बताते हैं।","ar":"يجب أن يمتلك كل قارب جهاز صوت فعّالاً. القوارب الصغيرة تحتاج صافرة أو بوقاً على الأقل، والقوارب الأكبر تحتاج جرساً أيضاً. تُحذّر الإشارات الصوتية الآخرين وتُبلّغ نوايا المناورة."}},{"cat":"equipment","a":0,"q":{"en":"How often should Coast Guard-approved pyrotechnic (flare) distress signals be replaced?","es":"¿Con qué frecuencia deben reemplazarse las señales de socorro pirotécnicas (bengalas) aprobadas?","ru":"Как часто нужно заменять одобренные пиротехнические сигналы бедствия (фальшфейеры)?","tr":"Onaylı piroteknik (fişek) tehlike işaretleri ne sıklıkla değiştirilmelidir?","hi":"अनुमोदित पायरोटेक्निक (फ्लेयर) संकट संकेतों को कितनी बार बदलना चाहिए?","ar":"كم مرة يجب استبدال إشارات الاستغاثة النارية (الشعلات) المعتمدة؟"},"o":[{"en":"Before the expiration date printed on them (they are stamped with a service life)","es":"Antes de la fecha de caducidad impresa (llevan una vida útil marcada)","ru":"До истечения указанного на них срока годности (у них есть срок службы)","tr":"Üzerlerinde yazılı son kullanma tarihinden önce (bir kullanım ömrü damgalıdır)","hi":"उन पर छपी समाप्ति तिथि से पहले (उन पर सेवा-अवधि अंकित होती है)","ar":"قبل تاريخ انتهاء الصلاحية المطبوع عليها (تحمل عمراً افتراضياً)"},{"en":"Only every ten years","es":"Solo cada diez años","ru":"Только раз в десять лет","tr":"Yalnızca on yılda bir","hi":"केवल हर दस साल में","ar":"كل عشر سنوات فقط"},{"en":"Never — they last forever","es":"Nunca: duran para siempre","ru":"Никогда — они вечные","tr":"Asla — sonsuza dek dayanır","hi":"कभी नहीं — वे हमेशा चलते हैं","ar":"أبداً — تدوم للأبد"},{"en":"Only if they get wet","es":"Solo si se mojan","ru":"Только если намокнут","tr":"Yalnızca ıslanırlarsa","hi":"केवल यदि वे गीले हो जाएँ","ar":"فقط إذا ابتلّت"}],"e":{"en":"Pyrotechnic flares are stamped with an expiration date and must be replaced before they expire — expired flares may misfire and do not count toward the required equipment.","es":"Las bengalas pirotécnicas llevan fecha de caducidad y deben reemplazarse antes de vencer; las vencidas pueden fallar y no cuentan como equipo requerido.","ru":"На пиротехнических фальшфейерах указан срок годности; их нужно заменять до истечения — просроченные могут не сработать и не засчитываются как обязательное снаряжение.","tr":"Piroteknik fişeklerde son kullanma tarihi damgalıdır ve dolmadan değiştirilmelidir; süresi geçmiş fişekler ateşlenmeyebilir ve zorunlu ekipmandan sayılmaz.","hi":"पायरोटेक्निक फ्लेयर पर समाप्ति तिथि अंकित होती है और उन्हें समाप्त होने से पहले बदलना चाहिए — समाप्त फ्लेयर ठीक से न चलें और आवश्यक उपकरण में नहीं गिने जाते।","ar":"تحمل الشعلات النارية تاريخ انتهاء وتُستبدل قبل انتهائها — فالشعلات المنتهية قد لا تشتعل ولا تُحتسب ضمن المعدات المطلوبة."}},{"cat":"equipment","a":1,"q":{"en":"What color of visual distress signal is recognized internationally as meaning \"distress\"?","es":"¿Qué color de señal visual de socorro se reconoce internacionalmente como \"socorro\"?","ru":"Какой цвет визуального сигнала бедствия признан во всём мире как обозначающий «бедствие»?","tr":"Hangi renkteki görsel tehlike işareti uluslararası olarak \"tehlike\" anlamıyla tanınır?","hi":"किस रंग का दृश्य संकट संकेत अंतरराष्ट्रीय स्तर पर \"संकट\" के अर्थ में मान्यता प्राप्त है?","ar":"ما لون إشارة الاستغاثة المرئية المعترف به دولياً بمعنى \"الاستغاثة\"؟"},"o":[{"en":"Green","es":"Verde","ru":"Зелёный","tr":"Yeşil","hi":"हरा","ar":"أخضر"},{"en":"Red","es":"Rojo","ru":"Красный","tr":"Kırmızı","hi":"लाल","ar":"أحمر"},{"en":"Blue","es":"Azul","ru":"Синий","tr":"Mavi","hi":"नीला","ar":"أزرق"},{"en":"White","es":"Blanco","ru":"Белый","tr":"Beyaz","hi":"सफ़ेद","ar":"أبيض"}],"e":{"en":"Red is the universal distress color for flares and distress lights. A red flare, red aerial signal, or orange smoke by day tells others you need immediate help.","es":"El rojo es el color universal de socorro para bengalas y luces. Una bengala roja, una señal aérea roja o humo naranja de día indican que necesita ayuda inmediata.","ru":"Красный — универсальный цвет бедствия для фальшфейеров и сигнальных огней. Красный фальшфейер, красный воздушный сигнал или оранжевый дым днём говорят, что вам нужна немедленная помощь.","tr":"Kırmızı, fişek ve tehlike ışıkları için evrensel tehlike rengidir. Kırmızı fişek, kırmızı havai işaret veya gündüz turuncu duman, acil yardıma ihtiyacınız olduğunu bildirir.","hi":"लाल फ्लेयर और संकट प्रकाश के लिए सार्वभौमिक संकट रंग है। लाल फ्लेयर, लाल हवाई संकेत, या दिन में नारंगी धुआँ बताते हैं कि आपको तुरंत मदद चाहिए।","ar":"الأحمر هو لون الاستغاثة العالمي للشعلات وأضواء الاستغاثة. الشعلة الحمراء أو الإشارة الجوية الحمراء أو الدخان البرتقالي نهاراً تُبلّغ الآخرين بحاجتك لمساعدة فورية."}},{"cat":"equipment","a":2,"q":{"en":"On a small boat under 16 feet operating at night, what light equipment is required?","es":"En una embarcación menor de 16 pies navegando de noche, ¿qué equipo de luces se requiere?","ru":"На малой лодке длиной менее 16 футов, идущей ночью, какое световое оборудование требуется?","tr":"Gece seyreden 16 fitten küçük bir teknede hangi aydınlatma ekipmanı gereklidir?","hi":"रात में चल रही 16 फुट से छोटी नाव पर कौन सा प्रकाश उपकरण आवश्यक है?","ar":"في قارب صغير يقل طوله عن 16 قدماً يعمل ليلاً، ما معدات الإضاءة المطلوبة؟"},"o":[{"en":"No lights are ever required on small boats","es":"Nunca se requieren luces en embarcaciones pequeñas","ru":"На малых лодках огни никогда не требуются","tr":"Küçük teknelerde asla fener gerekmez","hi":"छोटी नावों पर कभी बत्तियाँ आवश्यक नहीं","ar":"لا تُطلب أضواء أبداً على القوارب الصغيرة"},{"en":"Only a red flashing light","es":"Solo una luz roja intermitente","ru":"Только красный проблесковый огонь","tr":"Yalnızca kırmızı yanıp sönen fener","hi":"केवल एक लाल चमकती बत्ती","ar":"ضوء أحمر وامض فقط"},{"en":"Proper navigation lights (sidelights and a white light) visible to other boats","es":"Las luces de navegación adecuadas (de costado y una blanca) visibles a otras embarcaciones","ru":"Надлежащие навигационные огни (бортовые и белый), видимые другим судам","tr":"Diğer teknelere görünen uygun seyir fenerleri (yan fenerler ve beyaz fener)","hi":"अन्य नावों को दिखने वाली उचित नौवहन बत्तियाँ (साइड बत्तियाँ और एक सफ़ेद बत्ती)","ar":"أضواء الملاحة المناسبة (أضواء جانبية وضوء أبيض) مرئية للقوارب الأخرى"},{"en":"A spotlight aimed forward at all times","es":"Un reflector apuntando siempre hacia adelante","ru":"Постоянно направленный вперёд прожектор","tr":"Sürekli öne yönelik bir projektör","hi":"हमेशा आगे की ओर लक्षित एक स्पॉटलाइट","ar":"كشّاف موجّه للأمام دائماً"}],"e":{"en":"All boats operating between sunset and sunrise, or in reduced visibility, must display proper navigation lights so others can see them and judge their direction. A spotlight is not a substitute.","es":"Todas las embarcaciones que naveguen entre el atardecer y el amanecer, o con visibilidad reducida, deben mostrar luces de navegación adecuadas para que otros las vean y juzguen su dirección. Un reflector no las sustituye.","ru":"Все суда, идущие с заката до восхода или при ограниченной видимости, должны нести надлежащие навигационные огни, чтобы их видели и определяли направление. Прожектор их не заменяет.","tr":"Gün batımından gün doğumuna dek ya da azalan görüşte seyreden tüm tekneler, başkalarının görüp yönlerini anlaması için uygun seyir fenerleri göstermelidir. Projektör bunların yerini tutmaz.","hi":"सूर्यास्त से सूर्योदय तक या कम दृश्यता में चल रही सभी नावों को उचित नौवहन बत्तियाँ दिखानी चाहिए ताकि दूसरे उन्हें देख सकें और दिशा समझ सकें। स्पॉटलाइट इनका विकल्प नहीं है।","ar":"يجب أن تُظهِر كل القوارب العاملة بين الغروب والشروق أو في الرؤية المحدودة أضواء ملاحة مناسبة ليراها الآخرون ويحدّدوا اتجاهها. الكشّاف ليس بديلاً عنها."}},{"cat":"equipment","a":3,"q":{"en":"A sound signal such as a whistle attached to a life jacket helps you:","es":"Una señal sonora como un silbato sujeto al chaleco lo ayuda a:","ru":"Звуковое средство, например свисток на спасательном жилете, помогает вам:","tr":"Can yeleğine takılı düdük gibi bir ses işareti size ne sağlar?","hi":"लाइफ जैकेट से जुड़ी सीटी जैसा ध्वनि संकेत आपको मदद करता है:","ar":"إشارة صوتية مثل صافرة مثبّتة على سترة النجاة تساعدك على:"},"o":[{"en":"Swim faster","es":"Nadar más rápido","ru":"Плыть быстрее","tr":"Daha hızlı yüzmek","hi":"तेज़ तैरना","ar":"السباحة أسرع"},{"en":"Catch more fish","es":"Pescar más","ru":"Ловить больше рыбы","tr":"Daha çok balık tutmak","hi":"अधिक मछली पकड़ना","ar":"اصطياد سمك أكثر"},{"en":"Float higher","es":"Flotar más alto","ru":"Держаться выше на воде","tr":"Daha yükseğe yüzmek","hi":"अधिक ऊँचा तैरना","ar":"الطفو أعلى"},{"en":"Attract attention and be located if you are in the water","es":"Atraer atención y ser localizado si está en el agua","ru":"Привлечь внимание и быть найденным, если вы в воде","tr":"Suda iseniz dikkat çekmek ve konumunuzun bulunması","hi":"पानी में होने पर ध्यान आकर्षित करना और अपना पता बताना","ar":"جذب الانتباه وتحديد موقعك إذا كنت في الماء"}],"e":{"en":"Attaching a whistle to your life jacket lets you signal for help and be located, even when you are too tired, cold, or far away to shout. It is a simple but life-saving addition.","es":"Sujetar un silbato al chaleco le permite pedir ayuda y ser localizado, incluso cuando está demasiado cansado, con frío o lejos para gritar. Es un añadido simple pero salvavidas.","ru":"Свисток на жилете позволяет подать сигнал о помощи и быть найденным, даже когда вы слишком устали, замёрзли или далеко, чтобы кричать. Простое, но спасающее жизнь дополнение.","tr":"Can yeleğinize düdük takmak, bağıramayacak kadar yorgun, üşümüş ya da uzakta olsanız bile yardım işareti vermenizi ve bulunmanızı sağlar. Basit ama hayat kurtaran bir eklentidir.","hi":"लाइफ जैकेट से सीटी जोड़ना आपको मदद के लिए संकेत देने और अपना पता बताने देता है, तब भी जब आप चिल्लाने के लिए बहुत थके, ठंडे या दूर हों। यह सरल पर जीवनरक्षक जोड़ है।","ar":"تثبيت صافرة على سترة النجاة يتيح لك طلب المساعدة وتحديد موقعك، حتى عندما تكون متعباً أو بارداً أو بعيداً عن الصياح. إضافة بسيطة لكنها منقذة للحياة."}},{"cat":"equipment","a":0,"q":{"en":"An inflatable life jacket is a good choice for many adults because it:","es":"Un chaleco salvavidas inflable es una buena opción para muchos adultos porque:","ru":"Надувной спасательный жилет — хороший выбор для многих взрослых, потому что он:","tr":"Şişme bir can yeleği birçok yetişkin için iyi bir seçimdir çünkü:","hi":"इन्फ्लेटेबल लाइफ जैकेट कई वयस्कों के लिए एक अच्छा विकल्प है क्योंकि यह:","ar":"سترة النجاة القابلة للنفخ خيار جيد لكثير من البالغين لأنها:"},"o":[{"en":"Is comfortable and less bulky, encouraging people to actually wear it (must be worn to count and kept serviced)","es":"Es cómodo y poco voluminoso, lo que anima a usarlo (debe llevarse puesto para contar y mantenerse en servicio)","ru":"Удобен и менее громоздок, что побуждает его носить (должен быть надет, чтобы засчитываться, и обслуживаться)","tr":"Rahat ve daha az hantaldır, giyilmesini teşvik eder (sayılması için giyilmeli ve bakımı yapılmalı)","hi":"आरामदायक और कम भारी है, जिससे लोग इसे सचमुच पहनते हैं (गिनने के लिए पहनना और सर्विस बनाए रखना ज़रूरी)","ar":"مريحة وأقل ضخامة، ما يشجّع على ارتدائها فعلاً (يجب ارتداؤها لتُحتسب والحفاظ على صيانتها)"},{"en":"Never needs any maintenance","es":"Nunca necesita mantenimiento","ru":"Никогда не требует обслуживания","tr":"Hiç bakım gerektirmez","hi":"इसे कभी रखरखाव की ज़रूरत नहीं","ar":"لا تحتاج أي صيانة أبداً"},{"en":"Works well for weak swimmers and small children","es":"Funciona bien para nadadores débiles y niños pequeños","ru":"Хорошо подходит для слабых пловцов и маленьких детей","tr":"Zayıf yüzücüler ve küçük çocuklar için iyi çalışır","hi":"कमज़ोर तैराकों और छोटे बच्चों के लिए अच्छा है","ar":"تعمل جيداً لضعيفي السباحة والأطفال الصغار"},{"en":"Inflates automatically even when stored","es":"Se infla solo incluso guardado","ru":"Надувается сам даже при хранении","tr":"Depolanırken bile kendiliğinden şişer","hi":"भंडारित रहने पर भी अपने आप फूल जाता है","ar":"تنتفخ تلقائياً حتى وهي مخزّنة"}],"e":{"en":"Inflatable life jackets are comfortable and compact so people are more likely to wear them, but they must be worn to count, need regular inspection of the CO2 cartridge, and are not for weak swimmers or young children.","es":"Los chalecos inflables son cómodos y compactos, por lo que es más probable usarlos, pero deben llevarse puestos para contar, requieren revisar el cartucho de CO2 y no son para nadadores débiles ni niños pequeños.","ru":"Надувные жилеты удобны и компактны, поэтому их охотнее носят, но их нужно носить, чтобы засчитывались, регулярно проверять баллончик CO2, и они не для слабых пловцов и малышей.","tr":"Şişme can yelekleri rahat ve kompakttır, bu yüzden giyilmeleri daha olasıdır; ancak sayılması için giyilmeli, CO2 kartuşu düzenli kontrol edilmeli ve zayıf yüzücüler ile küçük çocuklar için uygun değildir.","hi":"इन्फ्लेटेबल लाइफ जैकेट आरामदायक और कॉम्पैक्ट हैं इसलिए लोग इन्हें पहनते हैं, पर गिनने के लिए इन्हें पहनना ज़रूरी है, CO2 कार्ट्रिज की नियमित जाँच चाहिए, और ये कमज़ोर तैराकों या छोटे बच्चों के लिए नहीं हैं।","ar":"سترات النجاة القابلة للنفخ مريحة وصغيرة الحجم فيميل الناس لارتدائها، لكن يجب ارتداؤها لتُحتسب، وتحتاج فحصاً منتظماً لخرطوشة CO2، وليست لضعيفي السباحة أو الأطفال الصغار."}},{"cat":"equipment","a":1,"q":{"en":"How many fire extinguishers a boat must carry depends mainly on:","es":"La cantidad de extintores que debe llevar una embarcación depende principalmente de:","ru":"Сколько огнетушителей должно быть на судне, зависит главным образом от:","tr":"Bir teknenin bulundurması gereken yangın söndürücü sayısı esas olarak neye bağlıdır?","hi":"नाव को कितने अग्निशामक रखने चाहिए, यह मुख्यतः किस पर निर्भर करता है:","ar":"يعتمد عدد طفايات الحريق التي يجب أن يحملها القارب أساساً على:"},"o":[{"en":"The color of the boat","es":"El color de la embarcación","ru":"Цвета лодки","tr":"Teknenin rengi","hi":"नाव के रंग","ar":"لون القارب"},{"en":"The length of the boat and whether it has enclosed spaces where vapors can collect","es":"La eslora de la embarcación y si tiene espacios cerrados donde se acumulen vapores","ru":"Длины судна и наличия закрытых пространств, где могут скапливаться пары","tr":"Teknenin boyu ve buharların birikebileceği kapalı alanların olup olmadığı","hi":"नाव की लंबाई और क्या इसमें बंद स्थान हैं जहाँ वाष्प जमा हो सकते हैं","ar":"طول القارب ووجود مساحات مغلقة يمكن أن تتجمّع فيها الأبخرة"},{"en":"How many people can swim","es":"Cuántas personas saben nadar","ru":"Числа людей, умеющих плавать","tr":"Kaç kişinin yüzebildiği","hi":"कितने लोग तैर सकते हैं","ar":"عدد من يجيدون السباحة"},{"en":"The engine brand","es":"La marca del motor","ru":"Марки двигателя","tr":"Motorun markası","hi":"इंजन के ब्रांड","ar":"علامة المحرك التجارية"}],"e":{"en":"The number and size of required fire extinguishers depend on the boat's length and construction (enclosed engine or fuel spaces). Longer boats and those with enclosed compartments need more or larger extinguishers.","es":"El número y tamaño de extintores requeridos dependen de la eslora y la construcción (espacios cerrados de motor o combustible). Las embarcaciones más largas o con compartimentos cerrados necesitan más o mayores.","ru":"Число и размер обязательных огнетушителей зависят от длины судна и его конструкции (закрытые моторные или топливные отсеки). Длинным судам и с закрытыми отсеками нужно больше или крупнее.","tr":"Gerekli yangın söndürücülerin sayısı ve boyutu, teknenin boyuna ve yapısına (kapalı motor veya yakıt alanları) bağlıdır. Daha uzun ve kapalı bölmeli tekneler daha çok veya daha büyük söndürücü gerektirir.","hi":"आवश्यक अग्निशामकों की संख्या और आकार नाव की लंबाई और निर्माण (बंद इंजन या ईंधन स्थान) पर निर्भर करते हैं। लंबी और बंद कक्षों वाली नावों को अधिक या बड़े अग्निशामक चाहिए।","ar":"يعتمد عدد وحجم طفايات الحريق المطلوبة على طول القارب وبنيته (مساحات محرك أو وقود مغلقة). القوارب الأطول وذات المقصورات المغلقة تحتاج طفايات أكثر أو أكبر."}},{"cat":"equipment","a":2,"q":{"en":"Where should a fire extinguisher be mounted on a boat?","es":"¿Dónde debe montarse un extintor en una embarcación?","ru":"Где следует крепить огнетушитель на судне?","tr":"Yangın söndürücü teknede nereye monte edilmelidir?","hi":"नाव पर अग्निशामक कहाँ लगाया जाना चाहिए?","ar":"أين يجب تركيب طفاية الحريق على القارب؟"},"o":[{"en":"Locked away in a sealed storage box","es":"Bajo llave en una caja sellada","ru":"В запертом герметичном ящике","tr":"Kilitli, kapalı bir saklama kutusunda","hi":"एक सीलबंद स्टोरेज बॉक्स में बंद","ar":"مقفلة في صندوق تخزين محكم"},{"en":"Deep in the bilge","es":"En el fondo de la sentina","ru":"Глубоко в трюме","tr":"Sintinenin derininde","hi":"बिल्ज में गहरे","ar":"في عمق قاع القارب"},{"en":"In an accessible location away from the engine/galley, ready to grab quickly","es":"En un lugar accesible lejos del motor/cocina, listo para tomar rápido","ru":"В доступном месте вдали от двигателя/камбуза, готовым к быстрому доступу","tr":"Motordan/mutfaktan uzak, kolay ulaşılır bir yerde, hemen alınacak şekilde","hi":"इंजन/गैली से दूर एक सुलभ स्थान पर, जल्दी पकड़ने के लिए तैयार","ar":"في مكان يسهل الوصول إليه بعيداً عن المحرك/المطبخ، جاهزة للإمساك بسرعة"},{"en":"Anywhere it fits, even if blocked","es":"En cualquier lugar donde quepa, aunque quede bloqueado","ru":"Где угодно, даже если доступ перекрыт","tr":"Sığdığı her yerde, engellenmiş olsa bile","hi":"जहाँ भी फिट हो, भले अवरुद्ध हो","ar":"في أي مكان يتّسع لها ولو كانت محجوبة"}],"e":{"en":"Mount extinguishers in accessible spots you can reach quickly — typically near the helm and away from likely fire sources like the galley or engine — never buried or behind locked doors.","es":"Monte los extintores en lugares accesibles y de fácil alcance —normalmente cerca del timón y lejos de fuentes de incendio como la cocina o el motor—, nunca escondidos ni tras puertas con llave.","ru":"Крепите огнетушители в доступных местах, до которых легко дотянуться — обычно у штурвала и вдали от вероятных источников огня (камбуз, двигатель) — никогда не заваливайте и не прячьте за запертыми дверцами.","tr":"Söndürücüleri hızlıca ulaşabileceğiniz erişilebilir yerlere monte edin — genellikle dümen yakınına ve mutfak ya da motor gibi olası yangın kaynaklarından uzağa — asla gömülü ya da kilitli kapılar ardında değil.","hi":"अग्निशामकों को सुलभ स्थानों पर लगाएँ जहाँ आप जल्दी पहुँच सकें — आमतौर पर पतवार के पास और गैली या इंजन जैसे संभावित आग स्रोतों से दूर — कभी दबा हुआ या बंद दरवाज़ों के पीछे नहीं।","ar":"ركّب الطفايات في أماكن يسهل الوصول إليها بسرعة — عادةً قرب الدفّة وبعيداً عن مصادر الحريق المحتملة كالمطبخ أو المحرك — وليست مدفونة أو خلف أبواب مقفلة."}},{"cat":"equipment","a":3,"q":{"en":"Which piece of equipment is designed to help a person who has fallen overboard get back aboard or stay afloat?","es":"¿Qué equipo está diseñado para ayudar a una persona que cayó al agua a volver a bordo o a mantenerse a flote?","ru":"Какое снаряжение предназначено помочь упавшему за борт вернуться на судно или удержаться на плаву?","tr":"Hangi ekipman, denize düşen kişinin tekneye geri dönmesine ya da su üstünde kalmasına yardımcı olacak şekilde tasarlanmıştır?","hi":"कौन सा उपकरण पानी में गिरे व्यक्ति को वापस नाव पर चढ़ने या तैरते रहने में मदद के लिए बनाया गया है?","ar":"أي معدة مصمّمة لمساعدة شخص سقط في الماء على العودة إلى القارب أو البقاء طافياً؟"},"o":[{"en":"A depth sounder","es":"Un ecosonda","ru":"Эхолот","tr":"Bir iskandil","hi":"एक डेप्थ साउंडर","ar":"مسبار العمق"},{"en":"A chartplotter","es":"Un trazador de cartas","ru":"Картплоттер","tr":"Bir harita çizici","hi":"एक चार्टप्लॉटर","ar":"راسم الخرائط"},{"en":"A bilge pump","es":"Una bomba de achique","ru":"Трюмная помпа","tr":"Bir sintine pompası","hi":"एक बिल्ज पंप","ar":"مضخة القاع"},{"en":"A Type IV throwable device (ring buoy or cushion) and a reboarding ladder","es":"Un dispositivo arrojable Tipo IV (aro o cojín) y una escalera de reembarque","ru":"Бросаемое средство типа IV (круг или подушка) и посадочный трап","tr":"Tip IV atılabilir cihaz (can simidi veya yastık) ve yeniden binme merdiveni","hi":"एक टाइप IV थ्रोएबल डिवाइस (रिंग बॉय या कुशन) और पुनः चढ़ने की सीढ़ी","ar":"جهاز قابل للرمي من النوع الرابع (طوق أو وسادة) وسلّم إعادة الصعود"}],"e":{"en":"A throwable Type IV device gives a person in the water something to hold onto, and a reboarding ladder helps them climb back aboard. Both make a man-overboard recovery faster and safer.","es":"Un dispositivo arrojable Tipo IV le da a la persona en el agua algo a lo que aferrarse, y una escalera de reembarque la ayuda a subir. Ambos hacen la recuperación más rápida y segura.","ru":"Бросаемое средство типа IV даёт человеку в воде опору, а посадочный трап помогает вернуться на борт. Вместе они делают спасение «человека за бортом» быстрее и безопаснее.","tr":"Atılabilir Tip IV cihaz, sudaki kişiye tutunacak bir şey verir; yeniden binme merdiveni tekneye tırmanmasına yardımcı olur. İkisi de denize adam düşmesi kurtarışını hızlandırır ve güvenli kılar.","hi":"टाइप IV थ्रोएबल डिवाइस पानी में व्यक्ति को पकड़ने के लिए कुछ देता है, और पुनः चढ़ने की सीढ़ी उसे वापस चढ़ने में मदद करती है। दोनों मैन-ओवरबोर्ड रिकवरी को तेज़ और सुरक्षित बनाते हैं।","ar":"يمنح الجهاز القابل للرمي من النوع الرابع الشخص في الماء ما يتمسّك به، ويساعده سلّم إعادة الصعود على العودة إلى القارب. كلاهما يجعل إنقاذ من سقط في الماء أسرع وأأمن."}},{"cat":"equipment","a":0,"q":{"en":"Why must the life jackets on board fit the people using them?","es":"¿Por qué deben los chalecos a bordo ajustarse a las personas que los usan?","ru":"Почему жилеты на борту должны подходить по размеру тем, кто их использует?","tr":"Teknedeki can yelekleri neden kullananlara uygun olmalıdır?","hi":"बोर्ड पर लाइफ जैकेट उन्हें उपयोग करने वाले लोगों को फिट क्यों होने चाहिए?","ar":"لماذا يجب أن تناسب سترات النجاة على متن القارب الأشخاص الذين يستخدمونها؟"},"o":[{"en":"An ill-fitting jacket can slip off or fail to keep the wearer's head above water","es":"Un chaleco mal ajustado puede salirse o no mantener la cabeza fuera del agua","ru":"Плохо сидящий жилет может соскользнуть или не удержать голову над водой","tr":"Uygun olmayan yelek çıkabilir ya da kullanıcının başını su üstünde tutamaz","hi":"गलत फिट जैकेट फिसल सकती है या पहनने वाले का सिर पानी के ऊपर रखने में असफल हो सकती है","ar":"السترة غير المناسبة قد تنزلق أو تفشل في إبقاء رأس مرتديها فوق الماء"},{"en":"It only affects the color","es":"Solo afecta el color","ru":"Это влияет только на цвет","tr":"Yalnızca rengi etkiler","hi":"यह केवल रंग को प्रभावित करता है","ar":"تؤثر على اللون فقط"},{"en":"Bigger jackets are always safer","es":"Los chalecos más grandes siempre son más seguros","ru":"Более крупные жилеты всегда безопаснее","tr":"Daha büyük yelekler her zaman daha güvenlidir","hi":"बड़े जैकेट हमेशा सुरक्षित होते हैं","ar":"السترات الأكبر أكثر أماناً دائماً"},{"en":"Fit does not matter for adults","es":"La talla no importa para adultos","ru":"Размер не важен для взрослых","tr":"Yetişkinler için beden önemsizdir","hi":"वयस्कों के लिए फिट मायने नहीं रखता","ar":"المقاس لا يهم للبالغين"}],"e":{"en":"A life jacket must fit snugly and match the wearer's weight and chest size. One that is too big can ride up or come off in the water; one too small will not float the person properly.","es":"Un chaleco debe ajustarse bien y corresponder al peso y talla del pecho. Uno muy grande puede subirse o salirse en el agua; uno muy pequeño no flotará bien a la persona.","ru":"Жилет должен плотно сидеть и соответствовать весу и обхвату груди. Слишком большой может задраться или слететь в воде; слишком маленький не удержит человека на плаву.","tr":"Can yeleği vücuda tam oturmalı ve kullanıcının kilosu ile göğüs ölçüsüne uygun olmalıdır. Çok büyük olan suda yukarı kayabilir ya da çıkabilir; çok küçük olan kişiyi düzgün yüzdürmez.","hi":"लाइफ जैकेट कसकर फिट होनी चाहिए और पहनने वाले के वज़न व छाती के आकार से मेल खानी चाहिए। बहुत बड़ी पानी में ऊपर खिसक या निकल सकती है; बहुत छोटी व्यक्ति को ठीक से नहीं तैराएगी।","ar":"يجب أن تناسب سترة النجاة الجسم بإحكام وتلائم وزن مرتديها ومقاس صدره. الكبيرة جداً قد ترتفع أو تنزلق في الماء، والصغيرة جداً لن تُطفي الشخص بشكل سليم."}},{"cat":"equipment","a":2,"q":{"en":"Which of the following is a good reason to carry a marine VHF radio aboard?","es":"¿Cuál de las siguientes es una buena razón para llevar una radio VHF marina a bordo?","ru":"Что из перечисленного — веская причина иметь на борту морскую УКВ-радиостанцию (VHF)?","tr":"Aşağıdakilerden hangisi teknede deniz VHF telsizi bulundurmak için iyi bir nedendir?","hi":"निम्न में से कौन सा बोर्ड पर समुद्री VHF रेडियो रखने का एक अच्छा कारण है?","ar":"أي مما يلي سبب وجيه لحمل جهاز راديو VHF بحري على متن القارب؟"},"o":[{"en":"To listen to music stations","es":"Para escuchar estaciones de música","ru":"Чтобы слушать музыкальные станции","tr":"Müzik istasyonlarını dinlemek için","hi":"संगीत स्टेशन सुनने के लिए","ar":"للاستماع إلى محطات الموسيقى"},{"en":"To replace navigation lights","es":"Para reemplazar las luces de navegación","ru":"Чтобы заменить навигационные огни","tr":"Seyir fenerlerinin yerine geçmesi için","hi":"नौवहन बत्तियों की जगह लेने के लिए","ar":"ليحلّ محل أضواء الملاحة"},{"en":"To call for help and receive weather and safety broadcasts (Channel 16 is the hailing/distress channel)","es":"Para pedir ayuda y recibir avisos de clima y seguridad (el canal 16 es de llamada/socorro)","ru":"Чтобы вызвать помощь и получать сводки погоды и безопасности (канал 16 — вызывной/бедствия)","tr":"Yardım çağırmak ve hava/güvenlik yayınlarını almak için (Kanal 16 çağrı/tehlike kanalıdır)","hi":"मदद के लिए कॉल करने और मौसम व सुरक्षा प्रसारण प्राप्त करने के लिए (चैनल 16 हेलिंग/संकट चैनल है)","ar":"لطلب المساعدة وتلقّي نشرات الطقس والسلامة (القناة 16 هي قناة النداء/الاستغاثة)"},{"en":"To increase engine power","es":"Para aumentar la potencia del motor","ru":"Чтобы увеличить мощность двигателя","tr":"Motor gücünü artırmak için","hi":"इंजन की शक्ति बढ़ाने के लिए","ar":"لزيادة قوة المحرك"}],"e":{"en":"A marine VHF radio lets you call for help, hear weather and safety broadcasts, and communicate with other boats and the Coast Guard. Channel 16 is monitored for hailing and distress calls.","es":"Una radio VHF marina permite pedir ayuda, oír avisos de clima y seguridad y comunicarse con otras embarcaciones y la Guardia Costera. El canal 16 se vigila para llamadas y socorro.","ru":"Морская УКВ-радиостанция позволяет вызвать помощь, слушать сводки погоды и безопасности и связываться с другими судами и Береговой охраной. Канал 16 контролируется для вызовов и бедствия.","tr":"Deniz VHF telsizi yardım çağırmanızı, hava ve güvenlik yayınlarını dinlemenizi ve diğer teknelerle Sahil Güvenlik ile iletişimi sağlar. Kanal 16 çağrı ve tehlike için izlenir.","hi":"समुद्री VHF रेडियो आपको मदद के लिए कॉल करने, मौसम व सुरक्षा प्रसारण सुनने, और अन्य नावों व कोस्ट गार्ड से संपर्क करने देता है। चैनल 16 हेलिंग व संकट कॉल के लिए मॉनिटर किया जाता है।","ar":"يتيح لك راديو VHF البحري طلب المساعدة وسماع نشرات الطقس والسلامة والتواصل مع القوارب الأخرى وخفر السواحل. تُراقَب القناة 16 لنداءات الاتصال والاستغاثة."}},{"cat":"emergencies","a":1,"q":{"en":"If your small boat capsizes but stays afloat, what should you usually do?","es":"Si su embarcación pequeña vuelca pero sigue a flote, ¿qué debe hacer normalmente?","ru":"Если ваша небольшая лодка перевернулась, но осталась на плаву, что обычно следует делать?","tr":"Küçük tekneniz alabora olur ama batmadan su üstünde kalırsa genellikle ne yapmalısınız?","hi":"यदि आपकी छोटी नाव पलट जाए पर तैरती रहे, तो आपको सामान्यतः क्या करना चाहिए?","ar":"إذا انقلب قاربك الصغير لكنه بقي طافياً، فماذا يجب أن تفعل عادةً؟"},"o":[{"en":"Swim to shore alone as fast as possible","es":"Nadar solo a la orilla lo más rápido posible","ru":"Как можно быстрее плыть к берегу в одиночку","tr":"Tek başına olabildiğince hızlı kıyıya yüzmek","hi":"अकेले जितनी जल्दी हो सके किनारे तैरना","ar":"السباحة بمفردك إلى الشاطئ بأسرع ما يمكن"},{"en":"Stay with the boat, account for everyone, and climb on or hold on while signaling for help","es":"Quedarse con la embarcación, contar a todos y subirse o sujetarse mientras pide ayuda","ru":"Оставаться у лодки, пересчитать всех и забраться на неё или держаться, подавая сигнал о помощи","tr":"Tekneyle kalmak, herkesi saymak ve yardım işareti verirken üstüne çıkmak veya tutunmak","hi":"नाव के साथ रहना, सभी की गिनती करना, और मदद के संकेत देते हुए उस पर चढ़ना या पकड़े रहना","ar":"البقاء مع القارب وإحصاء الجميع والصعود عليه أو التمسّك به مع الإشارة لطلب المساعدة"},{"en":"Remove your life jacket to swim better","es":"Quitarse el chaleco para nadar mejor","ru":"Снять жилет, чтобы лучше плыть","tr":"Daha iyi yüzmek için can yeleğini çıkarmak","hi":"बेहतर तैरने के लिए लाइफ जैकेट उतारना","ar":"خلع سترة النجاة للسباحة أفضل"},{"en":"Dive under to retrieve gear first","es":"Bucear para recuperar el equipo primero","ru":"Сначала нырнуть за снаряжением","tr":"Önce eşyaları almak için dalmak","hi":"पहले सामान लेने के लिए गोता लगाना","ar":"الغوص لاسترجاع العتاد أولاً"}],"e":{"en":"Most small boats float even when swamped or capsized. Stay with the boat — it is easier to spot than a swimmer — keep your life jacket on, count heads, and signal for help.","es":"La mayoría de las embarcaciones pequeñas flotan aun inundadas o volcadas. Quédese con la embarcación —es más fácil de ver que un nadador—, mantenga el chaleco, cuente a todos y pida ayuda.","ru":"Большинство малых лодок держатся на плаву даже залитыми или перевёрнутыми. Оставайтесь у лодки — её легче заметить, чем пловца — не снимайте жилет, пересчитайте людей и подавайте сигнал.","tr":"Çoğu küçük tekne su alsa ya da alabora olsa bile yüzer. Tekneyle kalın — yüzücüden daha kolay görülür — can yeleğinizi çıkarmayın, herkesi sayın ve yardım işareti verin.","hi":"अधिकांश छोटी नावें पानी भरने या पलटने पर भी तैरती हैं। नाव के साथ रहें — यह तैराक की तुलना में आसानी से दिखती है — लाइफ जैकेट पहने रहें, सिर गिनें और मदद के संकेत दें।","ar":"تطفو معظم القوارب الصغيرة حتى عند غمرها أو انقلابها. ابقَ مع القارب — فرؤيته أسهل من رؤية سابح — وأبقِ سترة نجاتك، وأحصِ الجميع، وأشر لطلب المساعدة."}},{"cat":"emergencies","a":0,"q":{"en":"Someone falls overboard. What is the first thing the operator should do?","es":"Alguien cae al agua. ¿Qué es lo primero que debe hacer el operador?","ru":"Человек упал за борт. Что судоводитель должен сделать в первую очередь?","tr":"Biri denize düşer. Operatörün yapması gereken ilk şey nedir?","hi":"कोई पानी में गिर जाता है। चालक को सबसे पहले क्या करना चाहिए?","ar":"سقط شخص في الماء. ما أول ما يجب أن يفعله المشغّل؟"},"o":[{"en":"Reduce speed, keep the person in sight, and assign someone to point at them","es":"Reducir la velocidad, mantener a la persona a la vista y asignar a alguien para que la señale","ru":"Снизить скорость, не терять человека из виду и назначить кого-то указывать на него","tr":"Hızı azaltmak, kişiyi görüş alanında tutmak ve birine onu işaret etme görevi vermek","hi":"गति कम करना, व्यक्ति को नज़र में रखना, और किसी को उस पर इशारा करने के लिए नियुक्त करना","ar":"تخفيف السرعة وإبقاء الشخص في مرمى البصر وتكليف شخص بالإشارة إليه"},{"en":"Speed up to get help faster","es":"Acelerar para conseguir ayuda más rápido","ru":"Ускориться, чтобы быстрее позвать помощь","tr":"Yardımı çabuk getirmek için hızlanmak","hi":"मदद जल्दी लाने के लिए गति बढ़ाना","ar":"التسريع لجلب المساعدة أسرع"},{"en":"Jump in immediately after them","es":"Saltar de inmediato tras ellos","ru":"Немедленно прыгнуть за ним","tr":"Hemen arkasından atlamak","hi":"तुरंत उनके पीछे कूदना","ar":"القفز خلفه فوراً"},{"en":"Continue on course and circle back later","es":"Seguir el rumbo y volver más tarde","ru":"Продолжать курс и вернуться позже","tr":"Rotaya devam edip sonra dönmek","hi":"मार्ग पर चलते रहना और बाद में लौटना","ar":"المتابعة في المسار والعودة لاحقاً"}],"e":{"en":"Immediately slow down, keep the victim in sight, and have someone continuously point at them so they are not lost. Then throw a flotation device and maneuver carefully to recover them.","es":"Reduzca la velocidad de inmediato, mantenga a la víctima a la vista y haga que alguien la señale continuamente para no perderla. Luego lance un flotador y maniobre con cuidado para recuperarla.","ru":"Сразу сбавьте ход, не теряйте пострадавшего из виду и поручите кому-то постоянно указывать на него, чтобы не потерять. Затем бросьте плавсредство и осторожно маневрируйте для подъёма.","tr":"Hemen yavaşlayın, kazazedeyi görüş alanında tutun ve birinin sürekli onu işaret etmesini sağlayın ki kaybolmasın. Sonra bir yüzdürme cihazı atın ve dikkatlice manevra yaparak alın.","hi":"तुरंत गति कम करें, पीड़ित को नज़र में रखें, और किसी को लगातार उन पर इशारा करने को कहें ताकि वे खो न जाएँ। फिर फ्लोटेशन डिवाइस फेंकें और सावधानी से मैन्युवर कर उन्हें निकालें।","ar":"خفّف السرعة فوراً، وأبقِ الضحية في مرمى البصر، وكلّف شخصاً بالإشارة إليه باستمرار حتى لا يُفقَد. ثم ارمِ جهاز طفو وناور بحذر لاستعادته."}},{"cat":"emergencies","a":3,"q":{"en":"When recovering a person from the water, you should approach with the:","es":"Al recuperar a una persona del agua, debe aproximarse con:","ru":"При подъёме человека из воды подходить следует:","tr":"Bir kişiyi sudan alırken nasıl yaklaşmalısınız?","hi":"पानी से किसी व्यक्ति को निकालते समय, आपको कैसे पहुँचना चाहिए:","ar":"عند استعادة شخص من الماء، يجب أن تقترب:"},"o":[{"en":"Bow pointed away and engine at full throttle","es":"Con la proa apuntando lejos y el motor a fondo","ru":"Носом от него и на полном газу","tr":"Baş uzağa dönük ve motor tam gazda","hi":"नाव की नाक दूर की ओर और इंजन पूरी गति पर","ar":"بالمقدمة بعيداً والمحرك بأقصى سرعة"},{"en":"Engine still in gear as you reach them","es":"Con el motor aún engranado al alcanzarlos","ru":"С включённой передачей, когда подходите","tr":"Onlara ulaşırken motor hâlâ viteste","hi":"उन तक पहुँचते समय इंजन अब भी गियर में","ar":"والمحرك ما زال في الترس عند الوصول إليه"},{"en":"Person on the windward (upwind) side so the boat drifts onto them","es":"Con la persona a barlovento para que la embarcación derive sobre ella","ru":"Так, чтобы человек был с наветренной стороны и лодку сносило на него","tr":"Kişi rüzgarüstü tarafta olacak şekilde, tekne üzerine sürüklensin","hi":"व्यक्ति हवा की ओर (अपविंड) ताकि नाव उन पर बहे","ar":"والشخص في الجهة المواجهة للريح ليجرف القارب نحوه"},{"en":"Person on the leeward (downwind) side and the engine shut off before they are near the boat","es":"Con la persona a sotavento y el motor apagado antes de que se acerque a la embarcación","ru":"Так, чтобы человек был с подветренной стороны, а двигатель заглушён до его приближения","tr":"Kişi rüzgaraltı tarafta ve kişi tekneye yaklaşmadan motor kapalı","hi":"व्यक्ति हवा के विपरीत (लीवर्ड) ओर और नाव के पास आने से पहले इंजन बंद","ar":"والشخص في الجهة المحمية من الريح والمحرك مُطفأ قبل اقترابه من القارب"}],"e":{"en":"Approach slowly from downwind so the boat does not drift onto the person, and turn the engine off before they come alongside so the propeller cannot injure them.","es":"Aproxímese despacio desde sotavento para que la embarcación no derive sobre la persona, y apague el motor antes de que llegue al costado para que la hélice no la lesione.","ru":"Подходите медленно с подветра, чтобы лодку не сносило на человека, и заглушите двигатель до того, как он окажется у борта, чтобы винт не поранил его.","tr":"Teknenin kişiye sürüklenmemesi için rüzgaraltından yavaşça yaklaşın ve pervanenin yaralamaması için kişi bordaya gelmeden motoru kapatın.","hi":"धीरे-धीरे हवा के विपरीत ओर से पहुँचें ताकि नाव व्यक्ति पर न बहे, और उनके नाव के किनारे आने से पहले इंजन बंद करें ताकि प्रोपेलर उन्हें चोट न पहुँचाए।","ar":"اقترب ببطء من الجهة المحمية من الريح حتى لا يجرف القارب نحو الشخص، وأطفئ المحرك قبل وصوله إلى جانب القارب حتى لا تؤذيه المروحة."}},{"cat":"emergencies","a":2,"q":{"en":"Carbon monoxide (CO) poisoning on a boat is dangerous because CO is:","es":"La intoxicación por monóxido de carbono (CO) en una embarcación es peligrosa porque el CO es:","ru":"Отравление угарным газом (CO) на судне опасно, потому что CO:","tr":"Teknede karbon monoksit (CO) zehirlenmesi tehlikelidir çünkü CO:","hi":"नाव पर कार्बन मोनोऑक्साइड (CO) विषाक्तता खतरनाक है क्योंकि CO:","ar":"التسمّم بأول أكسيد الكربون (CO) على القارب خطر لأن CO:"},"o":[{"en":"Bright red and easy to see","es":"Rojo brillante y fácil de ver","ru":"Ярко-красный и хорошо виден","tr":"Parlak kırmızı ve kolay görülür","hi":"चमकीला लाल और आसानी से दिखता है","ar":"أحمر لامع وسهل الرؤية"},{"en":"Harmless in small amounts","es":"Inofensivo en pequeñas cantidades","ru":"Безвреден в малых количествах","tr":"Küçük miktarlarda zararsız","hi":"छोटी मात्रा में हानिरहित","ar":"غير ضار بكميات صغيرة"},{"en":"Colorless and odorless, so it can build up and poison people without warning","es":"Incoloro e inodoro, por lo que puede acumularse y envenenar sin aviso","ru":"Бесцветный и без запаха, поэтому может незаметно скапливаться и отравлять людей","tr":"Renksiz ve kokusuz olduğundan uyarı vermeden birikip insanları zehirleyebilir","hi":"रंगहीन और गंधहीन, इसलिए यह बिना चेतावनी के जमा होकर लोगों को विषाक्त कर सकता है","ar":"عديم اللون والرائحة، فقد يتراكم ويسمّم الناس دون إنذار"},{"en":"Only a problem in cars","es":"Solo un problema en autos","ru":"Проблемой только в автомобилях","tr":"Yalnızca arabalarda sorun","hi":"केवल कारों में समस्या","ar":"مشكلة في السيارات فقط"}],"e":{"en":"CO is a colorless, odorless gas from engines and generators. It can accumulate in and around a boat and cause headaches, dizziness, or death. Early symptoms mimic seasickness or intoxication.","es":"El CO es un gas incoloro e inodoro de motores y generadores. Puede acumularse en y alrededor de la embarcación y causar dolor de cabeza, mareo o la muerte. Los primeros síntomas imitan el mareo o la embriaguez.","ru":"CO — бесцветный газ без запаха от двигателей и генераторов. Он может скапливаться на судне и вокруг него, вызывая головную боль, головокружение или смерть. Ранние симптомы похожи на морскую болезнь или опьянение.","tr":"CO, motor ve jeneratörlerden çıkan renksiz, kokusuz bir gazdır. Teknenin içinde ve çevresinde birikip baş ağrısı, baş dönmesi veya ölüme yol açabilir. Erken belirtiler deniz tutması ya da sarhoşluğa benzer.","hi":"CO इंजन और जेनरेटर से निकलने वाली रंगहीन, गंधहीन गैस है। यह नाव में और आसपास जमा होकर सिरदर्द, चक्कर या मृत्यु का कारण बन सकती है। शुरुआती लक्षण समुद्री बीमारी या नशे जैसे लगते हैं।","ar":"CO غاز عديم اللون والرائحة يصدر من المحركات والمولّدات. يمكن أن يتراكم داخل القارب وحوله ويسبّب صداعاً أو دوخة أو الموت. الأعراض المبكرة تشبه دوار البحر أو الثمالة."}},{"cat":"emergencies","a":1,"q":{"en":"Which activity most increases the risk of carbon monoxide poisoning near a boat?","es":"¿Qué actividad aumenta más el riesgo de intoxicación por monóxido de carbono cerca de una embarcación?","ru":"Какое действие сильнее всего повышает риск отравления угарным газом вблизи судна?","tr":"Hangi etkinlik tekne yakınında karbon monoksit zehirlenmesi riskini en çok artırır?","hi":"कौन सी गतिविधि नाव के पास कार्बन मोनोऑक्साइड विषाक्तता का जोखिम सबसे अधिक बढ़ाती है?","ar":"أي نشاط يزيد أكثر من خطر التسمّم بأول أكسيد الكربون قرب القارب؟"},"o":[{"en":"Standing on the bow","es":"Estar de pie en la proa","ru":"Стоять на носу","tr":"Baş tarafta durmak","hi":"नाव की नाक पर खड़े होना","ar":"الوقوف على المقدمة"},{"en":"\"Teak surfing\" or swimming/hanging near the stern or swim platform while the engine runs","es":"Hacer \"teak surfing\" o nadar/colgarse cerca de la popa o plataforma de baño con el motor en marcha","ru":"«Тик-сёрфинг» или плавание/висение у кормы или купальной платформы при работающем двигателе","tr":"Motor çalışırken \"teak surfing\" yapmak veya kıç ya da yüzme platformu yakınında yüzmek/tutunmak","hi":"इंजन चालू रहते \"टीक सर्फिंग\" या स्टर्न/स्विम प्लेटफ़ॉर्म के पास तैरना/लटकना","ar":"القيام بـ\"teak surfing\" أو السباحة/التعلّق قرب المؤخرة أو منصة السباحة والمحرك يعمل"},{"en":"Anchoring in open water","es":"Fondear en aguas abiertas","ru":"Стоять на якоре в открытой воде","tr":"Açık suda demirlemek","hi":"खुले पानी में लंगर डालना","ar":"الرسو في مياه مفتوحة"},{"en":"Wearing a life jacket","es":"Llevar puesto el chaleco","ru":"Носить спасательный жилет","tr":"Can yeleği giymek","hi":"लाइफ जैकेट पहनना","ar":"ارتداء سترة النجاة"}],"e":{"en":"Swimming, \"teak surfing,\" or hanging near the stern or swim platform while the engine or generator runs exposes people to concentrated exhaust. Keep everyone away from exhaust outlets and ventilate cabins.","es":"Nadar, hacer \"teak surfing\" o colgarse cerca de la popa o la plataforma de baño con el motor o generador en marcha expone a las personas a gases concentrados. Mantenga a todos lejos de las salidas de escape y ventile las cabinas.","ru":"Плавание, «тик-сёрфинг» или висение у кормы или купальной платформы при работающем двигателе или генераторе подвергает людей концентрированным выхлопам. Держите всех подальше от выхлопных отверстий и проветривайте каюты.","tr":"Motor veya jeneratör çalışırken kıç ya da yüzme platformu yakınında yüzmek, \"teak surfing\" yapmak veya tutunmak, insanları yoğun egzoza maruz bırakır. Herkesi egzoz çıkışlarından uzak tutun ve kabinleri havalandırın.","hi":"इंजन या जेनरेटर चालू रहते हुए स्टर्न या स्विम प्लेटफ़ॉर्म के पास तैरना, \"टीक सर्फिंग\" या लटकना लोगों को गाढ़े धुएँ के संपर्क में लाता है। सभी को एग्ज़ॉस्ट आउटलेट से दूर रखें और केबिन हवादार करें।","ar":"السباحة أو \"teak surfing\" أو التعلّق قرب المؤخرة أو منصة السباحة والمحرك أو المولّد يعمل يعرّض الناس لعادم مركّز. أبعِد الجميع عن مخارج العادم وهوِّ المقصورات."}},{"cat":"emergencies","a":0,"q":{"en":"If a fire starts on your boat while under way, one good early step is to:","es":"Si se inicia un incendio en su embarcación en marcha, un buen primer paso es:","ru":"Если на ходу возник пожар, одним из первых верных шагов будет:","tr":"Seyir halindeyken teknenizde yangın çıkarsa iyi bir ilk adım şudur:","hi":"यदि चलते समय आपकी नाव पर आग लगे, तो एक अच्छा शुरुआती कदम है:","ar":"إذا اندلع حريق في قاربك أثناء سيره، فمن الخطوات المبكرة الجيدة أن:"},"o":[{"en":"Position the boat so the fire is downwind (wind blows flames away from the boat and people)","es":"Colocar la embarcación de modo que el fuego quede a sotavento (el viento aleja las llamas de la embarcación y las personas)","ru":"Развернуть лодку так, чтобы огонь оказался с подветра (ветер относит пламя от лодки и людей)","tr":"Tekneyi, ateş rüzgaraltında kalacak şekilde konumlandırmak (rüzgar alevleri tekneden ve insanlardan uzağa savurur)","hi":"नाव को इस तरह रखना कि आग हवा के विपरीत ओर हो (हवा लपटों को नाव और लोगों से दूर उड़ाए)","ar":"توجيه القارب بحيث تكون النار في الجهة المحمية من الريح (تدفع الريح اللهب بعيداً عن القارب والناس)"},{"en":"Turn so the wind blows the flames across the boat","es":"Girar para que el viento arrastre las llamas por la embarcación","ru":"Повернуть так, чтобы ветер гнал пламя по лодке","tr":"Rüzgar alevleri tekne boyunca savuracak şekilde dönmek","hi":"मुड़ना ताकि हवा लपटों को नाव के आर-पार बहाए","ar":"الانعطاف بحيث تدفع الريح اللهب عبر القارب"},{"en":"Pour gasoline on it","es":"Echarle gasolina","ru":"Залить его бензином","tr":"Üzerine benzin dökmek","hi":"उस पर गैसोलीन डालना","ar":"سكب البنزين عليها"},{"en":"Speed up into the wind","es":"Acelerar contra el viento","ru":"Разогнаться против ветра","tr":"Rüzgara doğru hızlanmak","hi":"हवा की ओर गति बढ़ाना","ar":"التسريع نحو الريح"}],"e":{"en":"Turn the boat so the fire is downwind, keeping flames and smoke away from people and the fuel supply. Stop the engine if the fire is near it, use your extinguisher, and get everyone into life jackets.","es":"Gire la embarcación para que el fuego quede a sotavento, alejando llamas y humo de las personas y del combustible. Apague el motor si el fuego está cerca, use el extintor y ponga a todos el chaleco.","ru":"Разверните лодку так, чтобы огонь был с подветра, отводя пламя и дым от людей и топлива. Заглушите двигатель, если огонь рядом, примените огнетушитель и наденьте на всех жилеты.","tr":"Tekneyi ateş rüzgaraltında kalacak şekilde çevirin; alev ve dumanı insanlardan ve yakıttan uzak tutun. Yangın motora yakınsa motoru durdurun, söndürücüyü kullanın ve herkese can yeleği giydirin.","hi":"नाव को इस तरह मोड़ें कि आग हवा के विपरीत ओर हो, ताकि लपटें व धुआँ लोगों और ईंधन आपूर्ति से दूर रहें। यदि आग इंजन के पास हो तो इंजन बंद करें, अग्निशामक का उपयोग करें और सभी को लाइफ जैकेट पहनाएँ।","ar":"وجّه القارب بحيث تكون النار في الجهة المحمية من الريح، مبعِداً اللهب والدخان عن الناس وإمداد الوقود. أوقف المحرك إن كانت النار قربه، واستخدم الطفاية، وألبِس الجميع سترات النجاة."}},{"cat":"emergencies","a":3,"q":{"en":"By federal law, what must a boat operator do if involved in a collision or accident?","es":"Por ley federal, ¿qué debe hacer el operador de una embarcación si se ve implicado en una colisión o accidente?","ru":"По федеральному закону, что обязан сделать судоводитель при столкновении или происшествии?","tr":"Federal yasaya göre, bir çarpışma veya kazaya karışan tekne operatörü ne yapmalıdır?","hi":"संघीय कानून के अनुसार, टक्कर या दुर्घटना में शामिल होने पर नाव चालक को क्या करना चाहिए?","ar":"بموجب القانون الفيدرالي، ماذا يجب أن يفعل مشغّل القارب إذا تورّط في تصادم أو حادث؟"},"o":[{"en":"Leave the scene quickly to avoid blame","es":"Abandonar el lugar rápidamente para evitar culpas","ru":"Быстро покинуть место, чтобы избежать вины","tr":"Suçlanmamak için olay yerini hızla terk etmek","hi":"दोष से बचने के लिए घटनास्थल जल्दी छोड़ देना","ar":"مغادرة المكان بسرعة لتجنّب اللوم"},{"en":"Do nothing unless someone complains","es":"No hacer nada salvo que alguien se queje","ru":"Ничего не делать, если никто не жалуется","tr":"Biri şikayet etmedikçe hiçbir şey yapmamak","hi":"जब तक कोई शिकायत न करे कुछ न करना","ar":"عدم فعل شيء ما لم يشتكِ أحد"},{"en":"Only exchange phone numbers","es":"Solo intercambiar números de teléfono","ru":"Только обменяться телефонами","tr":"Yalnızca telefon numarası alışverişi yapmak","hi":"केवल फ़ोन नंबरों का आदान-प्रदान करना","ar":"تبادل أرقام الهواتف فقط"},{"en":"Stop, render assistance to others if it can be done safely, and exchange identifying information","es":"Detenerse, prestar auxilio a otros si puede hacerse con seguridad e intercambiar datos de identificación","ru":"Остановиться, оказать помощь другим, если это безопасно, и обменяться идентифицирующими данными","tr":"Durmak, güvenle yapılabiliyorsa diğerlerine yardım etmek ve kimlik bilgilerini paylaşmak","hi":"रुकना, यदि सुरक्षित रूप से किया जा सके तो दूसरों की सहायता करना, और पहचान जानकारी का आदान-प्रदान करना","ar":"التوقف وتقديم المساعدة للآخرين إن أمكن بأمان وتبادل معلومات التعريف"}],"e":{"en":"Operators must stop, render assistance to anyone injured or endangered if it can be done without serious danger to their own boat and people, and give their name, address, and vessel identification.","es":"Los operadores deben detenerse, prestar auxilio a los heridos o en peligro si puede hacerse sin grave riesgo para su propia embarcación y personas, y dar su nombre, dirección e identificación de la embarcación.","ru":"Судоводители обязаны остановиться, оказать помощь пострадавшим или тем, кто в опасности, если это возможно без серьёзной угрозы для своего судна и людей, и сообщить своё имя, адрес и данные судна.","tr":"Operatörler durmalı; kendi teknesi ve insanları için ciddi tehlike olmadan yapılabiliyorsa yaralı ya da tehlikedeki kişilere yardım etmeli ve ad, adres ile tekne kimliğini vermelidir.","hi":"चालकों को रुकना चाहिए, यदि अपनी नाव और लोगों को गंभीर खतरे के बिना संभव हो तो घायल या खतरे में पड़े किसी की सहायता करनी चाहिए, और अपना नाम, पता व नाव पहचान देनी चाहिए।","ar":"على المشغّلين التوقف وتقديم المساعدة لأي مصاب أو في خطر إن أمكن دون تعريض قاربهم وأشخاصهم لخطر جسيم، وإعطاء الاسم والعنوان وهوية المركب."}},{"cat":"emergencies","a":2,"q":{"en":"You come upon another boater who is in distress. Under the \"duty to assist,\" you should:","es":"Se encuentra con otro navegante en peligro. Según el \"deber de auxilio\", debe:","ru":"Вы встречаете другого судоводителя, терпящего бедствие. Согласно «обязанности оказать помощь», вы должны:","tr":"Tehlikedeki başka bir denizciyle karşılaşıyorsunuz. \"Yardım etme görevi\" gereği:","hi":"आप संकट में पड़े किसी अन्य नाविक के पास पहुँचते हैं। \"सहायता करने के कर्तव्य\" के तहत, आपको चाहिए:","ar":"تصادف بحّاراً آخر في ضائقة. بموجب \"واجب المساعدة\"، عليك أن:"},"o":[{"en":"Ignore them — it is not your problem","es":"Ignorarlos: no es su problema","ru":"Игнорировать — это не ваша проблема","tr":"Onları görmezden gelmek — sizin sorununuz değil","hi":"उन्हें अनदेखा करना — यह आपकी समस्या नहीं","ar":"تتجاهله — فهذه ليست مشكلتك"},{"en":"Charge them a fee before helping","es":"Cobrarles una tarifa antes de ayudar","ru":"Взять с них плату перед помощью","tr":"Yardım etmeden önce ücret almak","hi":"मदद से पहले उनसे शुल्क वसूलना","ar":"تتقاضى منه رسوماً قبل المساعدة"},{"en":"Provide assistance as long as you can do so without seriously endangering your own boat or passengers","es":"Prestar auxilio siempre que pueda hacerlo sin poner en grave peligro su embarcación o pasajeros","ru":"Оказать помощь, если это можно сделать без серьёзной угрозы своему судну или пассажирам","tr":"Kendi tekneniz veya yolcularınızı ciddi tehlikeye atmadan yapabildiğiniz sürece yardım etmek","hi":"जब तक आप अपनी नाव या यात्रियों को गंभीर खतरे में डाले बिना कर सकें, सहायता प्रदान करना","ar":"تقدّم المساعدة ما دام بإمكانك ذلك دون تعريض قاربك أو ركابك لخطر جسيم"},{"en":"Only help if they are a friend","es":"Ayudar solo si son amigos","ru":"Помогать только если это друг","tr":"Yalnızca arkadaşınızsa yardım etmek","hi":"केवल तभी मदद करना यदि वे मित्र हों","ar":"تساعد فقط إن كان صديقاً"}],"e":{"en":"Boaters have a legal and moral duty to assist anyone in danger at sea, as long as doing so does not put your own vessel or passengers in serious danger. Radio for help if you cannot assist safely.","es":"Los navegantes tienen el deber legal y moral de auxiliar a quien esté en peligro en el mar, siempre que no ponga en grave riesgo su embarcación o pasajeros. Pida ayuda por radio si no puede auxiliar con seguridad.","ru":"Судоводители имеют юридическую и моральную обязанность помогать любому в опасности на воде, если это не создаёт серьёзной угрозы своему судну или пассажирам. Вызовите помощь по радио, если помочь безопасно нельзя.","tr":"Denizciler, kendi teknesini veya yolcularını ciddi tehlikeye atmadığı sürece denizde tehlikedeki herkese yardım etmekle yasal ve ahlaki olarak yükümlüdür. Güvenle yardım edemiyorsanız telsizle yardım isteyin.","hi":"नाविकों का समुद्र में खतरे में पड़े किसी की भी सहायता करने का कानूनी व नैतिक कर्तव्य है, जब तक ऐसा करने से आपकी अपनी नाव या यात्री गंभीर खतरे में न पड़ें। यदि सुरक्षित रूप से मदद न कर सकें तो रेडियो पर मदद माँगें।","ar":"على البحّارة واجب قانوني وأخلاقي بمساعدة أي شخص في خطر في البحر، ما دام ذلك لا يعرّض قاربهم أو ركابهم لخطر جسيم. اطلب المساعدة بالراديو إن لم تستطع المساعدة بأمان."}},{"cat":"emergencies","a":1,"q":{"en":"What is a proper way to signal for help if you have no radio or flares?","es":"¿Cuál es una forma correcta de pedir ayuda si no tiene radio ni bengalas?","ru":"Как правильно подать сигнал о помощи, если нет ни радио, ни фальшфейеров?","tr":"Telsiz veya fişeğiniz yoksa yardım istemenin uygun bir yolu nedir?","hi":"यदि आपके पास रेडियो या फ्लेयर नहीं है तो मदद के लिए संकेत देने का एक उचित तरीका क्या है?","ar":"ما الطريقة الصحيحة لطلب المساعدة إذا لم يكن لديك راديو أو شعلات؟"},"o":[{"en":"Wave your hat casually","es":"Agitar el sombrero de forma casual","ru":"Небрежно помахать шляпой","tr":"Şapkanızı gelişigüzel sallamak","hi":"अपनी टोपी को यूँ ही हिलाना","ar":"تلوّح بقبعتك بشكل عابر"},{"en":"Slowly and repeatedly raise and lower your outstretched arms at your sides","es":"Levantar y bajar lenta y repetidamente los brazos extendidos a los costados","ru":"Медленно и многократно поднимать и опускать вытянутые в стороны руки","tr":"Yanlara açtığınız kollarınızı yavaş ve tekrar tekrar kaldırıp indirmek","hi":"अपनी फैली हुई बाहों को धीरे-धीरे और बार-बार बगल में ऊपर-नीचे करना","ar":"رفع ذراعيك الممدودتين إلى الجانبين وخفضهما ببطء وتكرار"},{"en":"Turn off all your lights","es":"Apagar todas sus luces","ru":"Выключить все огни","tr":"Tüm ışıklarınızı kapatmak","hi":"अपनी सभी बत्तियाँ बंद करना","ar":"إطفاء جميع أضوائك"},{"en":"Sit still and wait quietly","es":"Quedarse quieto y esperar en silencio","ru":"Сидеть неподвижно и тихо ждать","tr":"Hareketsiz oturup sessizce beklemek","hi":"चुपचाप बैठकर इंतज़ार करना","ar":"الجلوس بلا حراك والانتظار بهدوء"}],"e":{"en":"The recognized visual distress gesture is slowly and repeatedly raising and lowering your outstretched arms. You can also use a mirror flash, orange flag, dye marker, or continuous horn blasts.","es":"El gesto de socorro reconocido es levantar y bajar lenta y repetidamente los brazos extendidos. También puede usar el destello de un espejo, una bandera naranja, colorante o pitidos continuos.","ru":"Признанный визуальный жест бедствия — медленно и многократно поднимать и опускать вытянутые руки. Также можно использовать зеркальный отблеск, оранжевый флаг, краситель или непрерывные гудки.","tr":"Tanınan görsel tehlike işareti, açtığınız kolları yavaş ve tekrar tekrar kaldırıp indirmektir. Ayrıca ayna yansıması, turuncu bayrak, boya işaretleyici veya sürekli korna kullanabilirsiniz.","hi":"मान्यता प्राप्त दृश्य संकट संकेत है फैली हुई बाहों को धीरे-धीरे और बार-बार ऊपर-नीचे करना। आप शीशे की चमक, नारंगी झंडा, डाई मार्कर या लगातार हॉर्न का भी उपयोग कर सकते हैं।","ar":"إشارة الاستغاثة المرئية المعترف بها هي رفع ذراعيك الممدودتين وخفضهما ببطء وتكرار. يمكنك أيضاً استخدام وميض مرآة أو علم برتقالي أو صبغة تلوين أو نفخات بوق مستمرة."}},{"cat":"emergencies","a":0,"q":{"en":"If your engine stops and you start drifting toward danger (rocks, a dam, heavy surf), a good first action is to:","es":"Si el motor se detiene y comienza a derivar hacia un peligro (rocas, una presa, oleaje fuerte), una buena primera acción es:","ru":"Если двигатель заглох и вас сносит к опасности (камни, плотина, сильный прибой), хорошим первым действием будет:","tr":"Motorunuz durur ve tehlikeye (kayalar, baraj, güçlü dalga) doğru sürüklenmeye başlarsanız iyi bir ilk hareket şudur:","hi":"यदि आपका इंजन बंद हो जाए और आप खतरे (चट्टानें, बाँध, तेज़ लहरें) की ओर बहने लगें, तो एक अच्छी पहली कार्रवाई है:","ar":"إذا توقف محرّكك وبدأت تنجرف نحو خطر (صخور، سد، أمواج عاتية)، فمن التصرفات الأولى الجيدة أن:"},"o":[{"en":"Deploy the anchor to hold position while you assess the problem and call for help","es":"Echar el ancla para mantener la posición mientras evalúa el problema y pide ayuda","ru":"Отдать якорь, чтобы удержать позицию, пока оцениваете проблему и зовёте помощь","tr":"Sorunu değerlendirip yardım çağırırken konumu tutmak için çapayı atmak","hi":"समस्या का आकलन करते और मदद माँगते समय स्थिति बनाए रखने के लिए एंकर डालना","ar":"إلقاء المرساة لتثبيت الموضع بينما تقيّم المشكلة وتطلب المساعدة"},{"en":"Everyone jumps overboard to swim","es":"Que todos salten al agua a nadar","ru":"Всем прыгнуть за борт и плыть","tr":"Herkesin denize atlayıp yüzmesi","hi":"सभी पानी में कूदकर तैरें","ar":"يقفز الجميع إلى الماء للسباحة"},{"en":"Throw the anchor without any line attached","es":"Lanzar el ancla sin línea","ru":"Бросить якорь без каната","tr":"Halat bağlı olmadan çapayı atmak","hi":"बिना लाइन के एंकर फेंकना","ar":"رمي المرساة دون حبل"},{"en":"Ignore it and hope the wind changes","es":"Ignorarlo y esperar que cambie el viento","ru":"Игнорировать и надеяться, что ветер изменится","tr":"Görmezden gelip rüzgarın değişmesini ummak","hi":"इसे अनदेखा कर हवा बदलने की उम्मीद करना","ar":"تجاهله وتأمل تغيّر الريح"}],"e":{"en":"Dropping anchor can stop your drift toward hazards and hold you in place while you troubleshoot the engine and signal for help. Make sure the anchor line is secured to the bow first.","es":"Echar el ancla puede detener la deriva hacia los peligros y mantenerlo en su lugar mientras revisa el motor y pide ayuda. Asegúrese primero de que la línea esté sujeta a la proa.","ru":"Отдача якоря может остановить снос к опасностям и удержать вас на месте, пока вы разбираетесь с двигателем и подаёте сигнал. Сначала убедитесь, что канат закреплён на носу.","tr":"Çapa atmak, tehlikelere doğru sürüklenmeyi durdurup motoru kontrol edip yardım isterken sizi yerinde tutabilir. Önce çapa halatının başa bağlı olduğundan emin olun.","hi":"एंकर डालना खतरों की ओर बहाव रोक सकता है और आपको जगह पर बनाए रख सकता है जबकि आप इंजन जाँचते और मदद माँगते हैं। पहले सुनिश्चित करें कि एंकर लाइन नाव की नाक से बँधी हो।","ar":"إلقاء المرساة قد يوقف انجرافك نحو المخاطر ويثبّتك في مكانك بينما تفحص المحرك وتطلب المساعدة. تأكّد أولاً أن حبل المرساة مربوط بالمقدمة."}},{"cat":"emergencies","a":3,"q":{"en":"Which reduces the chance of a propeller-strike injury during a man-overboard recovery?","es":"¿Qué reduce la posibilidad de una lesión por golpe de hélice durante la recuperación de una persona en el agua?","ru":"Что снижает вероятность травмы от винта при подъёме человека за бортом?","tr":"Denize adam düşmesi kurtarması sırasında pervane çarpması yaralanması olasılığını ne azaltır?","hi":"मैन-ओवरबोर्ड रिकवरी के दौरान प्रोपेलर-स्ट्राइक चोट की संभावना क्या कम करता है?","ar":"ما الذي يقلّل احتمال إصابة اصطدام المروحة أثناء استعادة شخص سقط في الماء؟"},"o":[{"en":"Keeping the engine at high rpm near the person","es":"Mantener el motor a altas revoluciones cerca de la persona","ru":"Держать высокие обороты рядом с человеком","tr":"Kişinin yanında motoru yüksek devirde tutmak","hi":"व्यक्ति के पास इंजन को उच्च rpm पर रखना","ar":"إبقاء المحرك عند دوران عالٍ قرب الشخص"},{"en":"Reversing quickly toward them","es":"Retroceder rápidamente hacia ellos","ru":"Быстро сдавать назад к ним","tr":"Onlara doğru hızlıca geri gitmek","hi":"उनकी ओर तेज़ी से रिवर्स करना","ar":"الرجوع بسرعة نحوه"},{"en":"Circling them at speed","es":"Rodearlos a velocidad","ru":"Кружить вокруг них на скорости","tr":"Onların etrafında hızla dönmek","hi":"गति से उनके चारों ओर घूमना","ar":"الدوران حوله بسرعة"},{"en":"Shifting to neutral and shutting off the engine before the person is near the boat","es":"Poner en neutral y apagar el motor antes de que la persona esté cerca de la embarcación","ru":"Перейти в нейтраль и заглушить двигатель до приближения человека к лодке","tr":"Kişi tekneye yaklaşmadan boşa alıp motoru kapatmak","hi":"व्यक्ति के नाव के पास आने से पहले न्यूट्रल में डालकर इंजन बंद करना","ar":"التحويل إلى الوضع المحايد وإطفاء المحرك قبل اقتراب الشخص من القارب"}],"e":{"en":"Shift to neutral and turn off the engine before the person is alongside so the propeller cannot strike them. Propeller injuries are severe, so never let the engine turn while someone is close in the water.","es":"Ponga en neutral y apague el motor antes de que la persona llegue al costado para que la hélice no la golpee. Las lesiones por hélice son graves; nunca deje el motor girando con alguien cerca en el agua.","ru":"Переведите в нейтраль и заглушите двигатель до того, как человек окажется у борта, чтобы винт не задел его. Травмы от винта тяжёлые — никогда не оставляйте двигатель работающим, когда кто-то рядом в воде.","tr":"Pervanenin çarpmaması için kişi bordaya gelmeden boşa alın ve motoru kapatın. Pervane yaralanmaları ağırdır; suda biri yakınken motoru asla döner bırakmayın.","hi":"प्रोपेलर उन्हें न लगे इसके लिए व्यक्ति के किनारे आने से पहले न्यूट्रल में डालें और इंजन बंद करें। प्रोपेलर की चोटें गंभीर होती हैं, इसलिए जब कोई पानी में पास हो तो इंजन कभी घूमने न दें।","ar":"حوّل إلى الوضع المحايد وأطفئ المحرك قبل وصول الشخص إلى جانب القارب حتى لا تضربه المروحة. إصابات المروحة شديدة، فلا تدع المحرك يدور أبداً وشخص قريب في الماء."}},{"cat":"emergencies","a":2,"q":{"en":"What are early warning signs of carbon monoxide poisoning?","es":"¿Cuáles son las primeras señales de advertencia de intoxicación por monóxido de carbono?","ru":"Каковы ранние признаки отравления угарным газом?","tr":"Karbon monoksit zehirlenmesinin erken uyarı belirtileri nelerdir?","hi":"कार्बन मोनोऑक्साइड विषाक्तता के शुरुआती चेतावनी संकेत क्या हैं?","ar":"ما العلامات التحذيرية المبكرة للتسمّم بأول أكسيد الكربون؟"},"o":[{"en":"Sudden hunger","es":"Hambre repentina","ru":"Внезапный голод","tr":"Ani açlık","hi":"अचानक भूख","ar":"جوع مفاجئ"},{"en":"Improved vision","es":"Mejora de la visión","ru":"Улучшение зрения","tr":"Görüşün iyileşmesi","hi":"दृष्टि में सुधार","ar":"تحسّن الرؤية"},{"en":"Headache, dizziness, nausea, weakness, and confusion","es":"Dolor de cabeza, mareo, náuseas, debilidad y confusión","ru":"Головная боль, головокружение, тошнота, слабость и спутанность","tr":"Baş ağrısı, baş dönmesi, bulantı, halsizlik ve zihin bulanıklığı","hi":"सिरदर्द, चक्कर, मतली, कमज़ोरी और भ्रम","ar":"صداع ودوخة وغثيان وضعف وتشوّش"},{"en":"A strong smell of rotten eggs","es":"Un fuerte olor a huevos podridos","ru":"Сильный запах тухлых яиц","tr":"Kuvvetli çürük yumurta kokusu","hi":"सड़े अंडों की तेज़ गंध","ar":"رائحة قوية للبيض الفاسد"}],"e":{"en":"Early CO symptoms — headache, dizziness, nausea, weakness, and confusion — resemble seasickness or intoxication. If suspected, move people to fresh air immediately and seek medical help.","es":"Los primeros síntomas de CO —dolor de cabeza, mareo, náuseas, debilidad y confusión— se parecen al mareo o la embriaguez. Ante la sospecha, lleve a las personas a aire fresco de inmediato y busque ayuda médica.","ru":"Ранние симптомы CO — головная боль, головокружение, тошнота, слабость и спутанность — похожи на морскую болезнь или опьянение. При подозрении немедленно выведите людей на свежий воздух и обратитесь за помощью.","tr":"Erken CO belirtileri — baş ağrısı, baş dönmesi, bulantı, halsizlik ve zihin bulanıklığı — deniz tutması ya da sarhoşluğa benzer. Şüphelenirseniz insanları hemen temiz havaya çıkarın ve tıbbi yardım alın.","hi":"CO के शुरुआती लक्षण — सिरदर्द, चक्कर, मतली, कमज़ोरी और भ्रम — समुद्री बीमारी या नशे जैसे लगते हैं। संदेह होने पर लोगों को तुरंत ताज़ी हवा में ले जाएँ और चिकित्सा सहायता लें।","ar":"أعراض CO المبكرة — صداع ودوخة وغثيان وضعف وتشوّش — تشبه دوار البحر أو الثمالة. عند الاشتباه، انقل الناس إلى الهواء الطلق فوراً واطلب المساعدة الطبية."}},{"cat":"emergencies","a":1,"q":{"en":"To reduce the risk of a fire when running a portable generator or stove on a boat, you should:","es":"Para reducir el riesgo de incendio al usar un generador portátil o una estufa en una embarcación, debe:","ru":"Чтобы снизить риск пожара при использовании переносного генератора или плиты на судне, следует:","tr":"Teknede taşınabilir jeneratör veya ocak çalıştırırken yangın riskini azaltmak için:","hi":"नाव पर पोर्टेबल जेनरेटर या स्टोव चलाते समय आग का जोखिम कम करने के लिए, आपको चाहिए:","ar":"لتقليل خطر الحريق عند تشغيل مولّد محمول أو موقد على القارب، عليك أن:"},"o":[{"en":"Refuel it while it is hot and running","es":"Recargarlo caliente y en marcha","ru":"Заправлять его горячим и работающим","tr":"Sıcak ve çalışırken yakıt ikmali yapmak","hi":"इसे गर्म और चालू रहते ईंधन भरना","ar":"تعيد تزويده بالوقود وهو ساخن ويعمل"},{"en":"Keep it away from fuel and flammable materials, ensure good ventilation, and never refuel a hot unit","es":"Mantenerlo alejado del combustible y materiales inflamables, asegurar buena ventilación y nunca recargar una unidad caliente","ru":"Держать его вдали от топлива и горючих материалов, обеспечить вентиляцию и никогда не заправлять горячим","tr":"Yakıt ve yanıcı malzemelerden uzak tutmak, iyi havalandırma sağlamak ve sıcak üniteye asla yakıt koymamak","hi":"इसे ईंधन और ज्वलनशील सामग्री से दूर रखना, अच्छा वेंटिलेशन सुनिश्चित करना, और गर्म यूनिट में कभी ईंधन न भरना","ar":"إبقاءه بعيداً عن الوقود والمواد القابلة للاشتعال وضمان تهوية جيدة وعدم تزويد وحدة ساخنة بالوقود أبداً"},{"en":"Cover the vents to keep it warm","es":"Cubrir las rejillas para mantenerlo caliente","ru":"Закрыть вентотверстия, чтобы сохранить тепло","tr":"Sıcak kalması için menfezleri kapatmak","hi":"इसे गर्म रखने के लिए वेंट ढकना","ar":"تغطية الفتحات لإبقائه دافئاً"},{"en":"Store fuel next to it for convenience","es":"Guardar el combustible al lado por comodidad","ru":"Хранить топливо рядом для удобства","tr":"Kolaylık için yakıtı yanında saklamak","hi":"सुविधा के लिए ईंधन उसके पास रखना","ar":"تخزين الوقود بجانبه للتسهيل"}],"e":{"en":"Keep generators and stoves away from fuel and combustibles, provide good ventilation to prevent CO buildup, let equipment cool before refueling, and never refuel while hot or running.","es":"Mantenga generadores y estufas lejos del combustible y de materiales combustibles, ventile bien para evitar acumulación de CO, deje enfriar el equipo antes de recargar y nunca recargue en caliente o en marcha.","ru":"Держите генераторы и плиты вдали от топлива и горючего, обеспечьте вентиляцию для предотвращения накопления CO, дайте технике остыть перед заправкой и никогда не заправляйте горячей или работающей.","tr":"Jeneratör ve ocakları yakıt ve yanıcılardan uzak tutun, CO birikimini önlemek için iyi havalandırma sağlayın, yakıt koymadan önce ekipmanı soğutun ve sıcak veya çalışırken asla yakıt koymayın.","hi":"जेनरेटर और स्टोव को ईंधन व ज्वलनशील पदार्थों से दूर रखें, CO जमाव रोकने के लिए अच्छा वेंटिलेशन दें, ईंधन भरने से पहले उपकरण ठंडा होने दें, और गर्म या चालू रहते कभी ईंधन न भरें।","ar":"أبقِ المولّدات والمواقد بعيداً عن الوقود والمواد القابلة للاشتعال، ووفّر تهوية جيدة لمنع تراكم CO، واترك المعدة تبرد قبل التزويد، ولا تُزوّد وحدة ساخنة أو تعمل بالوقود أبداً."}},{"cat":"emergencies","a":0,"q":{"en":"If you must abandon a sinking boat, what should you do to improve your chances?","es":"Si debe abandonar una embarcación que se hunde, ¿qué debe hacer para mejorar sus posibilidades?","ru":"Если приходится покинуть тонущую лодку, что сделать, чтобы повысить свои шансы?","tr":"Batmakta olan bir tekneyi terk etmek zorunda kalırsanız, şansınızı artırmak için ne yapmalısınız?","hi":"यदि आपको डूबती नाव छोड़नी पड़े, तो अपनी संभावनाएँ बेहतर करने के लिए क्या करना चाहिए?","ar":"إذا اضطررت لمغادرة قارب يغرق، فماذا يجب أن تفعل لتحسين فرصك؟"},"o":[{"en":"Put on a life jacket, stay together as a group, and take flotation or a signaling device if possible","es":"Ponerse el chaleco, permanecer juntos en grupo y llevar flotación o un dispositivo de señalización si es posible","ru":"Надеть жилет, держаться группой и по возможности взять плавсредство или сигнальное устройство","tr":"Can yeleği giymek, grup halinde birlikte kalmak ve mümkünse yüzdürücü ya da işaret cihazı almak","hi":"लाइफ जैकेट पहनें, समूह में साथ रहें, और संभव हो तो फ्लोटेशन या सिग्नलिंग डिवाइस लें","ar":"ارتداء سترة النجاة والبقاء معاً كمجموعة وأخذ جهاز طفو أو إشارة إن أمكن"},{"en":"Swim off alone in different directions","es":"Nadar solos en distintas direcciones","ru":"Плыть поодиночке в разные стороны","tr":"Farklı yönlere tek tek yüzmek","hi":"अलग-अलग दिशाओं में अकेले तैरना","ar":"السباحة بمفردكم في اتجاهات مختلفة"},{"en":"Leave life jackets behind to swim faster","es":"Dejar los chalecos para nadar más rápido","ru":"Оставить жилеты, чтобы плыть быстрее","tr":"Daha hızlı yüzmek için can yeleklerini bırakmak","hi":"तेज़ तैरने के लिए लाइफ जैकेट छोड़ देना","ar":"ترك سترات النجاة للسباحة أسرع"},{"en":"Dive down to save belongings first","es":"Bucear para salvar pertenencias primero","ru":"Сначала нырнуть за вещами","tr":"Önce eşyaları kurtarmak için dalmak","hi":"पहले सामान बचाने के लिए गोता लगाना","ar":"الغوص لإنقاذ الأمتعة أولاً"}],"e":{"en":"Everyone should wear a life jacket, stay together (a group is easier to spot and helps morale and warmth), and bring anything that floats and any signaling gear you can grab.","es":"Todos deben llevar el chaleco, permanecer juntos (un grupo es más fácil de ver y ayuda a la moral y al calor) y llevar cualquier cosa que flote y equipo de señalización que puedan tomar.","ru":"Все должны надеть жилеты, держаться вместе (группу легче заметить, это поддерживает боевой дух и тепло) и взять всё, что плавает, и любые сигнальные средства, какие успеете схватить.","tr":"Herkes can yeleği giymeli, birlikte kalmalı (grup daha kolay görülür, morale ve sıcaklığa yardımcı olur) ve yüzen her şeyi ve alabildiğiniz işaret araçlarını yanınıza almalısınız.","hi":"सभी को लाइफ जैकेट पहनना चाहिए, साथ रहना चाहिए (समूह आसानी से दिखता है और मनोबल व गर्माहट में मदद करता है), और जो कुछ तैरता हो व जो सिग्नलिंग गियर पकड़ सकें, ले लेना चाहिए।","ar":"على الجميع ارتداء سترات النجاة والبقاء معاً (المجموعة أسهل رؤية وتساعد على المعنويات والدفء) وأخذ أي شيء يطفو وأي أداة إشارة يمكن الإمساك بها."}},{"cat":"emergencies","a":3,"q":{"en":"A boating accident that involves death, disappearance, serious injury, or major property damage must be:","es":"Un accidente de navegación que implique muerte, desaparición, lesiones graves o daños importantes debe ser:","ru":"О происшествии на воде с гибелью, исчезновением, серьёзной травмой или значительным ущербом имуществу необходимо:","tr":"Ölüm, kaybolma, ciddi yaralanma veya büyük maddi hasar içeren bir tekne kazası şöyle olmalıdır:","hi":"मृत्यु, लापता होना, गंभीर चोट या बड़ी संपत्ति क्षति वाली नौका दुर्घटना को होना चाहिए:","ar":"حادث القارب الذي يتضمّن وفاة أو اختفاءً أو إصابة خطيرة أو أضراراً مادية كبيرة يجب أن:"},"o":[{"en":"Kept secret","es":"Mantenido en secreto","ru":"Держать в секрете","tr":"Gizli tutulmalı","hi":"गुप्त रखा जाना","ar":"يبقى سرّاً"},{"en":"Handled only between the boaters","es":"Manejado solo entre los navegantes","ru":"Урегулировать только между судоводителями","tr":"Yalnızca denizciler arasında halledilmeli","hi":"केवल नाविकों के बीच निपटाया जाना","ar":"يُعالَج بين البحّارة فقط"},{"en":"Reported to a doctor only","es":"Reportado solo a un médico","ru":"Сообщать только врачу","tr":"Yalnızca bir doktora bildirilmeli","hi":"केवल एक डॉक्टर को रिपोर्ट किया जाना","ar":"يُبلَّغ لطبيب فقط"},{"en":"Reported to the proper marine authorities, usually within a set time limit","es":"Reportado a las autoridades marítimas correspondientes, normalmente dentro de un plazo establecido","ru":"Сообщить надлежащим морским органам, обычно в установленный срок","tr":"İlgili denizcilik makamlarına, genellikle belirli bir süre içinde bildirilmeli","hi":"उचित समुद्री अधिकारियों को, आमतौर पर एक निर्धारित समय-सीमा के भीतर, रिपोर्ट किया जाना","ar":"يُبلَّغ للسلطات البحرية المختصة، عادةً خلال مهلة زمنية محددة"}],"e":{"en":"Serious boating accidents must be reported to the state boating authority or Coast Guard, usually within a set number of hours or days. Reporting rules and deadlines vary by state.","es":"Los accidentes graves deben reportarse a la autoridad estatal de navegación o a la Guardia Costera, normalmente dentro de cierto número de horas o días. Las reglas y plazos varían por estado.","ru":"О серьёзных происшествиях нужно сообщать в органы штата по судоходству или Береговую охрану, обычно в течение установленного числа часов или дней. Правила и сроки различаются по штату.","tr":"Ciddi tekne kazaları, genellikle belirli saat veya gün içinde eyalet denizcilik makamına ya da Sahil Güvenlik'e bildirilmelidir. Kurallar ve süreler eyalete göre değişir.","hi":"गंभीर नौका दुर्घटनाएँ राज्य नौकायन प्राधिकरण या कोस्ट गार्ड को रिपोर्ट की जानी चाहिए, आमतौर पर निर्धारित घंटों या दिनों के भीतर। नियम व समय-सीमाएँ राज्यानुसार भिन्न होती हैं।","ar":"يجب الإبلاغ عن حوادث القوارب الخطيرة لسلطة القوارب في الولاية أو خفر السواحل، عادةً خلال عدد محدد من الساعات أو الأيام. تختلف القواعد والمهل حسب الولاية."}},{"cat":"emergencies","a":2,"q":{"en":"What should you do first if you smell gasoline fumes strongly in the boat?","es":"¿Qué debe hacer primero si huele fuertemente vapores de gasolina en la embarcación?","ru":"Что нужно сделать в первую очередь, если в лодке сильно пахнет парами бензина?","tr":"Teknede güçlü benzin kokusu alırsanız önce ne yapmalısınız?","hi":"यदि नाव में गैसोलीन के वाष्प की तेज़ गंध आए तो आपको सबसे पहले क्या करना चाहिए?","ar":"ماذا يجب أن تفعل أولاً إذا شممت رائحة أبخرة بنزين قوية في القارب؟"},"o":[{"en":"Start the engine to burn it off","es":"Arrancar el motor para quemarlos","ru":"Запустить двигатель, чтобы «сжечь» их","tr":"Yakmak için motoru çalıştırmak","hi":"इसे जलाने के लिए इंजन स्टार्ट करना","ar":"تشغيل المحرك لحرقها"},{"en":"Light a match to find the leak","es":"Encender un fósforo para hallar la fuga","ru":"Зажечь спичку, чтобы найти утечку","tr":"Sızıntıyı bulmak için kibrit yakmak","hi":"रिसाव खोजने के लिए माचिस जलाना","ar":"إشعال عود ثقاب لإيجاد التسرّب"},{"en":"Do not start the engine or use anything that could spark; shut off fuel, ventilate, and find the source","es":"No arranque el motor ni use nada que produzca chispa; corte el combustible, ventile y halle la fuente","ru":"Не запускайте двигатель и ничего искрящего; перекройте топливо, проветрите и найдите источник","tr":"Motoru çalıştırmayın veya kıvılcım çıkarabilecek hiçbir şey kullanmayın; yakıtı kesin, havalandırın ve kaynağı bulun","hi":"इंजन स्टार्ट न करें या कोई भी चिंगारी वाली चीज़ न चलाएँ; ईंधन बंद करें, हवादार करें और स्रोत खोजें","ar":"لا تُشغّل المحرك ولا تستخدم أي شيء قد يُحدث شرارة؛ أغلق الوقود وهوِّ وابحث عن المصدر"},{"en":"Turn on all electronics to check systems","es":"Encender toda la electrónica para revisar los sistemas","ru":"Включить всю электронику для проверки систем","tr":"Sistemleri kontrol için tüm elektroniği açmak","hi":"सिस्टम जाँचने के लिए सभी इलेक्ट्रॉनिक्स चालू करना","ar":"تشغيل جميع الإلكترونيات لفحص الأنظمة"}],"e":{"en":"Gasoline fumes can explode from a single spark. Do not start the engine or operate any electrical switch; shut off the fuel supply, ventilate the boat, and locate and fix the leak before restarting.","es":"Los vapores de gasolina pueden explotar con una sola chispa. No arranque el motor ni accione ningún interruptor; corte el combustible, ventile la embarcación y localice y repare la fuga antes de arrancar.","ru":"Пары бензина могут взорваться от одной искры. Не запускайте двигатель и не трогайте электрику; перекройте подачу топлива, проветрите лодку, найдите и устраните утечку до запуска.","tr":"Benzin buharları tek bir kıvılcımla patlayabilir. Motoru çalıştırmayın veya hiçbir elektrik anahtarını kullanmayın; yakıt beslemesini kesin, tekneyi havalandırın ve çalıştırmadan önce sızıntıyı bulup giderin.","hi":"गैसोलीन के वाष्प एक चिंगारी से भी फट सकते हैं। इंजन स्टार्ट न करें या कोई विद्युत स्विच न चलाएँ; ईंधन आपूर्ति बंद करें, नाव को हवादार करें, और स्टार्ट करने से पहले रिसाव खोजकर ठीक करें।","ar":"يمكن أن تنفجر أبخرة البنزين من شرارة واحدة. لا تُشغّل المحرك ولا تُشغّل أي مفتاح كهربائي؛ أغلق إمداد الوقود، وهوِّ القارب، وابحث عن التسرّب وأصلحه قبل إعادة التشغيل."}},{"cat":"emergencies","a":1,"q":{"en":"When towing a disabled boat, a key safety practice is to:","es":"Al remolcar una embarcación averiada, una práctica de seguridad clave es:","ru":"При буксировке неисправной лодки ключевой мерой безопасности является:","tr":"Arızalı bir tekneyi çekerken temel bir güvenlik uygulaması şudur:","hi":"किसी खराब नाव को खींचते समय एक मुख्य सुरक्षा अभ्यास है:","ar":"عند قطر قارب معطّل، من ممارسات السلامة الأساسية أن:"},"o":[{"en":"Tow at high speed to finish quickly","es":"Remolcar a alta velocidad para terminar rápido","ru":"Буксировать на высокой скорости, чтобы быстрее закончить","tr":"Çabuk bitirmek için yüksek hızda çekmek","hi":"जल्दी खत्म करने के लिए तेज़ गति पर खींचना","ar":"القطر بسرعة عالية لإنهاء الأمر بسرعة"},{"en":"Use a strong line, go slowly, and keep everyone clear of the towline under tension","es":"Usar una línea resistente, ir despacio y mantener a todos alejados del cabo en tensión","ru":"Использовать прочный трос, идти медленно и держать всех в стороне от натянутого троса","tr":"Sağlam bir halat kullanmak, yavaş gitmek ve herkesi gergin halattan uzak tutmak","hi":"एक मज़बूत लाइन का उपयोग करना, धीरे चलना, और तनाव में टोलाइन से सभी को दूर रखना","ar":"استخدام حبل قوي والسير ببطء وإبقاء الجميع بعيداً عن حبل القطر المشدود"},{"en":"Attach the line to a seat","es":"Atar la línea a un asiento","ru":"Крепить трос к сиденью","tr":"Halatı bir koltuğa bağlamak","hi":"लाइन को एक सीट से बाँधना","ar":"ربط الحبل بمقعد"},{"en":"Stand next to the line while towing","es":"Pararse junto a la línea mientras remolca","ru":"Стоять рядом с тросом во время буксировки","tr":"Çekerken halatın yanında durmak","hi":"खींचते समय लाइन के पास खड़े रहना","ar":"الوقوف بجانب الحبل أثناء القطر"}],"e":{"en":"Tow slowly with a strong line attached to solid fittings, and keep everyone away from the towline, which can snap back dangerously if it parts under tension. Adjust speed for the towed boat's condition.","es":"Remolque despacio con una línea resistente sujeta a herrajes sólidos, y mantenga a todos alejados del cabo, que puede latigar peligrosamente si se rompe en tensión. Ajuste la velocidad al estado de la embarcación remolcada.","ru":"Буксируйте медленно прочным тросом, закреплённым за надёжные детали, и держите всех вдали от троса — при разрыве под натяжением он может опасно хлестнуть. Подбирайте скорость под состояние буксируемой лодки.","tr":"Sağlam bağlantılara tutturulmuş güçlü bir halatla yavaş çekin ve herkesi halattan uzak tutun; gergin haldeyken kopar ve tehlikeli şekilde geri savrulabilir. Hızı çekilen teknenin durumuna göre ayarlayın.","hi":"मज़बूत फिटिंग से बँधी एक मज़बूत लाइन के साथ धीरे खींचें, और सभी को टोलाइन से दूर रखें, जो तनाव में टूटने पर खतरनाक तरीके से वापस झटक सकती है। खींची जा रही नाव की स्थिति अनुसार गति समायोजित करें।","ar":"اقطر ببطء بحبل قوي مربوط بتجهيزات متينة، وأبقِ الجميع بعيداً عن حبل القطر الذي قد يرتدّ بخطورة إذا انقطع تحت الشد. اضبط السرعة حسب حالة القارب المقطور."}},{"cat":"emergencies","a":0,"q":{"en":"A good way to prevent falls overboard is to:","es":"Una buena forma de prevenir caídas al agua es:","ru":"Хороший способ предотвратить падение за борт — это:","tr":"Denize düşmeyi önlemenin iyi bir yolu şudur:","hi":"पानी में गिरने से बचने का एक अच्छा तरीका है:","ar":"من الطرق الجيدة لمنع السقوط في الماء أن:"},"o":[{"en":"Keep three points of contact, stay seated while under way, and keep the deck clear of clutter","es":"Mantener tres puntos de contacto, permanecer sentado en marcha y mantener la cubierta despejada","ru":"Сохранять три точки опоры, оставаться сидя на ходу и держать палубу свободной от лишнего","tr":"Üç nokta temasını korumak, seyir halindeyken oturmak ve güverteyi dağınıklıktan uzak tutmak","hi":"तीन संपर्क बिंदु बनाए रखना, चलते समय बैठे रहना, और डेक को अव्यवस्था से मुक्त रखना","ar":"الحفاظ على ثلاث نقاط تماس والبقاء جالساً أثناء السير وإبقاء السطح خالياً من الفوضى"},{"en":"Move around freely at high speed","es":"Moverse libremente a alta velocidad","ru":"Свободно перемещаться на высокой скорости","tr":"Yüksek hızda serbestçe dolaşmak","hi":"तेज़ गति पर स्वतंत्र रूप से घूमना","ar":"التنقّل بحرية بسرعة عالية"},{"en":"Sit on the bow while cruising","es":"Sentarse en la proa durante la travesía","ru":"Сидеть на носу во время движения","tr":"Seyir sırasında baş tarafta oturmak","hi":"क्रूज़ के दौरान नाव की नाक पर बैठना","ar":"الجلوس على المقدمة أثناء الإبحار"},{"en":"Lean far over the side to look at the water","es":"Inclinarse mucho por la borda para mirar el agua","ru":"Сильно перегибаться через борт, глядя на воду","tr":"Suya bakmak için borddan çok sarkmak","hi":"पानी देखने के लिए किनारे से बहुत झुकना","ar":"الميل بعيداً فوق الحافة للنظر إلى الماء"}],"e":{"en":"Prevent falls overboard by staying seated while the boat moves, keeping three points of contact when you move, keeping decks dry and clear, and not overloading or standing in a small boat.","es":"Evite caídas permaneciendo sentado en marcha, manteniendo tres puntos de contacto al moverse, con cubiertas secas y despejadas, y sin sobrecargar ni ponerse de pie en una embarcación pequeña.","ru":"Предотвращайте падения: сидите, пока лодка движется, сохраняйте три точки опоры при перемещении, держите палубы сухими и свободными, не перегружайте и не вставайте в малой лодке.","tr":"Denize düşmeyi önlemek için tekne hareket ederken oturun, hareket ederken üç nokta teması koruyun, güverteleri kuru ve açık tutun, küçük teknede aşırı yükleme yapmayın ve ayağa kalkmayın.","hi":"पानी में गिरने से बचें: नाव चलते समय बैठे रहें, चलते समय तीन संपर्क बिंदु बनाए रखें, डेक सूखा व साफ़ रखें, और छोटी नाव में ओवरलोड न करें या खड़े न हों।","ar":"امنع السقوط في الماء بالبقاء جالساً أثناء تحرّك القارب، والحفاظ على ثلاث نقاط تماس عند التنقّل، وإبقاء الأسطح جافة وخالية، وعدم التحميل الزائد أو الوقوف في قارب صغير."}},{"cat":"emergencies","a":3,"q":{"en":"After you help rescue a hypothermia victim from cold water, you should:","es":"Después de ayudar a rescatar a una víctima de hipotermia del agua fría, debe:","ru":"После того как вы помогли спасти из холодной воды пострадавшего с гипотермией, следует:","tr":"Soğuk sudan bir hipotermi kazazedesini kurtardıktan sonra:","hi":"ठंडे पानी से हाइपोथर्मिया पीड़ित को बचाने में मदद के बाद, आपको चाहिए:","ar":"بعد مساعدتك في إنقاذ مصاب بانخفاض حرارة الجسم من الماء البارد، عليك أن:"},"o":[{"en":"Rub the skin briskly and give them alcohol","es":"Frotar la piel con fuerza y darle alcohol","ru":"Энергично растирать кожу и дать алкоголь","tr":"Cildi hızlıca ovmak ve alkol vermek","hi":"त्वचा को ज़ोर से रगड़ना और उन्हें शराब देना","ar":"تفرك الجلد بقوة وتعطيه كحولاً"},{"en":"Put them in a very hot bath immediately","es":"Meterlo de inmediato en un baño muy caliente","ru":"Немедленно поместить в очень горячую ванну","tr":"Hemen çok sıcak bir banyoya sokmak","hi":"उन्हें तुरंत बहुत गर्म पानी के स्नान में डालना","ar":"تضعه فوراً في حمام ساخن جداً"},{"en":"Make them exercise to warm up","es":"Hacerlo ejercitarse para calentarse","ru":"Заставить заниматься упражнениями, чтобы согреться","tr":"Isınması için egzersiz yaptırmak","hi":"गर्म होने के लिए उन्हें व्यायाम कराना","ar":"تجعله يتمرّن ليتدفّأ"},{"en":"Handle them gently, remove wet clothing, warm the core gradually with dry blankets, and seek medical help","es":"Manejarlo con suavidad, quitar la ropa mojada, calentar el tronco gradualmente con mantas secas y buscar ayuda médica","ru":"Обращаться бережно, снять мокрую одежду, постепенно согревать корпус сухими одеялами и обратиться за помощью","tr":"Nazikçe davranmak, ıslak giysileri çıkarmak, gövdeyi kuru battaniyelerle kademeli ısıtmak ve tıbbi yardım almak","hi":"उन्हें धीरे से संभालना, गीले कपड़े हटाना, सूखे कंबलों से धड़ को धीरे-धीरे गर्म करना, और चिकित्सा सहायता लेना","ar":"تتعامل معه برفق وتنزع الملابس المبلّلة وتدفّئ الجذع تدريجياً ببطانيات جافة وتطلب المساعدة الطبية"}],"e":{"en":"Handle a hypothermia victim gently, remove wet clothes, warm the core (chest, neck, groin) slowly with dry blankets or skin-to-skin contact, and get medical help. Avoid rubbing, alcohol, and sudden intense heat.","es":"Maneje con suavidad a la víctima, quítele la ropa mojada, caliente el tronco (pecho, cuello, ingle) lentamente con mantas secas o contacto piel con piel y busque ayuda médica. Evite frotar, el alcohol y el calor intenso repentino.","ru":"Обращайтесь с пострадавшим бережно, снимите мокрую одежду, медленно согревайте корпус (грудь, шею, пах) сухими одеялами или контактом кожа к коже и обратитесь за помощью. Избегайте растирания, алкоголя и резкого сильного тепла.","tr":"Hipotermi kazazedesine nazik davranın, ıslak giysileri çıkarın, gövdeyi (göğüs, boyun, kasık) kuru battaniye ya da ten temasıyla yavaşça ısıtın ve tıbbi yardım alın. Ovmaktan, alkolden ve ani yoğun ısıdan kaçının.","hi":"हाइपोथर्मिया पीड़ित को धीरे से संभालें, गीले कपड़े हटाएँ, धड़ (छाती, गर्दन, कमर) को सूखे कंबल या त्वचा-से-त्वचा संपर्क से धीरे-धीरे गर्म करें, और चिकित्सा सहायता लें। रगड़ना, शराब और अचानक तेज़ गर्मी से बचें।","ar":"تعامل مع المصاب برفق، وانزع الملابس المبلّلة، ودفّئ الجذع (الصدر والرقبة والفخذ) ببطء ببطانيات جافة أو تلامس الجلد، واطلب المساعدة الطبية. تجنّب الفرك والكحول والحرارة الشديدة المفاجئة."}},{"cat":"emergencies","a":2,"q":{"en":"Why is it dangerous to try to move to the high side or stand up when a boat starts to tip?","es":"¿Por qué es peligroso intentar moverse al lado alto o ponerse de pie cuando una embarcación empieza a inclinarse?","ru":"Почему опасно пытаться перейти на высокий борт или встать, когда лодка начинает крениться?","tr":"Tekne yana yatmaya başladığında yüksek tarafa geçmeye veya ayağa kalkmaya çalışmak neden tehlikelidir?","hi":"जब नाव झुकने लगे तो ऊँची ओर जाने या खड़े होने की कोशिश करना खतरनाक क्यों है?","ar":"لماذا من الخطر محاولة الانتقال إلى الجانب المرتفع أو الوقوف عندما يبدأ القارب بالميل؟"},"o":[{"en":"It makes the boat go faster","es":"Hace que la embarcación vaya más rápido","ru":"Это ускоряет лодку","tr":"Tekneyi hızlandırır","hi":"इससे नाव तेज़ चलती है","ar":"يجعل القارب أسرع"},{"en":"Sudden weight shifts and a higher center of gravity can capsize the boat or throw you overboard","es":"Los cambios bruscos de peso y un centro de gravedad más alto pueden volcar la embarcación o arrojarlo al agua","ru":"Резкое смещение веса и повышенный центр тяжести могут опрокинуть лодку или выбросить вас за борт","tr":"Ani ağırlık kaymaları ve yükselen ağırlık merkezi tekneyi alabora edebilir ya da sizi denize atabilir","hi":"अचानक वज़न खिसकना और ऊँचा गुरुत्व केंद्र नाव को पलटा सकता है या आपको पानी में फेंक सकता है","ar":"تحوّلات الوزن المفاجئة وارتفاع مركز الثقل قد يقلبان القارب أو يقذفانك في الماء"},{"en":"It improves stability","es":"Mejora la estabilidad","ru":"Это повышает устойчивость","tr":"Dengeyi iyileştirir","hi":"इससे स्थिरता बेहतर होती है","ar":"يحسّن الثبات"},{"en":"It has no effect","es":"No tiene efecto","ru":"Это не имеет эффекта","tr":"Etkisi yoktur","hi":"इसका कोई असर नहीं","ar":"لا أثر له"}],"e":{"en":"Standing up or lunging to the high side raises the center of gravity and shifts weight suddenly, which can flip the boat or throw you overboard. Stay low and centered, and shift weight slowly.","es":"Ponerse de pie o lanzarse al lado alto eleva el centro de gravedad y desplaza el peso de golpe, lo que puede volcar la embarcación o arrojarlo al agua. Manténgase bajo y centrado y desplace el peso despacio.","ru":"Вставание или рывок на высокий борт поднимает центр тяжести и резко смещает вес, что может перевернуть лодку или выбросить вас за борт. Оставайтесь низко и по центру, смещайте вес медленно.","tr":"Ayağa kalkmak veya yüksek tarafa atılmak ağırlık merkezini yükseltir ve ağırlığı aniden kaydırır; bu tekneyi devirebilir ya da sizi denize atabilir. Alçak ve ortada kalın, ağırlığı yavaş kaydırın.","hi":"खड़े होना या ऊँची ओर झपटना गुरुत्व केंद्र ऊँचा करता है और वज़न अचानक खिसकाता है, जो नाव को पलटा सकता है या आपको पानी में फेंक सकता है। नीचे और बीच में रहें, और वज़न धीरे-धीरे खिसकाएँ।","ar":"الوقوف أو الاندفاع نحو الجانب المرتفع يرفع مركز الثقل وينقل الوزن فجأة، مما قد يقلب القارب أو يقذفك في الماء. ابقَ منخفضاً وفي المنتصف وانقل الوزن ببطء."}},{"cat":"emergencies","a":1,"q":{"en":"If someone shows signs of drowning or has been pulled unresponsive from the water, you should:","es":"Si alguien muestra signos de ahogamiento o es sacado del agua sin responder, debe:","ru":"Если человек тонет или его вытащили из воды без сознания, следует:","tr":"Biri boğulma belirtileri gösteriyorsa ya da sudan tepkisiz çıkarıldıysa:","hi":"यदि किसी में डूबने के लक्षण हों या उसे पानी से बेहोश निकाला गया हो, तो आपको चाहिए:","ar":"إذا ظهرت على شخص علامات الغرق أو انتُشل من الماء فاقداً للاستجابة، عليك أن:"},"o":[{"en":"Give them food and water","es":"Darle comida y agua","ru":"Дать ему еду и воду","tr":"Ona yiyecek ve su vermek","hi":"उन्हें भोजन और पानी देना","ar":"تعطيه طعاماً وماء"},{"en":"Get them to safety, call emergency services, and begin CPR/rescue breaths if trained and they are not breathing","es":"Ponerlo a salvo, llamar a emergencias e iniciar RCP/respiraciones si está capacitado y no respira","ru":"Доставить в безопасность, вызвать экстренные службы и начать СЛР/искусственное дыхание, если обучены и он не дышит","tr":"Onu güvene almak, acil servisi aramak ve eğitimliyseniz ve nefes almıyorsa TYD/kurtarıcı soluk vermek","hi":"उन्हें सुरक्षा में लाना, आपातकालीन सेवाओं को कॉल करना, और प्रशिक्षित हों व वे साँस न ले रहे हों तो CPR/रेस्क्यू साँसें शुरू करना","ar":"نقله إلى بر الأمان والاتصال بخدمات الطوارئ والبدء بالإنعاش القلبي الرئوي/التنفس الإنقاذي إن كنت مدرّباً ولا يتنفّس"},{"en":"Wait to see if they recover on their own","es":"Esperar a ver si se recupera solo","ru":"Подождать, не придёт ли он в себя сам","tr":"Kendiliğinden düzelip düzelmediğini beklemek","hi":"देखने के लिए इंतज़ार करना कि वे स्वयं ठीक होते हैं या नहीं","ar":"الانتظار لترى إن كان سيتعافى وحده"},{"en":"Make them walk it off","es":"Hacerlo caminar para reponerse","ru":"Заставить его пройтись, чтобы прийти в себя","tr":"Atlatması için yürütmek","hi":"उन्हें चलाकर ठीक कराना","ar":"تجعله يمشي ليتعافى"}],"e":{"en":"Get the person to safety, call for emergency help immediately, and if you are trained and they are not breathing, start CPR and rescue breaths. Every second counts in a drowning emergency.","es":"Ponga a la persona a salvo, llame de inmediato a emergencias y, si está capacitado y no respira, inicie la RCP y las respiraciones de rescate. Cada segundo cuenta en un ahogamiento.","ru":"Доставьте человека в безопасность, немедленно вызовите экстренную помощь и, если вы обучены и он не дышит, начните СЛР и искусственное дыхание. При утоплении дорога каждая секунда.","tr":"Kişiyi güvene alın, hemen acil yardım çağırın ve eğitimliyseniz ve nefes almıyorsa TYD ile kurtarıcı soluğa başlayın. Boğulma acilinde her saniye önemlidir.","hi":"व्यक्ति को सुरक्षा में लाएँ, तुरंत आपातकालीन मदद बुलाएँ, और यदि आप प्रशिक्षित हों व वे साँस न ले रहे हों तो CPR और रेस्क्यू साँसें शुरू करें। डूबने की आपात स्थिति में हर सेकंड मायने रखता है।","ar":"انقل الشخص إلى بر الأمان، واتصل بالطوارئ فوراً، وإن كنت مدرّباً ولا يتنفّس فابدأ بالإنعاش القلبي الرئوي والتنفس الإنقاذي. كل ثانية مهمة في حالة الغرق."}},{"cat":"emergencies","a":3,"q":{"en":"A bilge pump on a boat is important in an emergency because it:","es":"Una bomba de achique en una embarcación es importante en una emergencia porque:","ru":"Трюмная помпа важна в аварийной ситуации, потому что она:","tr":"Teknedeki sintine pompası acil durumda önemlidir çünkü:","hi":"नाव पर बिल्ज पंप आपात स्थिति में महत्वपूर्ण है क्योंकि यह:","ar":"مضخة القاع في القارب مهمة في حالة الطوارئ لأنها:"},"o":[{"en":"Cools the engine","es":"Enfría el motor","ru":"Охлаждает двигатель","tr":"Motoru soğutur","hi":"इंजन को ठंडा करती है","ar":"تُبرّد المحرك"},{"en":"Increases speed","es":"Aumenta la velocidad","ru":"Увеличивает скорость","tr":"Hızı artırır","hi":"गति बढ़ाती है","ar":"تزيد السرعة"},{"en":"Charges the battery","es":"Carga la batería","ru":"Заряжает аккумулятор","tr":"Aküyü şarj eder","hi":"बैटरी चार्ज करती है","ar":"تشحن البطارية"},{"en":"Removes water that leaks or splashes into the boat, helping keep it from swamping or sinking","es":"Extrae el agua que entra por filtración o salpicaduras, ayudando a evitar que se inunde o se hunda","ru":"Откачивает воду, попавшую через течь или брызги, помогая не дать лодке залиться или затонуть","tr":"Sızan veya sıçrayan suyu teknede uzaklaştırır, su basmasını ya da batmasını önlemeye yardımcı olur","hi":"रिसाव या छींटों से नाव में आए पानी को निकालती है, जिससे उसे भरने या डूबने से रोकने में मदद मिलती है","ar":"تُزيل الماء المتسرّب أو المتناثر داخل القارب، ما يساعد على منعه من الغمر أو الغرق"}],"e":{"en":"A working bilge pump removes water that leaks or splashes aboard, helping prevent swamping and sinking. Check that it and any manual bailing device (bucket, bailer) work before every trip.","es":"Una bomba de achique en buen estado extrae el agua que entra a bordo, ayudando a evitar inundación y hundimiento. Compruebe que funciona, junto con un achicador manual (balde), antes de cada salida.","ru":"Исправная трюмная помпа откачивает попавшую воду, помогая предотвратить заливание и затопление. Перед каждым выходом проверяйте её и ручное водоотливное средство (ведро, черпак).","tr":"Çalışan bir sintine pompası tekneye giren suyu uzaklaştırır, su basmasını ve batmayı önlemeye yardımcı olur. Her seferden önce pompanın ve manuel su boşaltma aracının (kova, tas) çalıştığını kontrol edin.","hi":"चालू बिल्ज पंप बोर्ड पर आए पानी को निकालता है, जिससे भरने और डूबने से बचाव होता है। हर यात्रा से पहले जाँचें कि यह और कोई मैनुअल बेलिंग उपकरण (बाल्टी, बेलर) काम करते हैं।","ar":"مضخة القاع العاملة تُزيل الماء الذي يتسرّب أو يتناثر داخل القارب، فتساعد على منع الغمر والغرق. تأكّد قبل كل رحلة من عملها وعمل أداة نزح يدوية (دلو أو مغرفة)."}},{"cat":"law","a":0,"q":{"en":"Most motorized boats must display what to show they are legally registered?","es":"La mayoría de las embarcaciones motorizadas deben mostrar qué para acreditar que están legalmente registradas?","ru":"Большинство моторных судов обязаны нести что, чтобы подтвердить законную регистрацию?","tr":"Çoğu motorlu tekne, yasal olarak kayıtlı olduğunu göstermek için ne sergilemelidir?","hi":"अधिकांश मोटर चालित नावों को कानूनी रूप से पंजीकृत होने का प्रमाण दिखाने के लिए क्या प्रदर्शित करना चाहिए?","ar":"يجب أن تعرض معظم القوارب الآلية ماذا لإثبات أنها مسجّلة قانونياً؟"},"o":[{"en":"A registration (bow) number and a validation decal, displayed as required","es":"Un número de registro (en la proa) y una calcomanía de validación, exhibidos como se exige","ru":"Регистрационный (носовой) номер и наклейку-стикер, размещённые по правилам","tr":"Bir kayıt (baş) numarası ve gerektiği şekilde sergilenen bir geçerlilik etiketi","hi":"एक पंजीकरण (बो) नंबर और आवश्यकतानुसार प्रदर्शित एक वैधता डिकल","ar":"رقم تسجيل (على المقدمة) وملصق تحقّق مثبّت حسب المطلوب"},{"en":"A national flag only","es":"Solo una bandera nacional","ru":"Только государственный флаг","tr":"Yalnızca bir ulusal bayrak","hi":"केवल एक राष्ट्रीय ध्वज","ar":"علماً وطنياً فقط"},{"en":"The owner's phone number","es":"El número de teléfono del propietario","ru":"Номер телефона владельца","tr":"Sahibinin telefon numarası","hi":"मालिक का फ़ोन नंबर","ar":"رقم هاتف المالك"},{"en":"A fishing license","es":"Una licencia de pesca","ru":"Лицензию на рыбалку","tr":"Bir balıkçılık ruhsatı","hi":"एक मछली पकड़ने का लाइसेंस","ar":"رخصة صيد"}],"e":{"en":"Registered boats must display the assigned registration number on both sides of the bow in the required style, plus a current validation sticker/decal. Exact rules vary by state.","es":"Las embarcaciones registradas deben exhibir el número asignado a ambos lados de la proa con el estilo requerido, además de una calcomanía de validación vigente. Las reglas varían por estado.","ru":"Зарегистрированные суда должны нести присвоенный регистрационный номер по обоим бортам носа в установленном виде и действующий стикер. Точные правила зависят от штата.","tr":"Kayıtlı tekneler, atanmış kayıt numarasını başın her iki tarafına gerekli biçimde ve geçerli bir geçerlilik etiketiyle sergilemelidir. Kesin kurallar eyalete göre değişir.","hi":"पंजीकृत नावों को आवंटित पंजीकरण नंबर बो के दोनों ओर आवश्यक शैली में, साथ ही एक चालू वैधता स्टिकर/डिकल दिखाना चाहिए। सटीक नियम राज्यानुसार भिन्न होते हैं।","ar":"يجب أن تعرض القوارب المسجّلة رقم التسجيل المخصّص على جانبي المقدمة بالشكل المطلوب، إضافةً إلى ملصق تحقّق ساري المفعول. تختلف القواعد الدقيقة حسب الولاية."}},{"cat":"law","a":2,"q":{"en":"How should the registration number be displayed on a boat's bow?","es":"¿Cómo debe exhibirse el número de registro en la proa de una embarcación?","ru":"Как должен быть нанесён регистрационный номер на носу судна?","tr":"Kayıt numarası teknenin başında nasıl sergilenmelidir?","hi":"नाव के बो पर पंजीकरण नंबर कैसे प्रदर्शित होना चाहिए?","ar":"كيف يجب عرض رقم التسجيل على مقدمة القارب؟"},"o":[{"en":"In small print near the waterline","es":"En letra pequeña cerca de la línea de flotación","ru":"Мелким шрифтом у ватерлинии","tr":"Su hattı yakınında küçük puntoyla","hi":"जलरेखा के पास छोटे अक्षरों में","ar":"بخط صغير قرب خط الماء"},{"en":"Only on one side","es":"Solo en un lado","ru":"Только с одного борта","tr":"Yalnızca bir tarafta","hi":"केवल एक ओर","ar":"على جانب واحد فقط"},{"en":"In plain block letters/numbers, read left to right, on both sides of the bow, contrasting with the hull","es":"En caracteres de imprenta legibles, de izquierda a derecha, en ambos lados de la proa y contrastando con el casco","ru":"Простыми печатными буквами/цифрами, слева направо, по обоим бортам носа, контрастно к корпусу","tr":"Düz blok harf/rakamlarla, soldan sağa okunur, başın her iki tarafında ve gövdeyle kontrast oluşturacak şekilde","hi":"सादे ब्लॉक अक्षरों/अंकों में, बाएँ से दाएँ पढ़े जाने योग्य, बो के दोनों ओर, पतवार से विपरीत रंग में","ar":"بحروف/أرقام واضحة تُقرأ من اليسار إلى اليمين على جانبي المقدمة ومتباينة مع البدن"},{"en":"Written in cursive at the stern","es":"En cursiva en la popa","ru":"Курсивом на корме","tr":"Kıçta el yazısıyla","hi":"स्टर्न पर घसीट लिपि में","ar":"بخط مائل على المؤخرة"}],"e":{"en":"Registration numbers must be in plain, block characters at least 3 inches high, read left to right, contrast with the hull, and appear on both sides of the bow. Check your state for exact rules.","es":"Los números deben ir en caracteres de imprenta legibles de al menos 3 pulgadas de alto, leerse de izquierda a derecha, contrastar con el casco y aparecer a ambos lados de la proa. Verifique las reglas exactas de su estado.","ru":"Регистрационные номера должны быть простыми печатными знаками высотой не менее 3 дюймов, читаться слева направо, контрастировать с корпусом и наноситься по обоим бортам носа. Уточняйте правила в своём штате.","tr":"Kayıt numaraları en az 3 inç yüksekliğinde düz blok karakterlerle, soldan sağa okunur, gövdeyle kontrast oluşturacak şekilde ve başın her iki tarafında olmalıdır. Kesin kurallar için eyaletinize bakın.","hi":"पंजीकरण नंबर सादे ब्लॉक अक्षरों में कम से कम 3 इंच ऊँचे, बाएँ से दाएँ पढ़े जाने योग्य, पतवार से विपरीत रंग में, और बो के दोनों ओर होने चाहिए। सटीक नियमों के लिए अपने राज्य को देखें।","ar":"يجب أن تكون أرقام التسجيل بحروف واضحة لا يقل ارتفاعها عن 3 بوصات، تُقرأ من اليسار لليمين، متباينة مع البدن، وعلى جانبي المقدمة. راجع قواعد ولايتك الدقيقة."}},{"cat":"law","a":1,"q":{"en":"Operating a boat under the influence (BUI) of alcohol or drugs is:","es":"Operar una embarcación bajo los efectos (BUI) del alcohol o drogas es:","ru":"Управление судном в состоянии опьянения (BUI) алкоголем или наркотиками:","tr":"Alkol veya uyuşturucu etkisi altında tekne kullanmak (BUI):","hi":"शराब या नशीली दवाओं के प्रभाव में नाव चलाना (BUI):","ar":"قيادة القارب تحت تأثير (BUI) الكحول أو المخدّرات:"},"o":[{"en":"Legal as long as you go slowly","es":"Legal siempre que vaya despacio","ru":"Законно, если идти медленно","tr":"Yavaş gittiğiniz sürece yasal","hi":"धीरे चलने पर कानूनी","ar":"قانونية ما دمت تسير ببطء"},{"en":"Illegal everywhere in the U.S. and enforced like drunk driving","es":"Ilegal en todo EE. UU. y sancionado como conducir ebrio","ru":"Незаконно на всей территории США и карается как вождение в нетрезвом виде","tr":"ABD'nin her yerinde yasa dışıdır ve alkollü araç kullanmak gibi cezalandırılır","hi":"पूरे अमेरिका में अवैध है और शराब पीकर गाड़ी चलाने की तरह लागू किया जाता है","ar":"غير قانونية في كل الولايات الأمريكية وتُطبَّق مثل القيادة تحت تأثير الكحول"},{"en":"Only illegal at night","es":"Solo ilegal de noche","ru":"Незаконно только ночью","tr":"Yalnızca gece yasa dışı","hi":"केवल रात में अवैध","ar":"غير قانونية ليلاً فقط"},{"en":"Legal for passengers, not operators","es":"Legal para pasajeros, no operadores","ru":"Законно для пассажиров, но не судоводителей","tr":"Yolcular için yasal, operatörler için değil","hi":"यात्रियों के लिए कानूनी, चालकों के लिए नहीं","ar":"قانونية للركاب لا للمشغّلين"}],"e":{"en":"BUI is illegal in every U.S. state and under federal law, with a common legal limit of 0.08% blood alcohol for operators. Penalties are severe, and alcohol is a leading factor in boating deaths.","es":"El BUI es ilegal en todos los estados de EE. UU. y por ley federal, con un límite común de 0.08% de alcohol en sangre para operadores. Las sanciones son severas y el alcohol es un factor principal en muertes.","ru":"BUI незаконно во всех штатах США и по федеральному закону; распространённый предел — 0,08% алкоголя в крови для судоводителей. Наказания суровы, а алкоголь — ведущий фактор гибели на воде.","tr":"BUI, ABD'nin her eyaletinde ve federal yasada yasa dışıdır; operatörler için yaygın yasal sınır %0,08 kandaki alkoldür. Cezalar ağırdır ve alkol tekne ölümlerinde başlıca etkendir.","hi":"BUI अमेरिका के हर राज्य और संघीय कानून के तहत अवैध है, चालकों के लिए सामान्य कानूनी सीमा 0.08% रक्त-अल्कोहल है। दंड कठोर हैं, और शराब नौका मौतों में एक प्रमुख कारक है।","ar":"القيادة تحت التأثير (BUI) غير قانونية في كل ولاية أمريكية وبموجب القانون الفيدرالي، وحدّها القانوني الشائع 0.08% من الكحول في الدم للمشغّلين. العقوبات شديدة والكحول عامل رئيسي في وفيات القوارب."}},{"cat":"law","a":3,"q":{"en":"Why is alcohol especially dangerous on the water compared with on land?","es":"¿Por qué el alcohol es especialmente peligroso en el agua en comparación con la tierra?","ru":"Почему алкоголь особенно опасен на воде по сравнению с сушей?","tr":"Alkol suda karaya kıyasla neden özellikle tehlikelidir?","hi":"ज़मीन की तुलना में पानी पर शराब विशेष रूप से खतरनाक क्यों है?","ar":"لماذا يكون الكحول خطراً بشكل خاص على الماء مقارنةً بالبر؟"},"o":[{"en":"It tastes different on a boat","es":"Sabe diferente en una embarcación","ru":"Он иначе на вкус на лодке","tr":"Teknede tadı farklıdır","hi":"नाव पर इसका स्वाद अलग होता है","ar":"طعمه مختلف على القارب"},{"en":"It is cheaper on the water","es":"Es más barato en el agua","ru":"Он дешевле на воде","tr":"Suda daha ucuzdur","hi":"पानी पर यह सस्ता है","ar":"أرخص على الماء"},{"en":"Boats have seat belts","es":"Las embarcaciones tienen cinturones","ru":"На лодках есть ремни безопасности","tr":"Teknelerde emniyet kemeri vardır","hi":"नावों में सीट बेल्ट होते हैं","ar":"القوارب فيها أحزمة أمان"},{"en":"Sun, wind, motion, and noise intensify impairment, and impaired people who fall in cold water drown more easily","es":"El sol, viento, movimiento y ruido intensifican el deterioro, y una persona afectada que cae al agua fría se ahoga con más facilidad","ru":"Солнце, ветер, качка и шум усиливают опьянение, а пьяный, упавший в холодную воду, легче тонет","tr":"Güneş, rüzgar, hareket ve gürültü etkiyi artırır; sarhoş biri soğuk suya düşerse daha kolay boğulur","hi":"धूप, हवा, गति और शोर दुर्बलता बढ़ाते हैं, और नशे में ठंडे पानी में गिरा व्यक्ति अधिक आसानी से डूबता है","ar":"الشمس والرياح والحركة والضوضاء تُفاقِم الإعاقة، والشخص الثمِل الذي يسقط في الماء البارد يغرق بسهولة أكبر"}],"e":{"en":"\"Boater's fatigue\" from sun, wind, motion, and noise multiplies alcohol's effects, so a boater becomes impaired faster than a driver. An intoxicated person who falls overboard is also far more likely to drown.","es":"La \"fatiga del navegante\" por sol, viento, movimiento y ruido multiplica los efectos del alcohol, así que el navegante se deteriora más rápido que un conductor. Alguien ebrio que cae al agua también tiene mucho más riesgo de ahogarse.","ru":"«Усталость моряка» от солнца, ветра, качки и шума умножает действие алкоголя, поэтому судоводитель пьянеет быстрее водителя. Пьяный, упавший за борт, также гораздо вероятнее утонет.","tr":"Güneş, rüzgar, hareket ve gürültüden kaynaklanan \"denizci yorgunluğu\" alkolün etkilerini katlar; bu yüzden denizci bir sürücüden daha hızlı etkilenir. Denize düşen sarhoş biri de çok daha kolay boğulur.","hi":"धूप, हवा, गति और शोर से होने वाली \"बोटर की थकान\" शराब के प्रभाव को कई गुना बढ़ा देती है, इसलिए नाविक चालक से जल्दी दुर्बल हो जाता है। पानी में गिरा नशे में व्यक्ति भी कहीं अधिक आसानी से डूबता है।","ar":"يضاعف \"إرهاق البحّار\" الناتج عن الشمس والرياح والحركة والضوضاء آثار الكحول، فيصبح البحّار مصاباً أسرع من السائق. كما أن الشخص الثمِل الذي يسقط في الماء أكثر عرضة للغرق بكثير."}},{"cat":"law","a":0,"q":{"en":"If law enforcement signals your boat to stop, you should:","es":"Si las fuerzas del orden le indican que detenga su embarcación, debe:","ru":"Если сотрудники правопорядка сигналят вам остановиться, вы должны:","tr":"Kolluk kuvvetleri teknenize durmanız için işaret verirse:","hi":"यदि कानून प्रवर्तन आपकी नाव को रुकने का संकेत दे, तो आपको चाहिए:","ar":"إذا أشارت لك جهة إنفاذ القانون بإيقاف قاربك، عليك أن:"},"o":[{"en":"Reduce speed, stop safely, and comply with the officer's instructions","es":"Reducir la velocidad, detenerse con seguridad y cumplir las instrucciones del oficial","ru":"Снизить скорость, безопасно остановиться и выполнять указания сотрудника","tr":"Hızı azaltmak, güvenle durmak ve görevlinin talimatlarına uymak","hi":"गति कम करना, सुरक्षित रूप से रुकना, और अधिकारी के निर्देशों का पालन करना","ar":"تخفيف السرعة والتوقّف بأمان والامتثال لتعليمات الضابط"},{"en":"Speed away","es":"Huir a toda velocidad","ru":"Уйти на скорости","tr":"Hızla kaçmak","hi":"तेज़ी से भाग जाना","ar":"الهروب بسرعة"},{"en":"Ignore them if you did nothing wrong","es":"Ignorarlos si no hizo nada malo","ru":"Игнорировать, если ничего не нарушили","tr":"Bir yanlış yapmadıysanız görmezden gelmek","hi":"यदि आपने कुछ गलत नहीं किया तो अनदेखा करना","ar":"تجاهلهم إن لم تفعل خطأً"},{"en":"Throw your gear overboard","es":"Tirar su equipo por la borda","ru":"Выбросить снаряжение за борт","tr":"Eşyalarınızı denize atmak","hi":"अपना सामान पानी में फेंक देना","ar":"رمي عتادك في الماء"}],"e":{"en":"Boaters must stop when signaled by the Coast Guard, marine police, or other law enforcement, who may board to check registration, safety equipment, and sobriety. Failing to stop is a serious offense.","es":"Los navegantes deben detenerse cuando lo indiquen la Guardia Costera, la policía marítima u otras fuerzas del orden, que pueden abordar para revisar registro, equipo de seguridad y sobriedad. No detenerse es una falta grave.","ru":"Судоводители обязаны остановиться по сигналу Береговой охраны, водной полиции или иных органов, которые могут подняться на борт для проверки регистрации, снаряжения и трезвости. Неостановка — серьёзное нарушение.","tr":"Denizciler; Sahil Güvenlik, deniz polisi veya diğer kolluk işaret verdiğinde durmalıdır; bunlar kayıt, güvenlik ekipmanı ve ayıklık kontrolü için tekneye çıkabilir. Durmamak ağır bir suçtur.","hi":"नाविकों को कोस्ट गार्ड, समुद्री पुलिस या अन्य कानून प्रवर्तन के संकेत पर रुकना चाहिए, जो पंजीकरण, सुरक्षा उपकरण और नशे की जाँच के लिए बोर्ड कर सकते हैं। न रुकना एक गंभीर अपराध है।","ar":"على البحّارة التوقّف عند إشارة خفر السواحل أو الشرطة البحرية أو غيرهم من جهات إنفاذ القانون، التي قد تصعد للتحقّق من التسجيل ومعدات السلامة والرصانة. عدم التوقّف مخالفة خطيرة."}},{"cat":"law","a":2,"q":{"en":"Many states require boat operators born after a certain date to:","es":"Muchos estados exigen que los operadores nacidos después de cierta fecha:","ru":"Многие штаты требуют, чтобы судоводители, родившиеся после определённой даты:","tr":"Birçok eyalet, belirli bir tarihten sonra doğan tekne operatörlerinin:","hi":"कई राज्य एक निश्चित तिथि के बाद जन्मे नाव चालकों से आवश्यक करते हैं कि:","ar":"تشترط ولايات كثيرة على مشغّلي القوارب المولودين بعد تاريخ معيّن أن:"},"o":[{"en":"Own two boats","es":"Tener dos embarcaciones","ru":"Владели двумя лодками","tr":"İki tekneye sahip olması","hi":"दो नावें रखें","ar":"يمتلكوا قاربين"},{"en":"Be at least 30 years old","es":"Tener al menos 30 años","ru":"Быть не моложе 30 лет","tr":"En az 30 yaşında olması","hi":"कम से कम 30 वर्ष के हों","ar":"يكونوا في الثلاثين على الأقل"},{"en":"Complete an approved boater safety education course and carry the card","es":"Completar un curso aprobado de seguridad náutica y portar la tarjeta","ru":"Пройти одобренный курс безопасности на воде и иметь при себе карту","tr":"Onaylı bir tekne güvenliği eğitim kursunu tamamlaması ve kartı taşıması","hi":"एक अनुमोदित नौका सुरक्षा शिक्षा पाठ्यक्रम पूरा करें और कार्ड साथ रखें","ar":"يُكملوا دورة تعليم سلامة قوارب معتمدة ويحملوا البطاقة"},{"en":"Register with the FBI","es":"Registrarse ante el FBI","ru":"Зарегистрироваться в ФБР","tr":"FBI'a kaydolması","hi":"FBI में पंजीकरण कराएँ","ar":"يسجّلوا لدى الـ FBI"}],"e":{"en":"Most states now require operators born after a set year to pass an approved boater safety course and carry a boater education card. The exact age cutoffs and rules differ by state.","es":"La mayoría de los estados exige ahora que los operadores nacidos después de cierto año aprueben un curso aprobado y porten una tarjeta de educación náutica. Los cortes de edad y las reglas difieren por estado.","ru":"Большинство штатов теперь требуют, чтобы судоводители, рождённые после определённого года, сдали одобренный курс и имели карту обучения. Возрастные пороги и правила различаются по штату.","tr":"Çoğu eyalet artık belirli bir yıldan sonra doğan operatörlerin onaylı bir kursu geçmesini ve tekne eğitim kartı taşımasını ister. Yaş sınırları ve kurallar eyalete göre değişir.","hi":"अधिकांश राज्य अब एक निर्धारित वर्ष के बाद जन्मे चालकों से एक अनुमोदित पाठ्यक्रम पास करने और नौका शिक्षा कार्ड साथ रखने की माँग करते हैं। सटीक आयु सीमाएँ और नियम राज्यानुसार भिन्न होते हैं।","ar":"تشترط معظم الولايات الآن على المشغّلين المولودين بعد سنة معيّنة اجتياز دورة معتمدة وحمل بطاقة تعليم قوارب. تختلف حدود العمر والقواعد حسب الولاية."}},{"cat":"law","a":1,"q":{"en":"Which statement about minimum age to operate a motorized boat is generally true?","es":"¿Qué afirmación sobre la edad mínima para operar una embarcación motorizada es generalmente cierta?","ru":"Какое утверждение о минимальном возрасте для управления моторным судном в целом верно?","tr":"Motorlu tekne kullanmak için asgari yaşla ilgili hangi ifade genellikle doğrudur?","hi":"मोटर चालित नाव चलाने की न्यूनतम आयु के बारे में कौन सा कथन आमतौर पर सही है?","ar":"أي عبارة حول الحد الأدنى لسن قيادة قارب آلي صحيحة عموماً؟"},"o":[{"en":"There is one nationwide minimum age set by the federal government","es":"Hay una edad mínima única a nivel nacional fijada por el gobierno federal","ru":"Существует единый общенациональный минимальный возраст, установленный федеральным правительством","tr":"Federal hükümetin belirlediği tek bir ülke çapında asgari yaş vardır","hi":"संघीय सरकार द्वारा निर्धारित एक देशव्यापी न्यूनतम आयु है","ar":"هناك حد أدنى للسن على مستوى الدولة تحدّده الحكومة الفيدرالية"},{"en":"Minimum operating ages and horsepower limits for young operators are set by each state and vary","es":"Cada estado fija las edades mínimas y límites de potencia para operadores jóvenes, y varían","ru":"Минимальный возраст и ограничения по мощности для молодых судоводителей устанавливает каждый штат, и они различаются","tr":"Genç operatörler için asgari yaşlar ve güç sınırları her eyalet tarafından belirlenir ve değişir","hi":"युवा चालकों के लिए न्यूनतम आयु और हॉर्सपावर सीमाएँ प्रत्येक राज्य तय करता है और वे भिन्न होती हैं","ar":"تحدّد كل ولاية أعمار التشغيل الدنيا وحدود القوة للمشغّلين الصغار وهي متفاوتة"},{"en":"Anyone of any age may operate any boat","es":"Cualquiera de cualquier edad puede operar cualquier embarcación","ru":"Любой в любом возрасте может управлять любым судном","tr":"Her yaştan herkes her tekneyi kullanabilir","hi":"किसी भी आयु का कोई भी व्यक्ति कोई भी नाव चला सकता है","ar":"يمكن لأي شخص من أي عمر قيادة أي قارب"},{"en":"Only people over 21 may operate boats","es":"Solo mayores de 21 pueden operar embarcaciones","ru":"Только лица старше 21 года могут управлять судами","tr":"Yalnızca 21 yaş üstü tekne kullanabilir","hi":"केवल 21 वर्ष से ऊपर के लोग नाव चला सकते हैं","ar":"يقود القوارب من هم فوق 21 عاماً فقط"}],"e":{"en":"There is no single national minimum age; each state sets its own minimum operating ages, supervision rules, and horsepower limits for young operators. Always check the law where you boat.","es":"No hay una única edad mínima nacional; cada estado fija sus propias edades mínimas, reglas de supervisión y límites de potencia para jóvenes. Verifique siempre la ley del lugar donde navega.","ru":"Единого общенационального минимального возраста нет; каждый штат устанавливает свои минимальные возрасты, правила надзора и ограничения по мощности для молодых. Всегда проверяйте местный закон.","tr":"Tek bir ulusal asgari yaş yoktur; her eyalet genç operatörler için kendi asgari yaşlarını, gözetim kurallarını ve güç sınırlarını belirler. Tekne kullandığınız yerin yasasını daima kontrol edin.","hi":"कोई एकल राष्ट्रीय न्यूनतम आयु नहीं है; प्रत्येक राज्य युवा चालकों के लिए अपनी न्यूनतम आयु, पर्यवेक्षण नियम और हॉर्सपावर सीमाएँ तय करता है। जहाँ आप नाव चलाते हैं वहाँ का कानून हमेशा जाँचें।","ar":"لا يوجد حد أدنى واحد للسن على مستوى الدولة؛ فكل ولاية تحدّد أعمار التشغيل الدنيا وقواعد الإشراف وحدود القوة للمشغّلين الصغار. تحقّق دائماً من قانون المكان الذي تُبحر فيه."}},{"cat":"law","a":3,"q":{"en":"When must a boating accident generally be reported to authorities?","es":"¿Cuándo debe reportarse generalmente un accidente de navegación a las autoridades?","ru":"Когда, как правило, необходимо сообщать властям о происшествии на воде?","tr":"Bir tekne kazası genellikle ne zaman makamlara bildirilmelidir?","hi":"नौका दुर्घटना की सूचना आमतौर पर अधिकारियों को कब देनी चाहिए?","ar":"متى يجب عادةً الإبلاغ عن حادث قارب للسلطات؟"},"o":[{"en":"Only if the boat sinks completely","es":"Solo si la embarcación se hunde por completo","ru":"Только если лодка полностью затонула","tr":"Yalnızca tekne tamamen batarsa","hi":"केवल यदि नाव पूरी तरह डूब जाए","ar":"فقط إذا غرق القارب بالكامل"},{"en":"Never — reporting is optional","es":"Nunca: reportar es opcional","ru":"Никогда — отчётность необязательна","tr":"Asla — bildirim isteğe bağlıdır","hi":"कभी नहीं — रिपोर्टिंग वैकल्पिक है","ar":"أبداً — الإبلاغ اختياري"},{"en":"Only if police happen to see it","es":"Solo si la policía lo ve","ru":"Только если это заметит полиция","tr":"Yalnızca polis görürse","hi":"केवल यदि पुलिस देख ले","ar":"فقط إذا رأته الشرطة"},{"en":"When there is death, disappearance, injury beyond first aid, or property damage above a set dollar amount","es":"Cuando hay muerte, desaparición, lesiones más allá de primeros auxilios o daños por encima de cierto monto","ru":"При гибели, исчезновении, травме сверх первой помощи или ущербе имуществу свыше установленной суммы","tr":"Ölüm, kaybolma, ilk yardımı aşan yaralanma veya belirli bir tutarın üzerinde maddi hasar olduğunda","hi":"जब मृत्यु, लापता होना, प्राथमिक चिकित्सा से अधिक चोट, या निर्धारित राशि से अधिक संपत्ति क्षति हो","ar":"عند حدوث وفاة أو اختفاء أو إصابة تتجاوز الإسعافات الأولية أو أضرار مادية تفوق مبلغاً محدداً"}],"e":{"en":"A boating accident report is required when there is a death or disappearance, an injury needing more than first aid, or property damage above a set threshold (commonly around $2,000). Deadlines and amounts vary by state.","es":"Se exige un reporte cuando hay muerte o desaparición, una lesión que requiere más que primeros auxilios o daños por encima de un umbral (comúnmente unos $2,000). Los plazos y montos varían por estado.","ru":"Отчёт о происшествии требуется при гибели или исчезновении, травме, требующей больше чем первую помощь, или ущербе имуществу свыше порога (обычно около 2000 долл.). Сроки и суммы различаются по штату.","tr":"Ölüm ya da kaybolma, ilk yardımı aşan bir yaralanma veya belirli bir eşiği (genellikle ~2.000 $) aşan maddi hasar olduğunda kaza raporu gerekir. Süreler ve tutarlar eyalete göre değişir.","hi":"मृत्यु या लापता होना, प्राथमिक चिकित्सा से अधिक की चोट, या एक निर्धारित सीमा (आमतौर पर लगभग $2,000) से अधिक संपत्ति क्षति होने पर दुर्घटना रिपोर्ट आवश्यक है। समय-सीमाएँ और राशियाँ राज्यानुसार भिन्न होती हैं।","ar":"يلزم تقرير حادث عند حدوث وفاة أو اختفاء أو إصابة تتطلّب أكثر من إسعاف أولي أو أضرار مادية تتجاوز حداً معيّناً (غالباً نحو 2000 دولار). تختلف المهل والمبالغ حسب الولاية."}},{"cat":"law","a":0,"q":{"en":"Do you always need to carry your boat registration document while operating?","es":"¿Debe siempre llevar el documento de registro de la embarcación mientras la opera?","ru":"Нужно ли всегда иметь при себе регистрационный документ судна во время управления?","tr":"Tekne kullanırken kayıt belgesini her zaman yanınızda bulundurmanız gerekir mi?","hi":"क्या नाव चलाते समय आपको हमेशा अपना नाव पंजीकरण दस्तावेज़ साथ रखना चाहिए?","ar":"هل يجب دائماً حمل وثيقة تسجيل القارب أثناء القيادة؟"},"o":[{"en":"Yes — most states require the certificate of registration to be aboard and available for inspection","es":"Sí: la mayoría de los estados exigen tener a bordo el certificado de registro para su inspección","ru":"Да — большинство штатов требуют иметь на борту свидетельство о регистрации для проверки","tr":"Evet — çoğu eyalet kayıt belgesinin teknede ve denetime hazır bulundurulmasını ister","hi":"हाँ — अधिकांश राज्य पंजीकरण प्रमाणपत्र को बोर्ड पर और निरीक्षण के लिए उपलब्ध रखना आवश्यक करते हैं","ar":"نعم — تشترط معظم الولايات وجود شهادة التسجيل على متن القارب ومتاحة للفحص"},{"en":"No — it can stay at home","es":"No: puede quedarse en casa","ru":"Нет — можно оставить дома","tr":"Hayır — evde kalabilir","hi":"नहीं — यह घर पर रह सकता है","ar":"لا — يمكن أن تبقى في المنزل"},{"en":"Only for boats over 40 feet","es":"Solo para embarcaciones de más de 40 pies","ru":"Только для судов длиннее 40 футов","tr":"Yalnızca 40 fitten uzun tekneler için","hi":"केवल 40 फुट से बड़ी नावों के लिए","ar":"فقط للقوارب التي يزيد طولها عن 40 قدماً"},{"en":"Only when crossing state lines","es":"Solo al cruzar entre estados","ru":"Только при пересечении границ штатов","tr":"Yalnızca eyalet sınırlarını geçerken","hi":"केवल राज्य की सीमाएँ पार करते समय","ar":"فقط عند عبور حدود الولايات"}],"e":{"en":"Most states require the certificate of registration to be on board and available whenever the boat is in use, so it can be shown during a law-enforcement inspection. Rules vary by state.","es":"La mayoría de los estados exige tener a bordo el certificado de registro y disponible siempre que se use la embarcación, para mostrarlo en una inspección. Las reglas varían por estado.","ru":"Большинство штатов требуют, чтобы свидетельство о регистрации было на борту и доступно во время использования судна для предъявления при проверке. Правила зависят от штата.","tr":"Çoğu eyalet, tekne kullanımda olduğunda kayıt belgesinin teknede ve denetimde gösterilmeye hazır bulundurulmasını ister. Kurallar eyalete göre değişir.","hi":"अधिकांश राज्य नाव के उपयोग में रहते समय पंजीकरण प्रमाणपत्र को बोर्ड पर और उपलब्ध रखना आवश्यक करते हैं, ताकि निरीक्षण के दौरान दिखाया जा सके। नियम राज्यानुसार भिन्न होते हैं।","ar":"تشترط معظم الولايات وجود شهادة التسجيل على متن القارب ومتاحة كلما كان القارب مستخدماً لإظهارها أثناء الفحص. تختلف القواعد حسب الولاية."}},{"cat":"law","a":2,"q":{"en":"Discharging oil, fuel, or trash into the water is:","es":"Descargar aceite, combustible o basura al agua es:","ru":"Сброс масла, топлива или мусора в воду:","tr":"Suya yağ, yakıt veya çöp boşaltmak:","hi":"पानी में तेल, ईंधन या कचरा छोड़ना:","ar":"تصريف الزيت أو الوقود أو القمامة في الماء يُعدّ:"},"o":[{"en":"Fine in small amounts","es":"Aceptable en pequeñas cantidades","ru":"Допустимо в малых количествах","tr":"Küçük miktarlarda sorun değil","hi":"छोटी मात्रा में ठीक है","ar":"مقبولاً بكميات صغيرة"},{"en":"Encouraged to feed fish","es":"Recomendable para alimentar peces","ru":"Поощряется для кормления рыб","tr":"Balık beslemek için teşvik edilir","hi":"मछलियों को खिलाने के लिए प्रोत्साहित","ar":"مشجَّعاً لإطعام الأسماك"},{"en":"Illegal and subject to significant penalties under environmental laws","es":"Ilegal y sujeto a sanciones importantes según las leyes ambientales","ru":"Незаконно и влечёт значительные штрафы по природоохранным законам","tr":"Yasa dışıdır ve çevre yasaları uyarınca ciddi cezalara tabidir","hi":"अवैध है और पर्यावरण कानूनों के तहत महत्वपूर्ण दंड के अधीन है","ar":"غير قانوني ويخضع لعقوبات كبيرة بموجب القوانين البيئية"},{"en":"Only banned in oceans","es":"Solo prohibido en océanos","ru":"Запрещено только в океанах","tr":"Yalnızca okyanuslarda yasak","hi":"केवल महासागरों में प्रतिबंधित","ar":"محظوراً في المحيطات فقط"}],"e":{"en":"It is illegal to dump oil, fuel, or garbage into the water. Federal law prohibits discharging oil or hazardous substances, and dumping trash carries heavy fines. Report spills as required.","es":"Es ilegal verter aceite, combustible o basura al agua. La ley federal prohíbe descargar petróleo o sustancias peligrosas, y tirar basura conlleva multas cuantiosas. Reporte los derrames según se exija.","ru":"Сброс масла, топлива или мусора в воду незаконен. Федеральный закон запрещает сброс нефти или опасных веществ, а выброс мусора влечёт крупные штрафы. Сообщайте о разливах, как требуется.","tr":"Suya yağ, yakıt veya çöp dökmek yasa dışıdır. Federal yasa petrol veya tehlikeli madde boşaltmayı yasaklar; çöp dökmek ağır para cezası getirir. Sızıntıları gerektiği gibi bildirin.","hi":"पानी में तेल, ईंधन या कचरा डालना अवैध है। संघीय कानून तेल या खतरनाक पदार्थ छोड़ने पर रोक लगाता है, और कचरा डालने पर भारी जुर्माना है। आवश्यकतानुसार रिसाव की सूचना दें।","ar":"يُحظر إلقاء الزيت أو الوقود أو القمامة في الماء. يمنع القانون الفيدرالي تصريف النفط أو المواد الخطرة، وإلقاء القمامة يستوجب غرامات كبيرة. أبلِغ عن الانسكابات حسب المطلوب."}},{"cat":"law","a":1,"q":{"en":"Placards required on many boats remind operators not to:","es":"Los letreros exigidos en muchas embarcaciones recuerdan a los operadores no:","ru":"Таблички, обязательные на многих судах, напоминают судоводителям не:","tr":"Birçok teknede zorunlu olan levhalar operatörlere neyi hatırlatır?","hi":"कई नावों पर आवश्यक प्लेकार्ड चालकों को याद दिलाते हैं कि वे न करें:","ar":"اللوحات المطلوبة في كثير من القوارب تُذكّر المشغّلين بعدم:"},"o":[{"en":"Use the radio","es":"Usar la radio","ru":"Пользоваться радио","tr":"Telsiz kullanmayı","hi":"रेडियो का उपयोग करना","ar":"استخدام الراديو"},{"en":"Illegally dump oil or garbage overboard","es":"Verter ilegalmente aceite o basura por la borda","ru":"Незаконно сбрасывать масло или мусор за борт","tr":"Yağ veya çöpü yasa dışı olarak denize dökmeyi","hi":"अवैध रूप से तेल या कचरा पानी में फेंकना","ar":"تصريف الزيت أو القمامة في الماء بشكل غير قانوني"},{"en":"Wear life jackets","es":"Usar chalecos salvavidas","ru":"Носить спасательные жилеты","tr":"Can yeleği giymeyi","hi":"लाइफ जैकेट पहनना","ar":"ارتداء سترات النجاة"},{"en":"Anchor at night","es":"Fondear de noche","ru":"Становиться на якорь ночью","tr":"Gece demirlemeyi","hi":"रात में लंगर डालना","ar":"الرسو ليلاً"}],"e":{"en":"Oil-discharge and garbage-dumping placards are required aboard many boats (generally 26 feet and longer) to remind operators that dumping oil or trash overboard is illegal and to report spills.","es":"Los letreros sobre descarga de aceite y basura son obligatorios en muchas embarcaciones (por lo general de 26 pies o más) para recordar que tirar aceite o basura por la borda es ilegal y que se deben reportar derrames.","ru":"Таблички о сбросе масла и мусора обязательны на многих судах (обычно от 26 футов), чтобы напоминать: сброс масла или мусора за борт незаконен, а о разливах нужно сообщать.","tr":"Yağ boşaltma ve çöp dökme levhaları birçok teknede (genellikle 26 fit ve üzeri) zorunludur; yağ veya çöpü denize dökmenin yasa dışı olduğunu ve sızıntıların bildirilmesi gerektiğini hatırlatır.","hi":"तेल-निर्वहन और कचरा-डंपिंग प्लेकार्ड कई नावों (आमतौर पर 26 फुट या अधिक) पर आवश्यक हैं ताकि याद दिलाया जाए कि तेल या कचरा पानी में डालना अवैध है और रिसाव की सूचना देनी है।","ar":"لوحات تصريف الزيت وإلقاء القمامة مطلوبة في كثير من القوارب (عادةً 26 قدماً فأكثر) لتذكير المشغّلين بأن إلقاء الزيت أو القمامة في الماء غير قانوني وبوجوب الإبلاغ عن الانسكابات."}},{"cat":"law","a":3,"q":{"en":"Aquatic invasive species laws generally require boaters to:","es":"Las leyes sobre especies acuáticas invasoras generalmente exigen que los navegantes:","ru":"Законы об инвазивных водных видах обычно требуют, чтобы судоводители:","tr":"Sucul istilacı tür yasaları genellikle denizcilerin şunu yapmasını gerektirir:","hi":"जलीय आक्रामक प्रजाति कानून आमतौर पर नाविकों से आवश्यक करते हैं कि वे:","ar":"تشترط قوانين الأنواع المائية الغازية عموماً على البحّارة أن:"},"o":[{"en":"Move plants between lakes","es":"Trasladar plantas entre lagos","ru":"Перевозили растения между озёрами","tr":"Bitkileri göller arasında taşımak","hi":"झीलों के बीच पौधे ले जाएँ","ar":"ينقلوا النباتات بين البحيرات"},{"en":"Release bait fish into any water","es":"Soltar peces carnada en cualquier agua","ru":"Выпускали наживку в любую воду","tr":"Yem balıklarını herhangi bir suya bırakmak","hi":"चारा मछली को किसी भी पानी में छोड़ें","ar":"يطلقوا أسماك الطُّعم في أي ماء"},{"en":"Clean, drain, and dry the boat and gear when leaving the water to avoid spreading invasive species","es":"Limpiar, vaciar y secar la embarcación y el equipo al salir del agua para no propagar especies invasoras","ru":"Очищали, осушали и высушивали лодку и снаряжение при выходе из воды, чтобы не распространять инвазивные виды","tr":"Sudan çıkarken istilacı türlerin yayılmaması için tekneyi ve teçhizatı temizlemek, boşaltmak ve kurutmak","hi":"पानी से निकलते समय आक्रामक प्रजातियों के फैलाव से बचने के लिए नाव और उपकरण को साफ़, खाली और सुखाएँ","ar":"ينظّفوا القارب والعتاد ويصرّفوا ماءه ويجفّفوه عند مغادرة الماء لتجنّب نشر الأنواع الغازية"},{"en":"Leave mud and weeds on the trailer","es":"Dejar lodo y algas en el remolque","ru":"Оставляли грязь и водоросли на прицепе","tr":"Römorkta çamur ve yosun bırakmak","hi":"ट्रेलर पर कीचड़ और घास छोड़ दें","ar":"يتركوا الطين والأعشاب على المقطورة"}],"e":{"en":"To stop the spread of aquatic invasive species, clean off plants and mud, drain all water (bilge, live wells, motor), and dry your boat, trailer, and gear before moving to another body of water.","es":"Para frenar la propagación de especies invasoras, limpie plantas y lodo, vacíe toda el agua (sentina, viveros, motor) y seque la embarcación, el remolque y el equipo antes de ir a otro cuerpo de agua.","ru":"Чтобы остановить распространение инвазивных видов, удаляйте растения и грязь, сливайте всю воду (трюм, садки, двигатель) и просушивайте лодку, прицеп и снаряжение перед переходом к другому водоёму.","tr":"İstilacı türlerin yayılmasını durdurmak için bitki ve çamuru temizleyin, tüm suyu (sintine, canlı balık haznesi, motor) boşaltın ve başka bir su kütlesine gitmeden tekne, römork ve teçhizatı kurutun.","hi":"आक्रामक प्रजातियों का फैलाव रोकने के लिए, पौधे व कीचड़ साफ़ करें, सारा पानी निकालें (बिल्ज, लाइव वेल, मोटर), और किसी अन्य जल-निकाय में जाने से पहले नाव, ट्रेलर व उपकरण सुखाएँ।","ar":"لوقف انتشار الأنواع الغازية، أزِل النباتات والطين، وصرّف كل الماء (القاع، وأحواض الطُّعم الحي، والمحرك)، وجفّف قاربك ومقطورتك وعتادك قبل الانتقال إلى مسطح مائي آخر."}},{"cat":"law","a":0,"q":{"en":"A holding tank or Marine Sanitation Device (MSD) on a boat is used to:","es":"Un tanque de retención o dispositivo de saneamiento marino (MSD) en una embarcación se usa para:","ru":"Накопительный бак или судовое санитарное устройство (MSD) на судне используется для:","tr":"Teknedeki bir atık tankı veya Deniz Sanitasyon Cihazı (MSD) ne için kullanılır?","hi":"नाव पर होल्डिंग टैंक या मरीन सैनिटेशन डिवाइस (MSD) का उपयोग किया जाता है:","ar":"يُستخدم خزان التجميع أو جهاز الصرف الصحي البحري (MSD) على القارب من أجل:"},"o":[{"en":"Manage and store sewage so it is not illegally discharged into restricted waters","es":"Gestionar y almacenar las aguas residuales para no descargarlas ilegalmente en aguas restringidas","ru":"Сбора и хранения сточных вод, чтобы не сбрасывать их незаконно в закрытых водах","tr":"Atık suyu yönetip depolayarak kısıtlı sularda yasa dışı boşaltılmasını önlemek","hi":"अपशिष्ट जल को प्रबंधित व संग्रहीत करना ताकि इसे प्रतिबंधित जल में अवैध रूप से न छोड़ा जाए","ar":"إدارة مياه الصرف وتخزينها لعدم تصريفها بشكل غير قانوني في مياه محظورة"},{"en":"Store extra fuel","es":"Almacenar combustible adicional","ru":"Хранения запасного топлива","tr":"Ekstra yakıt depolamak","hi":"अतिरिक्त ईंधन संग्रहीत करना","ar":"تخزين وقود إضافي"},{"en":"Hold drinking water only","es":"Contener solo agua potable","ru":"Хранения только питьевой воды","tr":"Yalnızca içme suyu tutmak","hi":"केवल पीने का पानी रखना","ar":"تخزين مياه الشرب فقط"},{"en":"Cool the engine","es":"Enfriar el motor","ru":"Охлаждения двигателя","tr":"Motoru soğutmak","hi":"इंजन को ठंडा करना","ar":"تبريد المحرك"}],"e":{"en":"Boats with installed toilets need a Coast Guard-approved Marine Sanitation Device or holding tank. Discharging untreated sewage is prohibited in inland and coastal \"no-discharge\" waters. Rules vary by area.","es":"Las embarcaciones con inodoros instalados necesitan un MSD aprobado o tanque de retención. Está prohibido descargar aguas residuales sin tratar en aguas interiores y costeras de \"no descarga\". Las reglas varían por zona.","ru":"Судам с установленными туалетами нужно одобренное MSD или накопительный бак. Сброс необработанных сточных вод запрещён во внутренних и прибрежных «бессбросовых» водах. Правила зависят от района.","tr":"Tuvaleti kurulu tekneler onaylı bir MSD veya atık tankı gerektirir. Arıtılmamış atık suyu iç ve kıyı \"boşaltma yasak\" sularında boşaltmak yasaktır. Kurallar bölgeye göre değişir.","hi":"स्थापित शौचालय वाली नावों को अनुमोदित MSD या होल्डिंग टैंक चाहिए। अंतर्देशीय और तटीय \"नो-डिस्चार्ज\" जल में अनुपचारित अपशिष्ट जल छोड़ना निषिद्ध है। नियम क्षेत्रानुसार भिन्न होते हैं।","ar":"تحتاج القوارب ذات المراحيض المركّبة إلى MSD معتمد أو خزان تجميع. يُحظر تصريف مياه الصرف غير المعالَجة في المياه الداخلية والساحلية \"الممنوع فيها التصريف\". تختلف القواعد حسب المنطقة."}},{"cat":"law","a":2,"q":{"en":"Reckless or negligent operation of a boat (such as weaving through traffic at high speed) is:","es":"La operación imprudente o negligente de una embarcación (como zigzaguear entre el tráfico a alta velocidad) es:","ru":"Безрассудное или небрежное управление судном (например, лавирование в потоке на высокой скорости):","tr":"Bir teknenin pervasız veya ihmalkâr kullanımı (yüksek hızda trafikte zikzak çizmek gibi):","hi":"नाव का लापरवाह या उपेक्षापूर्ण संचालन (जैसे तेज़ गति से यातायात के बीच लहराना):","ar":"التشغيل المتهوّر أو المهمل للقارب (كالمناورة بين الحركة بسرعة عالية) يُعدّ:"},"o":[{"en":"Encouraged if you are skilled","es":"Recomendado si es hábil","ru":"Поощряется, если вы умелы","tr":"Beceriliyseniz teşvik edilir","hi":"यदि आप कुशल हैं तो प्रोत्साहित","ar":"مشجَّعاً إن كنت ماهراً"},{"en":"Legal on weekends","es":"Legal los fines de semana","ru":"Законно по выходным","tr":"Hafta sonları yasal","hi":"सप्ताहांत पर कानूनी","ar":"قانونياً في عطلة الأسبوع"},{"en":"A violation that can bring fines, loss of boating privileges, or criminal charges","es":"Una infracción que puede acarrear multas, pérdida de privilegios o cargos penales","ru":"Нарушением, влекущим штрафы, лишение права управления или уголовное преследование","tr":"Para cezası, tekne kullanma hakkının kaybı veya cezai suçlamalar getirebilen bir ihlal","hi":"एक उल्लंघन जो जुर्माना, नौकायन अधिकारों की हानि, या आपराधिक आरोप ला सकता है","ar":"مخالفة قد تجلب غرامات أو فقدان امتيازات القيادة أو تهماً جنائية"},{"en":"Only a problem if someone is hurt","es":"Solo un problema si alguien resulta herido","ru":"Проблемой только если кто-то пострадал","tr":"Yalnızca biri incinirse sorun","hi":"केवल तभी समस्या यदि कोई घायल हो","ar":"مشكلة فقط إذا أُصيب أحد"}],"e":{"en":"Reckless or negligent operation — like speeding near swimmers, weaving through traffic, or jumping wakes dangerously — is illegal everywhere and can bring fines, suspension of boating privileges, or criminal charges.","es":"La operación imprudente o negligente —como correr cerca de nadadores, zigzaguear o saltar estelas peligrosamente— es ilegal en todas partes y puede acarrear multas, suspensión de privilegios o cargos penales.","ru":"Безрассудное или небрежное управление — гонки у пловцов, лавирование в потоке, опасные прыжки по волне — незаконно везде и влечёт штрафы, приостановку права управления или уголовные обвинения.","tr":"Pervasız veya ihmalkâr kullanım — yüzücülerin yanında hız yapmak, trafikte zikzak çizmek ya da tehlikeli şekilde iz atlamak — her yerde yasa dışıdır ve para cezası, kullanma hakkının askıya alınması veya cezai suçlama getirebilir.","hi":"लापरवाह या उपेक्षापूर्ण संचालन — जैसे तैराकों के पास तेज़ चलना, यातायात के बीच लहराना, या खतरनाक तरीके से वेक कूदना — हर जगह अवैध है और जुर्माना, नौकायन अधिकारों का निलंबन, या आपराधिक आरोप ला सकता है।","ar":"التشغيل المتهوّر أو المهمل — كالإسراع قرب السباحين أو المناورة بين الحركة أو القفز فوق الأمواج بخطورة — غير قانوني في كل مكان وقد يجلب غرامات أو تعليق امتيازات القيادة أو تهماً جنائية."}},{"cat":"law","a":1,"q":{"en":"Implied-consent laws for boating mean that by operating a boat, you:","es":"Las leyes de consentimiento implícito para la navegación significan que, al operar una embarcación, usted:","ru":"Законы о подразумеваемом согласии для судоводителей означают, что, управляя судном, вы:","tr":"Tekne için zımni rıza yasaları, bir tekneyi kullanarak sizin şunu kabul ettiğiniz anlamına gelir:","hi":"नौकायन के लिए निहित-सहमति कानून का अर्थ है कि नाव चलाकर, आप:","ar":"قوانين الموافقة الضمنية للإبحار تعني أنك بقيادتك القارب:"},"o":[{"en":"Agree to pay for others' fuel","es":"Acepta pagar el combustible de otros","ru":"Соглашаетесь оплачивать чужое топливо","tr":"Başkalarının yakıtını ödemeyi kabul edersiniz","hi":"दूसरों का ईंधन भुगतान करने को सहमत होते हैं","ar":"توافق على دفع وقود الآخرين"},{"en":"Have consented to sobriety/chemical testing if lawfully suspected of BUI","es":"Ha consentido a pruebas de sobriedad/químicas si se le sospecha legalmente de BUI","ru":"Даёте согласие на проверку трезвости/химический анализ при законном подозрении в BUI","tr":"Yasal olarak BUI şüphesi varsa ayıklık/kimyasal teste rıza göstermiş sayılırsınız","hi":"यदि कानूनी रूप से BUI का संदेह हो तो नशा/रासायनिक परीक्षण के लिए सहमत हो चुके हैं","ar":"تكون قد وافقت على اختبار الرصانة/الكيميائي إذا اشتُبه قانونياً بقيادتك تحت التأثير"},{"en":"Waive the need for registration","es":"Renuncia a la necesidad de registro","ru":"Отказываетесь от необходимости регистрации","tr":"Kayıt zorunluluğundan feragat edersiniz","hi":"पंजीकरण की आवश्यकता को माफ़ करते हैं","ar":"تتنازل عن الحاجة إلى التسجيل"},{"en":"Agree to give rides to officers","es":"Acepta llevar a los oficiales","ru":"Соглашаетесь катать сотрудников","tr":"Görevlilere gezinti vermeyi kabul edersiniz","hi":"अधिकारियों को सैर कराने को सहमत होते हैं","ar":"توافق على إركاب الضباط"}],"e":{"en":"Under implied-consent laws, operating a boat means you have agreed to submit to sobriety or chemical (breath, blood) testing if an officer reasonably suspects boating under the influence. Refusal carries penalties.","es":"Según el consentimiento implícito, operar una embarcación significa que aceptó someterse a pruebas de sobriedad o químicas (aliento, sangre) si un oficial sospecha razonablemente BUI. Negarse conlleva sanciones.","ru":"По законам о подразумеваемом согласии управление судном означает, что вы согласились пройти проверку трезвости или химический анализ (дыхание, кровь) при обоснованном подозрении в BUI. Отказ влечёт наказание.","tr":"Zımni rıza yasaları gereği tekne kullanmak, bir görevli makul şekilde BUI'den şüphelenirse ayıklık veya kimyasal (nefes, kan) teste tabi olmayı kabul ettiğiniz anlamına gelir. Reddetmenin cezası vardır.","hi":"निहित-सहमति कानूनों के तहत, नाव चलाने का अर्थ है कि यदि कोई अधिकारी उचित रूप से BUI का संदेह करे तो आप नशा या रासायनिक (साँस, रक्त) परीक्षण के लिए सहमत हैं। इनकार पर दंड है।","ar":"بموجب قوانين الموافقة الضمنية، قيادة القارب تعني موافقتك على الخضوع لاختبار الرصانة أو الاختبار الكيميائي (نفَس، دم) إذا اشتبه ضابط بشكل معقول بقيادتك تحت التأثير. الرفض يستوجب عقوبات."}},{"cat":"law","a":3,"q":{"en":"Which is generally true about where boat registration is valid?","es":"¿Qué es generalmente cierto sobre dónde es válido el registro de una embarcación?","ru":"Что в целом верно относительно того, где действует регистрация судна?","tr":"Tekne kaydının nerede geçerli olduğuyla ilgili genellikle hangisi doğrudur?","hi":"नाव पंजीकरण कहाँ मान्य है, इस बारे में आमतौर पर क्या सही है?","ar":"أي مما يلي صحيح عموماً بشأن أين يكون تسجيل القارب سارياً؟"},"o":[{"en":"It is valid forever with no renewal","es":"Es válido para siempre sin renovación","ru":"Действует вечно без продления","tr":"Yenileme olmadan sonsuza dek geçerlidir","hi":"बिना नवीनीकरण के हमेशा मान्य है","ar":"ساري إلى الأبد دون تجديد"},{"en":"It only matters on the ocean","es":"Solo importa en el océano","ru":"Имеет значение только в океане","tr":"Yalnızca okyanusta önemlidir","hi":"केवल समुद्र पर मायने रखता है","ar":"يهم في المحيط فقط"},{"en":"A boat can be operated without any registration anywhere","es":"Una embarcación puede operarse sin registro en cualquier lugar","ru":"Судно можно эксплуатировать где угодно без регистрации","tr":"Bir tekne her yerde kayıtsız kullanılabilir","hi":"नाव को कहीं भी बिना पंजीकरण चलाया जा सकता है","ar":"يمكن تشغيل القارب دون أي تسجيل في أي مكان"},{"en":"Registration is issued by the state and must be kept current, and out-of-state boats have limited reciprocity","es":"El registro lo emite el estado y debe mantenerse vigente; las embarcaciones de otros estados tienen reciprocidad limitada","ru":"Регистрацию выдаёт штат, её нужно поддерживать действующей, а для судов из других штатов действует ограниченная взаимность","tr":"Kayıt eyalet tarafından verilir ve güncel tutulmalıdır; başka eyalet tekneleri sınırlı karşılıklılığa sahiptir","hi":"पंजीकरण राज्य द्वारा जारी होता है और चालू रखना चाहिए, और बाहरी-राज्य की नावों के लिए सीमित पारस्परिकता होती है","ar":"يصدر التسجيل عن الولاية ويجب إبقاؤه سارياً، وللقوارب من ولايات أخرى معاملة بالمثل محدودة"}],"e":{"en":"Registration is issued by your state, must be renewed to stay valid, and typically allows limited visiting time (reciprocity) in other states before you must register there. Always check the rules where you boat.","es":"El registro lo emite su estado, debe renovarse para seguir vigente y suele permitir un tiempo limitado de visita (reciprocidad) en otros estados antes de tener que registrarse allí. Verifique siempre las reglas locales.","ru":"Регистрацию выдаёт ваш штат, её нужно продлевать, и обычно она допускает ограниченное время пребывания (взаимность) в других штатах до необходимости регистрации там. Всегда проверяйте местные правила.","tr":"Kayıt eyaletiniz tarafından verilir, geçerli kalması için yenilenmelidir ve genellikle diğer eyaletlerde orada kaydolmadan önce sınırlı ziyaret süresi (karşılıklılık) tanır. Tekne kullandığınız yerin kurallarını daima kontrol edin.","hi":"पंजीकरण आपके राज्य द्वारा जारी होता है, मान्य रहने के लिए नवीनीकरण आवश्यक है, और आमतौर पर अन्य राज्यों में वहाँ पंजीकरण से पहले सीमित यात्रा-समय (पारस्परिकता) की अनुमति देता है। जहाँ आप नाव चलाते हैं वहाँ के नियम हमेशा जाँचें।","ar":"يصدر التسجيل عن ولايتك ويجب تجديده ليبقى سارياً، وعادةً يسمح بوقت زيارة محدود (معاملة بالمثل) في ولايات أخرى قبل أن يلزمك التسجيل فيها. تحقّق دائماً من قواعد المكان الذي تُبحر فيه."}},{"cat":"law","a":0,"q":{"en":"A boater education card (safety certificate) generally:","es":"Una tarjeta de educación náutica (certificado de seguridad) generalmente:","ru":"Карта обучения судоводителя (сертификат безопасности), как правило:","tr":"Tekne eğitim kartı (güvenlik sertifikası) genellikle:","hi":"एक नौका शिक्षा कार्ड (सुरक्षा प्रमाणपत्र) आमतौर पर:","ar":"بطاقة تعليم القوارب (شهادة السلامة) عموماً:"},"o":[{"en":"Proves you completed a boating safety course and usually does not expire, unlike a registration","es":"Prueba que completó un curso de seguridad y suele no caducar, a diferencia del registro","ru":"Подтверждает прохождение курса безопасности и обычно не истекает, в отличие от регистрации","tr":"Bir tekne güvenliği kursunu tamamladığınızı kanıtlar ve kayıttan farklı olarak genellikle süresi dolmaz","hi":"साबित करता है कि आपने एक नौका सुरक्षा पाठ्यक्रम पूरा किया और पंजीकरण के विपरीत आमतौर पर समाप्त नहीं होता","ar":"تُثبت أنك أكملت دورة سلامة قوارب وعادةً لا تنتهي صلاحيتها، بخلاف التسجيل"},{"en":"Is the same as a boat's registration","es":"Es lo mismo que el registro de la embarcación","ru":"То же самое, что регистрация судна","tr":"Teknenin kaydıyla aynı şeydir","hi":"नाव के पंजीकरण के समान है","ar":"هي نفسها تسجيل القارب"},{"en":"Must be renewed every year","es":"Debe renovarse cada año","ru":"Нужно продлевать ежегодно","tr":"Her yıl yenilenmelidir","hi":"हर साल नवीनीकरण करना चाहिए","ar":"يجب تجديدها كل عام"},{"en":"Is only for commercial captains","es":"Es solo para capitanes comerciales","ru":"Только для коммерческих капитанов","tr":"Yalnızca ticari kaptanlar içindir","hi":"केवल वाणिज्यिक कप्तानों के लिए है","ar":"للربابنة التجاريين فقط"}],"e":{"en":"A boater education card shows you passed an approved safety course. Unlike vessel registration, it usually does not expire and is separate from registering the boat. Requirements to carry it vary by state.","es":"La tarjeta de educación náutica demuestra que aprobó un curso aprobado. A diferencia del registro, normalmente no caduca y es distinta de registrar la embarcación. Los requisitos para portarla varían por estado.","ru":"Карта обучения показывает, что вы сдали одобренный курс. В отличие от регистрации судна, она обычно не истекает и не связана с регистрацией лодки. Требования иметь её при себе различаются по штату.","tr":"Tekne eğitim kartı, onaylı bir güvenlik kursunu geçtiğinizi gösterir. Tekne kaydından farklı olarak genellikle süresi dolmaz ve tekneyi kaydettirmekten ayrıdır. Taşıma zorunluluğu eyalete göre değişir.","hi":"नौका शिक्षा कार्ड दर्शाता है कि आपने एक अनुमोदित सुरक्षा पाठ्यक्रम पास किया। नाव पंजीकरण के विपरीत, यह आमतौर पर समाप्त नहीं होता और नाव पंजीकरण से अलग है। इसे साथ रखने की आवश्यकताएँ राज्यानुसार भिन्न होती हैं।","ar":"تُظهر بطاقة تعليم القوارب أنك اجتزت دورة سلامة معتمدة. بخلاف تسجيل المركب، عادةً لا تنتهي صلاحيتها وهي منفصلة عن تسجيل القارب. تختلف متطلبات حملها حسب الولاية."}},{"cat":"law","a":2,"q":{"en":"Which of the following is a common local rule that varies by state or waterway?","es":"¿Cuál de las siguientes es una regla local común que varía por estado o vía navegable?","ru":"Что из перечисленного — распространённое местное правило, различающееся по штату или водоёму?","tr":"Aşağıdakilerden hangisi eyalete veya su yoluna göre değişen yaygın bir yerel kuraldır?","hi":"निम्न में से कौन सा एक सामान्य स्थानीय नियम है जो राज्य या जलमार्ग के अनुसार भिन्न होता है?","ar":"أي مما يلي قاعدة محلية شائعة تختلف حسب الولاية أو الممر المائي؟"},"o":[{"en":"The color of the sky","es":"El color del cielo","ru":"Цвет неба","tr":"Gökyüzünün rengi","hi":"आसमान का रंग","ar":"لون السماء"},{"en":"Whether water is wet","es":"Si el agua está mojada","ru":"Мокрая ли вода","tr":"Suyun ıslak olup olmadığı","hi":"क्या पानी गीला है","ar":"هل الماء مبلّل"},{"en":"The number of stars","es":"El número de estrellas","ru":"Количество звёзд","tr":"Yıldız sayısı","hi":"तारों की संख्या","ar":"عدد النجوم"},{"en":"Speed limits, no-wake zones, life-jacket-wear ages, and required boater education","es":"Los límites de velocidad, zonas sin estela, edades de uso de chaleco y educación náutica exigida","ru":"Ограничения скорости, зоны «без волны», возраст обязательного ношения жилета и требование обучения","tr":"Hız sınırları, no-wake bölgeleri, can yeleği giyme yaşları ve zorunlu tekne eğitimi","hi":"गति सीमा, नो-वेक ज़ोन, लाइफ जैकेट पहनने की आयु, और आवश्यक नौका शिक्षा","ar":"حدود السرعة ومناطق بلا موجة وأعمار ارتداء سترة النجاة وتعليم القوارب المطلوب"}],"e":{"en":"Many important rules — speed limits, no-wake zones, life-jacket-wear ages for children, education requirements, and reporting thresholds — are set by each state or waterway, so always confirm the local rules where you boat.","es":"Muchas reglas importantes —límites de velocidad, zonas sin estela, edades de uso de chaleco para niños, requisitos de educación y umbrales de reporte— las fija cada estado o vía navegable, así que confirme siempre las reglas locales.","ru":"Многие важные правила — ограничения скорости, зоны «без волны», возраст обязательного ношения жилета детьми, требования к обучению и пороги отчётности — устанавливает каждый штат или водоём, поэтому всегда уточняйте местные правила.","tr":"Birçok önemli kural — hız sınırları, no-wake bölgeleri, çocuklar için can yeleği giyme yaşları, eğitim zorunlulukları ve bildirim eşikleri — her eyalet ya da su yolu tarafından belirlenir; bu yüzden tekne kullandığınız yerin yerel kurallarını daima teyit edin.","hi":"कई महत्वपूर्ण नियम — गति सीमा, नो-वेक ज़ोन, बच्चों के लिए लाइफ जैकेट पहनने की आयु, शिक्षा आवश्यकताएँ, और रिपोर्टिंग सीमाएँ — प्रत्येक राज्य या जलमार्ग तय करता है, इसलिए जहाँ आप नाव चलाते हैं वहाँ के स्थानीय नियम हमेशा पुष्टि करें।","ar":"يحدّد كل ولاية أو ممر مائي كثيراً من القواعد المهمة — حدود السرعة ومناطق بلا موجة وأعمار ارتداء سترة النجاة للأطفال ومتطلبات التعليم وعتبات الإبلاغ — لذا تحقّق دائماً من القواعد المحلية حيث تُبحر."}},{"cat":"law","a":1,"q":{"en":"What is generally required before you can legally rent (livery) a powered boat in many states?","es":"¿Qué se exige generalmente antes de poder alquilar legalmente (livery) una embarcación a motor en muchos estados?","ru":"Что обычно требуется, прежде чем законно взять напрокат (livery) моторное судно во многих штатах?","tr":"Birçok eyalette motorlu bir tekneyi yasal olarak kiralamadan (livery) önce genellikle ne gerekir?","hi":"कई राज्यों में किसी मोटर चालित नाव को कानूनी रूप से किराए (livery) पर लेने से पहले आमतौर पर क्या आवश्यक है?","ar":"ما المطلوب عادةً قبل أن تتمكّن قانونياً من استئجار (livery) قارب آلي في ولايات كثيرة؟"},"o":[{"en":"Owning your own boat first","es":"Poseer primero su propia embarcación","ru":"Сначала иметь свою лодку","tr":"Önce kendi teknenize sahip olmak","hi":"पहले अपनी नाव रखना","ar":"امتلاك قاربك الخاص أولاً"},{"en":"A commercial captain's license","es":"Una licencia de capitán comercial","ru":"Лицензию коммерческого капитана","tr":"Ticari kaptan ehliyeti","hi":"एक वाणिज्यिक कप्तान लाइसेंस","ar":"رخصة ربان تجاري"},{"en":"Meeting a minimum age and, in many states, showing boater education or completing a basic safety briefing","es":"Cumplir una edad mínima y, en muchos estados, mostrar educación náutica o completar una instrucción básica de seguridad","ru":"Достичь минимального возраста и во многих штатах предъявить обучение или пройти базовый инструктаж","tr":"Asgari yaşı karşılamak ve birçok eyalette tekne eğitimi göstermek ya da temel bir güvenlik brifingi almak","hi":"न्यूनतम आयु पूरी करना और कई राज्यों में नौका शिक्षा दिखाना या एक बुनियादी सुरक्षा ब्रीफिंग पूरी करना","ar":"استيفاء حد أدنى للسن، وفي ولايات كثيرة إبراز تعليم قوارب أو إكمال إحاطة سلامة أساسية"},{"en":"Nothing at all, ever","es":"Nada en absoluto, nunca","ru":"Совсем ничего, никогда","tr":"Hiçbir şey, asla","hi":"बिल्कुल कुछ नहीं, कभी नहीं","ar":"لا شيء على الإطلاق أبداً"}],"e":{"en":"Rental (livery) operators usually must meet a minimum age and, in many states, show a boater education card or receive a dockside safety checklist and instruction before taking the boat out. Requirements vary by state.","es":"Quienes alquilan suelen tener que cumplir una edad mínima y, en muchos estados, mostrar una tarjeta de educación náutica o recibir una lista y una instrucción de seguridad antes de zarpar. Los requisitos varían por estado.","ru":"Арендаторы обычно должны соответствовать минимальному возрасту и во многих штатах предъявить карту обучения либо получить у причала памятку по безопасности и инструктаж перед выходом. Требования различаются по штату.","tr":"Kiralayanlar genellikle asgari bir yaşı karşılamalı ve birçok eyalette tekneyi çıkarmadan önce tekne eğitim kartı göstermeli ya da iskele başında güvenlik kontrol listesi ve talimat almalıdır. Gereklilikler eyalete göre değişir.","hi":"किराए (livery) पर लेने वालों को आमतौर पर न्यूनतम आयु पूरी करनी होती है और कई राज्यों में नाव निकालने से पहले नौका शिक्षा कार्ड दिखाना या घाट-किनारे सुरक्षा चेकलिस्ट व निर्देश प्राप्त करना होता है। आवश्यकताएँ राज्यानुसार भिन्न होती हैं।","ar":"عادةً يجب على المستأجرين استيفاء حد أدنى للسن، وفي ولايات كثيرة إبراز بطاقة تعليم قوارب أو تلقّي قائمة تحقّق وإحاطة أمان على الرصيف قبل الإبحار. تختلف المتطلبات حسب الولاية."}},{"cat":"law","a":3,"q":{"en":"If you sell your boat or move to another state, you generally must:","es":"Si vende su embarcación o se muda a otro estado, generalmente debe:","ru":"Если вы продаёте лодку или переезжаете в другой штат, обычно необходимо:","tr":"Teknenizi satarsanız veya başka bir eyalete taşınırsanız genellikle:","hi":"यदि आप अपनी नाव बेचते हैं या किसी अन्य राज्य में जाते हैं, तो आपको आमतौर पर चाहिए:","ar":"إذا بعت قاربك أو انتقلت إلى ولاية أخرى، فيجب عليك عموماً أن:"},"o":[{"en":"Do nothing","es":"No hacer nada","ru":"Ничего не делать","tr":"Hiçbir şey yapmamak","hi":"कुछ नहीं करना","ar":"لا تفعل شيئاً"},{"en":"Keep using the old numbers indefinitely","es":"Seguir usando los números antiguos indefinidamente","ru":"Бесконечно пользоваться старыми номерами","tr":"Eski numaraları süresiz kullanmaya devam etmek","hi":"पुराने नंबर अनिश्चित काल तक उपयोग करते रहना","ar":"تستمر في استخدام الأرقام القديمة إلى أجل غير مسمى"},{"en":"Only tell your insurance company","es":"Solo avisar a su aseguradora","ru":"Сообщить только страховой компании","tr":"Yalnızca sigorta şirketinize bildirmek","hi":"केवल अपनी बीमा कंपनी को बताना","ar":"تُخبر شركة التأمين فقط"},{"en":"Notify the registering agency and follow transfer or re-registration rules within the required time","es":"Notificar a la agencia de registro y seguir las reglas de transferencia o nuevo registro dentro del plazo","ru":"Уведомить регистрирующий орган и выполнить правила переоформления или перерегистрации в срок","tr":"Kayıt kurumunu bilgilendirmek ve gereken süre içinde devir veya yeniden kayıt kurallarını izlemek","hi":"पंजीकरण एजेंसी को सूचित करना और आवश्यक समय के भीतर हस्तांतरण या पुनः-पंजीकरण नियमों का पालन करना","ar":"تُخطر جهة التسجيل وتتّبع قواعد النقل أو إعادة التسجيل خلال المدة المطلوبة"}],"e":{"en":"When ownership changes or you relocate, you typically must notify the registering agency and complete a transfer or re-register within a set time. Deadlines and procedures differ from state to state.","es":"Cuando cambia la propiedad o se muda, normalmente debe notificar a la agencia de registro y completar una transferencia o volver a registrar dentro de un plazo. Los plazos y procedimientos difieren por estado.","ru":"При смене владельца или переезде обычно нужно уведомить регистрирующий орган и оформить передачу или перерегистрацию в установленный срок. Сроки и процедуры различаются по штату.","tr":"Mülkiyet değiştiğinde veya taşındığınızda genellikle kayıt kurumunu bilgilendirmeli ve belirli bir süre içinde devri tamamlamalı ya da yeniden kaydettirmelisiniz. Süreler ve işlemler eyalete göre farklıdır.","hi":"स्वामित्व बदलने या स्थानांतरण पर, आमतौर पर पंजीकरण एजेंसी को सूचित करना और निर्धारित समय के भीतर हस्तांतरण पूरा करना या पुनः-पंजीकरण करना होता है। समय-सीमाएँ और प्रक्रियाएँ राज्य-दर-राज्य भिन्न होती हैं।","ar":"عند تغيّر الملكية أو الانتقال، يجب عادةً إخطار جهة التسجيل وإتمام النقل أو إعادة التسجيل خلال مدة محددة. تختلف المهل والإجراءات من ولاية لأخرى."}},{"cat":"law","a":2,"q":{"en":"On federally controlled waters, a boat's Hull Identification Number (HIN) is:","es":"En aguas de control federal, el Número de Identificación del Casco (HIN) de una embarcación es:","ru":"В федерально контролируемых водах идентификационный номер корпуса судна (HIN) — это:","tr":"Federal kontrollü sularda bir teknenin Tekne Kimlik Numarası (HIN):","hi":"संघीय-नियंत्रित जल में, नाव का हल आइडेंटिफिकेशन नंबर (HIN) है:","ar":"في المياه الخاضعة للسيطرة الفيدرالية، رقم تعريف بدن القارب (HIN) هو:"},"o":[{"en":"A temporary sticker you can remove","es":"Una calcomanía temporal que puede quitar","ru":"Временная наклейка, которую можно снять","tr":"Çıkarabileceğiniz geçici bir etiket","hi":"एक अस्थायी स्टिकर जिसे आप हटा सकते हैं","ar":"ملصق مؤقت يمكن إزالته"},{"en":"The same as the engine serial number","es":"Lo mismo que el número de serie del motor","ru":"То же, что серийный номер двигателя","tr":"Motorun seri numarasıyla aynı","hi":"इंजन के सीरियल नंबर के समान","ar":"نفس الرقم التسلسلي للمحرك"},{"en":"A permanent 12-character number that uniquely identifies the boat, like a car's VIN","es":"Un número permanente de 12 caracteres que identifica de forma única la embarcación, como el VIN de un auto","ru":"Постоянный 12-значный номер, однозначно идентифицирующий судно, как VIN автомобиля","tr":"Tekneyi benzersiz şekilde tanımlayan, araç VIN'i gibi kalıcı 12 karakterli bir numara","hi":"एक स्थायी 12-वर्ण संख्या जो नाव की विशिष्ट पहचान करती है, कार के VIN की तरह","ar":"رقم دائم من 12 خانة يميّز القارب بشكل فريد، مثل رقم هيكل السيارة (VIN)"},{"en":"Only needed for sailboats","es":"Solo necesario para veleros","ru":"Нужен только парусникам","tr":"Yalnızca yelkenliler için gerekli","hi":"केवल पाल-नावों के लिए आवश्यक","ar":"لازم للمراكب الشراعية فقط"}],"e":{"en":"The Hull Identification Number is a permanent 12-character number molded into the hull that uniquely identifies a boat, much like a car's VIN. It is used for registration and recall tracking and must not be altered.","es":"El Número de Identificación del Casco es un número permanente de 12 caracteres grabado en el casco que identifica de forma única la embarcación, como el VIN de un auto. Se usa para registro y rastreo de retiros y no debe alterarse.","ru":"Идентификационный номер корпуса — постоянный 12-значный номер, отформованный в корпусе, однозначно идентифицирующий судно, как VIN у авто. Используется для регистрации и отзывов; изменять его нельзя.","tr":"Tekne Kimlik Numarası, gövdeye kalıcı olarak işlenmiş 12 karakterli bir numaradır ve tıpkı araç VIN'i gibi tekneyi benzersiz tanımlar. Kayıt ve geri çağırma takibinde kullanılır ve değiştirilemez.","hi":"हल आइडेंटिफिकेशन नंबर पतवार में स्थायी रूप से ढाली गई 12-वर्ण संख्या है जो नाव की विशिष्ट पहचान करती है, कार के VIN की तरह। इसका उपयोग पंजीकरण और रिकॉल ट्रैकिंग के लिए होता है और इसे बदला नहीं जाना चाहिए।","ar":"رقم تعريف البدن رقم دائم من 12 خانة مصبوب في بدن القارب يميّزه بشكل فريد، مثل رقم هيكل السيارة. يُستخدم للتسجيل وتتبّع الاستدعاءات ولا يجوز تغييره."}},{"cat":"law","a":1,"q":{"en":"Regarding penalties for boating violations, which statement is most accurate?","es":"En cuanto a las sanciones por infracciones de navegación, ¿qué afirmación es más precisa?","ru":"Что касается наказаний за нарушения на воде, какое утверждение наиболее точно?","tr":"Tekne ihlalleri için cezalarla ilgili hangi ifade en doğrudur?","hi":"नौकायन उल्लंघनों के दंड के संबंध में, कौन सा कथन सबसे सटीक है?","ar":"بشأن عقوبات مخالفات القوارب، أي عبارة أدق؟"},"o":[{"en":"There are never any penalties for boating violations","es":"Nunca hay sanciones por infracciones de navegación","ru":"За нарушения на воде наказаний не бывает","tr":"Tekne ihlalleri için asla ceza yoktur","hi":"नौकायन उल्लंघनों के लिए कभी कोई दंड नहीं","ar":"لا توجد أبداً عقوبات لمخالفات القوارب"},{"en":"Violations can bring fines, points, mandatory education, or loss of boating privileges, and specifics vary by state","es":"Las infracciones pueden acarrear multas, puntos, educación obligatoria o pérdida de privilegios, y los detalles varían por estado","ru":"Нарушения могут повлечь штрафы, баллы, обязательное обучение или лишение права управления, а детали различаются по штату","tr":"İhlaller para cezası, ceza puanı, zorunlu eğitim veya tekne kullanma hakkının kaybını getirebilir; ayrıntılar eyalete göre değişir","hi":"उल्लंघन जुर्माना, अंक, अनिवार्य शिक्षा, या नौकायन अधिकारों की हानि ला सकते हैं, और विवरण राज्यानुसार भिन्न होते हैं","ar":"قد تجلب المخالفات غرامات أو نقاطاً أو تعليماً إلزامياً أو فقدان امتيازات القيادة، وتختلف التفاصيل حسب الولاية"},{"en":"Only commercial operators can be penalized","es":"Solo se puede sancionar a operadores comerciales","ru":"Наказать можно только коммерческих судоводителей","tr":"Yalnızca ticari operatörler cezalandırılabilir","hi":"केवल वाणिज्यिक चालकों को दंडित किया जा सकता है","ar":"لا يُعاقَب إلا المشغّلون التجاريون"},{"en":"Penalties are identical in every state","es":"Las sanciones son idénticas en todos los estados","ru":"Наказания одинаковы во всех штатах","tr":"Cezalar her eyalette aynıdır","hi":"दंड हर राज्य में समान हैं","ar":"العقوبات متطابقة في كل الولايات"}],"e":{"en":"Boating violations can result in fines, demerit points, mandatory boater education, or suspension of boating privileges, and in serious cases criminal charges. The exact penalties and procedures vary by state.","es":"Las infracciones pueden derivar en multas, puntos, educación náutica obligatoria o suspensión de privilegios y, en casos graves, cargos penales. Las sanciones y procedimientos exactos varían por estado.","ru":"Нарушения на воде могут повлечь штрафы, штрафные баллы, обязательное обучение или приостановку права управления, а в тяжёлых случаях — уголовные обвинения. Конкретные наказания и процедуры различаются по штату.","tr":"Tekne ihlalleri para cezası, ceza puanı, zorunlu tekne eğitimi veya kullanma hakkının askıya alınması, ciddi durumlarda cezai suçlama doğurabilir. Kesin cezalar ve işlemler eyalete göre değişir.","hi":"नौकायन उल्लंघन जुर्माना, डिमेरिट अंक, अनिवार्य नौका शिक्षा, या नौकायन अधिकारों के निलंबन, और गंभीर मामलों में आपराधिक आरोप ला सकते हैं। सटीक दंड और प्रक्रियाएँ राज्यानुसार भिन्न होती हैं।","ar":"قد تؤدّي مخالفات القوارب إلى غرامات أو نقاط جزائية أو تعليم إلزامي أو تعليق امتيازات القيادة، وفي الحالات الخطيرة تهماً جنائية. تختلف العقوبات والإجراءات الدقيقة حسب الولاية."}},{"cat":"sports","a":1,"q":{"en":"When towing a water skier, most states require the boat to have:","es":"Al remolcar a un esquiador acuático, la mayoría de los estados exigen que la embarcación tenga:","ru":"При буксировке воднолыжника большинство штатов требуют, чтобы на судне был:","tr":"Su kayakçısı çekerken çoğu eyalet teknede şunun bulunmasını ister:","hi":"वॉटर स्कीयर खींचते समय, अधिकांश राज्य आवश्यक करते हैं कि नाव में हो:","ar":"عند سحب متزلج مائي، تشترط معظم الولايات أن يكون في القارب:"},"o":[{"en":"Only the driver","es":"Solo el conductor","ru":"Только водитель","tr":"Yalnızca sürücü","hi":"केवल चालक","ar":"السائق فقط"},{"en":"A competent observer (spotter) in addition to the operator, or a wide-angle mirror where allowed","es":"Un observador competente además del operador, o un espejo gran angular donde se permita","ru":"Компетентный наблюдатель помимо судоводителя, либо широкоугольное зеркало, где разрешено","tr":"Operatöre ek olarak yetkin bir gözlemci ya da izin verilen yerlerde geniş açılı ayna","hi":"चालक के अतिरिक्त एक सक्षम ऑब्ज़र्वर (स्पॉटर), या जहाँ अनुमति हो वहाँ एक वाइड-एंगल मिरर","ar":"مراقب كفؤ إضافةً إلى المشغّل، أو مرآة واسعة الزاوية حيث يُسمح بذلك"},{"en":"At least four people","es":"Al menos cuatro personas","ru":"Не менее четырёх человек","tr":"En az dört kişi","hi":"कम से कम चार लोग","ar":"أربعة أشخاص على الأقل"},{"en":"A second engine","es":"Un segundo motor","ru":"Второй двигатель","tr":"İkinci bir motor","hi":"एक दूसरा इंजन","ar":"محرك ثانٍ"}],"e":{"en":"Most states require a competent observer at least 12 years old (age varies) to watch the skier and signal the operator, or in some states a wide-angle rearview mirror. The operator cannot safely watch both ahead and behind.","es":"La mayoría de los estados exige un observador competente de al menos 12 años (la edad varía) para vigilar al esquiador y avisar al operador, o en algunos estados un espejo gran angular. El operador no puede vigilar bien adelante y atrás a la vez.","ru":"Большинство штатов требуют компетентного наблюдателя не младше 12 лет (возраст различается), который следит за лыжником и сигналит судоводителю, либо, в некоторых штатах, широкоугольное зеркало. Судоводитель не может одновременно безопасно смотреть вперёд и назад.","tr":"Çoğu eyalet, kayakçıyı izleyip operatörü uyaracak en az 12 yaşında (yaş değişir) yetkin bir gözlemci ya da bazı eyaletlerde geniş açılı ayna ister. Operatör hem önü hem arkayı aynı anda güvenle izleyemez.","hi":"अधिकांश राज्य कम से कम 12 वर्ष (आयु भिन्न) के एक सक्षम ऑब्ज़र्वर की माँग करते हैं जो स्कीयर पर नज़र रखे और चालक को संकेत दे, या कुछ राज्यों में एक वाइड-एंगल मिरर। चालक आगे और पीछे दोनों को सुरक्षित रूप से नहीं देख सकता।","ar":"تشترط معظم الولايات مراقباً كفؤاً لا يقل عمره عن 12 عاماً (يختلف السن) يراقب المتزلج ويُبلّغ المشغّل، أو في بعض الولايات مرآة واسعة الزاوية. لا يستطيع المشغّل مراقبة الأمام والخلف بأمان في آنٍ واحد."}},{"cat":"sports","a":0,"q":{"en":"What is the job of the observer (spotter) when towing a skier or tuber?","es":"¿Cuál es la función del observador cuando se remolca a un esquiador o a alguien en una boya?","ru":"Какова задача наблюдателя при буксировке лыжника или «плюшки»?","tr":"Bir kayakçı ya da şişme çekerken gözlemcinin görevi nedir?","hi":"स्कीयर या ट्यूबर खींचते समय ऑब्ज़र्वर (स्पॉटर) का काम क्या है?","ar":"ما مهمة المراقب عند سحب متزلج أو راكب عوّامة؟"},"o":[{"en":"Watch the person being towed and relay their condition and hand signals to the operator","es":"Vigilar a la persona remolcada y transmitir su estado y señales al operador","ru":"Следить за буксируемым и передавать судоводителю его состояние и жесты","tr":"Çekilen kişiyi izlemek ve durumunu ile el işaretlerini operatöre iletmek","hi":"खींचे जा रहे व्यक्ति पर नज़र रखना और उनकी स्थिति व हाथ के संकेत चालक तक पहुँचाना","ar":"مراقبة الشخص المسحوب ونقل حالته وإشاراته اليدوية إلى المشغّل"},{"en":"Drive the boat","es":"Conducir la embarcación","ru":"Управлять судном","tr":"Tekneyi sürmek","hi":"नाव चलाना","ar":"قيادة القارب"},{"en":"Hold the tow rope the whole time","es":"Sostener la cuerda de remolque todo el tiempo","ru":"Всё время держать буксирный трос","tr":"Çekme halatını sürekli tutmak","hi":"पूरे समय टो रस्सी पकड़े रहना","ar":"إمساك حبل السحب طوال الوقت"},{"en":"Refuel the engine while under way","es":"Cargar combustible en marcha","ru":"Заправлять двигатель на ходу","tr":"Seyir halindeyken yakıt ikmali yapmak","hi":"चलते समय इंजन में ईंधन भरना","ar":"تزويد المحرك بالوقود أثناء السير"}],"e":{"en":"The observer faces backward and continuously watches the person being towed, telling the operator if the skier falls, signals, or is in trouble, so the driver can focus on steering and hazards ahead.","es":"El observador mira hacia atrás y vigila continuamente a la persona remolcada, avisando al operador si el esquiador cae, hace señas o tiene problemas, para que el conductor se concentre en dirigir y en los peligros.","ru":"Наблюдатель смотрит назад и постоянно следит за буксируемым, сообщая судоводителю, если лыжник упал, подаёт знаки или в беде, чтобы водитель мог сосредоточиться на управлении и опасностях впереди.","tr":"Gözlemci arkaya döner ve çekilen kişiyi sürekli izler; kayakçı düşerse, işaret verirse ya da zorda kalırsa operatöre bildirir; böylece sürücü dümene ve öndeki tehlikelere odaklanabilir.","hi":"ऑब्ज़र्वर पीछे की ओर मुँह करके खींचे जा रहे व्यक्ति पर लगातार नज़र रखता है और चालक को बताता है कि स्कीयर गिरा, संकेत दिया, या मुश्किल में है, ताकि चालक स्टीयरिंग व आगे के खतरों पर ध्यान दे सके।","ar":"يواجه المراقب الخلف ويراقب باستمرار الشخص المسحوب، ويُخبر المشغّل إن سقط المتزلج أو أشار أو تعرّض لمشكلة، حتى يركّز السائق على القيادة والمخاطر أمامه."}},{"cat":"sports","a":3,"q":{"en":"During which hours is towing a water skier generally prohibited?","es":"¿Durante qué horas está generalmente prohibido remolcar a un esquiador acuático?","ru":"В какое время суток буксировка воднолыжника обычно запрещена?","tr":"Su kayakçısı çekmek genellikle hangi saatlerde yasaktır?","hi":"वॉटर स्कीयर खींचना आमतौर पर किन घंटों में निषिद्ध है?","ar":"في أي ساعات يُمنع عادةً سحب متزلج مائي؟"},"o":[{"en":"During the middle of the day","es":"Durante el mediodía","ru":"В середине дня","tr":"Günün ortasında","hi":"दिन के मध्य में","ar":"في منتصف النهار"},{"en":"Only on weekends","es":"Solo los fines de semana","ru":"Только по выходным","tr":"Yalnızca hafta sonları","hi":"केवल सप्ताहांत पर","ar":"في عطلة الأسبوع فقط"},{"en":"Whenever it is windy","es":"Cuando hace viento","ru":"Когда ветрено","tr":"Rüzgarlı olduğunda","hi":"जब हवा चल रही हो","ar":"عندما تكون الرياح شديدة"},{"en":"From sunset to sunrise (at night), when a skier is hard to see","es":"Desde el atardecer hasta el amanecer (de noche), cuando es difícil ver al esquiador","ru":"С заката до восхода (ночью), когда лыжника трудно разглядеть","tr":"Gün batımından gün doğumuna (gece), kayakçının zor görüldüğü zaman","hi":"सूर्यास्त से सूर्योदय तक (रात में), जब स्कीयर को देखना कठिन होता है","ar":"من الغروب إلى الشروق (ليلاً)، حين يصعب رؤية المتزلج"}],"e":{"en":"Water skiing is generally allowed only during daylight — from sunrise to sunset. Towing at night is prohibited in most states because a skier in the water is nearly impossible to see and rescue.","es":"El esquí acuático suele permitirse solo con luz de día, desde el amanecer hasta el atardecer. Remolcar de noche está prohibido en la mayoría de los estados porque es casi imposible ver y rescatar al esquiador.","ru":"Воднолыжный спорт обычно разрешён только в светлое время — от восхода до заката. Буксировка ночью запрещена в большинстве штатов, так как лыжника в воде почти невозможно увидеть и спасти.","tr":"Su kayağına genellikle yalnızca gündüz — gün doğumundan gün batımına — izin verilir. Gece çekmek çoğu eyalette yasaktır, çünkü sudaki kayakçıyı görmek ve kurtarmak neredeyse imkânsızdır.","hi":"वॉटर स्कीइंग आमतौर पर केवल दिन के उजाले में — सूर्योदय से सूर्यास्त तक — की अनुमति है। रात में खींचना अधिकांश राज्यों में निषिद्ध है क्योंकि पानी में स्कीयर को देखना और बचाना लगभग असंभव है।","ar":"يُسمح بالتزلج المائي عموماً في ضوء النهار فقط — من الشروق إلى الغروب. سحب المتزلج ليلاً محظور في معظم الولايات لأن رؤية المتزلج في الماء وإنقاذه شبه مستحيل."}},{"cat":"sports","a":2,"q":{"en":"A red or orange flag with a white diagonal stripe on the water means:","es":"Una bandera roja o naranja con una franja diagonal blanca en el agua significa:","ru":"Красный или оранжевый флаг с белой диагональной полосой на воде означает:","tr":"Suda beyaz çapraz şeritli kırmızı veya turuncu bir bayrak neyi ifade eder?","hi":"पानी पर सफ़ेद विकर्ण पट्टी वाला लाल या नारंगी झंडा क्या दर्शाता है:","ar":"علم أحمر أو برتقالي بشريط أبيض قطري على الماء يعني:"},"o":[{"en":"A race is in progress","es":"Hay una carrera en curso","ru":"Идёт гонка","tr":"Bir yarış devam ediyor","hi":"एक दौड़ चल रही है","ar":"سباق جارٍ"},{"en":"Swimming is allowed here","es":"Se permite nadar aquí","ru":"Здесь разрешено плавать","tr":"Burada yüzmeye izin var","hi":"यहाँ तैरना अनुमत है","ar":"السباحة مسموحة هنا"},{"en":"A diver is down in the area — stay well clear and slow down","es":"Hay un buzo en el área: manténgase bien alejado y reduzca la velocidad","ru":"В районе находится погружённый водолаз — держитесь в стороне и снизьте скорость","tr":"Bölgede bir dalgıç var — iyice uzak durun ve yavaşlayın","hi":"क्षेत्र में एक गोताखोर नीचे है — अच्छी तरह दूर रहें और गति कम करें","ar":"يوجد غطاس في المنطقة — ابتعد جيداً وخفّف السرعة"},{"en":"Fishing tournament boundary","es":"Límite de un torneo de pesca","ru":"Граница рыболовного турнира","tr":"Balık turnuvası sınırı","hi":"मछली पकड़ने की प्रतियोगिता की सीमा","ar":"حدود بطولة صيد"}],"e":{"en":"The red-and-white \"diver down\" flag warns that a scuba diver or snorkeler is in the water nearby. Slow down, stay well clear (commonly at least 100-300 feet, varies by state), and watch for divers surfacing.","es":"La bandera roja y blanca de \"buzo abajo\" advierte que hay un buzo o esnórquel en el agua cerca. Reduzca la velocidad, manténgase bien alejado (por lo general al menos 100-300 pies, varía por estado) y vigile a los buzos que emergen.","ru":"Красно-белый флаг «водолаз под водой» предупреждает, что рядом в воде находится аквалангист или ныряльщик. Снизьте скорость, держитесь в стороне (обычно не менее 100-300 футов, зависит от штата) и следите за всплывающими водолазами.","tr":"Kırmızı-beyaz \"dalgıç var\" bayrağı, yakında suda tüplü ya da şnorkelli bir dalgıç olduğunu uyarır. Yavaşlayın, iyice uzak durun (genellikle en az 100-300 fit, eyalete göre değişir) ve yüzeye çıkan dalgıçlara dikkat edin.","hi":"लाल-सफ़ेद \"डाइवर डाउन\" झंडा चेतावनी देता है कि पास में पानी में एक स्कूबा गोताखोर या स्नॉर्कलर है। गति कम करें, अच्छी तरह दूर रहें (आमतौर पर कम से कम 100-300 फुट, राज्यानुसार भिन्न), और सतह पर आते गोताखोरों पर नज़र रखें।","ar":"يحذّر علم \"غطاس تحت الماء\" الأحمر والأبيض من وجود غطاس أو غطاس بأنبوب تنفّس في الماء قريباً. خفّف السرعة وابتعد جيداً (عادةً 100-300 قدم على الأقل، يختلف حسب الولاية) وراقب الغطاسين الصاعدين."}},{"cat":"sports","a":1,"q":{"en":"The blue-and-white \"Alpha\" flag flown from a vessel means:","es":"La bandera \"Alfa\" azul y blanca izada en una embarcación significa:","ru":"Сине-белый флаг «Альфа», поднятый на судне, означает:","tr":"Bir teknede çekilen mavi-beyaz \"Alfa\" bayrağı neyi ifade eder?","hi":"किसी नाव पर फहराया गया नीला-सफ़ेद \"अल्फ़ा\" झंडा क्या दर्शाता है:","ar":"علم \"ألفا\" الأزرق والأبيض المرفوع من مركب يعني:"},"o":[{"en":"The vessel is racing","es":"La embarcación está compitiendo","ru":"Судно участвует в гонке","tr":"Tekne yarışıyor","hi":"नाव दौड़ रही है","ar":"المركب يتسابق"},{"en":"The vessel has a diver down and has restricted maneuverability — keep clear","es":"La embarcación tiene un buzo abajo y su maniobra es limitada: manténgase alejado","ru":"На судне погружён водолаз, манёвренность ограничена — держитесь в стороне","tr":"Tekneden dalgıç indi ve manevrası kısıtlı — uzak durun","hi":"नाव में एक गोताखोर नीचे है और उसकी गतिशीलता सीमित है — दूर रहें","ar":"في المركب غطاس تحت الماء وقدرته على المناورة محدودة — ابتعد"},{"en":"The vessel is anchored for the night","es":"La embarcación está fondeada para pasar la noche","ru":"Судно стоит на якоре на ночь","tr":"Tekne geceyi geçirmek için demirlemiş","hi":"नाव रात के लिए लंगर डाले हुए है","ar":"المركب راسٍ لقضاء الليل"},{"en":"The vessel is for sale","es":"La embarcación está en venta","ru":"Судно продаётся","tr":"Tekne satılık","hi":"नाव बिक्री के लिए है","ar":"المركب معروض للبيع"}],"e":{"en":"The rigid blue-and-white International Code flag \"A\" (Alpha) flown from a vessel means a diver is down and the vessel's ability to maneuver is restricted. Other boats must keep well clear and pass at slow speed.","es":"La bandera rígida azul y blanca del Código Internacional \"A\" (Alfa) izada en una embarcación significa que hay un buzo abajo y su maniobra está restringida. Los demás deben mantenerse alejados y pasar a baja velocidad.","ru":"Жёсткий сине-белый флаг Международного свода «A» (Альфа), поднятый на судне, означает, что погружён водолаз и манёвренность судна ограничена. Другим следует держаться в стороне и проходить малым ходом.","tr":"Bir teknede çekilen sert mavi-beyaz Uluslararası Kod bayrağı \"A\" (Alfa), dalgıç indiğini ve teknenin manevra kabiliyetinin kısıtlı olduğunu belirtir. Diğer tekneler iyice uzak durup yavaş geçmelidir.","hi":"किसी नाव पर फहराया गया कठोर नीला-सफ़ेद अंतरराष्ट्रीय कोड झंडा \"A\" (अल्फ़ा) दर्शाता है कि एक गोताखोर नीचे है और नाव की गतिशीलता सीमित है। अन्य नावों को अच्छी तरह दूर रहना और धीमी गति से गुज़रना चाहिए।","ar":"علم الشيفرة الدولية الصلب الأزرق والأبيض \"A\" (ألفا) المرفوع من مركب يعني وجود غطاس تحت الماء وأن قدرة المركب على المناورة محدودة. على القوارب الأخرى الابتعاد جيداً والمرور بسرعة بطيئة."}},{"cat":"sports","a":0,"q":{"en":"A personal watercraft (PWC) that steers by directing a jet of water can lose steering control when:","es":"Una moto acuática (PWC) que dirige mediante un chorro de agua puede perder el control de dirección cuando:","ru":"Гидроцикл (PWC), управляемый струёй воды, может потерять управление, когда:","tr":"Su jetini yönlendirerek dönen bir jet ski (PWC) ne zaman direksiyon kontrolünü kaybedebilir?","hi":"पानी की धारा को निर्देशित करके मुड़ने वाला पर्सनल वॉटरक्राफ्ट (PWC) कब स्टीयरिंग नियंत्रण खो सकता है:","ar":"مركبة مائية شخصية (PWC) توجّه نفسها بدفع نفّاث ماء قد تفقد التحكّم في التوجيه عندما:"},"o":[{"en":"The throttle is released and the engine returns to idle (you lose thrust to steer)","es":"Se suelta el acelerador y el motor vuelve a ralentí (se pierde el empuje para dirigir)","ru":"Отпущен газ и двигатель возвращается на холостой ход (теряется тяга для управления)","tr":"Gaz bırakılıp motor rölantiye döndüğünde (yönlendirme itişi kaybolur)","hi":"थ्रॉटल छोड़ दिया जाए और इंजन आइडल पर लौट आए (मुड़ने के लिए थ्रस्ट खो जाता है)","ar":"يُطلَق الخانق ويعود المحرك إلى الخمول (تفقد الدفع اللازم للتوجيه)"},{"en":"You accelerate hard","es":"Acelera con fuerza","ru":"Вы резко ускоряетесь","tr":"Sert hızlandığınızda","hi":"आप ज़ोर से गति बढ़ाएँ","ar":"تسرّع بقوة"},{"en":"You steer toward open water","es":"Dirige hacia aguas abiertas","ru":"Вы направляетесь в открытую воду","tr":"Açık suya doğru yönlendirdiğinizde","hi":"आप खुले पानी की ओर मुड़ें","ar":"توجّه نحو المياه المفتوحة"},{"en":"You wear a life jacket","es":"Lleva puesto un chaleco","ru":"Вы надеваете жилет","tr":"Can yeleği giydiğinizde","hi":"आप लाइफ जैकेट पहनें","ar":"ترتدي سترة نجاة"}],"e":{"en":"Most PWCs steer only when the jet is pushing water. If you release the throttle to idle or the engine stops, you lose steering control. To turn away from an obstacle you usually must keep applying throttle.","es":"La mayoría de las motos acuáticas dirigen solo cuando el chorro empuja agua. Si suelta el acelerador a ralentí o el motor se detiene, pierde el control de dirección. Para esquivar un obstáculo, normalmente debe seguir acelerando.","ru":"Большинство гидроциклов управляются только при работающей струе. Если отпустить газ до холостого хода или заглушить двигатель, управление теряется. Чтобы отвернуть от препятствия, обычно нужно продолжать давать газ.","tr":"Çoğu jet ski yalnızca jet su iterken yönlenir. Gazı rölantiye bırakır ya da motor durursa direksiyon kontrolünü kaybedersiniz. Bir engelden dönmek için genellikle gaz vermeye devam etmelisiniz.","hi":"अधिकांश PWC तभी मुड़ते हैं जब जेट पानी को धकेल रहा हो। यदि आप थ्रॉटल को आइडल पर छोड़ दें या इंजन बंद हो जाए, तो स्टीयरिंग नियंत्रण खो जाता है। किसी बाधा से बचने के लिए आमतौर पर थ्रॉटल देते रहना ज़रूरी है।","ar":"معظم المركبات المائية الشخصية تتوجّه فقط عندما يدفع النفّاث الماء. إذا أرخيت الخانق إلى الخمول أو توقف المحرك، تفقد التحكّم في التوجيه. لتنعطف بعيداً عن عائق، عليك عادةً الاستمرار في دفع الخانق."}},{"cat":"sports","a":3,"q":{"en":"Which is a required or strongly recommended practice for personal watercraft (PWC) operators?","es":"¿Cuál es una práctica exigida o muy recomendada para operadores de motos acuáticas (PWC)?","ru":"Что является обязательной или настоятельно рекомендуемой практикой для водителей гидроциклов (PWC)?","tr":"Jet ski (PWC) operatörleri için zorunlu veya şiddetle önerilen bir uygulama hangisidir?","hi":"पर्सनल वॉटरक्राफ्ट (PWC) चालकों के लिए एक आवश्यक या दृढ़ता से अनुशंसित अभ्यास कौन सा है?","ar":"أي مما يلي ممارسة مطلوبة أو موصى بها بشدة لمشغّلي المركبات المائية الشخصية (PWC)?"},"o":[{"en":"Ride at night without lights","es":"Circular de noche sin luces","ru":"Кататься ночью без огней","tr":"Gece fenersiz sürmek","hi":"बिना बत्तियों के रात में चलाना","ar":"القيادة ليلاً بلا أضواء"},{"en":"Jump the wake close behind another boat","es":"Saltar la estela justo detrás de otra embarcación","ru":"Прыгать по волне вплотную за другой лодкой","tr":"Başka bir teknenin hemen arkasında iz atlamak","hi":"किसी अन्य नाव के ठीक पीछे वेक कूदना","ar":"القفز فوق موجة قارب آخر من الخلف القريب"},{"en":"Remove the safety lanyard while riding","es":"Quitarse el cordón de seguridad mientras circula","ru":"Снимать страховочный шнур во время движения","tr":"Sürerken güvenlik kordonunu çıkarmak","hi":"चलाते समय सुरक्षा लैनयार्ड हटाना","ar":"نزع حبل الأمان أثناء القيادة"},{"en":"Wear a life jacket and attach the engine cut-off lanyard to your wrist or life jacket","es":"Llevar chaleco y sujetar el cordón de corte del motor a la muñeca o al chaleco","ru":"Носить жилет и пристёгивать аварийный шнур двигателя к запястью или жилету","tr":"Can yeleği giymek ve motor durdurma kordonunu bileğinize veya can yeleğinize takmak","hi":"लाइफ जैकेट पहनना और इंजन कट-ऑफ लैनयार्ड को अपनी कलाई या लाइफ जैकेट से जोड़ना","ar":"ارتداء سترة نجاة وربط حبل إيقاف المحرك بمعصمك أو سترة نجاتك"}],"e":{"en":"PWC riders must wear a life jacket and should clip the engine cut-off lanyard to their wrist or jacket so the engine stops if they fall off. Reckless moves like wake-jumping close to boats are dangerous and often illegal.","es":"Los conductores de motos acuáticas deben llevar chaleco y sujetar el cordón de corte del motor a la muñeca o al chaleco para que el motor se detenga si caen. Maniobras imprudentes como saltar estelas cerca de embarcaciones son peligrosas y a menudo ilegales.","ru":"Водители гидроциклов должны носить жилет и пристёгивать аварийный шнур к запястью или жилету, чтобы двигатель заглох при падении. Безрассудные приёмы вроде прыжков по волне вплотную к лодкам опасны и часто незаконны.","tr":"Jet ski sürücüleri can yeleği giymeli ve düşerlerse motorun durması için motor durdurma kordonunu bileklerine ya da yeleklerine takmalıdır. Teknelere yakın iz atlama gibi pervasız hareketler tehlikeli ve çoğunlukla yasa dışıdır.","hi":"PWC चालकों को लाइफ जैकेट पहननी चाहिए और इंजन कट-ऑफ लैनयार्ड को कलाई या जैकेट से जोड़ना चाहिए ताकि गिरने पर इंजन बंद हो जाए। नावों के पास वेक-जंपिंग जैसे लापरवाह कार्य खतरनाक और अक्सर अवैध हैं।","ar":"على راكبي المركبات المائية الشخصية ارتداء سترة نجاة وربط حبل إيقاف المحرك بالمعصم أو السترة حتى يتوقف المحرك إذا سقطوا. الحركات المتهوّرة كالقفز فوق الأمواج قرب القوارب خطرة وغالباً غير قانونية."}},{"cat":"sports","a":2,"q":{"en":"How close may you normally operate a PWC or boat to a marked diver-down flag?","es":"¿A qué distancia puede normalmente operar una moto acuática o embarcación de una bandera de buzo abajo marcada?","ru":"Насколько близко обычно можно проходить на гидроцикле или лодке к обозначенному флагу «водолаз под водой»?","tr":"Bir jet ski veya tekneyi işaretli bir dalgıç bayrağına normalde ne kadar yakın kullanabilirsiniz?","hi":"आप सामान्यतः किसी चिह्नित डाइवर-डाउन झंडे के कितने पास तक PWC या नाव चला सकते हैं:","ar":"إلى أي مدى يمكنك عادةً قيادة PWC أو قارب قرب علم غطاس معلّم؟"},"o":[{"en":"Right next to it","es":"Justo al lado","ru":"Прямо рядом с ним","tr":"Hemen yanından","hi":"बिल्कुल उसके बगल में","ar":"بجانبه تماماً"},{"en":"There is no distance rule","es":"No hay regla de distancia","ru":"Правила расстояния нет","tr":"Mesafe kuralı yoktur","hi":"कोई दूरी नियम नहीं है","ar":"لا توجد قاعدة مسافة"},{"en":"Not closer than the posted state distance (often about 100 feet on lakes/rivers), at slow, no-wake speed","es":"No más cerca de la distancia estatal indicada (a menudo unos 100 pies en lagos/ríos), a velocidad lenta sin estela","ru":"Не ближе установленного штатом расстояния (часто около 100 футов на озёрах/реках), на малой скорости без волны","tr":"Belirtilen eyalet mesafesinden yakın olmayacak şekilde (göl/nehirlerde genellikle ~100 fit), yavaş ve iz bırakmayan hızda","hi":"निर्धारित राज्य दूरी से अधिक पास नहीं (झीलों/नदियों पर अक्सर लगभग 100 फुट), धीमी, नो-वेक गति पर","ar":"ليس أقرب من المسافة المقرّرة في الولاية (غالباً نحو 100 قدم في البحيرات/الأنهار) وبسرعة بطيئة بلا موجة"},{"en":"Only at night","es":"Solo de noche","ru":"Только ночью","tr":"Yalnızca gece","hi":"केवल रात में","ar":"ليلاً فقط"}],"e":{"en":"Stay outside the required distance from a diver-down flag — commonly about 100 feet on lakes and rivers and around 300 feet in open water, though exact distances vary by state — and pass at slow, no-wake speed.","es":"Manténgase fuera de la distancia exigida respecto a la bandera de buzo —comúnmente unos 100 pies en lagos y ríos y unos 300 pies en aguas abiertas, aunque varía por estado— y pase a velocidad lenta sin estela.","ru":"Держитесь дальше установленного расстояния от флага «водолаз» — обычно около 100 футов на озёрах и реках и порядка 300 футов на открытой воде, хотя точные значения зависят от штата — и проходите на малой скорости без волны.","tr":"Dalgıç bayrağından gereken mesafenin dışında kalın — göl ve nehirlerde genellikle ~100 fit, açık suda ~300 fit, ancak kesin mesafe eyalete göre değişir — ve yavaş, iz bırakmayan hızda geçin.","hi":"डाइवर-डाउन झंडे से आवश्यक दूरी के बाहर रहें — झीलों और नदियों पर आमतौर पर लगभग 100 फुट और खुले पानी में लगभग 300 फुट, हालाँकि सटीक दूरियाँ राज्यानुसार भिन्न — और धीमी, नो-वेक गति से गुज़रें।","ar":"ابقَ خارج المسافة المطلوبة من علم الغطاس — غالباً نحو 100 قدم في البحيرات والأنهار ونحو 300 قدم في المياه المفتوحة، مع اختلاف المسافات حسب الولاية — ومُرّ بسرعة بطيئة بلا موجة."}},{"cat":"sports","a":0,"q":{"en":"Before starting to tow a skier from a stopped boat, the operator should:","es":"Antes de comenzar a remolcar a un esquiador desde una embarcación detenida, el operador debe:","ru":"Перед началом буксировки лыжника из неподвижной лодки судоводитель должен:","tr":"Durmuş bir tekneden kayakçı çekmeye başlamadan önce operatör:","hi":"रुकी हुई नाव से स्कीयर खींचना शुरू करने से पहले, चालक को चाहिए:","ar":"قبل البدء بسحب متزلج من قارب متوقف، على المشغّل أن:"},"o":[{"en":"Make sure the towline is not around anyone, the skier is ready, and the area ahead is clear before applying power","es":"Asegurarse de que la cuerda no rodee a nadie, que el esquiador esté listo y que el área adelante esté despejada antes de dar potencia","ru":"Убедиться, что трос никого не оплетает, лыжник готов, а зона впереди свободна, прежде чем дать газ","tr":"Halatın kimseye dolanmadığından, kayakçının hazır olduğundan ve öndeki alanın açık olduğundan emin olmak, sonra gaz vermek","hi":"सुनिश्चित करना कि टोलाइन किसी के इर्द-गिर्द न हो, स्कीयर तैयार हो, और आगे का क्षेत्र साफ़ हो, फिर पावर देना","ar":"يتأكّد أن حبل السحب ليس حول أحد وأن المتزلج جاهز والمنطقة أمامه خالية قبل دفع الطاقة"},{"en":"Gun the throttle immediately","es":"Acelerar a fondo de inmediato","ru":"Сразу дать полный газ","tr":"Hemen tam gaz vermek","hi":"तुरंत थ्रॉटल को ज़ोर से देना","ar":"يدفع الخانق فوراً"},{"en":"Have the skier hold the rope wrapped around a hand","es":"Que el esquiador enrolle la cuerda en la mano","ru":"Заставить лыжника обмотать трос вокруг руки","tr":"Kayakçının halatı eline sarmasını sağlamak","hi":"स्कीयर से रस्सी हाथ में लपेटवाना","ar":"يجعل المتزلج يلف الحبل حول يده"},{"en":"Skip checking for other boats","es":"Omitir la verificación de otras embarcaciones","ru":"Не проверять другие суда","tr":"Diğer tekneleri kontrol etmeyi atlamak","hi":"अन्य नावों की जाँच छोड़ देना","ar":"يتجاهل التحقّق من القوارب الأخرى"}],"e":{"en":"Before applying power, confirm the towline is clear of people and the propeller, the skier signals ready, and the path ahead is free of swimmers, boats, and obstacles. Accelerate smoothly, never with the rope wrapped around anyone.","es":"Antes de dar potencia, confirme que la cuerda esté libre de personas y de la hélice, que el esquiador indique estar listo y que el camino esté libre de nadadores, embarcaciones y obstáculos. Acelere suavemente, nunca con la cuerda enrollada en alguien.","ru":"Перед подачей газа убедитесь, что трос не задевает людей и винт, лыжник подал сигнал готовности, а путь свободен от пловцов, лодок и препятствий. Разгоняйтесь плавно и никогда — если трос обмотан вокруг кого-либо.","tr":"Gaz vermeden önce halatın insanlardan ve pervaneden uzak olduğunu, kayakçının hazır işaretini ve öndeki yolun yüzücü, tekne ve engellerden arınık olduğunu doğrulayın. Yumuşak hızlanın, halat asla kimseye dolanmış olmasın.","hi":"पावर देने से पहले पुष्टि करें कि टोलाइन लोगों और प्रोपेलर से मुक्त है, स्कीयर तैयार होने का संकेत देता है, और आगे का रास्ता तैराकों, नावों व बाधाओं से मुक्त है। सुचारू रूप से गति बढ़ाएँ, कभी किसी के इर्द-गिर्द रस्सी लिपटी होने पर नहीं।","ar":"قبل دفع الطاقة، تأكّد أن حبل السحب بعيد عن الناس وعن المروحة، وأن المتزلج يشير بجاهزيته، وأن الطريق أمامه خالٍ من السباحين والقوارب والعوائق. سرّع بسلاسة، ولا تفعل أبداً والحبل ملفوف حول أحد."}},{"cat":"sports","a":1,"q":{"en":"When hunting or fishing from a boat, which practice improves safety?","es":"Al cazar o pescar desde una embarcación, ¿qué práctica mejora la seguridad?","ru":"При охоте или рыбалке с лодки какая практика повышает безопасность?","tr":"Bir tekneden avlanırken veya balık tutarken hangi uygulama güvenliği artırır?","hi":"नाव से शिकार या मछली पकड़ते समय, कौन सा अभ्यास सुरक्षा बढ़ाता है?","ar":"عند الصيد البري أو صيد الأسماك من قارب، أي ممارسة تُحسّن السلامة؟"},"o":[{"en":"Standing and shooting or casting from the gunwale in a small boat","es":"Ponerse de pie y disparar o lanzar desde la borda en una embarcación pequeña","ru":"Стоять и стрелять или забрасывать снасть с планширя в маленькой лодке","tr":"Küçük teknede ayağa kalkıp küpeşteden ateş etmek ya da olta atmak","hi":"छोटी नाव में गनवेल से खड़े होकर गोली चलाना या कास्ट करना","ar":"الوقوف وإطلاق النار أو رمي الصنارة من حافة قارب صغير"},{"en":"Keeping a low center of gravity, wearing a life jacket, and unloading firearms before moving","es":"Mantener un centro de gravedad bajo, llevar chaleco y descargar las armas antes de moverse","ru":"Держать низкий центр тяжести, носить жилет и разряжать оружие перед перемещением","tr":"Alçak ağırlık merkezi tutmak, can yeleği giymek ve hareket etmeden önce silahları boşaltmak","hi":"गुरुत्व केंद्र नीचा रखना, लाइफ जैकेट पहनना, और चलने से पहले आग्नेयास्त्र अनलोड करना","ar":"الحفاظ على مركز ثقل منخفض وارتداء سترة نجاة وتفريغ الأسلحة قبل التحرك"},{"en":"Overloading the boat with gear and dogs","es":"Sobrecargar la embarcación con equipo y perros","ru":"Перегружать лодку снаряжением и собаками","tr":"Tekneyi teçhizat ve köpeklerle aşırı yüklemek","hi":"सामान और कुत्तों से नाव को ओवरलोड करना","ar":"تحميل القارب زيادةً بالعتاد والكلاب"},{"en":"Boating alone without telling anyone","es":"Navegar solo sin avisar a nadie","ru":"Плавать в одиночку, никому не сообщив","tr":"Kimseye söylemeden tek başına tekneyle çıkmak","hi":"किसी को बताए बिना अकेले नौकायन","ar":"الإبحار وحدك دون إخبار أحد"}],"e":{"en":"Hunters and anglers should keep weight low and centered, wear life jackets, avoid overloading, and unload and secure firearms before moving in the boat. Cold-water risk is high in hunting season, so dress for immersion.","es":"Cazadores y pescadores deben mantener el peso bajo y centrado, llevar chaleco, evitar sobrecargar y descargar y asegurar las armas antes de moverse. El riesgo de agua fría es alto en temporada de caza; vístase para una posible inmersión.","ru":"Охотникам и рыболовам следует держать вес низко и по центру, носить жилеты, не перегружать лодку и разряжать и закреплять оружие перед перемещением. В сезон охоты высок риск холодной воды — одевайтесь на случай погружения.","tr":"Avcılar ve balıkçılar ağırlığı alçak ve ortada tutmalı, can yeleği giymeli, aşırı yüklememeli ve teknede hareket etmeden önce silahları boşaltıp sabitlemelidir. Av sezonunda soğuk su riski yüksektir; suya düşmeye karşı giyinin.","hi":"शिकारियों और मछुआरों को वज़न नीचा व केंद्रित रखना चाहिए, लाइफ जैकेट पहननी चाहिए, ओवरलोड से बचना चाहिए, और नाव में चलने से पहले आग्नेयास्त्र अनलोड कर सुरक्षित करने चाहिए। शिकार के मौसम में ठंडे पानी का जोखिम अधिक होता है, इसलिए डूबने की स्थिति के अनुसार कपड़े पहनें।","ar":"على الصيادين إبقاء الوزن منخفضاً وفي المنتصف وارتداء سترات نجاة وتجنّب التحميل الزائد وتفريغ الأسلحة وتأمينها قبل التحرك في القارب. خطر الماء البارد مرتفع في موسم الصيد، فارتدِ ملابس تناسب الغطس."}},{"cat":"sports","a":3,"q":{"en":"Why is it especially risky to overload a small boat with hunting or fishing gear?","es":"¿Por qué es especialmente arriesgado sobrecargar una embarcación pequeña con equipo de caza o pesca?","ru":"Почему особенно опасно перегружать небольшую лодку охотничьим или рыболовным снаряжением?","tr":"Küçük bir tekneyi av veya balık teçhizatıyla aşırı yüklemek neden özellikle risklidir?","hi":"शिकार या मछली पकड़ने के सामान से किसी छोटी नाव को ओवरलोड करना विशेष रूप से जोखिमपूर्ण क्यों है?","ar":"لماذا يكون تحميل قارب صغير زيادةً بعتاد الصيد خطراً بشكل خاص؟"},"o":[{"en":"It uses less fuel","es":"Consume menos combustible","ru":"Это расходует меньше топлива","tr":"Daha az yakıt harcar","hi":"इससे कम ईंधन खर्च होता है","ar":"يستهلك وقوداً أقل"},{"en":"It makes the boat faster","es":"Hace que la embarcación sea más rápida","ru":"Это делает лодку быстрее","tr":"Tekneyi hızlandırır","hi":"इससे नाव तेज़ हो जाती है","ar":"يجعل القارب أسرع"},{"en":"An overloaded boat sits low, is unstable, and can easily swamp or capsize, especially in cold water","es":"Una embarcación sobrecargada se asienta baja, es inestable y puede inundarse o volcar fácilmente, sobre todo en agua fría","ru":"Перегруженная лодка сидит низко, неустойчива и легко заливается или опрокидывается, особенно в холодной воде","tr":"Aşırı yüklü tekne alçak oturur, dengesizdir ve özellikle soğuk suda kolayca su alır ya da alabora olur","hi":"ओवरलोड नाव नीचे बैठती है, अस्थिर होती है, और आसानी से भर या पलट सकती है, विशेषकर ठंडे पानी में","ar":"القارب المحمّل زيادةً يجلس منخفضاً وغير مستقر ويمكن أن يُغمر أو ينقلب بسهولة، خصوصاً في الماء البارد"},{"en":"It has no real effect","es":"No tiene efecto real","ru":"Не имеет реального эффекта","tr":"Gerçek bir etkisi yoktur","hi":"इसका कोई वास्तविक असर नहीं","ar":"لا أثر حقيقي له"}],"e":{"en":"Overloading rides the boat low and raises the risk of swamping or capsizing, and hunting and fishing often happen in cold water where a sudden dunk can quickly cause hypothermia. Respect the capacity plate.","es":"La sobrecarga hace que la embarcación se asiente baja y aumenta el riesgo de inundación o volcadura; además, la caza y la pesca suelen darse en agua fría, donde una zambullida repentina puede causar hipotermia rápidamente. Respete la placa de capacidad.","ru":"Перегрузка сажает лодку низко и повышает риск заливания или опрокидывания, а охота и рыбалка часто идут в холодной воде, где внезапное погружение быстро вызывает гипотермию. Соблюдайте табличку вместимости.","tr":"Aşırı yük tekneyi alçaltır ve su alma ya da alabora riskini artırır; ayrıca av ve balıkçılık genellikle soğuk suda yapılır ve ani bir batış hızla hipotermiye yol açabilir. Kapasite plakasına uyun.","hi":"ओवरलोडिंग नाव को नीचा कर देती है और भरने या पलटने का जोखिम बढ़ाती है, और शिकार व मछली पकड़ना अक्सर ठंडे पानी में होता है जहाँ अचानक डुबकी तेज़ी से हाइपोथर्मिया पैदा कर सकती है। क्षमता प्लेट का सम्मान करें।","ar":"التحميل الزائد يُجلِس القارب منخفضاً ويزيد خطر الغمر أو الانقلاب، والصيد غالباً يجري في ماء بارد حيث قد يسبّب الانغماس المفاجئ انخفاض حرارة الجسم بسرعة. احترم لوحة السعة."}},{"cat":"sports","a":2,"q":{"en":"When operating a PWC near other boats and swimmers, you should:","es":"Al operar una moto acuática cerca de otras embarcaciones y nadadores, debe:","ru":"При управлении гидроциклом рядом с другими лодками и пловцами следует:","tr":"Diğer tekneler ve yüzücülerin yakınında jet ski kullanırken:","hi":"अन्य नावों और तैराकों के पास PWC चलाते समय, आपको चाहिए:","ar":"عند قيادة PWC قرب قوارب أخرى وسباحين، عليك أن:"},"o":[{"en":"Spray them for fun","es":"Salpicarlos por diversión","ru":"Обрызгивать их ради забавы","tr":"Eğlence için üzerlerine su sıçratmak","hi":"मज़े के लिए उन पर पानी छिड़कना","ar":"ترشّهم بالماء للتسلية"},{"en":"Weave sharply around them","es":"Zigzaguear bruscamente a su alrededor","ru":"Резко лавировать вокруг них","tr":"Etraflarında keskin zikzak çizmek","hi":"उनके इर्द-गिर्द तीखा लहराना","ar":"تناور بحدة حولهم"},{"en":"Slow to a safe speed, keep a safe distance, and follow the same navigation rules as other boats","es":"Reducir a velocidad segura, mantener distancia segura y seguir las mismas reglas de navegación que otras embarcaciones","ru":"Снизить скорость до безопасной, держать дистанцию и соблюдать те же правила судоходства, что и другие суда","tr":"Güvenli hıza düşmek, güvenli mesafe korumak ve diğer tekneler gibi aynı seyir kurallarına uymak","hi":"सुरक्षित गति तक धीमा करना, सुरक्षित दूरी रखना, और अन्य नावों जैसे ही नौवहन नियमों का पालन करना","ar":"تبطئ إلى سرعة آمنة وتحافظ على مسافة آمنة وتتّبع قواعد الملاحة نفسها كالقوارب الأخرى"},{"en":"Assume the rules don't apply to PWCs","es":"Suponer que las reglas no aplican a las motos acuáticas","ru":"Считать, что правила не касаются гидроциклов","tr":"Kuralların jet skilere uygulanmadığını varsaymak","hi":"मान लेना कि नियम PWC पर लागू नहीं होते","ar":"تفترض أن القواعد لا تنطبق على PWC"}],"e":{"en":"A PWC is a boat and must obey the same navigation rules, speed limits, and no-wake zones. Slow down and keep well clear of swimmers, divers, and other vessels; spraying or buzzing people is reckless and often illegal.","es":"Una moto acuática es una embarcación y debe cumplir las mismas reglas de navegación, límites de velocidad y zonas sin estela. Reduzca la velocidad y manténgase alejado de nadadores, buzos y otras embarcaciones; salpicar o rondar a la gente es imprudente y suele ser ilegal.","ru":"Гидроцикл — это судно и должен подчиняться тем же правилам судоходства, ограничениям скорости и зонам «без волны». Снижайте скорость и держитесь в стороне от пловцов, водолазов и судов; обрызгивать или кружить вокруг людей — безрассудно и часто незаконно.","tr":"Jet ski bir teknedir ve aynı seyir kurallarına, hız sınırlarına ve no-wake bölgelerine uymalıdır. Yavaşlayın; yüzücü, dalgıç ve diğer teknelerden iyice uzak durun; insanlara su sıçratmak ya da etraflarında dolanmak pervasızdır ve çoğunlukla yasa dışıdır.","hi":"PWC एक नाव है और उसे वही नौवहन नियम, गति सीमाएँ और नो-वेक ज़ोन मानने होते हैं। गति कम करें और तैराकों, गोताखोरों व अन्य नावों से अच्छी तरह दूर रहें; लोगों पर पानी छिड़कना या उनके पास चक्कर काटना लापरवाह और अक्सर अवैध है।","ar":"المركبة المائية الشخصية قارب ويجب أن تلتزم بقواعد الملاحة نفسها وحدود السرعة ومناطق بلا موجة. خفّف السرعة وابتعد جيداً عن السباحين والغطاسين والقوارب الأخرى؛ ورشّ الناس أو الدوران حولهم متهوّر وغالباً غير قانوني."}},{"cat":"sports","a":0,"q":{"en":"If a skier falls in the water, a good practice for the boat is to:","es":"Si un esquiador cae al agua, una buena práctica para la embarcación es:","ru":"Если лыжник упал в воду, хорошая практика для лодки — это:","tr":"Bir kayakçı suya düşerse tekne için iyi bir uygulama nedir?","hi":"यदि कोई स्कीयर पानी में गिर जाए, तो नाव के लिए एक अच्छा अभ्यास है:","ar":"إذا سقط متزلج في الماء، فمن الممارسات الجيدة للقارب أن:"},"o":[{"en":"Circle back slowly, approach from the side with the engine off as you reach them, and display a skier-down flag if required","es":"Regresar despacio, aproximarse por el costado con el motor apagado al llegar y mostrar la bandera de esquiador caído si se exige","ru":"Медленно вернуться, подойти сбоку с заглушённым двигателем и поднять флаг «лыжник в воде», если требуется","tr":"Yavaşça geri dönmek, motoru kapatarak yandan yaklaşmak ve gerekiyorsa kayakçı düştü bayrağı göstermek","hi":"धीरे लौटना, इंजन बंद कर बगल से पहुँचना, और आवश्यक हो तो स्कीयर-डाउन झंडा दिखाना","ar":"تعود ببطء وتقترب من الجانب والمحرك مطفأ عند الوصول إليه وترفع علم سقوط المتزلج إن لزم"},{"en":"Leave the area to get help","es":"Abandonar el área para buscar ayuda","ru":"Покинуть район, чтобы позвать помощь","tr":"Yardım için bölgeyi terk etmek","hi":"मदद के लिए क्षेत्र छोड़ देना","ar":"تغادر المنطقة لجلب المساعدة"},{"en":"Speed back toward the skier","es":"Regresar a toda velocidad hacia el esquiador","ru":"На скорости мчаться назад к лыжнику","tr":"Kayakçıya doğru hızla dönmek","hi":"स्कीयर की ओर तेज़ी से लौटना","ar":"تعود مسرعاً نحو المتزلج"},{"en":"Ignore them until they swim back","es":"Ignorarlos hasta que naden de vuelta","ru":"Игнорировать, пока сам не приплывёт","tr":"Geri yüzene kadar görmezden gelmek","hi":"जब तक वे तैरकर वापस न आएँ, अनदेखा करना","ar":"تتجاهله حتى يسبح عائداً"}],"e":{"en":"Return slowly, keeping the fallen skier in view, and approach from the side with the engine off before reaching them so the propeller can't strike them. Many states require a flag or raised ski to mark a downed skier.","es":"Regrese despacio, sin perder de vista al esquiador caído, y aproxímese por el costado con el motor apagado antes de llegar, para que la hélice no lo golpee. Muchos estados exigen una bandera o esquí levantado para señalar al esquiador caído.","ru":"Возвращайтесь медленно, не теряя упавшего лыжника из виду, и подходите сбоку с заглушённым двигателем, чтобы винт не задел его. Многие штаты требуют флаг или поднятую лыжу, чтобы обозначить упавшего.","tr":"Yavaşça dönün, düşen kayakçıyı görüş alanında tutun ve pervanenin çarpmaması için ona ulaşmadan motoru kapatıp yandan yaklaşın. Birçok eyalet, düşen kayakçıyı işaretlemek için bayrak veya kaldırılmış kayak ister.","hi":"धीरे लौटें, गिरे स्कीयर को नज़र में रखें, और उन तक पहुँचने से पहले इंजन बंद कर बगल से पहुँचें ताकि प्रोपेलर उन्हें न लगे। कई राज्य गिरे स्कीयर को चिह्नित करने के लिए झंडा या उठा हुआ स्की आवश्यक करते हैं।","ar":"عُد ببطء وأبقِ المتزلج الساقط في مرمى البصر، واقترب من الجانب والمحرك مطفأ قبل الوصول إليه حتى لا تضربه المروحة. تشترط ولايات كثيرة رفع علم أو زلاجة للدلالة على متزلج ساقط."}},{"cat":"sports","a":1,"q":{"en":"Wakeboarding, tubing, and towing riders generally require the boat to follow:","es":"El wakeboard, el tubing y remolcar personas generalmente exigen que la embarcación cumpla:","ru":"Вейкбординг, катание на «плюшке» и буксировка людей обычно требуют, чтобы судно соблюдало:","tr":"Wakeboard, şişme çekme ve insan çekme genellikle teknenin şuna uymasını gerektirir:","hi":"वेकबोर्डिंग, ट्यूबिंग और सवारों को खींचना आमतौर पर आवश्यक करते हैं कि नाव इसका पालन करे:","ar":"التزلج على الألواح والعوّامات وسحب الركّاب تتطلّب عموماً أن يلتزم القارب بـ:"},"o":[{"en":"No rules — it's just for fun","es":"Ninguna regla: es solo diversión","ru":"Никаких правил — это просто развлечение","tr":"Kural yok — sadece eğlence","hi":"कोई नियम नहीं — यह बस मज़े के लिए है","ar":"لا قواعد — إنه للتسلية فقط"},{"en":"The same observer, daylight, and distance rules as water skiing","es":"Las mismas reglas de observador, luz de día y distancia que el esquí acuático","ru":"Тех же правил наблюдателя, светлого времени и дистанции, что и воднолыжный спорт","tr":"Su kayağıyla aynı gözlemci, gündüz ve mesafe kuralları","hi":"वॉटर स्कीइंग जैसे ही ऑब्ज़र्वर, दिन-उजाला और दूरी नियम","ar":"نفس قواعد المراقب والنهار والمسافة كالتزلج المائي"},{"en":"Rules only for the rider, not the boat","es":"Reglas solo para el pasajero, no para la embarcación","ru":"Правил только для катающегося, но не для лодки","tr":"Yalnızca binici için kurallar, tekne için değil","hi":"केवल सवार के लिए नियम, नाव के लिए नहीं","ar":"قواعد للراكب فقط لا للقارب"},{"en":"A commercial license","es":"Una licencia comercial","ru":"Коммерческую лицензию","tr":"Ticari ehliyet","hi":"एक वाणिज्यिक लाइसेंस","ar":"رخصة تجارية"}],"e":{"en":"Towing a wakeboarder or tuber follows the same safety rules as water skiing: a competent observer or mirror, daylight-only operation, safe distance from shore and others, and enough room to maneuver.","es":"Remolcar a un wakeboarder o a alguien en tubo sigue las mismas reglas que el esquí acuático: observador competente o espejo, operación solo de día, distancia segura de la orilla y de otros, y espacio suficiente para maniobrar.","ru":"Буксировка вейкбордиста или «плюшки» подчиняется тем же правилам, что и воднолыжный спорт: компетентный наблюдатель или зеркало, движение только днём, безопасная дистанция от берега и других, достаточно места для манёвра.","tr":"Wakeboardçu ya da şişme çekmek, su kayağıyla aynı güvenlik kurallarına uyar: yetkin gözlemci ya da ayna, yalnızca gündüz kullanım, kıyıdan ve diğerlerinden güvenli mesafe ve manevra için yeterli alan.","hi":"वेकबोर्डर या ट्यूबर को खींचना वॉटर स्कीइंग जैसे ही सुरक्षा नियमों का पालन करता है: एक सक्षम ऑब्ज़र्वर या मिरर, केवल दिन में संचालन, तट और अन्य से सुरक्षित दूरी, और मैन्युवर के लिए पर्याप्त जगह।","ar":"سحب راكب لوح التزلج أو العوّامة يتّبع قواعد السلامة نفسها كالتزلج المائي: مراقب كفؤ أو مرآة، والتشغيل نهاراً فقط، ومسافة آمنة عن الشاطئ والآخرين، ومساحة كافية للمناورة."}},{"cat":"sports","a":3,"q":{"en":"What is the safest way for a downed skier to make themselves visible to other boats?","es":"¿Cuál es la forma más segura de que un esquiador caído se haga visible a otras embarcaciones?","ru":"Как упавшему лыжнику безопаснее всего стать заметным для других лодок?","tr":"Düşen bir kayakçının diğer teknelere kendini göstermesinin en güvenli yolu nedir?","hi":"गिरे हुए स्कीयर के लिए अन्य नावों को स्वयं को दिखाई देने योग्य बनाने का सबसे सुरक्षित तरीका क्या है?","ar":"ما أسلم طريقة لمتزلج ساقط ليجعل نفسه مرئياً للقوارب الأخرى؟"},"o":[{"en":"Duck under the water to rest","es":"Sumergirse para descansar","ru":"Нырнуть под воду, чтобы отдохнуть","tr":"Dinlenmek için suyun altına dalmak","hi":"आराम के लिए पानी के नीचे डुबकी लगाना","ar":"الغطس تحت الماء للراحة"},{"en":"Swim away from the boat","es":"Alejarse nadando de la embarcación","ru":"Отплыть от лодки","tr":"Tekneden uzağa yüzmek","hi":"नाव से दूर तैरना","ar":"السباحة بعيداً عن القارب"},{"en":"Take off the life jacket to wave it","es":"Quitarse el chaleco para agitarlo","ru":"Снять жилет, чтобы махать им","tr":"Sallamak için can yeleğini çıkarmak","hi":"इसे हिलाने के लिए लाइफ जैकेट उतारना","ar":"خلع سترة النجاة للتلويح بها"},{"en":"Hold up a ski or wear a bright life jacket while the tow boat displays a skier-down flag","es":"Levantar un esquí o llevar un chaleco brillante mientras la embarcación muestra la bandera de esquiador caído","ru":"Поднять лыжу или надеть яркий жилет, пока буксир поднимает флаг «лыжник в воде»","tr":"Bir kayağı kaldırmak ya da parlak can yeleği giymek; çeken tekne kayakçı düştü bayrağı gösterirken","hi":"एक स्की ऊपर उठाना या चमकीला लाइफ जैकेट पहनना जबकि टो नाव स्कीयर-डाउन झंडा दिखाए","ar":"يرفع زلاجة أو يرتدي سترة نجاة زاهية بينما يرفع القارب الساحب علم سقوط المتزلج"}],"e":{"en":"A downed skier should keep their bright life jacket on and hold up a ski or arm, while the tow boat stands by and, where required, raises a skier-down flag so other boaters slow down and steer clear.","es":"Un esquiador caído debe mantener su chaleco brillante y levantar un esquí o un brazo, mientras la embarcación permanece cerca y, donde se exija, iza la bandera de esquiador caído para que otros reduzcan la velocidad y se aparten.","ru":"Упавший лыжник должен оставаться в ярком жилете и поднять лыжу или руку, пока буксир держится рядом и, где требуется, поднимает флаг «лыжник в воде», чтобы другие снижали ход и держались в стороне.","tr":"Düşen kayakçı parlak can yeleğini çıkarmamalı ve bir kayağı ya da kolunu kaldırmalıdır; çeken tekne yakında beklerken ve gereken yerde kayakçı düştü bayrağını çekerken diğerleri yavaşlayıp uzak dursun.","hi":"गिरे स्कीयर को अपना चमकीला लाइफ जैकेट पहने रहना चाहिए और एक स्की या हाथ ऊपर उठाना चाहिए, जबकि टो नाव पास खड़ी रहे और जहाँ आवश्यक हो स्कीयर-डाउन झंडा उठाए ताकि अन्य नाविक गति कम करें और दूर रहें।","ar":"على المتزلج الساقط إبقاء سترة نجاته الزاهية ورفع زلاجة أو ذراعه، بينما يبقى القارب الساحب قريباً ويرفع حيث يلزم علم سقوط المتزلج ليبطئ الآخرون ويبتعدوا."}},{"cat":"sports","a":2,"q":{"en":"Riding a PWC, you approach a congested swimming area. You should:","es":"Conduciendo una moto acuática, se acerca a una zona de baño concurrida. Debe:","ru":"На гидроцикле вы приближаетесь к оживлённой зоне купания. Вам следует:","tr":"Jet ski kullanırken kalabalık bir yüzme alanına yaklaşıyorsunuz. Şunu yapmalısınız:","hi":"PWC चलाते हुए, आप एक भीड़भाड़ वाले तैराकी क्षेत्र के पास पहुँचते हैं। आपको चाहिए:","ar":"وأنت تقود PWC تقترب من منطقة سباحة مزدحمة. عليك أن:"},"o":[{"en":"Maintain high speed to pass quickly","es":"Mantener alta velocidad para pasar rápido","ru":"Держать высокую скорость, чтобы быстро проскочить","tr":"Hızlıca geçmek için yüksek hızı korumak","hi":"जल्दी गुज़रने के लिए तेज़ गति बनाए रखना","ar":"تحافظ على سرعة عالية للمرور بسرعة"},{"en":"Cut through the swimmers","es":"Atravesar entre los nadadores","ru":"Пройти сквозь пловцов","tr":"Yüzücülerin arasından geçmek","hi":"तैराकों के बीच से गुज़रना","ar":"تشقّ طريقك بين السباحين"},{"en":"Reduce to idle/no-wake speed and give the area a wide berth","es":"Reducir a ralentí/sin estela y dar un amplio margen a la zona","ru":"Снизить до холостого хода/«без волны» и обойти зону стороной","tr":"Rölanti/no-wake hızına düşmek ve alana geniş bir açıklık bırakmak","hi":"आइडल/नो-वेक गति तक धीमा करना और क्षेत्र को व्यापक जगह देना","ar":"تبطئ إلى الخمول/بلا موجة وتترك للمنطقة مسافة واسعة"},{"en":"Spray water to warn them","es":"Salpicar agua para advertirles","ru":"Обрызгать водой, чтобы предупредить","tr":"Uyarmak için su sıçratmak","hi":"चेतावनी देने के लिए पानी छिड़कना","ar":"ترشّ الماء لتحذيرهم"}],"e":{"en":"Slow to idle/no-wake speed and keep well away from a crowded swimming area. Swimmers are hard to see, and a PWC at speed can seriously injure them. Never operate at high speed near people in the water.","es":"Reduzca a ralentí/sin estela y manténgase bien alejado de una zona de baño concurrida. Los nadadores son difíciles de ver y una moto acuática a velocidad puede lesionarlos gravemente. Nunca navegue rápido cerca de personas en el agua.","ru":"Снизьте до холостого хода/«без волны» и держитесь подальше от оживлённой зоны купания. Пловцов трудно заметить, а гидроцикл на скорости может серьёзно их травмировать. Никогда не идите быстро рядом с людьми в воде.","tr":"Rölanti/no-wake hızına düşün ve kalabalık yüzme alanından iyice uzak durun. Yüzücüleri görmek zordur ve hızlı bir jet ski onları ağır yaralayabilir. Suda insanların yakınında asla yüksek hızda gitmeyin.","hi":"आइडल/नो-वेक गति तक धीमा करें और भीड़भाड़ वाले तैराकी क्षेत्र से अच्छी तरह दूर रहें। तैराकों को देखना कठिन है, और तेज़ गति पर PWC उन्हें गंभीर चोट पहुँचा सकता है। पानी में लोगों के पास कभी तेज़ गति से न चलाएँ।","ar":"أبطئ إلى الخمول/بلا موجة وابتعد جيداً عن منطقة السباحة المزدحمة. يصعب رؤية السباحين، وقد تصيبهم PWC مسرعة بجروح خطيرة. لا تقُد أبداً بسرعة عالية قرب الناس في الماء."}},{"cat":"sports","a":0,"q":{"en":"A key reason to keep a safe distance behind another boat when wakeboarding or tubing is:","es":"Una razón clave para mantener una distancia segura detrás de otra embarcación al hacer wakeboard o tubing es:","ru":"Ключевая причина держать безопасную дистанцию за другой лодкой при вейкбординге или катании на «плюшке»:","tr":"Wakeboard veya şişme çekerken başka bir teknenin arkasında güvenli mesafe bırakmanın temel bir nedeni:","hi":"वेकबोर्डिंग या ट्यूबिंग करते समय किसी अन्य नाव के पीछे सुरक्षित दूरी रखने का एक मुख्य कारण है:","ar":"سبب رئيسي للحفاظ على مسافة آمنة خلف قارب آخر أثناء التزلج على اللوح أو العوّامة هو:"},"o":[{"en":"Their wake and sudden stops can throw or injure your rider if you are too close","es":"Su estela y frenadas bruscas pueden arrojar o lesionar a su pasajero si está demasiado cerca","ru":"Их волна и резкие остановки могут сбросить или травмировать вашего райдера, если вы слишком близко","tr":"Onların izi ve ani duruşları, çok yakınsanız binicinizi savurabilir veya yaralayabilir","hi":"उनकी वेक और अचानक रुकावट आपके सवार को गिरा या घायल कर सकती है यदि आप बहुत पास हों","ar":"موجتهم وتوقفهم المفاجئ قد يقذف راكبك أو يؤذيه إن كنت قريباً جداً"},{"en":"It looks impressive","es":"Se ve impresionante","ru":"Это эффектно выглядит","tr":"Etkileyici görünür","hi":"यह प्रभावशाली दिखता है","ar":"يبدو مبهراً"},{"en":"It saves fuel","es":"Ahorra combustible","ru":"Это экономит топливо","tr":"Yakıt tasarrufu sağlar","hi":"इससे ईंधन बचता है","ar":"يوفّر الوقود"},{"en":"It is faster","es":"Es más rápido","ru":"Это быстрее","tr":"Daha hızlıdır","hi":"यह तेज़ है","ar":"إنه أسرع"}],"e":{"en":"Following too closely puts your rider in another boat's wake and leaves no room if that boat stops or turns suddenly. Keep a safe distance so the rider has smooth water and time to react to hazards.","es":"Seguir demasiado cerca pone a su pasajero en la estela de otra embarcación y no deja margen si esa embarcación se detiene o gira de repente. Mantenga distancia segura para que el pasajero tenga agua tranquila y tiempo de reaccionar.","ru":"Идти слишком близко — значит подставить райдера под чужую волну и не оставить запаса, если та лодка резко остановится или повернёт. Держите безопасную дистанцию, чтобы у райдера была ровная вода и время реагировать.","tr":"Çok yakın takip, binicinizi başka bir teknenin izine sokar ve o tekne aniden durur ya da dönerse yer bırakmaz. Binicinin düz su ve tepki verme zamanı olması için güvenli mesafe bırakın.","hi":"बहुत पास चलना आपके सवार को दूसरी नाव की वेक में डाल देता है और यदि वह नाव अचानक रुके या मुड़े तो कोई जगह नहीं बचती। सुरक्षित दूरी रखें ताकि सवार को समतल पानी और खतरों पर प्रतिक्रिया का समय मिले।","ar":"المتابعة عن قرب تضع راكبك في موجة قارب آخر ولا تترك مجالاً إذا توقف ذلك القارب أو انعطف فجأة. حافظ على مسافة آمنة ليحظى الراكب بماء هادئ ووقت للتفاعل مع المخاطر."}},{"cat":"sports","a":1,"q":{"en":"Why should you avoid operating a boat or PWC in posted swimming or wildlife-protection areas?","es":"¿Por qué debe evitar operar una embarcación o moto acuática en zonas señalizadas de baño o protección de fauna?","ru":"Почему следует избегать управления лодкой или гидроциклом в обозначенных зонах купания или охраны дикой природы?","tr":"İşaretli yüzme veya yaban hayatı koruma alanlarında tekne veya jet ski kullanmaktan neden kaçınmalısınız?","hi":"आपको चिह्नित तैराकी या वन्यजीव-संरक्षण क्षेत्रों में नाव या PWC चलाने से क्यों बचना चाहिए?","ar":"لماذا يجب تجنّب قيادة قارب أو PWC في مناطق السباحة أو حماية الحياة البرية المعلّمة؟"},"o":[{"en":"It is faster to go around","es":"Es más rápido rodear","ru":"Так быстрее объехать","tr":"Etrafından gitmek daha hızlıdır","hi":"चारों ओर जाना तेज़ है","ar":"الالتفاف أسرع"},{"en":"These zones protect people and habitats, and operating there is unsafe and usually prohibited","es":"Estas zonas protegen a personas y hábitats, y operar allí es inseguro y suele estar prohibido","ru":"Эти зоны защищают людей и среду обитания; движение там небезопасно и обычно запрещено","tr":"Bu bölgeler insanları ve yaşam alanlarını korur; buralarda kullanım güvensiz ve genellikle yasaktır","hi":"ये क्षेत्र लोगों और आवासों की रक्षा करते हैं, और वहाँ चलाना असुरक्षित और आमतौर पर निषिद्ध है","ar":"تحمي هذه المناطق الناس والموائل، والقيادة فيها غير آمنة وممنوعة عادةً"},{"en":"The water is deeper there","es":"El agua es más profunda allí","ru":"Там глубже","tr":"Su orada daha derindir","hi":"वहाँ पानी गहरा है","ar":"الماء أعمق هناك"},{"en":"There is better cell service","es":"Hay mejor señal de celular","ru":"Там лучше связь","tr":"Orada telefon çekimi daha iyidir","hi":"वहाँ बेहतर सेल सेवा है","ar":"إشارة الهاتف أفضل هناك"}],"e":{"en":"Marked swimming and wildlife/no-motor zones protect swimmers, nesting birds, shorelines, and sensitive habitats. Operating a motorized craft there endangers people and wildlife and is usually against the law.","es":"Las zonas señalizadas de baño y de fauna/sin motor protegen a nadadores, aves anidando, orillas y hábitats sensibles. Operar una embarcación motorizada allí pone en peligro a personas y fauna y suele ser ilegal.","ru":"Обозначенные зоны купания и охраны дикой природы/без моторов защищают пловцов, гнездящихся птиц, берега и уязвимые места обитания. Движение на моторном судне там угрожает людям и природе и обычно противозаконно.","tr":"İşaretli yüzme ve yaban hayatı/motorsuz bölgeler yüzücüleri, kuluçkadaki kuşları, kıyıları ve hassas yaşam alanlarını korur. Buralarda motorlu araç kullanmak insanları ve yaban hayatını tehlikeye atar ve genellikle yasa dışıdır.","hi":"चिह्नित तैराकी और वन्यजीव/नो-मोटर क्षेत्र तैराकों, घोंसला बना रहे पक्षियों, तटरेखाओं और संवेदनशील आवासों की रक्षा करते हैं। वहाँ मोटर चालित शिल्प चलाना लोगों और वन्यजीवों को खतरे में डालता है और आमतौर पर गैरकानूनी है।","ar":"تحمي مناطق السباحة والحياة البرية/الممنوع فيها المحركات المعلّمة السباحين والطيور المعشّشة والشواطئ والموائل الحساسة. قيادة مركبة آلية هناك تعرّض الناس والحياة البرية للخطر وغالباً مخالفة للقانون."}},{"cat":"sports","a":3,"q":{"en":"When multiple boats are towing skiers in the same area, operators should:","es":"Cuando varias embarcaciones remolcan esquiadores en la misma zona, los operadores deben:","ru":"Когда несколько лодок буксируют лыжников в одном районе, судоводителям следует:","tr":"Aynı bölgede birden fazla tekne kayakçı çekerken operatörler:","hi":"जब एक ही क्षेत्र में कई नावें स्कीयर खींच रही हों, तो चालकों को चाहिए:","ar":"عندما تسحب عدة قوارب متزلجين في المنطقة نفسها، على المشغّلين أن:"},"o":[{"en":"Cross each other's tow ropes","es":"Cruzar las cuerdas de remolque entre sí","ru":"Пересекать буксирные тросы друг друга","tr":"Birbirlerinin çekme halatlarını kesmek","hi":"एक-दूसरे की टो रस्सियाँ पार करना","ar":"يتقاطعوا مع حبال سحب بعضهم"},{"en":"Keep generous spacing, move in the same general direction, and watch for skiers and ropes in the water","es":"Mantener amplio espacio, moverse en la misma dirección general y vigilar esquiadores y cuerdas en el agua","ru":"Держать большие интервалы, двигаться в одном общем направлении и следить за лыжниками и тросами в воде","tr":"Bol aralık bırakmak, aynı genel yönde hareket etmek ve sudaki kayakçı ve halatlara dikkat etmek","hi":"पर्याप्त दूरी रखना, एक ही सामान्य दिशा में चलना, और पानी में स्कीयरों व रस्सियों पर नज़र रखना","ar":"يتركوا مسافات واسعة ويتحرّكوا في الاتجاه العام نفسه ويراقبوا المتزلجين والحبال في الماء"},{"en":"Race each other","es":"Competir entre sí","ru":"Соревноваться друг с другом","tr":"Birbirleriyle yarışmak","hi":"एक-दूसरे से दौड़ लगाना","ar":"يتسابقوا"},{"en":"Ignore the other boats","es":"Ignorar a las demás embarcaciones","ru":"Игнорировать другие лодки","tr":"Diğer tekneleri görmezden gelmek","hi":"अन्य नावों को अनदेखा करना","ar":"يتجاهلوا القوارب الأخرى"}],"e":{"en":"With several tow boats out, keep plenty of space, travel in the same general direction, avoid crossing others' ropes, and stay alert for downed skiers and floating lines to prevent collisions and injuries.","es":"Con varias embarcaciones remolcando, mantenga mucho espacio, viaje en la misma dirección general, evite cruzar las cuerdas de otros y esté atento a esquiadores caídos y cuerdas flotantes para evitar colisiones y lesiones.","ru":"Когда буксируют несколько лодок, держите много места, двигайтесь в одном общем направлении, не пересекайте чужие тросы и следите за упавшими лыжниками и плавающими фалами, чтобы избежать столкновений и травм.","tr":"Birden çok çekme teknesi varken bol yer bırakın, aynı genel yönde ilerleyin, başkalarının halatlarını kesmeyin ve çarpışma ile yaralanmaları önlemek için düşen kayakçılara ve yüzen halatlara karşı tetikte olun.","hi":"कई टो नावों के साथ, पर्याप्त जगह रखें, एक ही सामान्य दिशा में चलें, दूसरों की रस्सियाँ पार करने से बचें, और टक्कर व चोट रोकने के लिए गिरे स्कीयरों तथा तैरती रस्सियों के प्रति सतर्क रहें।","ar":"مع وجود عدة قوارب ساحبة، اترك مساحة وافرة، وسِر في الاتجاه العام نفسه، وتجنّب تقاطع حبال الآخرين، وابقَ متيقّظاً للمتزلجين الساقطين والحبال الطافية لمنع التصادم والإصابات."}},{"cat":"sports","a":0,"q":{"en":"Which statement about PWC and boat noise/nuisance rules is generally correct?","es":"¿Qué afirmación sobre las reglas de ruido/molestias de motos acuáticas y embarcaciones es generalmente correcta?","ru":"Какое утверждение о правилах шума/помех для гидроциклов и лодок в целом верно?","tr":"Jet ski ve tekne gürültü/rahatsızlık kurallarıyla ilgili hangi ifade genellikle doğrudur?","hi":"PWC और नाव के शोर/उपद्रव नियमों के बारे में कौन सा कथन आमतौर पर सही है?","ar":"أي عبارة حول قواعد ضوضاء/إزعاج المركبات المائية والقوارب صحيحة عموماً؟"},"o":[{"en":"Operators may run muffler-bypass exhaust anytime","es":"Los operadores pueden usar escape sin silenciador en cualquier momento","ru":"Судоводители могут ездить с прямотоком в любое время","tr":"Operatörler istedikleri zaman susturucu baypaslı egzoz kullanabilir","hi":"चालक कभी भी मफलर-बायपास एग्ज़ॉस्ट चला सकते हैं","ar":"يمكن للمشغّلين تشغيل عادم بلا كاتم في أي وقت"},{"en":"Many areas set noise limits and quiet hours, and creating a hazardous wake or disturbance can be an offense","es":"Muchas zonas fijan límites de ruido y horas de silencio, y crear una estela peligrosa o molestia puede ser una infracción","ru":"Во многих районах установлены пределы шума и тихие часы, а создание опасной волны или помехи может быть нарушением","tr":"Birçok bölge gürültü sınırları ve sessiz saatler koyar; tehlikeli iz veya rahatsızlık oluşturmak suç olabilir","hi":"कई क्षेत्र शोर सीमाएँ और शांत घंटे तय करते हैं, और खतरनाक वेक या गड़बड़ी पैदा करना एक अपराध हो सकता है","ar":"تحدّد مناطق كثيرة حدود ضوضاء وساعات هدوء، وإحداث موجة خطرة أو إزعاج قد يكون مخالفة"},{"en":"Noise is never regulated on the water","es":"El ruido nunca se regula en el agua","ru":"Шум на воде никогда не регулируется","tr":"Suda gürültü asla düzenlenmez","hi":"पानी पर शोर कभी विनियमित नहीं होता","ar":"الضوضاء لا تُنظَّم أبداً على الماء"},{"en":"Only sailboats must be quiet","es":"Solo los veleros deben ser silenciosos","ru":"Только парусники должны быть тихими","tr":"Yalnızca yelkenliler sessiz olmalıdır","hi":"केवल पाल-नावों को शांत रहना चाहिए","ar":"المراكب الشراعية فقط يجب أن تكون هادئة"}],"e":{"en":"Many waters set noise limits, quiet hours, and rules against nuisance operation. Creating a dangerous wake, harassing wildlife, or excessive noise can bring citations. Requirements and enforcement vary by state and locality.","es":"Muchas aguas fijan límites de ruido, horas de silencio y reglas contra la operación molesta. Crear una estela peligrosa, acosar a la fauna o hacer ruido excesivo puede acarrear multas. Los requisitos y la aplicación varían por estado y localidad.","ru":"Во многих водах установлены пределы шума, тихие часы и правила против создания помех. Опасная волна, беспокойство дикой природы или чрезмерный шум могут повлечь штрафы. Требования и правоприменение различаются по штату и местности.","tr":"Birçok su alanı gürültü sınırları, sessiz saatler ve rahatsız edici kullanıma karşı kurallar koyar. Tehlikeli iz oluşturmak, yaban hayatını rahatsız etmek veya aşırı gürültü ceza getirebilir. Gereklilikler ve uygulama eyalet ve yöreye göre değişir.","hi":"कई जल शोर सीमाएँ, शांत घंटे, और उपद्रवकारी संचालन के विरुद्ध नियम तय करते हैं। खतरनाक वेक बनाना, वन्यजीवों को परेशान करना, या अत्यधिक शोर करने पर चालान हो सकता है। आवश्यकताएँ और प्रवर्तन राज्य व स्थान अनुसार भिन्न होते हैं।","ar":"تضع مياه كثيرة حدود ضوضاء وساعات هدوء وقواعد ضد التشغيل المزعج. إحداث موجة خطرة أو مضايقة الحياة البرية أو الضوضاء المفرطة قد يستوجب مخالفات. تختلف المتطلبات والتطبيق حسب الولاية والمنطقة."}},{"cat":"sports","a":2,"q":{"en":"A safe minimum age and life-jacket rule for children being towed on a tube is:","es":"Una regla segura de edad mínima y chaleco para niños remolcados en un tubo es:","ru":"Безопасное правило минимального возраста и жилета для детей, буксируемых на «плюшке»:","tr":"Şişme üstünde çekilen çocuklar için güvenli asgari yaş ve can yeleği kuralı:","hi":"ट्यूब पर खींचे जा रहे बच्चों के लिए एक सुरक्षित न्यूनतम आयु और लाइफ जैकेट नियम है:","ar":"قاعدة آمنة للحد الأدنى للسن وسترة النجاة للأطفال المسحوبين على عوّامة هي:"},"o":[{"en":"No life jacket is needed if they can swim","es":"No se necesita chaleco si saben nadar","ru":"Жилет не нужен, если умеют плавать","tr":"Yüzebiliyorlarsa can yeleğine gerek yok","hi":"यदि वे तैर सकते हैं तो लाइफ जैकेट की ज़रूरत नहीं","ar":"لا حاجة لسترة نجاة إن كانوا يجيدون السباحة"},{"en":"Any child of any size may be towed at any speed","es":"Cualquier niño de cualquier tamaño puede ser remolcado a cualquier velocidad","ru":"Любого ребёнка любого размера можно буксировать на любой скорости","tr":"Her boyda çocuk her hızda çekilebilir","hi":"किसी भी आकार का कोई बच्चा किसी भी गति पर खींचा जा सकता है","ar":"يمكن سحب أي طفل بأي حجم بأي سرعة"},{"en":"Every person being towed must wear a properly fitted, approved life jacket, and towing speed should suit the rider","es":"Toda persona remolcada debe llevar un chaleco aprobado y de talla adecuada, y la velocidad debe adecuarse al pasajero","ru":"Каждый буксируемый должен носить подходящий одобренный жилет, а скорость буксировки — соответствовать райдеру","tr":"Çekilen herkes uygun bedende, onaylı can yeleği giymeli ve çekme hızı biniciye uygun olmalı","hi":"हर खींचे जा रहे व्यक्ति को सही फिट, अनुमोदित लाइफ जैकेट पहननी चाहिए, और खींचने की गति सवार के अनुकूल होनी चाहिए","ar":"على كل شخص مسحوب ارتداء سترة نجاة معتمدة ومناسبة المقاس، وأن تلائم سرعة السحب الراكب"},{"en":"Life jackets are only for the driver","es":"Los chalecos son solo para el conductor","ru":"Жилеты только для водителя","tr":"Can yelekleri yalnızca sürücü içindir","hi":"लाइफ जैकेट केवल चालक के लिए हैं","ar":"سترات النجاة للسائق فقط"}],"e":{"en":"Anyone being towed on skis, a wakeboard, or a tube must wear a properly fitting, approved life jacket, and the operator should match speed to the rider's age and ability. Check your state for specific towing and age rules.","es":"Cualquiera remolcado en esquís, wakeboard o tubo debe llevar un chaleco aprobado y de talla adecuada, y el operador debe ajustar la velocidad a la edad y capacidad del pasajero. Verifique las reglas específicas de su estado.","ru":"Любой, кого буксируют на лыжах, вейкборде или «плюшке», должен носить подходящий одобренный жилет, а судоводитель — подбирать скорость под возраст и умение райдера. Уточняйте правила буксировки и возраста в своём штате.","tr":"Kayak, wakeboard veya şişme üstünde çekilen herkes uygun bedende onaylı can yeleği giymelidir ve operatör hızı binicinin yaşına ve becerisine göre ayarlamalıdır. Çekme ve yaş kuralları için eyaletinize bakın.","hi":"स्की, वेकबोर्ड या ट्यूब पर खींचे जा रहे किसी भी व्यक्ति को सही फिट, अनुमोदित लाइफ जैकेट पहननी चाहिए, और चालक को गति सवार की आयु व क्षमता के अनुसार रखनी चाहिए। विशिष्ट खींचने व आयु नियमों के लिए अपने राज्य को देखें।","ar":"على أي شخص يُسحَب على زلاجات أو لوح أو عوّامة ارتداء سترة نجاة معتمدة ومناسبة المقاس، وعلى المشغّل ملاءمة السرعة لعمر الراكب وقدرته. راجع قواعد السحب والسن في ولايتك."}},{"cat":"sports","a":3,"q":{"en":"What should you do when you see a diver-down flag but no boat nearby?","es":"¿Qué debe hacer cuando ve una bandera de buzo abajo pero ninguna embarcación cerca?","ru":"Что делать, если вы видите флаг «водолаз под водой», но лодки рядом нет?","tr":"Yakınında tekne olmadan bir dalgıç bayrağı gördüğünüzde ne yapmalısınız?","hi":"जब आप डाइवर-डाउन झंडा देखें पर पास कोई नाव न हो तो आपको क्या करना चाहिए?","ar":"ماذا يجب أن تفعل عندما ترى علم غطاس دون قارب قريب؟"},"o":[{"en":"Assume no one is there and continue at speed","es":"Suponer que no hay nadie y seguir a velocidad","ru":"Считать, что там никого нет, и продолжать на скорости","tr":"Kimsenin olmadığını varsayıp hızla devam etmek","hi":"मान लेना कि वहाँ कोई नहीं है और गति से चलते रहना","ar":"تفترض أن لا أحد هناك وتستمر بسرعة"},{"en":"Circle the flag closely to look for the diver","es":"Rodear la bandera de cerca para buscar al buzo","ru":"Близко обойти флаг, чтобы найти водолаза","tr":"Dalgıcı aramak için bayrağın etrafında yakından dönmek","hi":"गोताखोर को खोजने के लिए झंडे के पास चक्कर लगाना","ar":"تدور حول العلم عن قرب للبحث عن الغطاس"},{"en":"Speed up to clear the area faster","es":"Acelerar para despejar la zona más rápido","ru":"Ускориться, чтобы быстрее покинуть район","tr":"Bölgeyi çabuk terk etmek için hızlanmak","hi":"क्षेत्र जल्दी खाली करने के लिए गति बढ़ाना","ar":"تسرّع لمغادرة المنطقة أسرع"},{"en":"Slow down, keep well clear, and assume a diver may be anywhere in the surrounding area","es":"Reducir la velocidad, mantenerse bien alejado y suponer que puede haber un buzo en cualquier parte del área","ru":"Снизить скорость, держаться в стороне и считать, что водолаз может быть где угодно поблизости","tr":"Yavaşlamak, iyice uzak durmak ve dalgıcın çevredeki herhangi bir yerde olabileceğini varsaymak","hi":"गति कम करना, अच्छी तरह दूर रहना, और मान लेना कि गोताखोर आसपास कहीं भी हो सकता है","ar":"تبطئ وتبتعد جيداً وتفترض أن الغطاس قد يكون في أي مكان من المنطقة المحيطة"}],"e":{"en":"A diver-down flag can mark a diver swimming away from a shore entry with no boat present. Slow down, give the flag a wide berth, and assume a diver could surface anywhere nearby.","es":"Una bandera de buzo abajo puede marcar a un buzo que entró desde la orilla sin embarcación. Reduzca la velocidad, dé un amplio margen a la bandera y suponga que un buzo puede emerger en cualquier lugar cercano.","ru":"Флаг «водолаз под водой» может обозначать водолаза, вошедшего с берега, без лодки. Снизьте скорость, обойдите флаг стороной и считайте, что водолаз может всплыть где угодно рядом.","tr":"Dalgıç bayrağı, tekne olmadan kıyıdan giren bir dalgıcı işaret ediyor olabilir. Yavaşlayın, bayrağa geniş açıklık bırakın ve bir dalgıcın yakında herhangi bir yerde yüzeye çıkabileceğini varsayın.","hi":"डाइवर-डाउन झंडा बिना नाव के तट से प्रवेश कर तैर रहे गोताखोर को चिह्नित कर सकता है। गति कम करें, झंडे को व्यापक जगह दें, और मान लें कि गोताखोर पास कहीं भी सतह पर आ सकता है।","ar":"قد يشير علم الغطاس إلى غطاس دخل من الشاطئ دون قارب. أبطئ، واترك للعلم مسافة واسعة، وافترض أن غطاساً قد يظهر في أي مكان قريب."}}]};
